/**
 * Smoke test — runs once on import and prints NDL/ceiling/TTS for a couple of
 * canonical dive profiles. Compares against numbers from the vendor's own
 * example.ts so we know the wrapper hasn't introduced a regression.
 *
 * Intentionally console-driven (not a real test framework). Open devtools
 * and look for the "[divecomp smoke]" group.
 *
 * Remove the import from main.ts when no longer needed.
 */

import { DiveComputer, STOCK_GASES, customGf } from './index';

function fmt(n: number, p = 1): string {
  return n.toFixed(p);
}

function runProfile1(): void {
  // Mirrors vendor's example.ts: descend to 30 m over 3 min, sit 25 min, all on air,
  // GF 30/85, surface 1013 mbar, ascent rate 9 m/min.
  // Expected: NDL = 0 (well in deco), ceiling ≈ 5-8 m, TTS includes stops.
  const dc = new DiveComputer({
    conservatism: customGf(30, 85),
    surfaceMbar: 1013,
    ascentRateMpm: 9,
    initialGases: [STOCK_GASES.air, STOCK_GASES.ean32, STOCK_GASES.o2],
    activeGasId: STOCK_GASES.air.id,
  });

  // Descend (3 min from 0 → 30 m, 1-second steps).
  const descentSeconds = 180;
  for (let i = 1; i <= descentSeconds; i++) {
    dc.update((i / descentSeconds) * 30, 1);
  }

  // Bottom (25 min @ 30 m).
  for (let i = 0; i < 25 * 60; i++) {
    dc.update(30, 1);
  }

  const s = dc.snapshot();
  const plan = dc.planDeco();

  console.group('[divecomp smoke] Profile 1 — 30m air, 25 min (GF 30/85)');
  console.log(`Depth      : ${fmt(s.depth_m)} m   (max ${fmt(s.maxDepth_m)} m)`);
  console.log(`Dive time  : ${fmt(s.diveTimeS / 60)} min`);
  console.log(`NDL        : ${fmt(s.ndlMin)} min  (engine caps at 99)`);
  console.log(`Ceiling    : ${fmt(s.ceiling_m)} m   (inDeco=${s.inDeco})`);
  console.log(`GF99       : ${fmt(s.gf99Pct)} %   SurGF ${fmt(s.surfGfPct)} %`);
  console.log(`CNS        : ${fmt(s.cnsPct)} %   OTU ${fmt(s.otu)}`);
  console.log(`Density    : ${fmt(s.density.gPerL, 2)} g/L  [${s.density.severity}]`);
  if (plan) {
    console.log(`TTS        : ${fmt(plan.ttsMin)} min  (${plan.stages.length} stages)`);
    for (const st of plan.stages) {
      console.log(
        `  • ${st.stageType.padEnd(9)} ${fmt(st.startDepth.asMeters())}m → ${fmt(st.endDepth.asMeters())}m, ` +
          `${fmt(st.duration.asMinutes())} min on ${st.gas.toString()}`
      );
    }
  } else {
    console.log('TTS        : (no plan)');
  }
  console.groupEnd();
}

function runProfile2(): void {
  // Recreational profile: descend to 18 m over 2 min, sit 30 min on EAN32, GF 40/85.
  // Expected: NDL > 0 throughout, no deco obligation, ceiling = 0.
  const dc = new DiveComputer({
    initialGases: [STOCK_GASES.ean32],
    activeGasId: STOCK_GASES.ean32.id,
  });

  const descentSeconds = 120;
  for (let i = 1; i <= descentSeconds; i++) {
    dc.update((i / descentSeconds) * 18, 1);
  }
  for (let i = 0; i < 30 * 60; i++) {
    dc.update(18, 1);
  }

  const s = dc.snapshot();
  console.group('[divecomp smoke] Profile 2 — 18m EAN32, 30 min (GF 40/85)');
  console.log(`NDL        : ${fmt(s.ndlMin)} min`);
  console.log(`Ceiling    : ${fmt(s.ceiling_m)} m  (inDeco=${s.inDeco})`);
  console.log(`GF99       : ${fmt(s.gf99Pct)} %   SurGF ${fmt(s.surfGfPct)} %`);
  console.log(`Density    : ${fmt(s.density.gPerL, 2)} g/L  [${s.density.severity}]`);
  console.groupEnd();
}

let alreadyRan = false;
export function runSmokeTest(): void {
  if (alreadyRan) return;
  alreadyRan = true;
  try {
    runProfile1();
    runProfile2();
  } catch (e) {
    console.error('[divecomp smoke] failed:', e);
  }
}
