/**
 * GasMix helpers. The host owns the canonical `GasMix` instances; this module
 * provides convenience constructors and standard recreational/tech mixes.
 *
 * MOD and density use stable reference formulas — see notes inline.
 */

import type { GasMix } from './types';

/** Stock mixes covering most recreational + intro-tech use. */
export const STOCK_GASES = {
  air:    { id: 'g-air',    name: 'Air',          o2Pct: 21, hePct: 0,  role: 'bottom' as const },
  ean28:  { id: 'g-ean28',  name: 'EAN28',        o2Pct: 28, hePct: 0,  role: 'bottom' as const },
  ean32:  { id: 'g-ean32',  name: 'EAN32',        o2Pct: 32, hePct: 0,  role: 'bottom' as const },
  ean36:  { id: 'g-ean36',  name: 'EAN36',        o2Pct: 36, hePct: 0,  role: 'bottom' as const },
  ean50:  { id: 'g-ean50',  name: 'EAN50',        o2Pct: 50, hePct: 0,  role: 'deco' as const },
  o2:     { id: 'g-o2',     name: 'O₂ 100%',      o2Pct: 100, hePct: 0, role: 'oxygen' as const },
  tx2135: { id: 'g-tx2135', name: 'Trimix 21/35', o2Pct: 21, hePct: 35, role: 'bottom' as const },
  tx1845: { id: 'g-tx1845', name: 'Trimix 18/45', o2Pct: 18, hePct: 45, role: 'bottom' as const },
} as const satisfies Record<string, GasMix>;

export function makeGas(
  id: string,
  name: string,
  o2Pct: number,
  hePct: number,
  role: GasMix['role'] = 'bottom'
): GasMix {
  if (o2Pct < 1 || o2Pct > 100) throw new Error(`bad O2%: ${o2Pct}`);
  if (hePct < 0 || hePct > 99) throw new Error(`bad He%: ${hePct}`);
  if (o2Pct + hePct > 100) throw new Error(`O2+He must ≤ 100`);
  return { id, name, o2Pct, hePct, role };
}

export function n2Pct(g: GasMix): number {
  return 100 - g.o2Pct - g.hePct;
}

/**
 * Maximum Operating Depth at a given PPO2 limit (typically 1.4 ATA bottom, 1.6 deco).
 * MOD = 10 × (ppO2Limit / fO2 − 1)  (saltwater, P_surface ≈ 1 ATA).
 */
export function modM(g: GasMix, ppO2Limit: number): number {
  return 10 * (ppO2Limit / (g.o2Pct / 100) - 1);
}

/**
 * Equivalent Narcotic Depth — depth-equivalent on air for the same narcosis dose.
 * Used for trimix planning. END = (depth + 10) × (1 − fHe) − 10.
 */
export function endM(g: GasMix, depth_m: number): number {
  const end = (depth_m + 10) * (1 - g.hePct / 100) - 10;
  return Math.max(0, end);
}

/**
 * Surface gas density (g/L) at 20°C, 1 atm. Uses the ideal-gas molar
 * volume V_m = 24.04 L/mol — matches the NOTES.md reference table:
 *   Air 21/0  → 1.20 g/L
 *   EAN32     → 1.22 g/L
 *   O₂ 100%   → 1.33 g/L
 *   Tmx 21/35 → 0.85 g/L
 * (Some manuals quote 0°C STP values which are ~7% higher — both are
 * defensible; we pick the warm-water number consistent with rec diving.)
 */
const MOLAR_VOLUME_L = 24.04;
export function surfaceDensity_gPerL(g: GasMix): number {
  const fO2 = g.o2Pct / 100;
  const fHe = g.hePct / 100;
  const fN2 = 1 - fO2 - fHe;
  // Molar masses: O2=32, He=4, N2=28
  const M = fO2 * 32 + fHe * 4 + fN2 * 28;
  return M / MOLAR_VOLUME_L;
}

/**
 * In-vivo gas density at depth — Boyle compression of the surface value.
 * Anthony 2017 / GUE limit: warning > 5.7 g/L, hard limit ~6.2 g/L.
 */
export function density_gPerL_atDepth(
  g: GasMix,
  depth_m: number,
  surfaceMbar = 1013
): number {
  const pAmb_bar = surfaceMbar / 1000 + Math.max(0, depth_m) / 10;
  return surfaceDensity_gPerL(g) * pAmb_bar;
}
