/**
 * AnthropicProvider — calls Claude's Messages API to produce a SceneSpec.
 *
 * Notes
 * -----
 * • This is a browser-side call. The Anthropic SDK normally refuses to run
 *   in a browser without `dangerouslyAllowBrowser`, because keys in the
 *   browser are de-facto public. The UI surfaces this warning before the
 *   user pastes a key.
 * • The provider does not bundle the SDK — it speaks the REST API directly
 *   with `fetch` so the project stays SDK-free and works offline if the
 *   user picks the MockProvider instead.
 * • Output validation is liberal: any JSON object matching the SceneSpec
 *   shape (after a best-effort coerce) is accepted; the renderer fills in
 *   defaults for missing fields.
 */

import type { SceneSpec } from '../../scene/genScene.types';
import { SCENE_SPEC_SCHEMA_HINT } from '../../scene/genScene.types';
import type {
  GenerateRequest,
  GenerateResponse,
  SceneProvider,
} from './Provider';

const MODEL_DEFAULT = 'claude-opus-4-7';
const API_URL = 'https://api.anthropic.com/v1/messages';

export class AnthropicProvider implements SceneProvider {
  readonly name = 'CLAUDE (Anthropic)';
  /** Override at construction to pin a different model id. */
  model: string;

  constructor(model: string = MODEL_DEFAULT) {
    this.model = model;
  }

  isReady(): boolean {
    // The provider itself is always ready; the call-site checks `apiKey`.
    return true;
  }

  async generate(req: GenerateRequest): Promise<GenerateResponse> {
    if (!req.apiKey) {
      return { ok: false, error: 'No API key set — paste a key in the panel.' };
    }

    const sys = buildSystemPrompt();
    const userPrompt = (req.prompt || '').trim() ||
      'A welcoming tropical reef at 18 m, lots of bright fish, a few hazards.';

    const body = {
      model: this.model,
      max_tokens: 2048,
      system: sys,
      messages: [{ role: 'user', content: userPrompt }],
    };

    let raw: string;
    try {
      const res = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'content-type': 'application/json',
          'x-api-key': req.apiKey,
          'anthropic-version': '2023-06-01',
          // SDK-equivalent of dangerouslyAllowBrowser — the API gateway uses
          // this header to allow CORS from non-server origins.
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify(body),
      });
      if (!res.ok) {
        const txt = await res.text();
        return { ok: false, error: `HTTP ${res.status} — ${truncate(txt, 200)}` };
      }
      const json = (await res.json()) as MessagesResponse;
      raw = extractText(json);
    } catch (err) {
      return { ok: false, error: 'Network error: ' + String(err) };
    }

    const parsed = parseSpec(raw, userPrompt);
    if (!parsed) {
      return { ok: false, error: 'Could not parse a SceneSpec from the model reply.' };
    }
    return { ok: true, spec: parsed, source: this.model };
  }
}

// ---- helpers ----

interface MessagesResponse {
  content?: Array<{ type: string; text?: string }>;
}

function extractText(j: MessagesResponse): string {
  if (!j.content) return '';
  for (const block of j.content) {
    if (block.type === 'text' && block.text) return block.text;
  }
  return '';
}

function buildSystemPrompt(): string {
  return [
    'You are a dive-scene generator. The user describes a dive site, and ',
    'you reply with a single JSON object describing the scene. No prose.',
    '',
    SCENE_SPEC_SCHEMA_HINT,
  ].join('\n');
}

/**
 * Pull the first {...} JSON object out of the model reply and validate it
 * just enough to render. Accepts an `id` / `label` fallback.
 */
function parseSpec(raw: string, prompt: string): SceneSpec | null {
  const j = findJsonBlock(raw);
  if (!j) return null;
  try {
    const obj = JSON.parse(j) as Partial<SceneSpec>;
    if (!obj || typeof obj !== 'object') return null;
    if (!Array.isArray(obj.creatures)) return null;
    if (!Array.isArray(obj.zones) || obj.zones.length === 0) return null;
    return {
      id: typeof obj.id === 'string' ? obj.id : 'llm-' + Date.now().toString(36),
      label: typeof obj.label === 'string' ? obj.label : 'GENERATED',
      zones: obj.zones,
      bottom: obj.bottom,
      creatures: obj.creatures,
      prompt,
    };
  } catch {
    return null;
  }
}

function findJsonBlock(text: string): string | null {
  // Strip code fences if present.
  const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) return fence[1].trim();
  const open = text.indexOf('{');
  const close = text.lastIndexOf('}');
  if (open >= 0 && close > open) return text.slice(open, close + 1);
  return null;
}

function truncate(s: string, n: number): string {
  return s.length > n ? s.slice(0, n) + '…' : s;
}
