/**
 * GenScenePanel — floating editor for prompt-driven scenes.
 *
 * Sits in the bottom-right of the water view, only visible while the GEN
 * scene is active. UI is intentionally tiny:
 *   • textarea for the prompt
 *   • provider picker (MOCK / CLAUDE)
 *   • optional key field (CLAUDE only) persisted in localStorage
 *   • APPLY button that runs the provider + emits the SceneSpec
 *
 * The panel doesn't know anything about Pixi or the scene graph — the
 * host wires `onApply` to call `genScene.applySpec(spec)`.
 */

import { AnthropicProvider } from './AnthropicProvider';
import { MockProvider } from './MockProvider';
import type { SceneProvider } from './Provider';
import type { SceneSpec } from '../../scene/genScene.types';

const LS_KEY_ANTHROPIC = 'ppb.genscene.anthropicKey';
const LS_PROMPT        = 'ppb.genscene.lastPrompt';
const LS_PROVIDER      = 'ppb.genscene.provider';

export interface GenScenePanelOpts {
  /** Called when the user produces a new spec. Host applies it to GenScene. */
  onApply: (spec: SceneSpec) => void;
  /** Initial prompt — usually the GenScene's current `spec.prompt`. */
  initialPrompt?: string;
}

export class GenScenePanel {
  readonly el: HTMLElement;
  private providers: Map<string, SceneProvider> = new Map();
  private activeProviderId = 'mock';
  private busy = false;

  private $prompt: HTMLTextAreaElement;
  private $providerSel: HTMLSelectElement;
  private $apiKey: HTMLInputElement;
  private $keyRow: HTMLElement;
  private $apply: HTMLButtonElement;
  private $status: HTMLElement;

  constructor(private opts: GenScenePanelOpts) {
    // Anthropic is the primary provider; mock is an optional offline fallback
    // listed second so it still appears in the dropdown.
    this.providers.set('anthropic', new AnthropicProvider());
    this.providers.set('mock',      new MockProvider());

    this.activeProviderId = localStorage.getItem(LS_PROVIDER) ?? 'anthropic';

    this.el = document.createElement('div');
    this.el.className = 'gen-panel';
    this.el.innerHTML = `
      <div class="gen-head">
        <span class="gen-title">SCENE PROMPT</span>
        <button type="button" class="gen-min" title="hide">_</button>
      </div>
      <div class="gen-body">
        <textarea class="gen-prompt" rows="3" spellcheck="false"
          placeholder="e.g. shallow tropical reef at 18 m, lots of small bright fish, a few jellyfish"></textarea>
        <div class="gen-row">
          <select class="gen-prov">
            <option value="anthropic">CLAUDE</option>
            <option value="mock">MOCK (offline)</option>
          </select>
          <button type="button" class="gen-apply">APPLY</button>
        </div>
        <div class="gen-row gen-key-row" hidden>
          <input type="password" class="gen-key" placeholder="Anthropic API key (kept in browser only)" />
        </div>
        <div class="gen-status"></div>
      </div>
    `;

    this.$prompt      = this.el.querySelector('.gen-prompt')! as HTMLTextAreaElement;
    this.$providerSel = this.el.querySelector('.gen-prov')!   as HTMLSelectElement;
    this.$apiKey      = this.el.querySelector('.gen-key')!    as HTMLInputElement;
    this.$keyRow      = this.el.querySelector('.gen-key-row')! as HTMLElement;
    this.$apply       = this.el.querySelector('.gen-apply')!  as HTMLButtonElement;
    this.$status      = this.el.querySelector('.gen-status')! as HTMLElement;
    const $min        = this.el.querySelector('.gen-min')!     as HTMLButtonElement;
    const $body       = this.el.querySelector('.gen-body')!    as HTMLElement;

    this.$prompt.value   = opts.initialPrompt ?? localStorage.getItem(LS_PROMPT) ?? '';
    this.$providerSel.value = this.activeProviderId;
    this.$apiKey.value   = localStorage.getItem(LS_KEY_ANTHROPIC) ?? '';

    this.refreshKeyRow();

    this.$providerSel.addEventListener('change', () => {
      this.activeProviderId = this.$providerSel.value;
      localStorage.setItem(LS_PROVIDER, this.activeProviderId);
      this.refreshKeyRow();
    });
    this.$apiKey.addEventListener('change', () => {
      localStorage.setItem(LS_KEY_ANTHROPIC, this.$apiKey.value.trim());
    });
    this.$prompt.addEventListener('change', () => {
      localStorage.setItem(LS_PROMPT, this.$prompt.value);
    });
    this.$apply.addEventListener('click', () => this.run());
    $min.addEventListener('click', () => {
      const hidden = $body.hasAttribute('hidden');
      if (hidden) $body.removeAttribute('hidden');
      else $body.setAttribute('hidden', '');
      $min.textContent = hidden ? '_' : '▢';
    });
  }

  /** Replace the prompt textarea (e.g. when GenScene gets a new spec from elsewhere). */
  setPrompt(text: string): void {
    this.$prompt.value = text;
  }

  private refreshKeyRow(): void {
    if (this.activeProviderId === 'anthropic') {
      this.$keyRow.removeAttribute('hidden');
    } else {
      this.$keyRow.setAttribute('hidden', '');
    }
  }

  private async run(): Promise<void> {
    if (this.busy) return;
    const prov = this.providers.get(this.activeProviderId);
    if (!prov) return;
    this.busy = true;
    this.$apply.disabled = true;
    this.setStatus('… generating', 'info');
    const prompt = this.$prompt.value.trim();
    localStorage.setItem(LS_PROMPT, prompt);
    const res = await prov.generate({
      prompt,
      apiKey: this.$apiKey.value.trim() || undefined,
    });
    this.busy = false;
    this.$apply.disabled = false;
    if (!res.ok) {
      this.setStatus(`✗ ${res.error}`, 'err');
      return;
    }
    this.setStatus(`✓ applied · ${res.source}`, 'ok');
    this.opts.onApply(res.spec);
  }

  private setStatus(text: string, kind: 'info' | 'ok' | 'err'): void {
    this.$status.textContent = text;
    this.$status.className = `gen-status k-${kind}`;
  }
}
