/**
 * Telemetry — time-series data collector.
 *
 * Caller registers a set of series (depth, NDL, GF99, tank pressure …)
 * and pushes samples each frame (or on a throttled tick). The collector
 * keeps a bounded window of samples per series.
 *
 * Performance notes
 * -----------------
 * • Pruning uses a `startIdx` pointer rather than `Array.shift()` so it's
 *   O(1) per record() call instead of O(N) — critical at 2 Hz × ~13 series
 *   over a 10-minute window.
 * • The buffer is compacted (sliced down to live samples) only when the
 *   wasted prefix grows above COMPACT_THRESHOLD, so it stays bounded.
 * • There is also a HARD per-series cap (`maxSamples`) that drops the
 *   oldest live samples if a misbehaving caller floods record(). Belt
 *   AND braces: the time window normally bounds memory, but the cap
 *   protects against runaway accumulation if a series is recorded much
 *   faster than expected.
 * • Consumers read the raw `samples` array plus `startIdx`; they iterate
 *   inline (no Array.slice / intermediate copies).
 */

export interface SeriesConfig {
  /** Stable id used by record() and the panel. */
  id: string;
  /** Display label shown in the panel. */
  label: string;
  /** Display unit appended to the latest value (e.g. 'm', 'min'). */
  unit?: string;
  /** Override the auto-allocated colour (CSS string). */
  color?: string;
  /** Fixed y-range; if omitted, the chart auto-scales to the visible window. */
  yRange?: [number, number];
  /** Decimal places to show in the latest-value readout. */
  precision?: number;
}

export interface Sample {
  /** Timestamp in ms (performance.now() domain). */
  t: number;
  /** Recorded value. NaN/Infinity are dropped by record(). */
  v: number;
}

/**
 * Live view into one series. The valid range is
 * `[startIdx, samples.length)` — anything before startIdx is dead but not
 * yet compacted. Treat samples as read-only.
 */
export interface SeriesView {
  cfg: SeriesConfig;
  samples: ReadonlyArray<Sample>;
  startIdx: number;
}

/** Compact when the dead prefix grows past this many samples. */
const COMPACT_THRESHOLD = 4096;

/**
 * Hard upper bound on live samples per series. At 2 Hz × 10 min = 1200
 * samples, so 4096 leaves a 3× safety margin if a series is pushed faster
 * than expected. When exceeded, the oldest live samples are dropped (we
 * advance startIdx) so memory stays bounded even if the time-window prune
 * isn't keeping up.
 */
const DEFAULT_MAX_SAMPLES = 4096;

interface SeriesStore {
  cfg: SeriesConfig;
  samples: Sample[];
  startIdx: number;
}

export class Telemetry {
  private series = new Map<string, SeriesStore>();

  /** Window length in ms. Samples older than this are pruned on record(). */
  windowMs: number;
  /** Hard cap on live samples per series — drops oldest if exceeded. */
  maxSamples: number;

  constructor(windowMs: number = 10 * 60 * 1000, maxSamples: number = DEFAULT_MAX_SAMPLES) {
    this.windowMs = windowMs;
    this.maxSamples = Math.max(16, maxSamples);
  }

  /** Register a new series. No-op if already registered. */
  registerSeries(cfg: SeriesConfig): void {
    if (this.series.has(cfg.id)) return;
    this.series.set(cfg.id, { cfg, samples: [], startIdx: 0 });
  }

  /**
   * Push a sample. NaN/Infinity values are silently dropped.
   *
   * Pruning advances `startIdx` past out-of-window samples (O(1) amortised
   * — typically just one ++ per call once the window is full). The buffer
   * is compacted lazily, and a hard `maxSamples` cap guarantees boundedness.
   */
  record(id: string, value: number, tMs: number = performance.now()): void {
    if (!Number.isFinite(value)) return;
    const s = this.series.get(id);
    if (!s) return;
    s.samples.push({ t: tMs, v: value });

    const cutoff = tMs - this.windowMs;
    while (s.startIdx < s.samples.length && s.samples[s.startIdx].t < cutoff) {
      s.startIdx++;
    }

    // Hard cap: if live samples exceed maxSamples, advance startIdx to drop
    // the oldest. Belt for the braces of the time-window prune above.
    let live = s.samples.length - s.startIdx;
    if (live > this.maxSamples) {
      s.startIdx += live - this.maxSamples;
      live = this.maxSamples;
    }

    // Lazy compaction — only when the wasted prefix grows large. Cuts memory
    // without doing the slice on every call.
    if (s.startIdx >= COMPACT_THRESHOLD) {
      s.samples = s.samples.slice(s.startIdx);
      s.startIdx = 0;
    }
  }

  /**
   * Get a live view of one series. Returns the underlying buffer + startIdx
   * — callers iterate from `startIdx` to `samples.length - 1`. Treat
   * `samples` as read-only.
   */
  getSeries(id: string): SeriesView | undefined {
    const s = this.series.get(id);
    if (!s) return undefined;
    return { cfg: s.cfg, samples: s.samples, startIdx: s.startIdx };
  }

  /** All registered series in registration order. */
  list(): SeriesConfig[] {
    const out: SeriesConfig[] = [];
    for (const v of this.series.values()) out.push(v.cfg);
    return out;
  }

  /** Drop all samples (keeps registrations). */
  reset(): void {
    for (const v of this.series.values()) {
      v.samples.length = 0;
      v.startIdx = 0;
    }
  }
}
