/**
 * DepthHoldMissionRunner — implements the "hover at depth X ±Y for N s"
 * mission. Accumulates on-target time monotonically (off-target time
 * doesn't decrement, mirroring the legacy HOLD SCORE behaviour) and
 * marks complete when `durationS` is reached.
 */

import type { SimState } from '../state';
import type {
  DepthHoldMission,
  Mission,
  MissionRuntime,
  MissionStatus,
} from './types';

export class DepthHoldMissionRunner implements Mission {
  readonly spec: DepthHoldMission;
  private onTargetS = 0;
  private status: MissionStatus = 'active';

  constructor(spec: DepthHoldMission) {
    this.spec = spec;
  }

  reset(): void {
    this.onTargetS = 0;
    this.status = 'active';
  }

  update(state: SimState, dt: number): MissionRuntime {
    if (this.status !== 'active') return this.snapshot();
    const dev = state.depth - this.spec.targetDepth_m;
    const onTarget = Math.abs(dev) <= this.spec.tolerance_m;
    if (onTarget) {
      this.onTargetS = Math.min(this.spec.durationS, this.onTargetS + dt);
      if (this.onTargetS >= this.spec.durationS) this.status = 'complete';
    }
    return this.snapshot();
  }

  snapshot(): MissionRuntime {
    const progress = Math.max(0, Math.min(1, this.onTargetS / this.spec.durationS));
    const targetStr = this.spec.targetDepth_m.toFixed(1);
    const tolStr = this.spec.tolerance_m.toFixed(1);
    const onStr = this.onTargetS.toFixed(1);
    const totalStr = this.spec.durationS.toFixed(0);
    return {
      spec: this.spec,
      progress,
      status: this.status,
      hudLine: `${targetStr} m ±${tolStr} · ${onStr} / ${totalStr} s`,
      hudHint: this.status === 'complete'
        ? '✓ COMPLETE'
        : undefined,
    };
  }
}
