import { Container, Graphics } from 'pixi.js';
import type { SimState } from '../state';
import type { CollisionRect, DepthLimits, HazardContact, Scene, ZoneInfo } from './types';
import { resolveDepthLimits } from './collision';

/**
 * ShipwreckScene — a partially-buried wreck on a sand bottom around 40 m.
 *
 * Layout (relative to the wreck centre at WRECK_DEPTH_M):
 *
 *      MAST                                        ─── 24 m
 *       │
 *       │
 *      CABIN  ┌──┐                                 ─── 32 m
 *      DECK  ━┷━━┷━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ ─── 36 m
 *      HULL  ┃══════════════════════════════════╗
 *            ┃             cargo                ╗  ─── 40 m
 *      SAND  ╰╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╲╱   ─── 44 m
 *
 * The hull tilts ~6° starboard so it doesn't read as a perfect box.
 * Structural collision (impassable hull / cabin rectangles) is out of scope
 * here — exposed as collider data via `colliders()` for a future physics pass.
 */

/**
 * Length of the wreck along the bottom (m). Smaller than typical real boats
 * so it fits comfortably in the camera view.
 */
const WRECK_LENGTH_M    = 26;
const WRECK_DECK_M      = 36;
const WRECK_KEEL_M      = 42;
const WRECK_MAST_TOP_M  = 24;
const SAND_BASE_M       = 44;
const SAND_AMP_M        = 1.0;
const STRIP_LENGTH_M    = 320;
const SAMPLES_PER_M     = 1;
const WRECK_TILT_RAD    = (6 * Math.PI) / 180;

type WreckCreatureType = 'school' | 'lionfish' | 'eel' | 'grouper' | 'shrimp';

interface WreckCreature {
  depth: number;
  xAlong: number;
  phase: number;
  type: WreckCreatureType;
  litColor: number;
  scale: number;
  hazard?: HazardContact['kind'];
  index: number;
}

export class ShipwreckScene implements Scene {
  readonly id = 'wreck';
  readonly name = 'SHIPWRECK';
  readonly container = new Container();

  private bottomGfx = new Graphics();
  private wreckGfx  = new Graphics();
  private biotaGfx  = new Graphics();
  private sandProfile: number[] = [];
  private creatures: WreckCreature[] = [];

  private w = 0;
  private h = 0;
  private pxPerMeter = 60;

  constructor() {
    this.container.addChild(this.bottomGfx, this.wreckGfx, this.biotaGfx);
    this.buildSandProfile();
    this.buildCreatures();
  }

  resize(w: number, h: number, pxPerMeter: number): void {
    this.w = w;
    this.h = h;
    this.pxPerMeter = pxPerMeter;
  }

  update(
    _state: SimState,
    camTopDepth: number,
    scrollX: number,
    sunLight: number,
    illumination: number
  ): void {
    if (!this.w || !this.h) return;
    const camBotDepth = camTopDepth + this.h / this.pxPerMeter;
    this.drawSandBottom(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
    this.drawWreck(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
    this.drawBiota(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
  }

  /** Impassable rectangles in world frame — used by physics to clamp depth. */
  getColliders(): CollisionRect[] {
    const len = WRECK_LENGTH_M;
    const deck = WRECK_DECK_M;
    const keel = WRECK_KEEL_M;
    const hullH = keel - deck;
    const cx = this.wreckCentreX_m();
    return [
      // Hull body — long horizontal slab.
      {
        centreX_m: cx,
        centreDepth_m: (deck + keel) / 2,
        halfW_m: len / 2,
        halfH_m: hullH / 2,
        rotation: WRECK_TILT_RAD,
      },
      // Cabin — small box on top of deck, slightly forward of centre.
      {
        centreX_m: cx - 1.5,
        centreDepth_m: deck - 2.5,
        halfW_m: 2,
        halfH_m: 2.5,
        rotation: WRECK_TILT_RAD,
      },
      // Mast — a thin vertical pillar from deck up.
      {
        centreX_m: cx - 1.0,
        centreDepth_m: (deck + WRECK_MAST_TOP_M) / 2,
        halfW_m: 0.35,
        halfH_m: (deck - WRECK_MAST_TOP_M) / 2,
        rotation: WRECK_TILT_RAD,
      },
    ];
  }

  /** Depth limits at world x — sand floor below, wreck colliders constrain in between. */
  getDepthLimitsAt(worldX_m: number, currentDepth_m: number = 0): DepthLimits {
    const floor = this.sandDepthAt(worldX_m) - 0.25;
    return resolveDepthLimits(worldX_m, currentDepth_m, floor, 0, this.getColliders());
  }

  /** World-x of the wreck centre, anchored so it sits in the diver's initial view. */
  private wreckCentreX_m(): number {
    // Camera shows roughly [0, screenW / pxPerMeter] in metres at scrollX=0.
    // Default screen width ≈ 16 m → centre ~8 m.
    return Math.max(8, (this.w || 800) / (this.pxPerMeter || 60) * 0.5);
  }

  getHazardContacts(scrollX_m: number, diverDepth_m: number, range_m: number): HazardContact[] {
    const diverWorldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    const out: HazardContact[] = [];
    for (const c of this.creatures) {
      if (!c.hazard) continue;
      let dx = c.xAlong - diverWorldX;
      const half = STRIP_LENGTH_M / 2;
      dx = ((dx + half) % STRIP_LENGTH_M + STRIP_LENGTH_M) % STRIP_LENGTH_M - half;
      const dy = c.depth - diverDepth_m;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist <= range_m) {
        const label = c.type === 'lionfish' ? 'LIONFISH'
                    : c.type === 'eel'      ? 'MORAY EEL'
                    : c.type.toUpperCase();
        out.push({
          kind: c.hazard,
          label,
          id: `${c.hazard}:${c.index}`,
          severity: 1 - dist / range_m,
        });
      }
    }
    return out;
  }

  getBottomDepthAt(scrollX_m: number): number | null {
    const diverWorldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    return this.sandDepthAt(diverWorldX);
  }

  zoneInfoAt(depth: number): ZoneInfo {
    let label: string, zStart: number, zEnd: number, note: string;
    if (depth < WRECK_MAST_TOP_M) {
      label = 'OPEN WATER';
      zStart = 0; zEnd = WRECK_MAST_TOP_M;
      note = 'wreck silhouette below';
    } else if (depth < WRECK_DECK_M) {
      label = 'WRECK SHADOW';
      zStart = WRECK_MAST_TOP_M; zEnd = WRECK_DECK_M;
      note = 'mast + superstructure · pelagics';
    } else if (depth < WRECK_KEEL_M) {
      label = 'HULL';
      zStart = WRECK_DECK_M; zEnd = WRECK_KEEL_M;
      note = 'grouper · lionfish · moray';
    } else {
      label = 'SAND DEBRIS';
      zStart = WRECK_KEEL_M; zEnd = 200;
      note = 'sandy bottom · shrimp · scattered fauna';
    }
    let pop = 0;
    const types = new Set<string>();
    for (const c of this.creatures) {
      if (c.depth >= zStart && c.depth < zEnd) {
        pop += c.type === 'school' ? 8 : 1;
        types.add(c.type);
      }
    }
    return { label, population: pop, variety: types.size, note };
  }

  // ---------------- Sand ----------------

  private buildSandProfile(): void {
    const total = STRIP_LENGTH_M * SAMPLES_PER_M;
    const seed = 2.91;
    for (let i = 0; i < total; i++) {
      const u = i / SAMPLES_PER_M;
      const v =
        0.5 * Math.sin(u * 0.11 + seed) +
        0.3 * Math.sin(u * 0.27 + seed * 1.4) +
        0.2 * Math.sin(u * 0.61 + seed * 2.1);
      this.sandProfile.push(v);
    }
  }

  private sandDepthAt(worldX_m: number): number {
    const u = ((worldX_m % STRIP_LENGTH_M) + STRIP_LENGTH_M) % STRIP_LENGTH_M;
    const idx = Math.floor(u * SAMPLES_PER_M) % this.sandProfile.length;
    return SAND_BASE_M + this.sandProfile[idx] * SAND_AMP_M;
  }

  private drawSandBottom(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sun: number,
    _ill: number
  ): void {
    this.bottomGfx.clear();
    if (camBotDepth < SAND_BASE_M - SAND_AMP_M - 1) return;
    const samples = Math.max(40, Math.ceil(this.w / 12));
    const dx = this.w / samples;
    const pts: number[] = [];
    pts.push(0, this.h + 10);
    for (let i = 0; i <= samples; i++) {
      const px = i * dx;
      const worldX = scrollX + px / this.pxPerMeter;
      const sd = this.sandDepthAt(worldX);
      pts.push(px, (sd - camTopDepth) * this.pxPerMeter);
    }
    pts.push(this.w, this.h + 10);
    // Slightly cooler sand than the coral scene — silty, low-light habitat.
    this.bottomGfx.poly(pts).fill({ color: 0x6c5a44, alpha: 0.97 });

    // Scatter of rocks/debris dots along the bottom for texture.
    const rand = mulberry32(0x5ed1ed);
    for (let i = 0; i < samples; i += 3) {
      const px = i * dx + rand() * dx;
      const worldX = scrollX + px / this.pxPerMeter;
      const sd = this.sandDepthAt(worldX);
      const py = (sd - camTopDepth) * this.pxPerMeter;
      const r = 0.6 + rand() * 1.4;
      this.bottomGfx.circle(px, py + r * 0.6, r).fill({ color: 0x4d4030, alpha: 0.7 });
    }
  }

  // ---------------- Wreck ----------------

  private drawWreck(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sun: number,
    _ill: number
  ): void {
    const g = this.wreckGfx;
    g.clear();
    if (camBotDepth < WRECK_MAST_TOP_M - 1 || camTopDepth > WRECK_KEEL_M + 2) return;

    // Local-to-screen transform helpers — rotate the wreck slightly so it
    // reads as listed on the bottom.
    const cx = this.wreckCentreX_m();
    const cd = (WRECK_DECK_M + WRECK_KEEL_M) / 2;
    const cos = Math.cos(WRECK_TILT_RAD);
    const sin = Math.sin(WRECK_TILT_RAD);

    const toScreen = (worldX: number, worldDepth: number): [number, number] => {
      // Translate so wreck centre is origin, rotate, translate back.
      const lx = worldX - cx;
      const ly = (worldDepth - cd) * 1; // depth axis points down in world coords
      const rx = lx * cos - ly * sin;
      const ry = lx * sin + ly * cos;
      const wx = rx + cx;
      const wd = ry + cd;
      // Then translate to screen by scrollX + camTopDepth.
      const sx = (wx - scrollX) * this.pxPerMeter;
      const sy = (wd - camTopDepth) * this.pxPerMeter;
      return [sx, sy];
    };

    // Hull silhouette — boat-shaped polygon.
    const halfLen = WRECK_LENGTH_M / 2;
    const deck = WRECK_DECK_M;
    const keel = WRECK_KEEL_M;
    const bowOverhang = 6;  // bow is more rounded than stern
    const sternOverhang = 4;
    const hullPts: number[] = [];
    const push = (worldX: number, worldDepth: number): void => {
      const [sx, sy] = toScreen(worldX, worldDepth);
      hullPts.push(sx, sy);
    };
    push(cx - halfLen + 2, deck);              // upper stern
    push(cx - halfLen + sternOverhang, deck - 1);
    push(cx + halfLen - bowOverhang, deck - 0.5);
    push(cx + halfLen, deck);                  // upper bow
    push(cx + halfLen - 1.5, deck + 1);
    push(cx + halfLen - 4, keel - 1);          // bow underside
    push(cx + halfLen - 14, keel);             // keel forward
    push(cx - halfLen + 12, keel);             // keel aft
    push(cx - halfLen + 5, keel - 1.5);
    push(cx - halfLen + 1, deck + 1);          // stern down
    g.poly(hullPts).fill({ color: 0x222a30, alpha: 0.96 });
    // Hull plating highlight.
    g.poly(hullPts).stroke({ color: 0x3a4651, alpha: 0.55, width: 1 });

    // Deck stripe (a slightly lighter horizontal line just under the deck).
    const [dx0, dy0] = toScreen(cx - halfLen + 6,   deck + 0.3);
    const [dx1, dy1] = toScreen(cx + halfLen - 8,   deck + 0.3);
    g.moveTo(dx0, dy0).lineTo(dx1, dy1).stroke({ color: 0x3d4b56, alpha: 0.5, width: 2 });

    // Cabin — squarish box on top of deck, slightly forward of midship.
    const cabin: [number, number][] = [
      [cx - 8, deck - 5], [cx, deck - 5],
      [cx, deck], [cx - 8, deck],
    ];
    const cabPts: number[] = [];
    for (const [x, d] of cabin) {
      const [sx, sy] = toScreen(x, d);
      cabPts.push(sx, sy);
    }
    g.poly(cabPts).fill({ color: 0x2a323a, alpha: 0.97 });
    // Cabin window row — three tiny squares.
    for (let i = 0; i < 3; i++) {
      const wx = cx - 7 + i * 2.4;
      const wd = deck - 3.5;
      const [sx, sy] = toScreen(wx, wd);
      g.rect(sx - 1, sy - 1, 2, 2).fill({ color: 0xffc764, alpha: 0.55 });
    }

    // Mast — thin pillar from cabin top up to MAST_TOP.
    const [mx0, my0] = toScreen(cx - 3, deck);
    const [mx1, my1] = toScreen(cx - 3, WRECK_MAST_TOP_M);
    g.moveTo(mx0, my0).lineTo(mx1, my1).stroke({ color: 0x18202a, alpha: 0.92, width: 3 });
    // Crow's nest blob near the mast top.
    g.circle(mx1, my1, 3).fill({ color: 0x1c252e, alpha: 0.92 });

    // Cargo-hold opening — dark rectangle in the middle of the deck.
    const holdX0 = cx - 4, holdX1 = cx + 6;
    const [hx0, hy0] = toScreen(holdX0, deck);
    const [hx1, hy1] = toScreen(holdX1, deck + 4);
    g.rect(Math.min(hx0, hx1), Math.min(hy0, hy1), Math.abs(hx1 - hx0), Math.abs(hy1 - hy0))
      .fill({ color: 0x05080a, alpha: 0.92 });

    // Rust streaks running down the hull from the deck.
    for (let i = 0; i < 6; i++) {
      const wx = cx - halfLen + 10 + i * 12;
      const [rsx0, rsy0] = toScreen(wx, deck + 0.5);
      const [rsx1, rsy1] = toScreen(wx + 1.5, deck + 4);
      g.moveTo(rsx0, rsy0).lineTo(rsx1, rsy1)
        .stroke({ color: 0x6a3a22, alpha: 0.45, width: 1.2 });
    }
  }

  // ---------------- Biota ----------------

  private buildCreatures(): void {
    const rand = mulberry32(0x5eaf1ee7);
    const push = (
      type: WreckCreatureType,
      count: number,
      depthRange: [number, number],
      xRange: [number, number],
      colorPool: number[],
      scaleRange: [number, number],
      hazard?: HazardContact['kind'],
    ) => {
      for (let i = 0; i < count; i++) {
        this.creatures.push({
          depth: depthRange[0] + rand() * (depthRange[1] - depthRange[0]),
          xAlong: xRange[0] + rand() * (xRange[1] - xRange[0]),
          phase: rand() * Math.PI * 2,
          type,
          litColor: colorPool[Math.floor(rand() * colorPool.length)],
          scale: scaleRange[0] + rand() * (scaleRange[1] - scaleRange[0]),
          hazard,
          index: this.creatures.length,
        });
      }
    };

    // Open-water schools above the wreck (sweepers, baitfish).
    push('school',   6, [WRECK_MAST_TOP_M - 4, WRECK_DECK_M], [10, STRIP_LENGTH_M - 10],
         [0x7eb6d4, 0xa6d6e8], [0.7, 1.0]);

    // Lionfish around the wreck — venomous spines.
    push('lionfish', 5, [WRECK_DECK_M, WRECK_KEEL_M + 1], [0, STRIP_LENGTH_M],
         [0xd96b3a, 0xc05225, 0xe09148], [0.9, 1.4], 'venomous');

    // Moray eels peeking out of hull openings — bite hazard.
    push('eel',      3, [WRECK_DECK_M + 1.5, WRECK_KEEL_M - 1], [0, STRIP_LENGTH_M],
         [0x6e7a4e, 0x8a8a55], [1.0, 1.4], 'venomous');

    // Grouper hanging near the cargo hold.
    push('grouper',  4, [WRECK_DECK_M + 2, WRECK_KEEL_M + 2], [0, STRIP_LENGTH_M],
         [0x6e503c, 0x836047, 0x55402f], [1.4, 2.0]);

    // Shrimp / small fauna on the sand around the wreck.
    push('shrimp',  10, [SAND_BASE_M - 1, SAND_BASE_M],
         [10, STRIP_LENGTH_M - 10],
         [0xd6a07a, 0xa07a5a], [0.5, 0.8]);
  }

  private drawBiota(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sun: number,
    _ill: number
  ): void {
    const g = this.biotaGfx;
    g.clear();
    const t = performance.now() * 0.001;

    for (const c of this.creatures) {
      const u = (c.xAlong - scrollX) % STRIP_LENGTH_M;
      const uMod = ((u % STRIP_LENGTH_M) + STRIP_LENGTH_M) % STRIP_LENGTH_M;
      const x = uMod * this.pxPerMeter;
      const screenX = x % this.w;
      if (screenX < -60 || screenX > this.w + 60) continue;
      const effDepth = c.depth + Math.sin(t * 0.6 + c.phase) * 0.4;
      if (effDepth < camTopDepth - 1 || effDepth > camBotDepth + 1) continue;
      const y = (effDepth - camTopDepth) * this.pxPerMeter;
      const color = c.litColor;
      const alpha = 0.94;
      const phase = c.phase + t;

      switch (c.type) {
        case 'school': {
          const n = 10;
          for (let i = 0; i < n; i++) {
            const a = i * 0.65 + phase;
            const fx = screenX + Math.cos(a) * 18 * c.scale;
            const fy = y + Math.sin(a * 1.3) * 9 * c.scale;
            const s = 2.4 * c.scale;
            g.poly([fx - s, fy, fx + s, fy - s * 0.6, fx + s, fy + s * 0.6])
              .fill({ color, alpha });
          }
          break;
        }
        case 'lionfish': {
          // Spiky-fin body — instantly recognisable + telegraphs "hazard".
          const w = 16 * c.scale, h2 = 5 * c.scale;
          const dir = Math.sin(phase * 0.5) > 0 ? 1 : -1;
          // Body
          g.ellipse(screenX, y, w * 0.5, h2 * 0.9).fill({ color, alpha });
          // Long radiating spines
          const spines = 7;
          for (let i = 0; i < spines; i++) {
            const a = -Math.PI / 2 + (i / (spines - 1)) * Math.PI;
            const sx = screenX + Math.cos(a) * w * 0.7;
            const sy = y + Math.sin(a) * h2 * 2.6;
            g.moveTo(screenX, y).lineTo(sx, sy)
              .stroke({ color: 0xffe6b0, alpha: alpha * 0.65, width: 1.1 });
          }
          // Tail
          g.poly([
            screenX + (w * 0.5) * dir, y,
            screenX + (w * 0.5 + h2 * 1.2) * dir, y - h2,
            screenX + (w * 0.5 + h2 * 1.2) * dir, y + h2,
          ]).fill({ color, alpha: alpha * 0.85 });
          break;
        }
        case 'eel': {
          // Long sinuous body — undulates with phase.
          const len = 24 * c.scale;
          const segs = 8;
          for (let i = 0; i < segs; i++) {
            const u2 = i / (segs - 1);
            const xx = screenX - len / 2 + u2 * len;
            const yy = y + Math.sin(u2 * Math.PI * 2 + phase) * 3 * c.scale;
            const r = (1.0 - Math.abs(u2 - 0.5) * 1.6) * 2.6 * c.scale;
            g.circle(xx, yy, Math.max(1, r)).fill({ color, alpha });
          }
          break;
        }
        case 'grouper': {
          const w = 24 * c.scale, h2 = 8 * c.scale;
          const dir = Math.sin(phase * 0.3) > 0 ? 1 : -1;
          g.poly([
            screenX - (w * 0.45) * dir, y,
            screenX - (w * 0.1) * dir,  y - h2 * 0.9,
            screenX + (w * 0.5) * dir,  y,
            screenX - (w * 0.1) * dir,  y + h2 * 0.9,
          ]).fill({ color, alpha });
          g.rect(screenX - w * 0.35 * dir, y - h2 * 0.7, w * 0.55, 2)
            .fill({ color: 0x2c1f15, alpha: 0.45 });
          break;
        }
        case 'shrimp': {
          // Tiny curved sliver.
          const r = 2.5 * c.scale;
          g.ellipse(screenX, y, r * 1.6, r * 0.6).fill({ color, alpha });
          g.moveTo(screenX - r, y).lineTo(screenX - r * 2, y - r * 1.2)
            .stroke({ color, alpha: alpha * 0.8, width: 0.7 });
          break;
        }
      }
    }
  }
}

// ---- helpers ----

function mulberry32(seed: number) {
  let s = seed | 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
