/**
 * Menu controller — drives the Perdix-style menu tree.
 *
 * Manual §11 lists the hierarchy: top-level items (Turn Off, Select Gas, Dive
 * Setup, Dive Log, System Setup) plus several layers of submenus. The MENU
 * button advances within the current level (with wrap), SELECT drills into
 * a submenu or commits a leaf, and reaching the synthetic "← BACK" item +
 * SELECT pops the stack.
 *
 * Leaves can either be data-only (placeholder for not-yet-built screens) or
 * dispatch a side-effect via the host callbacks (`onSwitchGas`, `onEndDive`).
 */

import type { Perdix2ButtonId } from './buttons';

export interface MenuLeaf {
  kind: 'leaf';
  id: string;
  label: string;
  /** Discriminator for side-effects; null for placeholder leaves. */
  action: 'end-dive' | 'switch-gas' | 'back' | 'noop';
  /** When action='switch-gas', the rig slotId this leaf maps to. */
  slotId?: string;
  /** Human-readable hint shown after a placeholder leaf is activated. */
  placeholderText?: string;
}

export interface MenuBranch {
  kind: 'branch';
  id: string;
  label: string;
  /** Resolver — invoked each time the user enters the branch so dynamic
   *  data (tanks, gases) is fresh. */
  children: () => MenuItem[];
}

export type MenuItem = MenuLeaf | MenuBranch;

export interface MenuHost {
  /** Currently-known rig tanks (used to populate SELECT GAS dynamically). */
  rigTanks: () => { slotId: string; slotLabel: string; gasName: string; isActive: boolean }[];
  /** Switch the regulator to the given slot. */
  onSwitchGas?: (slotId: string) => void;
  /** End-dive shortcut (manual §11.2). */
  onEndDive?: () => void;
  /** Short banner for placeholder leaves and "MOD warning"-style feedback. */
  notify?: (text: string, kind?: 'info' | 'warn' | 'danger') => void;
}

/** Action returned from `press()`; the watch acts on it. */
export type MenuPressResult =
  | { kind: 'stay' }
  | { kind: 'exit' }     // close menu, back to dive-main
  | { kind: 'redraw' };  // refresh menu DOM (e.g., depth, dive setup tree)

export class MenuController {
  private host: MenuHost;
  /** Stack of branches the user has descended into. Always non-empty. */
  private stack: MenuBranch[] = [];
  private indices: number[] = [];
  private currentChildren: MenuItem[] = [];

  constructor(host: MenuHost) {
    this.host = host;
    this.reset();
  }

  /** Reset to root, called on every menu-open. */
  reset(): void {
    this.stack = [rootMenu(this.host)];
    this.indices = [0];
    this.refreshChildren();
  }

  /** Stack depth — 1 means at root. */
  get depth(): number {
    return this.stack.length;
  }

  get currentNode(): MenuBranch {
    return this.stack[this.stack.length - 1];
  }

  get currentIndex(): number {
    return this.indices[this.indices.length - 1];
  }

  get items(): MenuItem[] {
    return this.currentChildren;
  }

  /** Title shown at the top of the menu page. */
  get title(): string {
    return this.currentNode.label.toUpperCase();
  }

  press(btn: Perdix2ButtonId): MenuPressResult {
    if (btn === 'MENU') {
      const len = this.currentChildren.length;
      if (len > 0) {
        const i = (this.currentIndex + 1) % len;
        this.indices[this.indices.length - 1] = i;
      }
      return { kind: 'redraw' };
    }
    if (btn === 'SELECT') {
      const sel = this.currentChildren[this.currentIndex];
      if (!sel) return { kind: 'stay' };
      if (sel.kind === 'branch') {
        this.stack.push(sel);
        this.indices.push(0);
        this.refreshChildren();
        return { kind: 'redraw' };
      }
      return this.activateLeaf(sel);
    }
    return { kind: 'stay' };
  }

  private activateLeaf(leaf: MenuLeaf): MenuPressResult {
    switch (leaf.action) {
      case 'back': {
        if (this.stack.length > 1) {
          this.stack.pop();
          this.indices.pop();
          this.refreshChildren();
          return { kind: 'redraw' };
        }
        return { kind: 'exit' };
      }
      case 'end-dive': {
        this.host.onEndDive?.();
        this.host.notify?.('END DIVE — surface interval started', 'info');
        return { kind: 'exit' };
      }
      case 'switch-gas': {
        if (leaf.slotId) this.host.onSwitchGas?.(leaf.slotId);
        return { kind: 'exit' };
      }
      case 'noop':
      default: {
        if (leaf.placeholderText) this.host.notify?.(leaf.placeholderText, 'info');
        return { kind: 'stay' };
      }
    }
  }

  private refreshChildren(): void {
    this.currentChildren = this.currentNode.children();
    // Clamp index in case dynamic children shrank.
    const len = this.currentChildren.length;
    if (this.currentIndex >= len) {
      this.indices[this.indices.length - 1] = Math.max(0, len - 1);
    }
  }
}

// ---- Menu tree definition --------------------------------------------------

function back(): MenuLeaf {
  return { kind: 'leaf', id: 'back', label: '← BACK', action: 'back' };
}
function placeholder(id: string, label: string, hint: string): MenuLeaf {
  return { kind: 'leaf', id, label, action: 'noop', placeholderText: hint };
}

function rootMenu(host: MenuHost): MenuBranch {
  return {
    kind: 'branch',
    id: 'root',
    label: 'MAIN MENU',
    children: () => [
      { kind: 'leaf', id: 'end-dive', label: 'END DIVE', action: 'end-dive' },
      selectGasBranch(host),
      diveSetupBranch(),
      diveLogBranch(),
      systemSetupBranch(),
    ],
  };
}

function selectGasBranch(host: MenuHost): MenuBranch {
  return {
    kind: 'branch',
    id: 'select-gas',
    label: 'SELECT GAS',
    children: () => {
      const tanks = host.rigTanks();
      const items: MenuItem[] = [back()];
      for (const t of tanks) {
        items.push({
          kind: 'leaf',
          id: `gas:${t.slotId}`,
          label: `${t.isActive ? '● ' : '  '}${t.slotLabel} · ${t.gasName}`,
          action: 'switch-gas',
          slotId: t.slotId,
        });
      }
      return items;
    },
  };
}

function diveSetupBranch(): MenuBranch {
  return {
    kind: 'branch',
    id: 'dive-setup',
    label: 'DIVE SETUP',
    children: () => [
      back(),
      placeholder('define-gas',  'DEFINE GAS',  'Edit from gear modal (G key) — coming to menu later.'),
      placeholder('ndl-planner', 'NDL PLANNER', 'NDL planner not yet implemented.'),
      placeholder('deco-planner','DECO PLANNER','Deco planner not yet implemented.'),
    ],
  };
}

function diveLogBranch(): MenuBranch {
  return {
    kind: 'branch',
    id: 'dive-log',
    label: 'DIVE LOG',
    children: () => [
      back(),
      placeholder('last',     'LAST DIVE',    'Dive log not yet recorded.'),
      placeholder('all-logs', 'ALL LOGS',     'Dive log not yet recorded.'),
    ],
  };
}

function systemSetupBranch(): MenuBranch {
  return {
    kind: 'branch',
    id: 'system-setup',
    label: 'SYSTEM SETUP',
    children: () => [
      back(),
      placeholder('mode',       'MODE SETUP',    'Mode setup not yet implemented.'),
      placeholder('deco',       'DECO SETUP',    'Adjust GF from the gear modal.'),
      placeholder('bottom-row', 'BOTTOM ROW',    'Bottom-row config not yet implemented.'),
      placeholder('display',    'DISPLAY SETUP', 'Display config not yet implemented.'),
      placeholder('compass',    'COMPASS',       'Compass interface not yet wired.'),
    ],
  };
}
