/**
 * Collision helpers — rotated AABB intersection in the diver's vertical
 * axis. Diver movement is one-dimensional (depth only; horizontal is the
 * scene scrolling past) so we collapse 2-D rectangles down to a depth
 * interval at the diver's current worldX and let physics clamp to that.
 */

import type { CollisionRect, DepthLimits } from './types';

/**
 * Returns the depth interval [dmin, dmax] that a rotated rect occupies at
 * the vertical line x = worldX_m, or `null` if the rect doesn't reach
 * that x at all.
 *
 * Math
 * ----
 * In the rect's local frame the rect is axis-aligned with extents
 * [-halfW, halfW] × [-halfH, halfH]. A world point (worldX, depth) maps
 * to a local point (lx, ly) by:
 *   dx = worldX - centreX_m;  dy = depth - centreDepth_m
 *   lx =  dx·cosθ + dy·sinθ
 *   ly = -dx·sinθ + dy·cosθ
 *
 * Parametrising by t = depth - centreDepth_m and varying t over all
 * depths gives a pair of linear equations in t. The rect contains the
 * point iff both |lx(t)| ≤ halfW and |ly(t)| ≤ halfH, which intersects
 * into a single t-interval (possibly empty). We then add centreDepth_m
 * back to recover depth.
 */
export function rectDepthInterval(
  rect: CollisionRect,
  worldX_m: number,
): [number, number] | null {
  const dx = worldX_m - rect.centreX_m;
  const c = Math.cos(rect.rotation);
  const s = Math.sin(rect.rotation);

  // Constraint 1: -halfW ≤ dx·c + t·s ≤ halfW
  let t1_lo: number, t1_hi: number;
  const a1 = s;
  const c1 = dx * c;
  if (Math.abs(a1) < 1e-9) {
    if (c1 < -rect.halfW_m - 1e-9 || c1 > rect.halfW_m + 1e-9) return null;
    t1_lo = -Infinity;
    t1_hi = Infinity;
  } else {
    const lo = (-rect.halfW_m - c1) / a1;
    const hi = ( rect.halfW_m - c1) / a1;
    t1_lo = Math.min(lo, hi);
    t1_hi = Math.max(lo, hi);
  }

  // Constraint 2: -halfH ≤ -dx·s + t·c ≤ halfH
  let t2_lo: number, t2_hi: number;
  const a2 = c;
  const c2 = -dx * s;
  if (Math.abs(a2) < 1e-9) {
    if (c2 < -rect.halfH_m - 1e-9 || c2 > rect.halfH_m + 1e-9) return null;
    t2_lo = -Infinity;
    t2_hi = Infinity;
  } else {
    const lo = (-rect.halfH_m - c2) / a2;
    const hi = ( rect.halfH_m - c2) / a2;
    t2_lo = Math.min(lo, hi);
    t2_hi = Math.max(lo, hi);
  }

  const tLo = Math.max(t1_lo, t2_lo);
  const tHi = Math.min(t1_hi, t2_hi);
  if (tLo > tHi) return null;
  return [rect.centreDepth_m + tLo, rect.centreDepth_m + tHi];
}

/**
 * Combine raw bottom + ceiling + rotated colliders into a single depth-axis
 * window the diver may occupy. `currentDepth_m` is used to decide which
 * side of an intersected collider becomes a wall:
 *   • collider entirely above diver → raises the ceiling
 *   • collider entirely below diver → lowers the floor
 *   • diver inside the collider     → eject toward whichever side is nearer
 */
export function resolveDepthLimits(
  worldX_m: number,
  currentDepth_m: number,
  rawFloor_m: number,
  rawCeiling_m: number,
  colliders: ReadonlyArray<CollisionRect>,
): DepthLimits {
  let floor = rawFloor_m;
  let ceiling = rawCeiling_m;
  for (const rect of colliders) {
    const iv = rectDepthInterval(rect, worldX_m);
    if (!iv) continue;
    const [dmin, dmax] = iv;
    if (dmax <= currentDepth_m + 1e-3) {
      // Rect is above diver — its bottom edge is a ceiling.
      if (dmax > ceiling) ceiling = dmax;
    } else if (dmin >= currentDepth_m - 1e-3) {
      // Rect is below diver — its top edge is a floor.
      if (dmin < floor) floor = dmin;
    } else {
      // Diver is inside — eject toward the nearer edge.
      if (currentDepth_m - dmin < dmax - currentDepth_m) {
        if (dmin < floor) floor = dmin;
      } else {
        if (dmax > ceiling) ceiling = dmax;
      }
    }
  }
  if (ceiling > floor) ceiling = floor;  // degenerate; pinned.
  return { floor_m: floor, ceiling_m: ceiling };
}
