/**
 * TelemetryPanel — draggable debug overlay that visualises Telemetry series.
 *
 * Series are shown as a chip strip up top (click a chip to add/remove the
 * series from the chart stack). Each visible series renders as a small SVG
 * line chart with the latest value alongside the label.
 *
 * Hidden by default; toggled by main.ts (`T` keybinding). All visual state
 * — geometry, visibility, active-series set — persists to localStorage.
 */

import './telemetry.css';
import { Telemetry, type SeriesConfig, type Sample, type SeriesView } from './Telemetry';

const STORAGE_PREFIX = 'ppb_telem_';
const GEO_KEY = STORAGE_PREFIX + 'geo';
const VIS_KEY = STORAGE_PREFIX + 'visible';
const ACTIVE_KEY = STORAGE_PREFIX + 'series';
const WINDOW_KEY = STORAGE_PREFIX + 'window';

/** Display window choices (ms). Collector still holds 10 min total. */
const WINDOW_CHOICES_MS: Record<string, number> = {
  '30s':  30_000,
  '1m':   60_000,
  '2m':  120_000,
  '5m':  300_000,
  '10m': 600_000,
};
const DEFAULT_WINDOW_KEY = '2m';
/** Hard cap on points per polyline — keeps SVG paths tractable even at 10 m / 10 Hz. */
const MAX_POINTS_PER_SERIES = 240;

/** Default series shown on first run. Others can be added via the toggle strip. */
const DEFAULT_ACTIVE = ['depth', 'ndl', 'gf99', 'density'];

const PALETTE = [
  '#38d6e6', '#ff5b9a', '#ffb547', '#6ee29a', '#a279ff',
  '#ff8a5b', '#7adfff', '#ffe066', '#ff4a4a', '#4be0e8',
];

interface Geometry { left: number; top: number; width: number }

export class TelemetryPanel {
  readonly root: HTMLElement;
  private telemetry: Telemetry;
  private geo: Geometry;
  private active = new Set<string>();
  private chartsHost!: HTMLElement;
  private togglesHost!: HTMLElement;
  private colorByIndex = new Map<string, string>();
  private renderEveryMs = 200;   // 5 Hz redraw cap
  private lastRenderMs = 0;
  private windowKey: string = DEFAULT_WINDOW_KEY;
  private windowMs: number = WINDOW_CHOICES_MS[DEFAULT_WINDOW_KEY];

  constructor(telemetry: Telemetry) {
    this.telemetry = telemetry;
    this.geo = this.loadGeo() ?? this.defaultGeo();
    this.active = this.loadActive();
    const savedWindow = this.loadWindowKey();
    if (savedWindow && WINDOW_CHOICES_MS[savedWindow] !== undefined) {
      this.windowKey = savedWindow;
      this.windowMs = WINDOW_CHOICES_MS[savedWindow];
    }

    this.root = document.createElement('div');
    this.root.className = 'dc-telem';
    const windowOptions = Object.keys(WINDOW_CHOICES_MS)
      .map((k) => `<option value="${k}" ${k === this.windowKey ? 'selected' : ''}>${k}</option>`)
      .join('');
    this.root.innerHTML = /*html*/ `
      <div class="dc-telem-head">
        <span class="dc-telem-title">TELEMETRY</span>
        <div class="dc-telem-actions">
          <label class="dc-telem-window">
            <span>win</span>
            <select data-bind="window">${windowOptions}</select>
          </label>
          <button class="dc-telem-btn" type="button" data-act="clear" title="clear">⟲</button>
          <button class="dc-telem-btn" type="button" data-act="close" title="hide">✕</button>
        </div>
      </div>
      <div class="dc-telem-toggles" data-bind="toggles"></div>
      <div class="dc-telem-charts" data-bind="charts"></div>
    `;
    document.body.appendChild(this.root);

    this.togglesHost = this.root.querySelector('[data-bind="toggles"]') as HTMLElement;
    this.chartsHost = this.root.querySelector('[data-bind="charts"]') as HTMLElement;
    const winSel = this.root.querySelector('[data-bind="window"]') as HTMLSelectElement;
    winSel.addEventListener('change', () => {
      const k = winSel.value;
      if (WINDOW_CHOICES_MS[k] !== undefined) {
        this.windowKey = k;
        this.windowMs = WINDOW_CHOICES_MS[k];
        this.saveWindowKey();
        this.renderChart();
      }
    });

    this.applyGeometry();
    this.bindDrag();
    this.bindActions();

    if (this.loadVisible()) this.show();
    else this.hide();

    // First-time setup: ensure default series are active and registered before
    // chips render. If the registrar hasn't called registerSeries yet, the
    // chip list will be empty until rebuildToggles() is called externally.
    this.rebuildToggles();
  }

  // ---- Public API ----

  show(): void {
    this.root.classList.add('is-visible');
    try { localStorage.setItem(VIS_KEY, 'true'); } catch { /* quota */ }
    // Build charts on first show in case toggles were registered after hide.
    this.rebuildCharts();
  }

  hide(): void {
    this.root.classList.remove('is-visible');
    try { localStorage.setItem(VIS_KEY, 'false'); } catch { /* quota */ }
  }

  toggle(): void {
    if (this.root.classList.contains('is-visible')) this.hide();
    else this.show();
  }

  isVisible(): boolean {
    return this.root.classList.contains('is-visible');
  }

  /** Called whenever the registrar has finished registering series. */
  syncSeries(): void {
    // Auto-seed default active series the first time a matching series exists
    // and the user hasn't already touched the toggle list.
    if (this.loadActiveRaw() === null) {
      this.active = new Set(DEFAULT_ACTIVE.filter((id) => !!this.telemetry.getSeries(id)));
      this.saveActive();
    }
    this.rebuildToggles();
  }

  /** Per-frame refresh — cheap if hidden. */
  update(): void {
    if (!this.isVisible()) return;
    const now = performance.now();
    if (now - this.lastRenderMs < this.renderEveryMs) return;
    this.lastRenderMs = now;
    this.renderChart();
  }

  // ---- Internal ----

  private colorFor(cfg: SeriesConfig, fallbackIndex: number): string {
    if (cfg.color) return cfg.color;
    const cached = this.colorByIndex.get(cfg.id);
    if (cached) return cached;
    const c = PALETTE[fallbackIndex % PALETTE.length];
    this.colorByIndex.set(cfg.id, c);
    return c;
  }

  private rebuildToggles(): void {
    this.togglesHost.innerHTML = '';
    const all = this.telemetry.list();
    all.forEach((cfg, idx) => {
      const on = this.active.has(cfg.id);
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = `dc-telem-toggle${on ? ' is-on' : ''}`;
      btn.setAttribute('data-id', cfg.id);
      btn.innerHTML = `<span class="dot" style="background:${this.colorFor(cfg, idx)}"></span>${escapeHtml(cfg.label)}`;
      btn.addEventListener('click', () => this.toggleSeries(cfg.id));
      this.togglesHost.appendChild(btn);
    });
    this.rebuildCharts();
  }

  private toggleSeries(id: string): void {
    if (this.active.has(id)) this.active.delete(id);
    else this.active.add(id);
    this.saveActive();
    this.rebuildToggles();
  }

  /**
   * Build the single combined chart + legend. Called whenever the active-
   * series set changes; per-frame updates happen in renderAll() without
   * rebuilding the DOM.
   */
  private rebuildCharts(): void {
    this.chartsHost.innerHTML = '';
    if (this.active.size === 0) {
      const empty = document.createElement('div');
      empty.className = 'dc-telem-empty';
      empty.textContent = 'No series selected — click chips above to add charts.';
      this.chartsHost.appendChild(empty);
      return;
    }
    const all = this.telemetry.list();
    const colorIdx = new Map<string, number>();
    all.forEach((cfg, i) => colorIdx.set(cfg.id, i));

    const mainChart = document.createElement('div');
    mainChart.className = 'dc-telem-mainchart';
    // One polyline per active series, inside one SVG. Each line is normalised
    // to its own min/max so they can share the chart even with different units.
    const polylines = Array.from(this.active)
      .map((id) => {
        const data = this.telemetry.getSeries(id);
        if (!data) return '';
        const col = this.colorFor(data.cfg, colorIdx.get(id) ?? 0);
        return `<polyline data-series="${escapeAttr(id)}" stroke="${col}" />`;
      })
      .join('');

    const legendRows = Array.from(this.active)
      .map((id) => {
        const data = this.telemetry.getSeries(id);
        if (!data) return '';
        const col = this.colorFor(data.cfg, colorIdx.get(id) ?? 0);
        return /*html*/ `
          <div class="row" data-series="${escapeAttr(id)}">
            <span class="swatch" style="background:${col}"></span>
            <span class="name" style="color:${col}">${escapeHtml(data.cfg.label)}</span>
            <span class="val"   data-bind="val">—</span>
            <span class="range" data-bind="range">—</span>
          </div>
        `;
      })
      .join('');

    mainChart.innerHTML = /*html*/ `
      <div class="svg-wrap">
        <div class="grid"></div>
        <div class="midline"></div>
        <svg class="line" viewBox="0 0 200 100" preserveAspectRatio="none">
          ${polylines}
        </svg>
        <span class="scale-note">each series · own min/max</span>
      </div>
      <div class="dc-telem-legend">
        ${legendRows}
      </div>
    `;
    this.chartsHost.appendChild(mainChart);
  }

  /**
   * Per-frame draw. Each series is normalised to its own min/max within the
   * visible window so all lines fit the chart vertically. They share the X
   * axis (time) — leftmost = newest-sample-time minus windowMs, rightmost
   * = newest. The legend reports each series' current value + min/max.
   *
   * Performance: no intermediate Array.slice. We binary-search inside the
   * raw buffer (respecting `startIdx`), then stride-iterate up to
   * MAX_POINTS_PER_SERIES samples, building the points string in one pass.
   */
  private renderChart(): void {
    if (this.active.size === 0) return;
    const mainChart = this.chartsHost.querySelector('.dc-telem-mainchart');
    if (!mainChart) return;

    // Anchor the shared X-axis on the newest sample across all active series.
    let tNow = -Infinity;
    const views: { id: string; view: SeriesView }[] = [];
    for (const id of this.active) {
      const v = this.telemetry.getSeries(id);
      if (!v || v.samples.length <= v.startIdx) continue;
      views.push({ id, view: v });
      const last = v.samples[v.samples.length - 1].t;
      if (last > tNow) tNow = last;
    }
    if (views.length === 0) return;
    const tFrom = tNow - this.windowMs;
    const dt = Math.max(1, this.windowMs);
    const W = 200, H = 100;

    for (const { id, view } of views) {
      const { cfg, samples, startIdx } = view;

      // Binary-search the first sample with t >= tFrom, starting from startIdx.
      let lo = startIdx, hi = samples.length;
      while (lo < hi) {
        const mid = (lo + hi) >>> 1;
        if (samples[mid].t < tFrom) lo = mid + 1;
        else hi = mid;
      }
      const visStart = lo;
      const visEnd = samples.length;
      const visCount = visEnd - visStart;
      if (visCount <= 0) continue;

      // Y-axis: either fixed range or auto from the visible slice.
      let yMin: number, yMax: number;
      if (cfg.yRange) {
        [yMin, yMax] = cfg.yRange;
      } else {
        yMin = Infinity; yMax = -Infinity;
        for (let i = visStart; i < visEnd; i++) {
          const v = samples[i].v;
          if (v < yMin) yMin = v;
          if (v > yMax) yMax = v;
        }
        if (yMin === yMax) { yMin -= 0.5; yMax += 0.5; }
        const pad = (yMax - yMin) * 0.04;
        yMin -= pad; yMax += pad;
      }
      const dy = Math.max(0.001, yMax - yMin);

      // Stride downsample inline. `step` = float index increment per output point.
      const outCount = visCount <= MAX_POINTS_PER_SERIES ? visCount : MAX_POINTS_PER_SERIES;
      const step = visCount <= MAX_POINTS_PER_SERIES ? 1 : (visCount - 1) / (outCount - 1);
      const ptsParts = new Array<string>(outCount);
      for (let i = 0; i < outCount; i++) {
        const idx = i === outCount - 1 ? visEnd - 1 : visStart + Math.floor(i * step);
        const s = samples[idx];
        const x = ((s.t - tFrom) / dt) * W;
        const y = H - ((s.v - yMin) / dy) * H;
        ptsParts[i] = `${x.toFixed(1)},${y.toFixed(1)}`;
      }

      const poly = mainChart.querySelector(`polyline[data-series="${cssEscape(id)}"]`) as SVGPolylineElement | null;
      if (poly) poly.setAttribute('points', ptsParts.join(' '));

      // Legend row update — single DOM write per series, only when value changes.
      const row = mainChart.querySelector(`.dc-telem-legend .row[data-series="${cssEscape(id)}"]`) as HTMLElement | null;
      if (row) {
        const valEl   = row.querySelector('[data-bind="val"]') as HTMLElement | null;
        const rangeEl = row.querySelector('[data-bind="range"]') as HTMLElement | null;
        const lastV = samples[visEnd - 1].v;
        const prec = cfg.precision ?? 1;
        const unit = cfg.unit ?? '';
        const newVal = `${lastV.toFixed(prec)}${unit ? ' ' + unit : ''}`;
        const newRange = `${yMin.toFixed(prec)} → ${yMax.toFixed(prec)}`;
        if (valEl && valEl.textContent !== newVal) valEl.textContent = newVal;
        if (rangeEl && rangeEl.textContent !== newRange) rangeEl.textContent = newRange;
      }
    }
  }

  private bindActions(): void {
    this.root.querySelector('[data-act="close"]')!.addEventListener('click', () => this.hide());
    this.root.querySelector('[data-act="clear"]')!.addEventListener('click', () => {
      this.telemetry.reset();
      this.update();
    });
  }

  private bindDrag(): void {
    const head = this.root.querySelector('.dc-telem-head') as HTMLElement;
    let drag: { mx: number; my: number; left: number; top: number; ptr: number } | null = null;
    head.addEventListener('pointerdown', (e) => {
      if ((e.target as HTMLElement).closest('.dc-telem-actions')) return;
      head.setPointerCapture(e.pointerId);
      const rect = this.root.getBoundingClientRect();
      drag = { mx: e.clientX, my: e.clientY, left: rect.left, top: rect.top, ptr: e.pointerId };
      e.preventDefault();
    });
    head.addEventListener('pointermove', (e) => {
      if (!drag || e.pointerId !== drag.ptr) return;
      this.geo.left = Math.max(8, Math.min(window.innerWidth - this.geo.width - 8, drag.left + (e.clientX - drag.mx)));
      this.geo.top = Math.max(8, Math.min(window.innerHeight - 60, drag.top + (e.clientY - drag.my)));
      this.applyGeometry();
    });
    const end = (e: PointerEvent): void => {
      if (!drag || e.pointerId !== drag.ptr) return;
      try { head.releasePointerCapture(e.pointerId); } catch { /* ignore */ }
      this.saveGeo();
      drag = null;
    };
    head.addEventListener('pointerup', end);
    head.addEventListener('pointercancel', end);
  }

  private defaultGeo(): Geometry {
    return { left: 24, top: 120, width: 380 };
  }

  private applyGeometry(): void {
    this.root.style.left = `${this.geo.left}px`;
    this.root.style.top = `${this.geo.top}px`;
    this.root.style.width = `${this.geo.width}px`;
  }

  private loadGeo(): Geometry | null {
    try {
      const raw = localStorage.getItem(GEO_KEY);
      if (!raw) return null;
      const g = JSON.parse(raw);
      if (typeof g?.left !== 'number' || typeof g?.top !== 'number') return null;
      return { left: g.left, top: g.top, width: typeof g.width === 'number' ? g.width : 380 };
    } catch { return null; }
  }
  private saveGeo(): void {
    try { localStorage.setItem(GEO_KEY, JSON.stringify(this.geo)); } catch { /* quota */ }
  }

  private loadVisible(): boolean {
    return localStorage.getItem(VIS_KEY) === 'true';   // false by default
  }

  private loadActiveRaw(): string | null {
    return localStorage.getItem(ACTIVE_KEY);
  }
  private loadActive(): Set<string> {
    const raw = this.loadActiveRaw();
    if (!raw) return new Set();  // syncSeries() seeds defaults later
    try {
      const arr = JSON.parse(raw);
      if (Array.isArray(arr)) return new Set(arr.filter((x): x is string => typeof x === 'string'));
    } catch { /* fall through */ }
    return new Set();
  }
  private saveActive(): void {
    try { localStorage.setItem(ACTIVE_KEY, JSON.stringify(Array.from(this.active))); }
    catch { /* quota */ }
  }

  private loadWindowKey(): string | null {
    try { return localStorage.getItem(WINDOW_KEY); }
    catch { return null; }
  }
  private saveWindowKey(): void {
    try { localStorage.setItem(WINDOW_KEY, this.windowKey); }
    catch { /* quota */ }
  }
}

// Stride downsampling is now inlined in renderChart() to avoid an
// intermediate array allocation per series per frame.

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}
function escapeAttr(s: string): string {
  return escapeHtml(s);
}
/** Minimal CSS.escape() polyfill for series ids that go into attribute selectors. */
function cssEscape(s: string): string {
  if (typeof (window as unknown as { CSS?: { escape?: (s: string) => string } }).CSS?.escape === 'function') {
    return (window as unknown as { CSS: { escape: (s: string) => string } }).CSS.escape(s);
  }
  return s.replace(/([!"#$%&'()*+,./:;<=>?@[\]^`{|}~])/g, '\\$1');
}
