/**
 * Tank — one physical cylinder carried by the diver.
 *
 * `slotId` identifies *where* it's worn (BACK, L-STAGE, R-STAGE, DECO-O2, …),
 * `cylinder` is its physical spec, `gas` is what's in it, `pressureBar` is
 * the live state that drains as the diver breathes.
 *
 * `enabled` is the watch concept: a tank can be physically on the diver but
 * "off" for deco calculations (e.g. forgot to remove an empty stage from the
 * gas list — Perdix §11.4 warns about this).
 */

import type { GasMix } from '../engine';
import type { CylinderSpec } from './cylinders';

export type SlotId = 'BACK' | 'L-STAGE' | 'R-STAGE' | 'DECO-O2' | string;

export interface Tank {
  slotId: SlotId;
  slotLabel: string;
  cylinder: CylinderSpec;
  gas: GasMix;
  pressureBar: number;
  enabled: boolean;
}

export interface TankInit {
  slotId: SlotId;
  slotLabel?: string;
  cylinder: CylinderSpec;
  gas: GasMix;
  pressureBar?: number;     // defaults to cylinder.ratedBar
  enabled?: boolean;        // defaults to true
}

export function makeTank(init: TankInit): Tank {
  return {
    slotId: init.slotId,
    slotLabel: init.slotLabel ?? init.slotId,
    cylinder: init.cylinder,
    gas: init.gas,
    pressureBar: init.pressureBar ?? init.cylinder.ratedBar,
    enabled: init.enabled ?? true,
  };
}

/** Mass of gas currently in a tank (kg). */
export function tankGasMassKg(t: Tank): number {
  const surfaceDensity = gasSurfaceDensity(t.gas);
  return (t.cylinder.capacityL * t.pressureBar * surfaceDensity) / 1000;
}

/** Same constant used by engine/gasMix.ts. Inlined here to avoid circular dep. */
function gasSurfaceDensity(g: GasMix): number {
  const fO2 = g.o2Pct / 100;
  const fHe = g.hePct / 100;
  const fN2 = 1 - fO2 - fHe;
  const M = fO2 * 32 + fHe * 4 + fN2 * 28;
  return M / 24.04;
}
