/**
 * Diving equipment configuration — user choices that drive the physics.
 *
 * Reference values:
 *  - AL80 single: +1.95 kg empty buoyancy, 11.1 L capacity, 207 bar
 *  - Aluminum twinset (double 14s): -3.6 kg net @ 200 bar, +2.0 kg @ 40 bar (EAN32)
 *  - Steel twinset: -7.6 kg net @ 200 bar, -2.0 kg @ 40 bar (EAN32)
 *  - Twinset regulator package (manifold + 2 first stages + hoses): -2.8 kg
 *  - Primary canister light: -1.4 kg
 *  - Wings: 25 / 30 / 40 / 60 lb lift (Halcyon Eclipse + Evolve family)
 *  - EAN32 gas density: 1.25 g/L at 1 atm (user-confirmed)
 *  - 3 mm wetsuit: +3 kg surface lift, k≈0.4
 *  - 5 mm wetsuit: +5 kg surface lift, k≈0.55
 *  - 7 mm wetsuit: +7 kg surface lift, k≈0.65 (loses 4-5 kg by 30 m)
 *  - Aluminum backplate: ~1 kg; Stainless: ~3 kg (DIR preferred for trim)
 */

import { RHO } from './config';

