// ---- Cylinders (singles + twinsets) ----

export interface CylinderSpec {
  id: string;
  name: string;
  variant: 'single' | 'twinset';
  /** Total water capacity (L). For twinset, both cylinders combined. */
  capacityL: number;
  ratedPressureBar: number;
  /** Net buoyancy of the cylinder shell(s) at 0 bar (kg, positive = floats). */
  emptyBuoyancyKg: number;
  /** Fixed regulator package buoyancy (kg, negative). Twinsets carry more iron. */
  regsBuoyancyKg: number;
}

