// ---- BCD wings ----

export interface WingSpec {
  id: string;
  name: string;
  /** Rated lift in kg. */
  liftKg: number;
  /** Surface-equivalent gas volume the wing can hold (L). */
  maxLitersSurface: number;
}

const LB_TO_KG = 0.4535924;
function wingFromLb(id: string, lb: number, label: string): WingSpec {
  const kg = lb * LB_TO_KG;
  return {
    id,
    name: `${lb} lb · ${kg.toFixed(1)} kg ${label}`,
    liftKg: kg,
    maxLitersSurface: (kg * 1000) / RHO, // L of gas needed at surface for that lift
  };
}

export const WINGS: Record<string, WingSpec> = {
  w25: wingFromLb('w25', 25, 'travel single'),
  w30: wingFromLb('w30', 30, 'single rec'),
  w40: wingFromLb('w40', 40, 'twinset warm'),
  w60: wingFromLb('w60', 60, 'twinset cold'),
};

