// ---- Composite equipment ----

export interface EquipmentConfig {
  bodyMassKg: number;
  bodyDisplacementL: number;
  cylinder: CylinderSpec;
  gas: GasSpec;
  tankPressureBar: number;   // mutable — depletes via SAC consumption
  wing: WingSpec;
  wetsuit: WetsuitSpec;
  backplate: BackplateSpec;
  primaryLight: boolean;     // -1.4 kg when true
  leadKg: number;
}

export const PRIMARY_LIGHT_KG = 1.4;

export function defaultEquipment(): EquipmentConfig {
  return {
    bodyMassKg: 75,
    bodyDisplacementL: 72,
    cylinder: CYLINDERS.al80,
    gas: GASES.ean32,
    tankPressureBar: CYLINDERS.al80.ratedPressureBar,
    wing: WINGS.w30,
    wetsuit: WETSUITS.w5,
    backplate: BACKPLATES.alu,
    primaryLight: false,
    leadKg: 5,
  };
}

// ---- Derived quantities ----

/** Gas mass currently in the cylinder(s) (kg). */
export function gasMassKg(eq: EquipmentConfig): number {
  return (eq.cylinder.capacityL * eq.tankPressureBar * eq.gas.densityGperL) / 1000;
}

/** Gas mass when filled to rated pressure (kg). */
export function gasMassFullKg(eq: EquipmentConfig): number {
  return (eq.cylinder.capacityL * eq.cylinder.ratedPressureBar * eq.gas.densityGperL) / 1000;
}

/** Combined buoyancy contribution of cylinder shell + regs (kg, positive = up). */
export function cylinderShellBuoyancyKg(eq: EquipmentConfig): number {
  return eq.cylinder.emptyBuoyancyKg + eq.cylinder.regsBuoyancyKg;
}

/** Total mass of everything sinking (kg). */
export function totalMassKg(eq: EquipmentConfig): number {
  const light = eq.primaryLight ? PRIMARY_LIGHT_KG : 0;
  return eq.bodyMassKg + eq.backplate.massKg + eq.leadKg + gasMassKg(eq) + light;
}

/** Wetsuit displacement (L) at given depth, partial-Boyle compression. */
export function wetsuitVolumeAtDepthL(eq: EquipmentConfig, depth_m: number): number {
  const surfaceVolumeL = eq.wetsuit.surfaceLiftKg / (RHO / 1000);
  const P = 1 + Math.max(0, depth_m) / 10;
  return surfaceVolumeL / (1 + eq.wetsuit.compressionK * (P - 1));
}

/** Maximum gas surface-equivalent the wing can hold (L). */
export function wingMaxLitersSurface(eq: EquipmentConfig): number {
  return eq.wing.maxLitersSurface;
}

/**
 * Weighting check — net force (kg, positive = sinking) at a specified depth,
 * tank pressure, and lung volume. The classic DIR weighting test sets depth
 * = 3 m (safety stop), tank pressure to ~30 bar, lung to FRC, BCD empty.
 */
export function weightingCheckKg(
  eq: EquipmentConfig,
  testDepthM: number,
  testTankPressureBar: number,
  lungL: number
): number {
  // Volumes at test depth
  const probeEq = { ...eq, tankPressureBar: testTankPressureBar };
  const displacementL = eq.bodyDisplacementL + wetsuitVolumeAtDepthL(eq, testDepthM) + lungL;
  const liftKg = (displacementL * RHO) / 1000 + cylinderShellBuoyancyKg(eq);
  return totalMassKg(probeEq) - liftKg;
}
