/**
 * AssetRegistry — central lookup for per-archetype sprite specs.
 *
 * Singleton; populated at boot by `loadPlaceholderPack()` and any
 * later loader calls (URL-based packs, LLM-emitted atlases, etc.).
 * Scenes consult it synchronously via `get(archetype)`; absence
 * means "no sprite registered — fall back to procedural drawing."
 */

import { Assets, Rectangle, Texture } from 'pixi.js';
import type { CreatureSpriteSpec, SpriteSource } from './types';
import { svgToTexture } from './svgToTexture';
import { PLACEHOLDER_ATTRIBUTION, PLACEHOLDER_SPRITES } from './placeholderAtlas';

export class AssetRegistry {
  private sprites = new Map<string, CreatureSpriteSpec>();
  private packsLoaded = new Set<string>();

  /** Sync lookup — returns `null` if the archetype has no sprite registered. */
  get(archetype: string): CreatureSpriteSpec | null {
    return this.sprites.get(archetype) ?? null;
  }

  has(archetype: string): boolean { return this.sprites.has(archetype); }

  /** All registered archetypes — useful for diagnostics + the smoke harness. */
  list(): string[] { return [...this.sprites.keys()]; }

  /**
   * Load the built-in placeholder pack (hand-rolled SVGs). Idempotent —
   * subsequent calls are no-ops once the pack is loaded.
   */
  async loadPlaceholderPack(): Promise<void> {
    if (this.packsLoaded.has('placeholder')) return;
    await this.registerSources(PLACEHOLDER_SPRITES, PLACEHOLDER_ATTRIBUTION);
    this.packsLoaded.add('placeholder');
  }

  /**
   * Load the Ansimuz Underwater Diving Pack. Idempotent; safe to call
   * after the placeholder pack — later registrations overwrite earlier
   * ones under the same archetype id.
   */
  async loadAnsimuzPack(): Promise<void> {
    if (this.packsLoaded.has('ansimuz')) return;
    // Dynamic import so the (small) png URLs aren't pulled into the
    // initial bundle for users who don't need them.
    const { ANSIMUZ_DIVING_SPRITES, ANSIMUZ_DIVING_ATTRIBUTION } = await import('./ansimuzPack');
    await this.registerSources(ANSIMUZ_DIVING_SPRITES, ANSIMUZ_DIVING_ATTRIBUTION);
    this.packsLoaded.add('ansimuz');
  }

  /**
   * Generic loader for a list of sprite source descriptors. Each one is
   * rasterised in parallel; failures for a single sprite are logged but
   * don't abort the whole pack (the failed archetype just falls back to
   * procedural drawing).
   */
  async registerSources(sources: SpriteSource[], attribution?: string): Promise<void> {
    const work = sources.map(async (src) => {
      try {
        const frames = await loadFrames(src);
        if (frames.length === 0) throw new Error('no frames produced');
        this.sprites.set(src.id, {
          frames,
          frameDurationMs: src.frameDurationMs,
          anchor: src.anchor,
          baseScale: src.baseScale,
          attribution: src.attribution ?? attribution,
        });
      } catch (err) {
        // Don't crash the whole boot if a sprite fails to decode (malformed
        // SVG, missing URL, etc.); the procedural path covers it.
        console.warn(`[assets] failed to load sprite "${src.id}":`, err);
      }
    });
    await Promise.all(work);
  }
}

/**
 * Materialise the frame textures for one source. Three input shapes:
 *   • inline `<svg…>` string → svgToTexture(), single frame
 *   • URL / data URL with no `sheet` → Pixi `Assets.load()`, single frame
 *   • URL with `sheet` → load the base texture, then carve N sub-textures
 *     out of it via `new Texture({ source, frame: Rectangle })`.
 */
async function loadFrames(src: SpriteSource): Promise<Texture[]> {
  const isInlineSvg = src.src.trimStart().startsWith('<svg');
  if (isInlineSvg) {
    const tex = await svgToTexture(src.src, src.width, src.height);
    return [tex];
  }
  const base: Texture = await Assets.load(src.src);
  if (!src.sheet || src.sheet.count <= 1) {
    return [base];
  }
  const { frameW, frameH, count } = src.sheet;
  const out: Texture[] = [];
  for (let i = 0; i < count; i++) {
    out.push(new Texture({
      source: base.source,
      frame: new Rectangle(i * frameW, 0, frameW, frameH),
    }));
  }
  return out;
}

/** Global singleton — scenes pick it up by import. */
const _registry = new AssetRegistry();
export function getAssetRegistry(): AssetRegistry { return _registry; }
