/**
 * Default LevelSpec per built-in scene.
 *
 * Each scene has a baseline level so the user gets something to do the
 * moment they pick it — no need to load a JSON file first. Loaded levels
 * (LLM-generated, user-edited) will override this map later.
 */

import type { LevelSpec } from './types';

const TRAINING_HOLD_S = 30;

export const DEFAULT_LEVELS: Record<string, LevelSpec> = {
  // CLIFF — open water training. Hold depth at 3 m (shallow training
  // depth) for 30 s. Training range overlay visible, dive limit at 40 m.
  cliff: {
    id: 'cliff-training-3m',
    label: 'CLIFF · 3 m TRAINING',
    sceneId: 'cliff',
    trainingRange: { targetDepth_m: 3, tolerance_m: 0.5 },
    fineDiveLimit_m: 40,
    missions: [{
      id: 'cliff-hold-3m',
      kind: 'depth-hold',
      label: 'Hold 3 m ±0.5',
      description: 'Hover within 0.5 m of 3 m depth for 30 seconds.',
      targetDepth_m: 3,
      tolerance_m: 0.5,
      durationS: TRAINING_HOLD_S,
    }],
  },

  // CORAL — sit just above the reef shelf (~18 m) and observe the
  // canopy. Training range visible but tighter (±0.8 m).
  coral: {
    id: 'coral-canopy-18m',
    label: 'CORAL · CANOPY 18 m',
    sceneId: 'coral',
    trainingRange: { targetDepth_m: 18, tolerance_m: 0.8 },
    fineDiveLimit_m: 30,
    missions: [{
      id: 'coral-hold-18m',
      kind: 'depth-hold',
      label: 'Canopy hold 18 m',
      description: 'Hold position above the coral canopy at 18 m ±0.8 for 30 s.',
      targetDepth_m: 18,
      tolerance_m: 0.8,
      durationS: TRAINING_HOLD_S,
    }],
  },

  // WRECK — free exploration. No training overlay, no depth-hold mission.
  // (Photo / navigate missions arrive in a later pass.)
  wreck: {
    id: 'wreck-explore',
    label: 'WRECK · EXPLORE',
    sceneId: 'wreck',
    missions: [],
  },

  // CAVE — navigation challenge in spirit; mission impl arrives later.
  cave: {
    id: 'cave-explore',
    label: 'CAVE · EXPLORE',
    sceneId: 'cave',
    missions: [],
  },

  // GEN — user supplies the scene via prompt; no default mission.
  gen: {
    id: 'gen-freeform',
    label: 'GEN · FREEFORM',
    sceneId: 'gen',
    missions: [],
  },
};

/** Find a default level for a scene id, or null. */
export function defaultLevelFor(sceneId: string): LevelSpec | null {
  return DEFAULT_LEVELS[sceneId] ?? null;
}
