/**
 * Setup modal — single-page gear configuration.
 *
 * Layout sections (vertical scroll):
 *   • EXPOSURE  — wetsuit, backplate, primary canister light
 *   • CYLINDERS — multi-tank rig editor (slot / cylinder / gas / pressure / on)
 *   • GASES     — catalog of available mixes (read-only)
 *   • DEVICES   — show/hide toggles for Perdix watch + generic panel
 *   • WING LIFT — BCD lift selector
 *   • LEAD      — slider
 *   • WEIGHTING CHECK — needle bars at stop / surface / target depth
 *
 * Opened at boot and via the GEAR button. Sim pauses while open.
 */

import {
  BACKPLATES,
  CYLINDERS as PPB_CYLINDERS,
  GASES,
  WETSUITS,
  WINGS,
  weightingCheckKg,
} from './equipment';
import { CYLINDERS as RIG_CYLINDERS } from './divecomp/equipment/cylinders';
import { STOCK_GASES } from './divecomp/engine';
import type { GasMix } from './divecomp/engine';
import type { TankRig } from './divecomp/equipment';
import { FRC_L } from './config';
import { onLangChange, t } from './i18n';
import { confirmDialog } from './divecomp/ui/confirmDialog';
import type { SimState } from './state';
import { resetState } from './state';

const ROOT_ID = 'setup-modal';

type CatKey = 'wing' | 'wetsuit' | 'backplate';

const STOCK_GAS_LIST: readonly GasMix[] = Object.values(STOCK_GASES);

/**
 * Show/hide handles for a single device shown in the DEVICES section.
 * Modeled as a duck-typed control surface so the modal doesn't depend on
 * any concrete watch class.
 */
export interface DeviceControl {
  /** Human-readable name (already-localised string or a single label). */
  nameKey: 'gear_dev_perdix' | 'gear_dev_generic' | 'gear_dev_ai' | 'gear_dev_compass';
  /** Specification line / status text shown under the name. */
  specKey?: 'gear_dev_na';
  isVisible(): boolean;
  setVisible(v: boolean): void;
  /** When true, the toggle is rendered disabled (not-yet-implemented). */
  disabled?: boolean;
}

export interface SetupSceneOption {
  id: string;
  label: string;
}

export interface SetupModalOptions {
  rig?: TankRig;
  devices?: DeviceControl[];
  /** Available dive scenes shown as chips in the SCENE section. */
  scenes?: SetupSceneOption[];
  /** Currently selected scene id; the modal reflects this on open. */
  selectedSceneId?: string;
  /** Fired when the user changes the scene chip selection inside the modal. */
  onSceneChange?: (id: string) => void;
}

export class SetupModal {
  private root!: HTMLElement;
  private state: SimState;
  private rig: TankRig | null;
  private devices: DeviceControl[];
  private scenes: SetupSceneOption[];
  private selectedSceneId: string;
  private onSceneChange?: (id: string) => void;
  private isOpen = false;

  constructor(state: SimState, opts: SetupModalOptions = {}) {
    this.state = state;
    this.rig = opts.rig ?? null;
    this.devices = opts.devices ?? [];
    this.scenes = opts.scenes ?? [];
    this.selectedSceneId = opts.selectedSceneId ?? this.scenes[0]?.id ?? '';
    this.onSceneChange = opts.onSceneChange;
    this.build();
    onLangChange(() => {
      const wasOpen = this.isOpen;
      this.build();
      if (wasOpen) this.root.classList.add('open');
    });
  }

  /** Sync the selection chip with whatever the host considers active. */
  setSelectedScene(id: string): void {
    this.selectedSceneId = id;
    this.refreshSceneChips();
  }

  private refreshSceneChips(): void {
    this.root?.querySelectorAll<HTMLButtonElement>('.setup-scene-chip').forEach((c) => {
      c.classList.toggle('is-on', c.getAttribute('data-id') === this.selectedSceneId);
    });
  }

  get open_(): boolean {
    return this.isOpen;
  }

  open(opts: { initial?: boolean } = {}) {
    if (this.isOpen) return;
    this.isOpen = true;
    this.state.paused = true;
    this.root.classList.add('open');
    if (!opts.initial) {
      this.root.querySelector('.setup-firstrun')?.classList.add('hidden');
    }
    this.refresh();
  }

  close(reset: boolean) {
    if (!this.isOpen) return;
    this.isOpen = false;
    this.state.paused = false;
    this.root.classList.remove('open');
    if (reset) resetState(this.state);
  }

  // ---------------------------------------------------------------- shell

  private build() {
    document.getElementById(ROOT_ID)?.remove();

    const root = document.createElement('div');
    root.id = ROOT_ID;
    root.className = 'setup-overlay';
    root.innerHTML = /*html*/ `
      <div class="setup-card">
        <div class="setup-head">
          <div>
            <div class="setup-eyebrow">${t('gear_eyebrow')}</div>
            <h2 class="setup-title">${t('gear_title')}</h2>
          </div>
          <div class="setup-meta">
            <div class="setup-meta-line"><span>${t('gear_meta_standard')}</span><b>DIR</b></div>
            <div class="setup-meta-line"><span>${t('gear_meta_site')}</span><b>SW / 30m</b></div>
          </div>
        </div>

        <div class="setup-firstrun">
          <b>${t('gear_weightcheck')}</b> <span>${t('gear_weightcheck_body')}</span>
        </div>

        <div class="setup-grid" id="setupBody"></div>

        <div class="setup-foot">
          <button class="setup-btn ghost"  id="setupReset">${t('gear_btn_reset')}</button>
          <button class="setup-btn ghost"  id="setupCancel">${t('gear_btn_cancel')}</button>
          <button class="setup-btn primary" id="setupDive">${t('gear_btn_dive')}</button>
        </div>
      </div>
    `;
    document.body.appendChild(root);
    this.root = root;

    const body = root.querySelector('#setupBody') as HTMLElement;
    body.append(this.renderSceneSection());
    body.append(this.renderExposureSection());
    body.append(this.renderExtrasSection());
    body.append(this.renderCylindersSection());
    body.append(this.renderDevicesSection());
    body.append(this.renderWingSection());
    body.append(this.renderLeadSection());
    body.append(this.renderWeightingSection());

    root.querySelector('#setupDive')!.addEventListener('click', () => this.handleDive());
    root.querySelector('#setupReset')!.addEventListener('click', () => this.handleReset());
    root.querySelector('#setupCancel')!.addEventListener('click', () => this.close(false));

    this.refresh();
  }

  // ---------------------------------------------------------------- SCENE

  /**
   * Scene selection — rendered at the top of the setup grid since site
   * choice is the most "where is this dive happening?" decision. Hidden
   * entirely when the host doesn't pass any scenes (back-compat).
   */
  private renderSceneSection(): HTMLElement {
    const wrap = document.createElement('section');
    wrap.className = 'setup-section setup-section-wide setup-section-scene';
    if (this.scenes.length === 0) {
      wrap.hidden = true;
      return wrap;
    }
    wrap.innerHTML = /*html*/ `
      <h3>${t('gear_sec_scene')}</h3>
      <div class="setup-scene-chips">
        ${this.scenes.map(s => `
          <button type="button" class="setup-scene-chip${s.id === this.selectedSceneId ? ' is-on' : ''}"
                  data-id="${s.id}">${s.label}</button>
        `).join('')}
      </div>
      <div class="setup-scene-hint">${t('gear_sec_scene_hint')}</div>
    `;
    wrap.querySelectorAll<HTMLButtonElement>('.setup-scene-chip').forEach((b) => {
      b.addEventListener('click', () => {
        const id = b.getAttribute('data-id')!;
        if (id === this.selectedSceneId) return;
        this.selectedSceneId = id;
        this.refreshSceneChips();
        this.onSceneChange?.(id);
      });
    });
    return wrap;
  }

  // ---------------------------------------------------------------- EXPOSURE

  private renderExposureSection(): HTMLElement {
    const wrap = document.createElement('div');
    wrap.className = 'setup-section-wrap';
    wrap.style.display = 'contents';
    wrap.innerHTML = /*html*/ `
      <section class="setup-section">
        <h3>${t('gear_sec_exposure')}</h3>
        <div class="opt-group cols2" data-key="wetsuit"></div>
      </section>
      <section class="setup-section">
        <h3>${t('gear_sec_backplate')}</h3>
        <div class="opt-group cols2" data-key="backplate"></div>
      </section>
    `;
    this.buildChipGroup(wrap, 'wetsuit', WETSUITS);
    this.buildChipGroup(wrap, 'backplate', BACKPLATES);
    return wrap;
  }

  private renderExtrasSection(): HTMLElement {
    const wrap = document.createElement('section');
    wrap.className = 'setup-section setup-section-wide';
    wrap.innerHTML = /*html*/ `
      <h3>${t('gear_sec_extras')}</h3>
      <label class="setup-toggle">
        <input type="checkbox" id="lightToggle" />
        <span class="toggle-mark"></span>
        <span class="toggle-label">
          <b>${t('gear_light_label')}</b>
          <span class="toggle-spec">${t('gear_light_spec')}</span>
        </span>
      </label>
    `;
    const light = wrap.querySelector('#lightToggle') as HTMLInputElement;
    light.checked = this.state.equipment.primaryLight;
    light.addEventListener('change', () => {
      this.state.equipment.primaryLight = light.checked;
      this.refresh();
    });
    return wrap;
  }

  // ---------------------------------------------------------------- CYLINDERS

  private renderCylindersSection(): HTMLElement {
    const section = document.createElement('section');
    section.className = 'setup-section setup-section-wide';

    if (!this.rig) {
      section.innerHTML = `<h3>${t('gear_sec_cyl')}</h3><div class="setup-hint">${t('gear_dev_na')}</div>`;
      return section;
    }

    const rig = this.rig;
    const head = `
      <div class="cyl-row-head">
        <span>${t('gear_cyl_active')}</span>
        <span class="left">${t('gear_cyl_slot')}</span>
        <span class="left">${t('gear_cyl_cyl')}</span>
        <span class="left">${t('gear_cyl_gas')}</span>
        <span>${t('gear_cyl_pressure')}</span>
        <span>${t('gear_cyl_on')}</span>
      </div>
    `;

    const rows = rig.tanks
      .map((tank) => {
        const isActive = tank.slotId === rig.activeSlotId;
        const pct = Math.max(0, Math.min(100, (tank.pressureBar / tank.cylinder.ratedBar) * 100));
        const pCls = tank.pressureBar < 21 ? 'crit' : tank.pressureBar < 50 ? 'low' : '';
        const cylOptions = Object.values(RIG_CYLINDERS)
          .map((c) => `<option value="${c.id}" ${c.id === tank.cylinder.id ? 'selected' : ''}>${c.name} · ${c.capacityL}L · ${c.ratedBar} bar</option>`)
          .join('');
        const gasOptions = STOCK_GAS_LIST
          .map((g) => `<option value="${g.id}" ${g.id === tank.gas.id ? 'selected' : ''}>${g.name}</option>`)
          .join('');
        return /*html*/ `
          <div class="cyl-row ${isActive ? 'is-active' : ''}" data-slot="${tank.slotId}">
            <div class="cell"><input type="radio" name="cylActive" class="cyl-radio" ${isActive ? 'checked' : ''} data-action="activate" /></div>
            <div class="cell cyl-slot"><input type="text" value="${escapeHtml(tank.slotLabel)}" data-action="rename" maxlength="12" /></div>
            <div class="cell"><select class="cyl-select" data-action="cylinder">${cylOptions}</select></div>
            <div class="cell"><select class="cyl-select" data-action="gas">${gasOptions}</select></div>
            <div class="cell">
              <div class="cyl-pressure">
                <span class="val">${Math.round(tank.pressureBar)} / ${tank.cylinder.ratedBar} bar</span>
                <span class="bar"><span class="fill ${pCls}" style="width:${pct.toFixed(0)}%"></span></span>
              </div>
            </div>
            <div class="cell"><input type="checkbox" ${tank.enabled ? 'checked' : ''} ${isActive ? 'disabled' : ''} data-action="enabled" /></div>
          </div>
        `;
      })
      .join('');

    const tankCount = rig.tanks.length;
    const dryKg = rig.totalDryMassKg();
    const gasFullKg = rig.tanks.reduce((sum, tank) => {
      const surfaceDensity = gasSurfDen(tank.gas);
      return sum + (tank.cylinder.capacityL * tank.cylinder.ratedBar * surfaceDensity) / 1000;
    }, 0);

    section.innerHTML = /*html*/ `
      <h3>${t('gear_sec_cyl')}</h3>
      <div class="cyl-table">
        ${head}
        ${rows}
      </div>
      <div class="cyl-actions">
        <button type="button" class="cyl-add"    id="cylAdd">${t('gear_cyl_add')}</button>
        <button type="button" class="cyl-refill" id="cylRefill">${t('gear_cyl_refill')}</button>
      </div>
      <div class="cyl-total">
        ${t('gear_cyl_total')}: <b>${tankCount}</b> · ${dryKg.toFixed(1)} kg ${t('gear_cyl_dry')} · ${gasFullKg.toFixed(1)} kg ${t('gear_cyl_gas_full')}
      </div>
    `;

    section.querySelectorAll<HTMLElement>('.cyl-row').forEach((row) => {
      const slot = row.getAttribute('data-slot')!;
      const radio = row.querySelector('[data-action="activate"]') as HTMLInputElement;
      radio.addEventListener('change', () => {
        if (radio.checked) rig.setActive(slot);
        this.rebuildBody();
      });
      const rename = row.querySelector('[data-action="rename"]') as HTMLInputElement;
      rename.addEventListener('change', () => {
        const tt = rig.tankBySlot(slot);
        if (tt && rename.value.trim()) tt.slotLabel = rename.value.trim();
      });
      const cyl = row.querySelector('[data-action="cylinder"]') as HTMLSelectElement;
      cyl.addEventListener('change', () => {
        const spec = RIG_CYLINDERS[cyl.value as keyof typeof RIG_CYLINDERS];
        if (spec) rig.setCylinder(slot, spec);
        this.rebuildBody();
      });
      const gas = row.querySelector('[data-action="gas"]') as HTMLSelectElement;
      gas.addEventListener('change', () => {
        const g = STOCK_GAS_LIST.find((x) => x.id === gas.value);
        if (g) rig.setGas(slot, g);
        this.rebuildBody();
      });
      const ena = row.querySelector('[data-action="enabled"]') as HTMLInputElement;
      ena.addEventListener('change', () => {
        try { rig.setEnabled(slot, ena.checked); }
        catch { ena.checked = !ena.checked; }
      });
    });
    (section.querySelector('#cylAdd') as HTMLButtonElement).addEventListener('click', () => {
      rig.addTank(RIG_CYLINDERS.al40, STOCK_GASES.ean32);
      this.rebuildBody();
    });
    (section.querySelector('#cylRefill') as HTMLButtonElement).addEventListener('click', () => {
      rig.refillAll();
      this.rebuildBody();
    });

    return section;
  }

  // ---------------------------------------------------------------- DEVICES

  private renderDevicesSection(): HTMLElement {
    const section = document.createElement('section');
    section.className = 'setup-section setup-section-wide';
    section.innerHTML = `<h3>${t('gear_tab_devices')}</h3><div class="dev-list"></div>`;
    const list = section.querySelector('.dev-list') as HTMLElement;

    if (this.devices.length === 0) {
      list.innerHTML = `<div class="setup-hint">${t('gear_dev_na')}</div>`;
      return section;
    }

    for (const dev of this.devices) {
      const row = document.createElement('div');
      row.className = 'dev-row' + (dev.disabled ? ' is-disabled' : '');
      const visible = dev.isVisible();
      row.innerHTML = /*html*/ `
        <span>
          <span class="name">${t(dev.nameKey)}</span>
          ${dev.specKey ? `<span class="spec">${t(dev.specKey)}</span>` : ''}
        </span>
        <label class="setup-toggle">
          <input type="checkbox" ${visible ? 'checked' : ''} ${dev.disabled ? 'disabled' : ''} />
          <span class="toggle-mark"></span>
          <span class="toggle-label"><b data-label></b></span>
        </label>
      `;
      const checkbox = row.querySelector('input[type="checkbox"]') as HTMLInputElement;
      const label = row.querySelector('[data-label]') as HTMLElement;
      const updateLabel = () => {
        label.textContent = checkbox.checked ? t('gear_dev_show') : t('gear_dev_hide');
      };
      updateLabel();
      checkbox.addEventListener('change', () => {
        dev.setVisible(checkbox.checked);
        updateLabel();
      });
      list.appendChild(row);
    }

    return section;
  }

  // ---------------------------------------------------------------- WING + LEAD + WEIGHTING

  private renderWingSection(): HTMLElement {
    const section = document.createElement('section');
    section.className = 'setup-section setup-section-wide';
    section.innerHTML = /*html*/ `
      <h3>${t('gear_sec_wing')}</h3>
      <div class="opt-group cols4" data-key="wing"></div>
    `;
    this.buildChipGroup(section, 'wing', WINGS);
    return section;
  }

  private renderLeadSection(): HTMLElement {
    const section = document.createElement('section');
    section.className = 'setup-section setup-section-wide';
    section.innerHTML = /*html*/ `
      <h3>${t('gear_sec_lead')} <span class="head-tag">${t('gear_lead_unit')}</span></h3>
      <div class="lead-row">
        <input type="range" id="leadSlider" min="0" max="16" step="0.5" value="5" />
        <span class="lead-readout" id="leadReadout">5.0</span>
      </div>
      <div class="setup-hint">${t('gear_lead_hint')}</div>
    `;
    const slider = section.querySelector('#leadSlider') as HTMLInputElement;
    slider.value = this.state.equipment.leadKg.toString();
    slider.addEventListener('input', () => {
      this.state.equipment.leadKg = parseFloat(slider.value);
      this.refresh();
    });
    return section;
  }

  private renderWeightingSection(): HTMLElement {
    const section = document.createElement('section');
    section.className = 'setup-section setup-section-wide';
    section.innerHTML = /*html*/ `
      <h3>${t('gear_sec_check')}</h3>
      <div class="check-grid">
        <div class="check-cell" id="checkStop">
          <div class="check-label">${t('gear_check_stop')}</div>
          <div class="check-value"><span id="checkStopVal">0.0</span> <span class="ck-unit">${t('gear_lead_unit')}</span></div>
          <div class="check-bar"><div class="check-needle"></div></div>
        </div>
        <div class="check-cell" id="checkSurface">
          <div class="check-label">${t('gear_check_surface')}</div>
          <div class="check-value"><span id="checkSurfaceVal">0.0</span> <span class="ck-unit">${t('gear_lead_unit')}</span></div>
          <div class="check-bar"><div class="check-needle"></div></div>
        </div>
        <div class="check-cell" id="checkDeep">
          <div class="check-label">${t('gear_check_deep')}</div>
          <div class="check-value"><span id="checkDeepVal">0.0</span> <span class="ck-unit">${t('gear_lead_unit')}</span></div>
          <div class="check-bar"><div class="check-needle"></div></div>
        </div>
      </div>
      <div class="setup-hint">${t('gear_check_hint')}</div>
    `;
    return section;
  }

  // ---------------------------------------------------------------- shared

  private rebuildBody(): void {
    // Used after the rig changes shape (add/remove tanks, swap cylinder/gas).
    // Simplest correct approach: rebuild the whole modal then refresh.
    const wasOpen = this.isOpen;
    this.build();
    if (wasOpen) this.root.classList.add('open');
  }

  private buildChipGroup<T extends { id: string; name: string }>(
    scope: HTMLElement,
    key: CatKey,
    catalog: Record<string, T>
  ) {
    const host = scope.querySelector(`.opt-group[data-key="${key}"]`) as HTMLElement;
    if (!host) return;
    host.innerHTML = '';
    for (const id of Object.keys(catalog)) {
      const item = catalog[id];
      const chip = document.createElement('button');
      chip.type = 'button';
      chip.className = 'opt-chip';
      chip.dataset.id = id;
      chip.innerHTML = `
        <span class="chip-name">${item.name}</span>
        <span class="chip-spec">${describeOption(key, item as unknown as Record<string, number | string>)}</span>
      `;
      chip.addEventListener('click', () => {
        const eq = this.state.equipment;
        if (key === 'wing') eq.wing = WINGS[id];
        if (key === 'wetsuit') eq.wetsuit = WETSUITS[id];
        if (key === 'backplate') eq.backplate = BACKPLATES[id];
        this.refresh();
      });
      host.appendChild(chip);
    }
  }

  private async handleDive() {
    // If the diver is already mid-dive, ask before wiping the session.
    // `state.diveStartT` is set the first time depth crosses 1 m (physics.ts).
    const inDive = this.state.diveStartT !== null;
    if (!inDive) {
      this.close(false);
      return;
    }
    const ok = await confirmDialog({
      title: t('gear_dive_confirm_title'),
      message: t('gear_dive_confirm'),
      confirmText: t('gear_dive_confirm_ok'),
      cancelText: t('gear_btn_cancel'),
      destructive: true,
    });
    if (ok) this.close(true);
  }

  private handleReset() {
    const eq = this.state.equipment;
    eq.cylinder = PPB_CYLINDERS.al80;
    eq.gas = GASES.ean32;
    eq.tankPressureBar = PPB_CYLINDERS.al80.ratedPressureBar;
    eq.wing = WINGS.w30;
    eq.wetsuit = WETSUITS.w5;
    eq.backplate = BACKPLATES.alu;
    eq.primaryLight = false;
    eq.leadKg = 5;
    if (this.rig) this.rig.refillAll();
    this.rebuildBody();
  }

  private refresh() {
    const eq = this.state.equipment;

    for (const [key, currentId] of [
      ['wing', eq.wing.id],
      ['wetsuit', eq.wetsuit.id],
      ['backplate', eq.backplate.id],
    ] as const) {
      this.root.querySelectorAll(`.opt-group[data-key="${key}"] .opt-chip`).forEach((c) => {
        c.classList.toggle('selected', (c as HTMLElement).dataset.id === currentId);
      });
    }

    const leadReadout = this.root.querySelector('#leadReadout') as HTMLElement | null;
    if (leadReadout) leadReadout.textContent = eq.leadKg.toFixed(1);

    const fmt = (k: number) => (k >= 0 ? '+' : '') + k.toFixed(2);
    const wStop = weightingCheckKg(eq, 3, 30, FRC_L);
    const wSurf = weightingCheckKg(eq, 0, eq.cylinder.ratedPressureBar, FRC_L);
    const wDeep = weightingCheckKg(eq, 10, eq.cylinder.ratedPressureBar, FRC_L);
    this.applyCheck('checkStop', wStop, 0.5);
    this.applyCheck('checkSurface', wSurf, 2.0);
    this.applyCheck('checkDeep', wDeep, 1.5);
    const stopVal = this.root.querySelector('#checkStopVal') as HTMLElement | null;
    const surfVal = this.root.querySelector('#checkSurfaceVal') as HTMLElement | null;
    const deepVal = this.root.querySelector('#checkDeepVal') as HTMLElement | null;
    if (stopVal) stopVal.textContent = fmt(wStop);
    if (surfVal) surfVal.textContent = fmt(wSurf);
    if (deepVal) deepVal.textContent = fmt(wDeep);
  }

  private applyCheck(cellId: string, valueKg: number, tolerance: number) {
    const cell = this.root.querySelector(`#${cellId}`) as HTMLElement | null;
    if (!cell) return;
    const needle = cell.querySelector('.check-needle') as HTMLElement;
    const pct = Math.max(0, Math.min(100, ((valueKg + 10) / 20) * 100));
    needle.style.left = `${pct}%`;
    cell.classList.remove('ok', 'warn', 'bad');
    if (Math.abs(valueKg) <= tolerance) cell.classList.add('ok');
    else if (Math.abs(valueKg) <= tolerance * 2.5) cell.classList.add('warn');
    else cell.classList.add('bad');
  }
}

function describeOption(key: CatKey, opt: Record<string, number | string>): string {
  if (key === 'wing') {
    return `${(opt.liftKg as number).toFixed(1)} kg lift · ${(opt.maxLitersSurface as number).toFixed(0)} L gas`;
  }
  if (key === 'wetsuit') {
    return (opt.surfaceLiftKg as number)
      ? `+${(opt.surfaceLiftKg as number).toFixed(1)} kg lift · k=${(opt.compressionK as number).toFixed(2)}`
      : 'no lift';
  }
  return `${(opt.massKg as number).toFixed(1)} kg`;
}

function gasSurfDen(g: GasMix): number {
  const fO2 = g.o2Pct / 100;
  const fHe = g.hePct / 100;
  const fN2 = 1 - fO2 - fHe;
  return (fO2 * 32 + fHe * 4 + fN2 * 28) / 24.04;
}

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}
