/**
 * Perdix2Watch — Perdix-2-style watch face.
 *
 * Renders a faithful (functional) recreation of the Perdix 2 recreational-
 * mode layout: rectangular LCD with large depth, NDL/DECO block, dive-time,
 * active-gas info row, and button hints. Two physical buttons on the bezel
 * (MENU / SELECT) drive a page state machine (`state.ts`).
 *
 * This skin is independent of `DiveWatchPanel` — it builds its own shell so
 * the device aspect ratio (480×272) is fixed regardless of where the user
 * drags it. Multiple Perdix2Watch instances can coexist (multi-watch mode).
 */

import './perdix2.css';
import type { DecoSnapshot } from '../../engine';
import type { PanelRigSnapshot } from '../../panel/DiveWatchPanel';
import {
  buildMainPage,
  buildInfoCnsPage,
  buildInfoGfPage,
  buildInfoDensityPage,
  buildMenuPage,
  type PageHost,
  type PageExtras,
  type MenuPageHandle,
} from './pages';
import {
  initialState,
  reducePress,
  reduceIdle,
  type Perdix2State,
  type Perdix2PageId,
} from './state';
import {
  DEFAULT_KEYMAP,
  keyToButton,
  type Perdix2ButtonId,
} from './buttons';
import { MenuController, type MenuHost } from './menu';

const STORAGE_KEY = 'ppb_perdix2_geo';
const Z_INDEX_BASE = 92;

interface Geometry { left: number; top: number; width: number }

export interface Perdix2WatchOptions {
  title?: string;
  /** Pixel width of the device (height scales by 480:272). */
  width?: number;
  /** Override the keyboard → button mapping (e.g. for a second watch). */
  keymap?: Record<string, Perdix2ButtonId>;
  /** Used to namespace the localStorage key when multiple watches coexist. */
  instanceId?: string;
  /** Menu hooks: rig data + side-effect callbacks. */
  menuHost?: MenuHost;
}

export class Perdix2Watch {
  readonly root: HTMLElement;
  private device!: HTMLElement;
  private screen!: HTMLElement;

  private geometry: Geometry;
  private storageKey: string;
  private keymap: Record<string, Perdix2ButtonId>;

  private pages: Record<Perdix2PageId, PageHost>;
  private menuPage: MenuPageHandle;
  private menu: MenuController;
  private state: Perdix2State;
  private hasFocus = false;

  constructor(opts: Perdix2WatchOptions = {}) {
    this.keymap = opts.keymap ?? DEFAULT_KEYMAP;
    this.storageKey = STORAGE_KEY + (opts.instanceId ? `:${opts.instanceId}` : '');
    this.geometry = this.loadGeometry() ?? this.defaultGeometry(opts.width);
    this.state = initialState(performance.now());

    this.root = document.createElement('div');
    this.root.className = 'p2';
    this.root.style.zIndex = String(Z_INDEX_BASE);
    this.root.tabIndex = -1; // focusable for key intercept
    this.root.innerHTML = /*html*/ `
      <div class="p2-head">
        <span>${escapeHtml(opts.title ?? 'PERDIX 2 · REC')}</span>
        <div class="p2-actions">
          <button class="p2-btn p2-close" type="button" title="hide">✕</button>
        </div>
      </div>
      <div class="p2-device">
        <!-- Decorative bezel screws (8 around the rim) -->
        <div class="p2-screws" aria-hidden="true">
          <span class="p2-screw" style="top:5px;  left:5px;"></span>
          <span class="p2-screw" style="top:5px;  right:5px;"></span>
          <span class="p2-screw" style="bottom:5px;left:5px;"></span>
          <span class="p2-screw" style="bottom:5px;right:5px;"></span>
          <span class="p2-screw" style="top:50%; left:5px;  transform:translateY(-50%);"></span>
          <span class="p2-screw" style="top:50%; right:5px; transform:translateY(-50%);"></span>
          <span class="p2-screw" style="top:5px; left:50%; transform:translateX(-50%);"></span>
          <span class="p2-screw" style="bottom:5px;left:50%;transform:translateX(-50%);"></span>
        </div>
        <div class="p2-side">
          <button class="p2-pbtn" data-btn="MENU" type="button">MENU</button>
        </div>
        <div class="p2-screen">
          <!-- Generic wordmark slot — kept neutral so no third-party branding is reproduced -->
          <span class="p2-brand" aria-hidden="true">DIVE · SIM</span>
        </div>
        <div class="p2-side">
          <button class="p2-pbtn" data-btn="SELECT" type="button">SELECT</button>
        </div>
      </div>
    `;
    document.body.appendChild(this.root);

    this.device = this.root.querySelector('.p2-device') as HTMLElement;
    this.screen = this.root.querySelector('.p2-screen') as HTMLElement;

    // Menu controller + page. If no host provided, fall back to no-op stubs
    // so the menu still works visually (placeholders only).
    this.menu = new MenuController(opts.menuHost ?? {
      rigTanks: () => [],
      onSwitchGas: undefined,
      onEndDive: undefined,
      notify: undefined,
    });
    this.menuPage = buildMenuPage(this.menu);
    this.pages = {
      'main':   buildMainPage(),
      'info-0': buildInfoCnsPage(),
      'info-1': buildInfoGfPage(),
      'info-2': buildInfoDensityPage(),
      'menu':   this.menuPage,
    };
    for (const k of Object.keys(this.pages) as Perdix2PageId[]) {
      this.screen.appendChild(this.pages[k].root);
    }
    this.activatePage(this.state.page);

    this.applyGeometry();
    this.bindDrag();
    this.bindButtons();
    this.bindKeyboard();
    this.bindFocus();
    this.bindClose();
  }

  // ---- Public API ----

  /** Per-frame refresh. `extra` provides host data the engine doesn't track. */
  update(s: DecoSnapshot, rig?: PanelRigSnapshot, extra?: PageExtras): void {
    // Idle-timeout housekeeping
    const nowMs = performance.now();
    const next = reduceIdle(this.state, nowMs);
    if (next.page !== this.state.page) {
      this.state = next;
      this.activatePage(next.page);
    }
    // Push data to the currently visible page only — others stay dormant
    this.pages[this.state.page].update(s, rig, extra);
  }

  press(btn: Perdix2ButtonId): void {
    const wasPage = this.state.page;
    const result = reducePress(this.state, btn, performance.now());

    if ('delegateTo' in result) {
      // Menu controller handles intra-menu navigation.
      const r = this.menu.press(btn);
      this.menuPage.refresh();
      if (r.kind === 'exit') {
        this.state = { ...this.state, page: 'main', lastInputMs: performance.now() };
        this.activatePage('main');
      }
      return;
    }

    this.state = result;
    // Reset menu to root every time we enter the menu page fresh.
    if (this.state.page === 'menu' && wasPage !== 'menu') {
      this.menu.reset();
      this.menuPage.refresh();
    }
    if (this.state.page !== wasPage) this.activatePage(this.state.page);
  }

  hide(): void { this.root.style.display = 'none'; }
  show(): void { this.root.style.display = ''; }
  isHidden(): boolean { return this.root.style.display === 'none'; }
  destroy(): void { this.root.remove(); }

  // ---- Internals ----

  private activatePage(p: Perdix2PageId): void {
    for (const k of Object.keys(this.pages) as Perdix2PageId[]) {
      const el = this.pages[k].root;
      if (k === p) el.setAttribute('data-active', '');
      else el.removeAttribute('data-active');
    }
  }

  private defaultGeometry(width?: number): Geometry {
    const w = width ?? 480;
    return { left: window.innerWidth - w - 24, top: 60, width: w };
  }

  private applyGeometry(): void {
    const { left, top, width } = this.geometry;
    this.root.style.left = `${left}px`;
    this.root.style.top = `${top}px`;
    this.root.style.width = `${width}px`;
  }

  private bindDrag(): void {
    const head = this.root.querySelector('.p2-head') as HTMLElement;
    let drag: { mx: number; my: number; left: number; top: number; ptr: number } | null = null;

    head.addEventListener('pointerdown', (e) => {
      if ((e.target as HTMLElement).closest('.p2-actions')) return;
      head.setPointerCapture(e.pointerId);
      const rect = this.root.getBoundingClientRect();
      drag = { mx: e.clientX, my: e.clientY, left: rect.left, top: rect.top, ptr: e.pointerId };
      this.root.style.zIndex = String(Z_INDEX_BASE + 5);
      e.preventDefault();
    });
    head.addEventListener('pointermove', (e) => {
      if (!drag || e.pointerId !== drag.ptr) return;
      this.geometry.left = Math.max(8, Math.min(window.innerWidth - this.geometry.width - 8, drag.left + (e.clientX - drag.mx)));
      this.geometry.top = Math.max(8, Math.min(window.innerHeight - 80, drag.top + (e.clientY - drag.my)));
      this.applyGeometry();
    });
    const end = (e: PointerEvent): void => {
      if (!drag || e.pointerId !== drag.ptr) return;
      try { head.releasePointerCapture(e.pointerId); } catch { /* ignore */ }
      this.saveGeometry();
      this.root.style.zIndex = String(Z_INDEX_BASE);
      drag = null;
    };
    head.addEventListener('pointerup', end);
    head.addEventListener('pointercancel', end);
  }

  private bindButtons(): void {
    this.device.querySelectorAll<HTMLButtonElement>('.p2-pbtn').forEach((btn) => {
      btn.addEventListener('click', () => {
        const id = btn.getAttribute('data-btn') as Perdix2ButtonId;
        this.press(id);
      });
    });
  }

  private bindKeyboard(): void {
    window.addEventListener('keydown', (e) => {
      if (!this.hasFocus) return;
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      const btn = keyToButton(e, this.keymap);
      if (!btn) return;
      e.preventDefault();
      this.press(btn);
    });
  }

  private bindFocus(): void {
    // Click anywhere on the watch grabs key focus; click outside releases.
    this.root.addEventListener('pointerdown', () => { this.hasFocus = true; this.root.classList.add('p2-focus'); });
    document.addEventListener('pointerdown', (e) => {
      if (!this.root.contains(e.target as Node)) {
        this.hasFocus = false;
        this.root.classList.remove('p2-focus');
      }
    });
  }

  private bindClose(): void {
    const close = this.root.querySelector('.p2-close') as HTMLButtonElement;
    close.addEventListener('click', () => this.hide());
  }

  private loadGeometry(): Geometry | null {
    try {
      const raw = localStorage.getItem(this.storageKey);
      if (!raw) return null;
      const g = JSON.parse(raw);
      if (typeof g?.left !== 'number' || typeof g?.top !== 'number') return null;
      return { left: g.left, top: g.top, width: typeof g.width === 'number' ? g.width : 360 };
    } catch { return null; }
  }
  private saveGeometry(): void {
    try { localStorage.setItem(this.storageKey, JSON.stringify(this.geometry)); } catch { /* quota */ }
  }
}

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}
