/**
 * Perdix 2 page state machine.
 *
 * Pages, per manual §4.6 (Info Screens) and §11 (Menus):
 *
 *   Main         — depth / time / NDL / gas / info row (dive layout)
 *                  or depth=0 + surface interval (surface layout)
 *   InfoN        — additional info screens, cycled by SELECT, time out
 *                  after 10 s back to Main
 *   Menu         — main menu tree; navigation handled by MenuController
 *
 * Idle timeout returns Info / Menu pages to Main after 10 s of inactivity.
 */

import type { Perdix2ButtonId } from './buttons';

export type Perdix2PageId =
  | 'main'           // dive-main or surface-main (decided by snapshot.depth)
  | 'info-0'         // CNS / MOD / Temperature
  | 'info-1'         // GF99 / SurGF
  | 'info-2'         // Density / Conservatism
  | 'menu';

export const INFO_PAGES: Perdix2PageId[] = ['info-0', 'info-1', 'info-2'];

const IDLE_TIMEOUT_MS = 10_000;

export interface Perdix2State {
  page: Perdix2PageId;
  /** Timestamp of last button press — used for idle-back-to-main. */
  lastInputMs: number;
}

export function initialState(nowMs: number): Perdix2State {
  return { page: 'main', lastInputMs: nowMs };
}

/**
 * Compute the next *page* after a button press. The menu controller handles
 * intra-menu navigation; this reducer only deals with crossing page boundaries
 * (main ↔ info ↔ menu). Returns `null` when the press should be routed to
 * the menu controller instead.
 */
export function reducePress(
  s: Perdix2State,
  btn: Perdix2ButtonId,
  nowMs: number
): Perdix2State | { delegateTo: 'menu' } {
  const next: Perdix2State = { ...s, lastInputMs: nowMs };

  if (btn === 'BOTH') return next; // chord is power-on; runtime ignores while on

  if (s.page === 'main') {
    if (btn === 'SELECT') next.page = INFO_PAGES[0];
    else if (btn === 'MENU') next.page = 'menu';
    return next;
  }

  if (s.page === 'menu') {
    // Menu navigation belongs to MenuController; signal delegation.
    return { delegateTo: 'menu' };
  }

  // Info screens — SELECT cycles forward, MENU returns to main.
  const idx = INFO_PAGES.indexOf(s.page);
  if (idx >= 0) {
    if (btn === 'SELECT') {
      const nextIdx = idx + 1;
      next.page = nextIdx < INFO_PAGES.length ? INFO_PAGES[nextIdx] : 'main';
    } else if (btn === 'MENU') {
      next.page = 'main';
    }
  }

  return next;
}

/**
 * Idle-tick — if enough time has elapsed without input, return Info / Menu
 * pages to Main. Pure; caller invokes per frame.
 */
export function reduceIdle(s: Perdix2State, nowMs: number): Perdix2State {
  if (s.page === 'main') return s;
  if (nowMs - s.lastInputMs < IDLE_TIMEOUT_MS) return s;
  return { ...s, page: 'main' };
}
