/**
 * Bidirectional conversion between our domain `GasMix` and the vendored `Gas`.
 *
 * Vendor uses fractions (0..1) and tracks O2/He/N2 internally. We use whole
 * percentages and a richer descriptor (id, name, role).
 */

import { Gas } from './vendored/gas';
import type { GasMix } from './types';

export function gasMixToVendor(mix: GasMix): Gas {
  return new Gas(mix.o2Pct / 100, mix.hePct / 100);
}

/**
 * Reverse: useful only for tests / debugging. Produces a synthetic GasMix
 * (no stable id, no role) from a vendor Gas.
 */
export function vendorToGasMix(g: Gas, name = ''): GasMix {
  const o2Pct = Math.round(g.o2 * 100);
  const hePct = Math.round(g.he * 100);
  return {
    id: `g-${o2Pct}-${hePct}`,
    name: name || `${o2Pct}/${hePct}`,
    o2Pct,
    hePct,
    role: 'bottom',
  };
}

/**
 * Cache of GasMix.id → vendor Gas instance. The vendored model uses object
 * identity in `gasMixes.find(g => g.equals(...))`, so we want stable Gas
 * objects per mix to avoid building new ones every frame.
 */
export class VendorGasCache {
  private cache = new Map<string, Gas>();
  private mixById = new Map<string, GasMix>();

  get(mix: GasMix): Gas {
    const cached = this.cache.get(mix.id);
    if (cached) return cached;
    const g = gasMixToVendor(mix);
    this.cache.set(mix.id, g);
    this.mixById.set(mix.id, mix);
    return g;
  }

  getAll(mixes: GasMix[]): Gas[] {
    return mixes.map(m => this.get(m));
  }

  mixFor(g: Gas): GasMix | undefined {
    for (const [id, vg] of this.cache) {
      if (vg.equals(g)) return this.mixById.get(id);
    }
    return undefined;
  }

  clear(): void {
    this.cache.clear();
    this.mixById.clear();
  }
}
