/**
 * MockProvider — offline scene generator.
 *
 * Builds a SceneSpec from rough keyword heuristics on the user's prompt
 * ("reef", "wreck", "deep", "kelp"…). Always ready — no key required.
 * Useful as a smoke test for the rendering side without a network round
 * trip, and as a fallback when no real LLM is configured.
 */

import type { SceneSpec } from '../../scene/genScene.types';
import type {
  GenerateRequest,
  GenerateResponse,
  SceneProvider,
} from './Provider';

export class MockProvider implements SceneProvider {
  readonly name = 'MOCK (offline)';

  isReady(): boolean {
    return true;
  }

  async generate(req: GenerateRequest): Promise<GenerateResponse> {
    // Tiny async pause so the UI's loading state is visible.
    await new Promise((r) => setTimeout(r, 250));
    const spec = synthesizeFromPrompt(req.prompt);
    return { ok: true, spec, source: 'mock' };
  }
}

// ---- heuristic synthesis ----

function synthesizeFromPrompt(prompt: string): SceneSpec {
  const p = (prompt || '').toLowerCase();
  const hasReef    = /reef|coral/.test(p);
  const hasWreck   = /wreck|ship|debris/.test(p);
  const hasKelp    = /kelp|forest|temperate/.test(p);
  const hasDeep    = /deep|mesophotic|wall|drop/.test(p);
  const hasCave    = /cave|cavern/.test(p);
  const hasJelly   = /jelly|jellyfish|bloom/.test(p);
  const hasShark   = /shark|big fish|pelagic/.test(p);

  let baseDepth = 18;
  let label = 'GEN — TROPICAL';
  let topColor = 0xc5b58a;
  let accentColor = 0x8d7a52;

  if (hasDeep) { baseDepth = 38; label = 'GEN — DEEP WALL'; topColor = 0x4a3d2a; accentColor = 0x2e261a; }
  if (hasKelp) { baseDepth = 14; label = 'GEN — KELP FOREST'; topColor = 0x4a5238; accentColor = 0x2f3625; }
  if (hasCave) { baseDepth = 22; label = 'GEN — CAVERN'; topColor = 0x3a322a; accentColor = 0x1f1c17; }
  if (hasReef && !hasDeep) label = 'GEN — REEF';
  if (hasWreck) label = 'GEN — WRECK SITE';

  const creatures: SceneSpec['creatures'] = [];
  // Always: shallow school + mid-water fish.
  creatures.push({
    archetype: 'school', count: 6,
    depthRange: [3, Math.min(10, baseDepth - 4)],
    colors: [0x9ecbe6, 0xa6d6e8], scaleRange: [0.7, 1.1],
  });
  creatures.push({
    archetype: 'fish', count: 10,
    depthRange: [5, baseDepth - 2],
    colors: hasKelp
      ? [0x6e8a4e, 0x4caaff, 0xffd76b]
      : [0x4cd6c4, 0xffd76b, 0xff8b6e],
    scaleRange: [0.9, 1.4],
  });

  if (hasJelly) {
    creatures.push({
      archetype: 'jelly', count: 12,
      depthRange: [4, Math.max(6, baseDepth - 4)],
      colors: [0xeaf4ff, 0xcad6ff],
      hazard: 'stinging', hazardLabel: 'JELLY',
    });
  }

  if (hasShark) {
    creatures.push({
      archetype: 'fish', count: 2,
      depthRange: [baseDepth - 10, baseDepth - 3],
      colors: [0x4a5763, 0x5b6a78],
      scaleRange: [2.4, 3.2],
    });
  }

  // Benthic layer — depends on substrate.
  if (hasReef && !hasWreck) {
    creatures.push({
      archetype: 'coral', count: 14,
      depthRange: [baseDepth - 0.5, baseDepth + 0.2], benthic: true,
      colors: [0xd2773d, 0xc05a3e, 0xb89149], scaleRange: [0.9, 1.6],
      hazard: 'fragile', hazardLabel: 'FRAGILE CORAL',
    });
    creatures.push({
      archetype: 'anemone', count: 8,
      depthRange: [baseDepth - 0.5, baseDepth + 0.2], benthic: true,
      colors: [0xff8c69, 0xff5b9a, 0xffb46e], scaleRange: [0.7, 1.0],
    });
    creatures.push({
      archetype: 'urchin', count: 6,
      depthRange: [baseDepth - 0.5, baseDepth + 0.2], benthic: true,
      colors: [0x2c2030, 0x1f1525, 0x382744], scaleRange: [0.6, 0.9],
      hazard: 'stinging', hazardLabel: 'URCHIN',
    });
  } else if (hasKelp) {
    creatures.push({
      archetype: 'coral', count: 20,  // tall verticals — kelp-ish
      depthRange: [baseDepth - 0.5, baseDepth + 0.2], benthic: true,
      colors: [0x3a5a2a, 0x4a6f30, 0x2e421e], scaleRange: [1.6, 2.8],
    });
    creatures.push({
      archetype: 'urchin', count: 14,
      depthRange: [baseDepth - 0.5, baseDepth + 0.2], benthic: true,
      colors: [0x5a2a30, 0x6e3640], scaleRange: [0.5, 0.8],
      hazard: 'stinging', hazardLabel: 'URCHIN',
    });
  } else if (hasWreck) {
    creatures.push({
      archetype: 'eel', count: 4,
      depthRange: [baseDepth - 2, baseDepth + 0.5],
      colors: [0x6e7a4e, 0x8a8a55], scaleRange: [1.0, 1.4],
      hazard: 'venomous', hazardLabel: 'MORAY EEL',
    });
    creatures.push({
      archetype: 'fish', count: 5,
      depthRange: [baseDepth - 4, baseDepth + 1],
      colors: [0xd96b3a, 0xc05225, 0xe09148], scaleRange: [0.9, 1.4],
      hazard: 'venomous', hazardLabel: 'LIONFISH',
    });
  }

  // Optional ray on the sand for sandy sites.
  if (!hasKelp && !hasWreck) {
    creatures.push({
      archetype: 'ray', count: 2,
      depthRange: [baseDepth - 0.3, baseDepth + 0.2], benthic: true,
      colors: [0x6f5a3e, 0x8b7250], scaleRange: [1.1, 1.4],
    });
  }

  return {
    id: 'mock-' + hashId(prompt + label),
    label,
    zones: [
      { startDepth_m: 0, endDepth_m: 8, label: 'SUNLIT', note: 'warm, schools' },
      { startDepth_m: 8, endDepth_m: Math.max(10, baseDepth - 2),
        label: hasKelp ? 'CANOPY' : 'MIDWATER',
        note: hasJelly ? 'jelly bloom' : 'open blue' },
      { startDepth_m: Math.max(10, baseDepth - 2), endDepth_m: baseDepth + 1,
        label: hasReef ? 'REEF SHELF' : hasWreck ? 'WRECK DECK' : 'BOTTOM' },
      { startDepth_m: baseDepth + 1, endDepth_m: 99,
        label: hasDeep ? 'WALL' : 'EDGE',
        note: 'open / drop-off' },
    ],
    bottom: {
      baseDepth_m: baseDepth,
      amplitude_m: hasCave ? 2.4 : 0.8,
      period_m: hasDeep ? 32 : 22,
      lengthM: 280,
      color: topColor,
      accentColor,
    },
    creatures,
    prompt,
  };
}

function hashId(s: string): string {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h.toString(36);
}
