export type StringKey = keyof typeof STRINGS.en;

const STORAGE_KEY = 'ppb_lang';
let _lang: Lang = (localStorage.getItem(STORAGE_KEY) as Lang) || 'en';

export function getLang(): Lang { return _lang; }

export function setLang(l: Lang): void {
  _lang = l;
  try { localStorage.setItem(STORAGE_KEY, l); } catch { /* quota */ }
  applyAll();
  for (const cb of _subs) cb();
}

export function t(key: StringKey): string {
  return STRINGS[_lang][key];
}

export function applyAll(): void {
  document.querySelectorAll<HTMLElement>('[data-i18n]').forEach(el => {
    const k = el.dataset.i18n as StringKey | undefined;
    if (k && k in STRINGS[_lang]) el.textContent = t(k);
  });
  // Markup-preserving variant for strings containing <b>/<sub>/etc.
  document.querySelectorAll<HTMLElement>('[data-i18n-html]').forEach(el => {
    const k = (el.dataset.i18nHtml || '') as StringKey;
    if (k && k in STRINGS[_lang]) el.innerHTML = t(k);
  });
}

/** Subscribe to language changes. */
const _subs: Array<() => void> = [];
export function onLangChange(cb: () => void): void { _subs.push(cb); }
