/**
 * MissionRegistry — owns the active level and routes per-frame ticks to
 * each Mission runner. Designed so the host only knows about the
 * registry, not concrete mission classes — adding a new mission type
 * later just means registering a new factory.
 */

import type { SimState } from '../state';
import { DepthHoldMissionRunner } from './depthHold';
import type {
  LevelSpec,
  Mission,
  MissionRuntime,
  MissionSpec,
} from './types';

type Factory = (spec: MissionSpec) => Mission;

const FACTORIES: Partial<Record<MissionSpec['kind'], Factory>> = {
  'depth-hold': (s) => new DepthHoldMissionRunner(s as never),
  // photo / qte / navigate / ascent-rate — stubs land in future passes.
};

export class MissionRegistry {
  private level: LevelSpec | null = null;
  private runners: Mission[] = [];

  /**
   * Replace the active level. Drops any in-flight runner state. Missions
   * whose `kind` has no factory yet are silently skipped — keeps the
   * schema forward-compatible with files written for future versions.
   */
  loadLevel(level: LevelSpec | null): void {
    this.level = level;
    this.runners = [];
    if (!level) return;
    for (const m of level.missions) {
      const factory = FACTORIES[m.kind];
      if (factory) this.runners.push(factory(m));
    }
  }

  /** Currently active level, or null if none. */
  getLevel(): LevelSpec | null { return this.level; }

  /** Tick every mission with the latest physics state. */
  update(state: SimState, dt: number): MissionRuntime[] {
    return this.runners.map((r) => r.update(state, dt));
  }

  /** Snapshot without advancing — useful for read-only HUD reads. */
  snapshot(): MissionRuntime[] {
    return this.runners.map((r) => r.snapshot());
  }

  reset(): void {
    for (const r of this.runners) r.reset();
  }
}
