import { Container, Graphics } from 'pixi.js';
import { clamp } from '../physics';
import type { SimState } from '../state';
import type { HazardContact, Scene, ZoneInfo } from './types';

/**
 * CoralReefScene — a flat sand-and-coral bottom at ~28 m with gentle
 * undulation. Above the bottom is open mid-water where fish schools roam;
 * below the bottom the procedural terrain blocks the view.
 *
 * Depth zones for population/variety reporting:
 *
 *   0–18 m   OPEN WATER     (light schools, mostly empty)
 *   18–25 m  CORAL CANOPY   (anemones + soft corals + butterflyfish)
 *   25–32 m  CORAL SHELF    (hard corals + parrotfish + grouper)
 *   > 32 m   SAND BOTTOM    (sand + sparse fauna)
 */

const BOTTOM_BASE_M = 28;
/** Vertical amplitude of the undulation around BOTTOM_BASE_M (m). */
const BOTTOM_AMP_M = 1.8;
/** World length of the bottom strip (m). */
const BOTTOM_LENGTH_M = 320;
/** Horizontal sampling resolution (samples / metre). */
const SAMPLES_PER_M = 1;

type ReefCreatureType =
  | 'school' | 'parrot' | 'butterfly' | 'grouper'
  | 'anemone' | 'softcoral' | 'hardcoral' | 'urchin';

interface ReefCreature {
  /** World depth (m). For benthic creatures, this is just above the bottom. */
  depth: number;
  /** World x along bottom strip (m, mod BOTTOM_LENGTH_M). */
  xAlong: number;
  /** Drives oscillation / drift phase. */
  phase: number;
  type: ReefCreatureType;
  litColor: number;
  scale: number;
  /** Benthic creatures stick to the bottom; pelagic ones float at `depth`. */
  benthic: boolean;
  /** Hazard kind when in close contact, if any. */
  hazard?: HazardContact['kind'];
  /** Stable index — used for hazard de-dup. */
  index: number;
}

export class CoralReefScene implements Scene {
  readonly id = 'coral';
  readonly name = 'CORAL REEF';
  readonly container = new Container();

  private bottomGfx = new Graphics();
  private biotaGfx = new Graphics();
  private bottomProfile: number[] = [];
  private creatures: ReefCreature[] = [];

  private w = 0;
  private h = 0;
  private pxPerMeter = 60;

  constructor() {
    this.container.addChild(this.bottomGfx, this.biotaGfx);
    this.buildBottomProfile();
    this.buildCreatures();
  }

  resize(w: number, h: number, pxPerMeter: number): void {
    this.w = w;
    this.h = h;
    this.pxPerMeter = pxPerMeter;
  }

  update(
    _state: SimState,
    camTopDepth: number,
    scrollX: number,
    sunLight: number,
    illumination: number
  ): void {
    if (!this.w || !this.h) return;
    const camBotDepth = camTopDepth + this.h / this.pxPerMeter;
    this.drawBottom(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
    this.drawBiota(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
  }

  // ---------------- Bottom geometry ----------------

  private buildBottomProfile(): void {
    const total = BOTTOM_LENGTH_M * SAMPLES_PER_M;
    const seed = 4.71;
    for (let i = 0; i < total; i++) {
      const u = i / SAMPLES_PER_M;
      const v =
        0.55 * Math.sin(u * 0.13 + seed) +
        0.30 * Math.sin(u * 0.34 + seed * 1.7) +
        0.15 * Math.sin(u * 0.81 + seed * 2.3);
      // [-1, 1] roughly; centred around 0 so undulation goes both ways.
      this.bottomProfile.push(v);
    }
  }

  /** Return the bottom depth in metres at world x (with wrap). */
  private bottomDepthAt(worldX_m: number): number {
    const u = ((worldX_m % BOTTOM_LENGTH_M) + BOTTOM_LENGTH_M) % BOTTOM_LENGTH_M;
    const idx = Math.floor(u * SAMPLES_PER_M) % this.bottomProfile.length;
    return BOTTOM_BASE_M + this.bottomProfile[idx] * BOTTOM_AMP_M;
  }

  private drawBottom(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sunLight: number,
    _illumination: number
  ): void {
    this.bottomGfx.clear();
    // If the bottom isn't on-screen at all, skip.
    const minBottom = BOTTOM_BASE_M - BOTTOM_AMP_M;
    if (camBotDepth < minBottom - 1) return;

    // Build the silhouette polygon: horizontal strip from left edge to right
    // edge, sampling the undulating profile and dropping down to camBotDepth.
    const samplesAcross = Math.max(40, Math.ceil(this.w / 12));
    const dx = this.w / samplesAcross;
    const pts: number[] = [];
    pts.push(0, this.h + 10);  // bottom-left of viewport (under the screen)
    for (let i = 0; i <= samplesAcross; i++) {
      const px = i * dx;
      // Convert screen-x to world-x — scrollX is in metres along the bottom strip.
      const worldX = scrollX + px / this.pxPerMeter;
      const bd = this.bottomDepthAt(worldX);
      const y = (bd - camTopDepth) * this.pxPerMeter;
      pts.push(px, y);
    }
    pts.push(this.w, this.h + 10);
    // Sand colour — warm tan, slightly desaturated by the water column overlay.
    this.bottomGfx.poly(pts).fill({ color: 0x8a6d3f, alpha: 0.96 });

    // Subtle ripple lines on the sand to imply texture.
    for (let i = 1; i < pts.length / 2 - 1; i += 6) {
      const x = pts[i * 2];
      const y = pts[i * 2 + 1];
      this.bottomGfx
        .moveTo(x, y + 2)
        .lineTo(x + 8, y + 4)
        .stroke({ color: 0xa28452, alpha: 0.35, width: 0.8 });
    }
  }

  // ---------------- Biota ----------------

  private buildCreatures(): void {
    const rand = mulberry32(0xc04a17ee);
    const push = (
      type: ReefCreatureType,
      count: number,
      depthRange: [number, number] | 'benthic',
      colorPool: number[],
      scaleRange: [number, number],
      hazard?: HazardContact['kind'],
    ) => {
      for (let i = 0; i < count; i++) {
        const benthic = depthRange === 'benthic';
        const xAlong = rand() * BOTTOM_LENGTH_M;
        let depth: number;
        if (benthic) {
          depth = this.bottomDepthAt(xAlong) - 0.3;
        } else {
          depth = depthRange[0] + rand() * (depthRange[1] - depthRange[0]);
        }
        this.creatures.push({
          depth,
          xAlong,
          phase: rand() * Math.PI * 2,
          type,
          litColor: colorPool[Math.floor(rand() * colorPool.length)],
          scale: scaleRange[0] + rand() * (scaleRange[1] - scaleRange[0]),
          benthic,
          hazard,
          index: this.creatures.length,
        });
      }
    };

    // Open water (0–18 m): light schools, mostly empty.
    push('school', 6, [4, 18], [0x9ecbe6, 0xa6d6e8, 0x7eb6d4], [0.7, 1.0]);

    // Canopy (18–25 m): butterflyfish + soft corals on tall stalks.
    push('butterfly', 14, [16, 26], [0xffd84d, 0xffae3a, 0xffe066], [0.7, 1.1]);
    push('school',    5, [16, 24], [0xc6ed8f, 0x8fd47a], [0.8, 1.2]);

    // Shelf benthic (25–32 m): dense coral colonies + anemones + parrotfish.
    push('hardcoral', 26, 'benthic', [0xd2773d, 0xc05a3e, 0xb89149], [0.9, 1.8],
         'fragile');  // hard corals snap on contact — protected habitat
    push('softcoral', 18, 'benthic', [0xc759a1, 0x9b6bc0, 0xe07cbd], [0.7, 1.3]);
    push('anemone',   14, 'benthic', [0xff8c69, 0xff5b9a, 0xffb46e], [0.6, 1.0]);
    push('urchin',    10, 'benthic', [0x2c2030, 0x1f1525, 0x382744], [0.5, 0.8],
         'stinging');  // pin-cushion of long sharp spines
    push('parrot',    12, [22, 30], [0x4cd6c4, 0x60d2a0, 0x4caaff], [0.9, 1.3]);
    push('grouper',    4, [24, 30], [0x6e503c, 0x836047, 0x55402f], [1.3, 1.8]);
  }

  private drawBiota(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sunLight: number,
    _illumination: number
  ): void {
    const g = this.biotaGfx;
    g.clear();
    const t = performance.now() * 0.001;

    for (const c of this.creatures) {
      // Where in screen space is this creature now?
      const u = (c.xAlong - scrollX) % BOTTOM_LENGTH_M;
      const uMod = ((u % BOTTOM_LENGTH_M) + BOTTOM_LENGTH_M) % BOTTOM_LENGTH_M;
      const x = uMod * this.pxPerMeter;
      // Wrap roaming — if it walks off-screen right, wrap to the left.
      const xWrapped = x % (BOTTOM_LENGTH_M * this.pxPerMeter);
      const screenX = xWrapped - Math.floor(xWrapped / this.w) * this.w;
      if (screenX < -60 || screenX > this.w + 60) continue;

      // Effective depth — pelagic creatures drift up/down a little with phase.
      const effDepth = c.benthic ? c.depth : c.depth + Math.sin(t * 0.6 + c.phase) * 0.6;
      if (effDepth < camTopDepth - 1 || effDepth > camBotDepth + 1) continue;
      const y = (effDepth - camTopDepth) * this.pxPerMeter;
      const color = c.litColor;
      const alpha = 0.95;
      const phase = c.phase + t * (c.benthic ? 0.4 : 1.2);

      switch (c.type) {
        case 'school': {
          const n = 9;
          for (let i = 0; i < n; i++) {
            const a = i * 0.7 + phase;
            const fx = screenX + Math.cos(a) * 16 * c.scale;
            const fy = y + Math.sin(a * 1.3) * 9 * c.scale;
            const s = 2.5 * c.scale;
            g.poly([fx - s, fy, fx + s, fy - s * 0.6, fx + s, fy + s * 0.6])
              .fill({ color, alpha });
          }
          break;
        }
        case 'butterfly': {
          // Disc-shaped fish with a vertical fin stripe.
          const r = 5 * c.scale;
          const dx = Math.sin(phase) > 0 ? 1 : -1;
          g.circle(screenX, y, r).fill({ color, alpha });
          g.poly([
            screenX + r * 0.6 * dx, y,
            screenX + (r + 4) * dx, y - r * 0.5,
            screenX + (r + 4) * dx, y + r * 0.5,
          ]).fill({ color, alpha: alpha * 0.9 });
          // dark vertical band
          g.rect(screenX - 1, y - r * 0.7, 2, r * 1.4)
            .fill({ color: 0x1c1820, alpha: 0.5 });
          break;
        }
        case 'parrot': {
          // Elongated fish, blunt nose, broad tail.
          const w = 18 * c.scale, h2 = 5 * c.scale;
          const dir = Math.sin(phase * 0.5) > 0 ? 1 : -1;
          g.poly([
            screenX - (w * 0.5) * dir, y,
            screenX,                  y - h2,
            screenX + (w * 0.5) * dir, y,
            screenX,                  y + h2,
          ]).fill({ color, alpha });
          g.poly([
            screenX + (w * 0.5) * dir, y,
            screenX + (w * 0.5 + h2 * 1.4) * dir, y - h2 * 1.1,
            screenX + (w * 0.5 + h2 * 1.4) * dir, y + h2 * 1.1,
          ]).fill({ color, alpha: alpha * 0.85 });
          break;
        }
        case 'grouper': {
          // Larger, oblong body with a darker accent stripe.
          const w = 26 * c.scale, h2 = 9 * c.scale;
          const dir = Math.sin(phase * 0.3) > 0 ? 1 : -1;
          g.poly([
            screenX - (w * 0.45) * dir, y,
            screenX - (w * 0.1) * dir,  y - h2 * 0.95,
            screenX + (w * 0.5) * dir,  y,
            screenX - (w * 0.1) * dir,  y + h2 * 0.95,
          ]).fill({ color, alpha });
          // Dorsal band
          g.rect(screenX - w * 0.35 * dir, y - h2 * 0.75, w * 0.6, 2)
            .fill({ color: 0x2c1f15, alpha: 0.45 });
          break;
        }
        case 'anemone': {
          // Stubby base with wavy tentacles
          const baseR = 5 * c.scale;
          g.ellipse(screenX, y + baseR * 0.4, baseR, baseR * 0.55)
            .fill({ color: 0x6e4040, alpha });
          const arms = 9;
          for (let i = 0; i < arms; i++) {
            const a = -Math.PI + (i / (arms - 1)) * Math.PI + Math.sin(phase + i) * 0.08;
            const ex = screenX + Math.cos(a) * baseR * 1.6;
            const ey = y + Math.sin(a) * baseR * 1.0;
            g.moveTo(screenX, y - 1)
              .lineTo(ex, ey)
              .stroke({ color, alpha, width: 1.2 });
          }
          break;
        }
        case 'softcoral': {
          // Tall feathery branches.
          const trunkH = 18 * c.scale;
          const baseY = y;
          g.moveTo(screenX, baseY)
            .lineTo(screenX + Math.sin(phase) * 2, baseY - trunkH)
            .stroke({ color, alpha, width: 2 });
          for (let i = 1; i < 6; i++) {
            const ty = baseY - (trunkH / 6) * i;
            const offs = Math.sin(phase + i * 0.7) * 1.5;
            const armLen = 6 * c.scale * (1 - i / 8);
            g.moveTo(screenX + offs, ty)
              .lineTo(screenX + offs - armLen, ty - 2)
              .stroke({ color, alpha: alpha * 0.85, width: 1 });
            g.moveTo(screenX + offs, ty)
              .lineTo(screenX + offs + armLen, ty - 2)
              .stroke({ color, alpha: alpha * 0.85, width: 1 });
          }
          break;
        }
        case 'hardcoral': {
          // Branching coral — bunch of upward spires.
          const baseY = y;
          const baseR = 8 * c.scale;
          for (let i = 0; i < 4; i++) {
            const ox = (i - 1.5) * baseR * 0.5;
            const top = baseY - (8 + i * 2) * c.scale;
            g.moveTo(screenX + ox, baseY)
              .lineTo(screenX + ox * 0.7, top)
              .stroke({ color, alpha, width: 2.4 });
            // small bud
            g.circle(screenX + ox * 0.7, top, 2 * c.scale).fill({ color, alpha });
          }
          // base lobe
          g.ellipse(screenX, baseY + 1, baseR, 3 * c.scale)
            .fill({ color, alpha: alpha * 0.85 });
          break;
        }
        case 'urchin': {
          // Dark spiky ball.
          const r = 4 * c.scale;
          g.circle(screenX, y, r).fill({ color, alpha });
          const spines = 10;
          for (let i = 0; i < spines; i++) {
            const a = (i / spines) * Math.PI * 2;
            const sx = screenX + Math.cos(a) * r * 1.8;
            const sy = y + Math.sin(a) * r * 1.8;
            g.moveTo(screenX, y).lineTo(sx, sy)
              .stroke({ color, alpha: alpha * 0.85, width: 0.9 });
          }
          break;
        }
      }
    }
  }

  // ---------------- Scene API ----------------

  /** Hazards within `range_m` of the diver. */
  getHazardContacts(scrollX_m: number, diverDepth_m: number, range_m: number): HazardContact[] {
    const diverWorldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    const out: HazardContact[] = [];
    for (const c of this.creatures) {
      if (!c.hazard) continue;
      // Wrap-aware horizontal distance.
      let dx = c.xAlong - diverWorldX;
      const half = BOTTOM_LENGTH_M / 2;
      dx = ((dx + half) % BOTTOM_LENGTH_M + BOTTOM_LENGTH_M) % BOTTOM_LENGTH_M - half;
      const dy = c.depth - diverDepth_m;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist <= range_m) {
        const label = c.type === 'urchin'    ? 'URCHIN'
                    : c.type === 'hardcoral' ? 'FRAGILE CORAL'
                    : c.type.toUpperCase();
        out.push({
          kind: c.hazard,
          label,
          id: `${c.hazard}:${c.index}`,
          severity: 1 - dist / range_m,
        });
      }
    }
    return out;
  }

  /** Bottom depth at the diver's worldX — drives silt-stir proximity. */
  getBottomDepthAt(scrollX_m: number): number | null {
    const diverWorldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    return this.bottomDepthAt(diverWorldX);
  }

  /** Coral reef has only a sand bottom — no overhead, no solid colliders. */
  getDepthLimitsAt(worldX_m: number, _currentDepth_m: number = 0) {
    return { floor_m: this.bottomDepthAt(worldX_m) - 0.25, ceiling_m: 0 };
  }

  zoneInfoAt(depth: number): ZoneInfo {
    let label: string;
    let zoneStart: number;
    let zoneEnd: number;
    let note: string;
    if (depth < 18) {
      label = 'OPEN WATER';
      zoneStart = 0; zoneEnd = 18;
      note = 'mid-water · light pelagics';
    } else if (depth < 25) {
      label = 'CORAL CANOPY';
      zoneStart = 18; zoneEnd = 25;
      note = 'butterflyfish · soft coral';
    } else if (depth < 32) {
      label = 'CORAL SHELF';
      zoneStart = 25; zoneEnd = 32;
      note = 'hard coral · anemones · parrotfish';
    } else {
      label = 'SAND BOTTOM';
      zoneStart = 32; zoneEnd = 200;
      note = 'sandy plain · sparse';
    }
    let pop = 0;
    const types = new Set<string>();
    for (const c of this.creatures) {
      const d = c.depth;
      if (d >= zoneStart && d < zoneEnd) {
        pop += c.type === 'school' ? 9 : 1;  // schools draw 9 per record
        types.add(c.type);
      }
    }
    return { label, population: pop, variety: types.size, note };
  }
}

// ---- helpers ----

// Small deterministic RNG — keeps creature placement stable across resizes.
function mulberry32(seed: number) {
  let s = seed | 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// `clamp` is re-used to silence the unused-import lint on `physics` when this
// file is included in builds that strip dead code.
void clamp;
