/**
 * GenScene spec — a serializable JSON description of a dive site.
 *
 * This is the schema an LLM emits (or a hand-authored default fills) to
 * describe a complete underwater scene that the renderer can play back
 * without any pixel-level instructions.
 *
 * Design intent
 * -------------
 * The LLM should think in *semantic* terms (a school of bait fish at 12 m,
 * a brown ray on the sand) rather than draw calls. Keep the surface small
 * and stable so prompts stay portable across model upgrades.
 */

import type { HazardContact } from './types';

export type CreatureArchetype =
  | 'school'        // tight ball of small fish
  | 'fish'          // single mid-sized fish (oblong body + tail)
  | 'eel'           // long sinuous body, peeks out of crevices
  | 'urchin'        // spiked benthic ball
  | 'coral'         // branching benthic colony
  | 'anemone'       // tentacle cluster
  | 'jelly'         // pelagic translucent bell
  | 'ray';          // flat triangular benthic / mid-water cruiser

export interface ZoneSpec {
  /** Top of the zone (inclusive), m. */
  startDepth_m: number;
  /** Bottom of the zone (exclusive), m. */
  endDepth_m: number;
  /** Display label, e.g. "OPEN WATER", "MESOPHOTIC". */
  label: string;
  /** Optional atmospheric note shown under the label. */
  note?: string;
}

export interface BottomSpec {
  /** Mean depth of the bottom strip, m. */
  baseDepth_m: number;
  /** Vertical amplitude of the gentle undulation, m. */
  amplitude_m: number;
  /** Wavelength of the undulation, m. */
  period_m: number;
  /** Strip length (wraps), m. */
  lengthM: number;
  /** Base fill colour (0xRRGGBB). */
  color: number;
  /** Optional accent colour for scatter dots / debris. */
  accentColor?: number;
}

export interface CreatureSpec {
  archetype: CreatureArchetype;
  /** How many to place. */
  count: number;
  /** Depth band the creatures are placed within, m. */
  depthRange: [number, number];
  /** Fallback to BottomSpec.lengthM if omitted. */
  xRange?: [number, number];
  /** Scale jitter; default [0.8, 1.2]. */
  scaleRange?: [number, number];
  /** One of these is picked per creature (0xRRGGBB). */
  colors: number[];
  /** If true, creature sticks to the bottom at its xAlong. */
  benthic?: boolean;
  /** Hazard kind on contact. */
  hazard?: HazardContact['kind'];
  /** Label used in the hazard banner. */
  hazardLabel?: string;
}

export interface SceneSpec {
  /** Stable id — primarily a hash/slug for caching. */
  id: string;
  /** HUD label. */
  label: string;
  /** Depth zones, sorted shallow→deep. */
  zones: ZoneSpec[];
  /** Optional flat bottom; omit for open-water scenes (no silt-stir). */
  bottom?: BottomSpec;
  /** Biota to scatter. */
  creatures: CreatureSpec[];
  /** Free-form prompt that produced this spec — round-trips for editing. */
  prompt?: string;
}

