/**
 * JSON schema text suitable for prompting an LLM. Kept here as a single
 * source of truth so the prompt-building code and the parser can stay in
 * sync.
 */
export const SCENE_SPEC_SCHEMA_HINT = `\
Emit ONLY a single JSON object matching this TypeScript type, no commentary:

type SceneSpec = {
  id: string;                  // short slug
  label: string;               // HUD title in upper-case, <24 chars
  zones: Array<{               // sorted shallow -> deep, contiguous
    startDepth_m: number;
    endDepth_m: number;
    label: string;             // e.g. "REEF CREST", "MESOPHOTIC"
    note?: string;
  }>;
  bottom?: {                   // omit for open-water (no sand floor)
    baseDepth_m: number;       // 5..60
    amplitude_m: number;       // 0..3
    period_m: number;          // 8..40
    lengthM: number;           // 200..400
    color: number;             // 0xRRGGBB
    accentColor?: number;
  };
  creatures: Array<{
    archetype: 'school'|'fish'|'eel'|'urchin'|'coral'|'anemone'|'jelly'|'ray';
    count: number;             // 1..30 per entry
    depthRange: [number, number];
    xRange?: [number, number];
    scaleRange?: [number, number];
    colors: number[];          // 0xRRGGBB, 1..4 entries
    benthic?: boolean;
    hazard?: 'venomous'|'stinging'|'fragile';
    hazardLabel?: string;
  }>;
};

Rules:
- Numbers are plain JS literals (you may use 0x… hex for colours).
- Total creature count across entries: 20..80.
- All depths consistent with each other (no creatures below the bottom).
- Zones must cover 0..99 with no gaps.`;
