/**
 * Tiny OS / browser-platform detection used to pick UX defaults.
 *
 * `navigator.platform` is technically deprecated, but the User-Agent
 * Client Hints replacement (`navigator.userAgentData`) is still not
 * available on Safari / Firefox at the time of writing. Falling back
 * to the user-agent string keeps detection consistent across browsers.
 */

export type OSKind = 'mac' | 'windows' | 'linux' | 'other';

export function detectOS(): OSKind {
  // `navigator.userAgentData.platform` is the modern API; only Chromium
  // exposes it today, but it returns a clean lowercase name.
  const uaData = (navigator as unknown as {
    userAgentData?: { platform?: string };
  }).userAgentData;
  if (uaData?.platform) {
    const p = uaData.platform.toLowerCase();
    if (p.startsWith('mac')) return 'mac';
    if (p.startsWith('win')) return 'windows';
    if (p.startsWith('linux')) return 'linux';
  }
  // Fallback — userAgent string. We probe BOTH userAgent and the legacy
  // `navigator.platform` so we still resolve correctly on iPadOS, which
  // masquerades as Mac in userAgentData.
  const probe = (navigator.userAgent || '') + ' ' + (navigator.platform || '');
  if (/Mac|iPhone|iPad|iPod/.test(probe)) return 'mac';
  if (/Win/.test(probe)) return 'windows';
  if (/Linux|X11/.test(probe)) return 'linux';
  return 'other';
}
