import { applyAll, getLang, setLang, t, type StringKey } from './i18n';

export class WelcomeScreen {
  private el: HTMLElement;
  private dismissed = false;

  constructor(private onDismiss: () => void) {
    this.el = document.getElementById('welcomeScreen') as HTMLElement;

    // Populate all data-i18n elements with the persisted language immediately.
    applyAll();
    this.updateLangBtn();

    document.getElementById('langToggle')?.addEventListener('click', () => {
      setLang(getLang() === 'en' ? 'zh' : 'en');
      this.updateLangBtn();
    });

    document.getElementById('welcomeStart')?.addEventListener('click', () => this.dismiss());

    window.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' && !this.dismissed) this.dismiss();
    }, { once: false });

    // Trigger stagger reveal after one frame so CSS transitions fire.
    requestAnimationFrame(() => {
      this.el.querySelectorAll<HTMLElement>('.ws-section').forEach((sec, i) => {
        sec.style.transitionDelay = `${i * 0.08 + 0.05}s`;
        sec.classList.add('ws-in');
      });
    });
  }

  private updateLangBtn(): void {
    const btn = document.getElementById('langToggle');
    if (btn) btn.textContent = t('lang_btn' as StringKey);
  }

  private dismiss(): void {
    if (this.dismissed) return;
    this.dismissed = true;
    this.el.classList.add('ws-out');
    this.el.addEventListener('transitionend', () => {
      this.el.style.display = 'none';
      this.onDismiss();
    }, { once: true });
  }
}
