// ---- Breathing curves — VT1/VT2 physiological model ----
// arousal ∈ [0,1] derived from max(co2_stress, exertion).
//
//   RR(arousal)  rises slowly to VT1 (~0.4), then climbs hard above VT2 (~0.7)
//                12 → 20 → 36 bpm
//   TV(arousal)  rises faster than RR up to VT2, then plateaus / slightly drops
//                0.8 → 2.2 → ~1.9 L  (efficient breathing breaks down at peak)
//
// References: minute ventilation V_E = RR·TV. VT2 marks transition where
// RR begins a non-linear climb while TV levels off / decreases.
export const REST_BREATH_RATE_BPM       = 12;
export const VT1_BREATH_RATE_BPM        = 20;
export const PEAK_BREATH_RATE_BPM       = 36;
export const REST_TIDAL_VOLUME_L        = 0.8;
export const VT2_TIDAL_VOLUME_L         = 2.2;
export const PEAK_TIDAL_VOLUME_L        = 1.9;
export const VT1_AROUSAL                = 0.40;
export const VT2_AROUSAL                = 0.70;

// ---- Horizontal motion / kicking ----
// Real-world references (recreational + tech diving):
//   Relaxed frog-kick cruise : ~0.3-0.5 m/s
//   Sustained working pace   : ~0.6 m/s
//   Sprint flutter           : ~1.0-1.2 m/s briefly
// Cycle: each power-stroke imparts an impulse, then quadratic drag bleeds it.
export const KICK_IMPULSE_MPS    = 0.55;  // m/s velocity bump per power-stroke
// Realistic tech-diving frog-kick cadence is 30-40/min (relaxed) to ~50-60/min
// (aggressive). 1.0s refractory caps at 60 kicks/min — past that the kick
// becomes ineffective and you'd switch to flutter.
export const KICK_REFRACTORY_S   = 1.00;
// Per-kick bump applied to `exertionTarget`. `exertion` then lerps toward the
// target with a ~EXERTION_RISE_TAU_S time constant, so a single kick no
// longer causes an instant jump in ventilation.
export const KICK_EXERTION_COST  = 0.020;
export const KICK_RAPID_BONUS    = 0.040;
export const CD_A_HORIZ          = 0.40;  // horizontal Cd·A (streamlined trim)

// Exertion dynamics
export const EXERTION_TAU_S      = 28;    // target recovery half-time (s)
export const EXERTION_RISE_TAU_S = 4.0;   // exertion → target follow time-constant (s)

// CO₂ dynamics — target-seeking model.
//
// While breathing, alveolar PaCO₂ tracks toward a setpoint determined by
// metabolic demand. At rest the setpoint sits at CO2_REST (40 mmHg). As
// exertion climbs, the setpoint shifts up by CO2_EXERTION_SETPOINT_GAIN mmHg
// at full exertion, modelling the small physiological rise during heavy work
// and the panic-breathing CO₂-drive feedback loop.
//
// Ventilation does NOT independently scrub CO₂ — it just controls how fast
// we approach the setpoint. At higher minute ventilation (working harder)
// the time constant shrinks, so the diver settles into the new setpoint
// quickly rather than over-/under-shooting it. This matches real physiology
// where ventilation and CO₂ production stay tightly coupled.
//
// Breath-hold is the exception: no ventilation, so CO₂ rises monotonically
// at CO2_APNEA_RATE × metabolic-multiplier — that's the only path to the
// "urge / breakpoint / danger" thresholds during a hold.
export const CO2_EXERTION_SETPOINT_GAIN = 8;   // mmHg shift at full exertion
export const CO2_TAU_REST_S             = 6.0; // setpoint approach τ at rest (s)
/** Multiplier on CO₂ production during breath-hold. Higher exertion = faster
 *  apneic rise (your body is making more CO₂, no ventilation to clear it). */
export const CO2_PROD_EXERTION_GAIN = 3.0;
// Hard-kick speed cap so spamming kicks doesn't make the diver superhuman.
export const MAX_SUSTAINED_SPEED = 1.2;   // m/s

// ---- BCD ----
// Rates are AT-DEPTH litres per second. A balanced first-stage regulator
// outputs at ambient pressure, so the *physical* (at-depth) flow rate is
// roughly constant with depth. The surface-equivalent gas added per second
// = BCD_INFLATE_RATE × P_amb_ATA — handled in physics.ts step().
//
//   4 L/s inflate ≈ a typical recreational LP inflator
//  12 L/s dump    ≈ shoulder dump valve fully open
export const BCD_INFLATE_RATE = 4;
export const BCD_DUMP_RATE = 12;

/** Max safe ascent rate per Jablonski Ch. 8.9: 30 ft/min ≈ 10 m/min = 0.167 m/s. */
export const MAX_ASCENT_RATE_MPS = 10 / 60;

// ---- Underwater light attenuation (Beer-Lambert, clear ocean) ----
// I(z) = I₀ · exp(-K_LIGHT · z)
//   At  10 m : ~55 % remaining
//   At  30 m : ~17 % (upper-mesophotic boundary)
//   At  60 m : ~ 3 % (lower-mesophotic boundary)
//   At 100 m : ~0.25 %
//   At 150 m : aphotic
export const K_LIGHT = 0.06;
export const APHOTIC_DEPTH = 150;
/** Useful penetration of a HID primary light underwater (m). */
export const PRIMARY_LIGHT_RANGE_M = 6;

// ---- Depth-zone biota breakpoints (mesophotic-reef literature, NOAA) ----
export const ZONE_SHALLOW_MAX     = 30;   // 0-30 m : shallow tropical reef
export const ZONE_UPPER_MESO_MAX  = 60;   // 30-60 m : upper mesophotic
export const ZONE_LOWER_MESO_MAX  = 150;  // 60-150 m : lower mesophotic
