import './styles.css';
import { Application, Container } from 'pixi.js';
import { createState, resetState } from './state';
import { ambientPressureAtm, bcdVolumeAtDepthL, sac5sLpm, step } from './physics';
import { setupInput } from './input';
import { WaterScene } from './scene/water';
import { Scenery } from './scene/scenery';
import { DiverSprite } from './scene/diver';
import { Bubbles, Particulates } from './scene/particles';
import { ZoneOverlay } from './scene/zoneOverlay';
import { SCENE_CATALOG, createScene } from './scene/factory';
import type { Scene } from './scene/types';
import { HUD } from './hud';
import { SetupModal } from './setup';
import { SettingsModal } from './settings';
import { WelcomeScreen } from './welcome';
import { runSmokeTest } from './divecomp/engine/smokeTest';
import { DiveComputer } from './divecomp/engine';
import { DiveWatchPanel } from './divecomp/panel';
import { defaultRig } from './divecomp/equipment';
import { Perdix2Watch } from './divecomp/skins/perdix2';
import { Notifications } from './divecomp/notifications';
import { ALL_MODES, threeGasMode, type DiveMode } from './divecomp/modes';
import { DIVECOMP_DEFAULTS, resolveVisibility } from './divecomp/config/defaults';
import { Telemetry, TelemetryPanel } from './divecomp/telemetry';
import { GenScenePanel } from './divecomp/genscene/GenScenePanel';
import { GenScene } from './scene/genScene';
import { ImmersiveToggle } from './scene/immersiveToggle';
import { t } from './i18n';
import { maybeStartUiSmoke } from './uiSmoke';
import { getAssetRegistry } from './assets';
import {
  MissionHud,
  MissionRegistry,
  defaultLevelFor,
  type LevelSpec,
} from './missions';

// Opt-in engine sanity check — open the page with `?smoke=1` to log a
// canonical 30 m air dive and an 18 m EAN32 recreational dive to the console.
if (new URLSearchParams(location.search).has('smoke')) {
  runSmokeTest();
}

async function main() {
  const host = document.getElementById('water-host') as HTMLDivElement;
  const canvasMount = document.getElementById('water-canvas') as HTMLDivElement;

  // Load sprite atlases in parallel with the Pixi app boot. Order
  // matters: placeholder first, then Ansimuz — the second pack
  // overrides any archetype it has a better sprite for. Failures
  // are non-fatal; scenes fall back to procedural drawing for any
  // archetype that didn't load.
  const registry = getAssetRegistry();
  const assetsReady = registry
    .loadPlaceholderPack()
    .then(() => registry.loadAnsimuzPack())
    .catch((err) => console.warn('[assets] pack load failed:', err));

  const app = new Application();
  await app.init({
    resizeTo: canvasMount,
    background: 0x000000,
    backgroundAlpha: 0,
    antialias: true,
    resolution: Math.min(2, window.devicePixelRatio || 1),
    autoDensity: true,
  });
  canvasMount.appendChild(app.canvas);

  // Scene graph. Active scene is hot-swappable via the picker top-right or
  // via URL param `?scene=cliff|coral|wreck` (kept for deep-linking).
  const water = new WaterScene(host);
  const SCENE_KEY = 'ppb_scene';
  const initialSceneId =
    new URLSearchParams(location.search).get('scene') ??
    localStorage.getItem(SCENE_KEY) ??
    'cliff';
  let scenery: Scene = createScene(initialSceneId);
  const particulates = new Particulates();
  const diver = new DiverSprite();
  const bubbles = new Bubbles();
  const zoneOverlay = new ZoneOverlay();
  host.appendChild(zoneOverlay.el);

  // Cached viewport dimensions so hot-swapping a scene can resize it immediately.
  let curW = 0, curH = 0, curPxPerMeter = 60;

  // Immersive-mode toggle — sits alone in the top-right corner; scene
  // selection is now part of the New Dive flow (inside SetupModal),
  // not a runtime control. Keyboard shortcut: `I`.
  const immersive = new ImmersiveToggle();
  immersive.el.classList.add('imm-standalone');
  host.appendChild(immersive.el);

  /**
   * Currently active scene id — used only to decide which scene
   * `swapScene` should pick during a New Dive. The runtime selector
   * widget is gone, so there's no need for a stateful component;
   * a single variable is enough.
   */
  let activeSceneId: string = scenery.id;

  // Scenario controls (visibility / haze tint) are no longer rendered in
  // the UI per UX request. `water.setVisibility(level, tintColor)` is
  // still callable from `window.__dc.water` for debugging / scripted
  // scenarios. Default visibility = 1 (clear).

  // GEN-scene prompt panel — only attached while the GEN scene is active.
  // Its `onApply` calls `genScene.applySpec(spec)` to hot-swap the contents
  // without rebuilding the Pixi container hierarchy.
  const genPanel = new GenScenePanel({
    onApply: (spec) => {
      if (scenery instanceof GenScene) scenery.applySpec(spec);
    },
    initialPrompt: scenery instanceof GenScene
      ? (scenery.getSpec().prompt ?? '')
      : '',
  });
  if (scenery instanceof GenScene) host.appendChild(genPanel.el);

  // Mission system — picks up the default LevelSpec for the active scene,
  // drives training-range / dive-limit overlays on the water layer, and
  // pumps each Mission with the latest physics state.
  const missionRegistry = new MissionRegistry();
  const missionHud = new MissionHud();
  host.appendChild(missionHud.el);

  function applyLevel(level: LevelSpec | null): void {
    missionRegistry.loadLevel(level);
    water.setTrainingRange(level?.trainingRange ?? null);
    water.setFineDiveLimit(level?.fineDiveLimit_m ?? null);
    // Render once so the HUD reflects the new level immediately (the
    // ticker will keep refreshing it from now on).
    missionHud.render(level, missionRegistry.snapshot());
  }
  applyLevel(defaultLevelFor(scenery.id));

  /** Hot-swap the active scene without disturbing water / particles / diver. */
  function swapScene(id: string): void {
    if (id === scenery.id) return;
    const oldContainer = scenery.container;
    const idx = world.getChildIndex(oldContainer);
    world.removeChildAt(idx);
    scenery = createScene(id);
    scenery.resize(curW, curH, curPxPerMeter);
    world.addChildAt(scenery.container, idx);
    activeSceneId = id;
    try { localStorage.setItem(SCENE_KEY, id); } catch { /* quota */ }
    setupRef?.setSelectedScene(id);
    applyLevel(defaultLevelFor(id));
    // Show / hide the GEN panel based on the active scene.
    if (scenery instanceof GenScene) {
      if (!genPanel.el.isConnected) host.appendChild(genPanel.el);
      genPanel.setPrompt(scenery.getSpec().prompt ?? '');
    } else if (genPanel.el.isConnected) {
      genPanel.el.remove();
    }
  }

  // z-order:
  //   water.container (gradient + caustics + grid)
  //     → scenery (cliff + biota; before darkness so they get dimmed)
  //     → water.overlay (darkness + light cone + target band)
  //     → particulates → diver → bubbles
  //     → water.foreground (visibility haze — dims diver + bubbles too)
  const world = new Container();
  world.addChild(
    water.container,
    scenery.container,
    water.overlay,
    particulates.container,
    diver.container,
    bubbles.container,
    water.foreground
  );
  app.stage.addChild(world);

  /**
   * Per-meter pixel density. Pinned to whatever the very first layout
   * pass produced so toggling immersive mode (or hiding any other
   * chrome) reveals MORE world rather than zooming the diver larger.
   * Window resize also keeps the density — a wider/taller window just
   * shows more of the scene.
   */
  let basePxPerMeter: number | null = null;
  /**
   * Read the mount element's CSS dimensions and resize EVERYTHING from
   * those numbers — Pixi's renderer backing store, our cached layout
   * vars, and every scene's internal w/h. Reading from
   * `canvasMount.getBoundingClientRect()` (rather than `app.renderer`)
   * is critical: Pixi's own `resizeTo` listener and our ResizeObserver
   * both observe `canvasMount`, but they fire in undefined order. If
   * `layout()` runs first and reads `app.renderer.width`, it gets the
   * *stale* size — the canvas then stays at its old backing-store
   * resolution while CSS stretches it to fill the new box. That's the
   * anamorphic stretch the user was seeing in immersive mode.
   *
   * Explicitly resizing the renderer ourselves makes the ordering
   * irrelevant: whichever observer wins, the renderer + scene state
   * end up consistent in a single pass.
   */
  function layout() {
    const rect = canvasMount.getBoundingClientRect();
    const w = Math.max(1, Math.round(rect.width));
    const h = Math.max(1, Math.round(rect.height));
    // Drive Pixi from the CSS size — this updates the canvas backing
    // store AND the internal renderer.width/height in one call.
    app.renderer.resize(w, h);
    if (basePxPerMeter == null || basePxPerMeter <= 0) {
      // First layout — use the legacy "14 m fit vertically" rule to pick
      // a sensible scale, then lock it.
      basePxPerMeter = h / 14;
    }
    curW = w; curH = h; curPxPerMeter = basePxPerMeter;
    water.resize(w, h, basePxPerMeter);
    scenery.resize(w, h, basePxPerMeter);
    particulates.resize(w, h);
    bubbles.resize(w, h);
    diver.setPosition(water.diverScreenX(), water.diverScreenY());
  }
  layout();
  window.addEventListener('resize', () => requestAnimationFrame(layout));
  // ResizeObserver catches CSS-driven container changes (e.g. immersive
  // mode hides the HUD strip → the .water-canvas div grows taller). We
  // run layout() ourselves rather than relying on Pixi's `resizeTo`
  // because of the race condition described above.
  if (typeof ResizeObserver !== 'undefined') {
    const ro = new ResizeObserver(() => requestAnimationFrame(layout));
    ro.observe(canvasMount);
  }

  // Sim wiring
  const state = createState();
  const input = setupInput(state);

  // Tank rig — 3-cylinder tech-light setup: backmount Air + EAN50 stage + O₂ stage.
  // Active tank feeds the regulator; switching is bound to number keys below.
  // Created before the HUD + setup modal so they can both read/edit it.
  const rig = defaultRig();

  // HUD takes the rig + a gas-switch callback so clicking a tank chip in the
  // TANK panel routes through the same MOD-aware switcher the number keys use.
  // gasSwitchByIndex is defined further down — forward-referenced via closure.
  const hud = new HUD(rig, (idx) => gasSwitchByIndex(idx));

  // MenuModal (was SettingsModal). `setup` is created further down and
  // closed over by these callbacks — we just declare a placeholder then
  // backfill the closure target once the SetupModal exists.
  let setupRef: SetupModal | null = null;
  const settings = new SettingsModal(state, {
    onNewDive: () => {
      // Reset the simulation and re-open gear as a fresh first-run.
      // Scene selection happens inside the gear modal — no separate widget
      // to unlock here.
      resetState(state);
      missionRegistry.reset();
      missionHud.render(missionRegistry.getLevel(), missionRegistry.snapshot());
      immersive.set(false);
      setupRef?.open({ initial: true });
    },
    isDiveActive: () => state.diveStartT !== null,
  });

  // Dive mode — Air / Nitrox / 3GasNx / Gauge. Default to the most flexible
  // (3GasNx) since the default rig has 3 tanks. Press `M` to cycle modes.
  let currentMode: DiveMode = threeGasMode;

  // Silt-driven visibility drop — when the diver is stirring sand, the
  // effective visibility falls (faster rise than recovery). Independent
  // of any user-set baseline so we can compose with scripted visibility
  // changes later.
  let siltVisDrop = 0;            // 0 = clear, 1 = max silt obscuration
  const SILT_RISE_TAU_S = 0.4;
  const SILT_FALL_TAU_S = 3.5;
  /** Cap so even max silt isn't a total blackout (you can still see your gauges). */
  const SILT_MAX_DROP = 0.85;
  const SILT_HAZE_COLOR = 0x2a2018;

  // Hazard contact bookkeeping — per-id cooldown so a stationary diver doesn't
  // get spammed every frame the urchin is in range.
  const hazardCooldown = new Map<string, number>();
  const HAZARD_COOLDOWN_MS = 4500;
  function handleHazardContact(h: import('./scene/types').HazardContact): void {
    const kind = h.kind;
    let banner: string;
    let bannerKind: 'info' | 'warn' | 'danger';
    if (kind === 'venomous') {
      banner = `⚠ ${h.label} STING · CO₂ surge`;
      bannerKind = 'danger';
      // Sharp CO2 + stress bump — venomous sting causes rapid breathing.
      state.co2 = Math.min(100, state.co2 + 6);
      state.exertionTarget = Math.min(1, state.exertionTarget + 0.25);
    } else if (kind === 'stinging') {
      banner = `⚠ ${h.label} · stinging contact`;
      bannerKind = 'warn';
      state.co2 = Math.min(100, state.co2 + 2);
      state.exertionTarget = Math.min(1, state.exertionTarget + 0.10);
    } else {
      // fragile — diver damaged the habitat, not the other way round.
      banner = `${h.label} · do not touch protected coral`;
      bannerKind = 'warn';
    }
    notifications.show({ text: banner, kind: bannerKind, durationMs: 2400, key: `hz:${h.id}` });
  }

  // Telemetry — time-series collector + draggable debug panel.
  // Hidden by default; press `Y` to toggle (T is reserved for future use).
  const telemetry = new Telemetry(/* windowMs */ 10 * 60 * 1000);
  telemetry.registerSeries({ id: 'depth',    label: 'Depth',         unit: 'm',     precision: 1, color: '#38d6e6' });
  telemetry.registerSeries({ id: 'velocity', label: 'Velocity',      unit: 'm/s',   precision: 2, color: '#ffb547' });
  telemetry.registerSeries({ id: 'lung',     label: 'Lung volume',   unit: 'L',     precision: 2, color: '#7adfff' });
  telemetry.registerSeries({ id: 'bcd',      label: 'BCD @ depth',   unit: 'L',     precision: 1, color: '#a279ff' });
  telemetry.registerSeries({ id: 'co2',      label: 'CO₂',           unit: 'mmHg',  precision: 0, color: '#ff8a5b' });
  telemetry.registerSeries({ id: 'ndl',      label: 'NDL',           unit: 'min',   precision: 0, yRange: [0, 99], color: '#6ee29a' });
  telemetry.registerSeries({ id: 'ceiling',  label: 'Ceiling',       unit: 'm',     precision: 1, color: '#ff4242' });
  telemetry.registerSeries({ id: 'gf99',     label: 'GF99',          unit: '%',     precision: 0, color: '#ff5b9a' });
  telemetry.registerSeries({ id: 'surfGf',   label: 'SurGF',         unit: '%',     precision: 0, color: '#ffe066' });
  telemetry.registerSeries({ id: 'cns',      label: 'CNS',           unit: '%',     precision: 0, color: '#ff4a4a' });
  telemetry.registerSeries({ id: 'density',  label: 'Gas density',   unit: 'g/L',   precision: 2, color: '#4be0e8' });
  telemetry.registerSeries({ id: 'tankP',    label: 'Active tank',   unit: 'bar',   precision: 0, color: '#38d6e6' });
  telemetry.registerSeries({ id: 'sac',      label: 'SAC 5s',        unit: 'L/min', precision: 1, color: '#ffb547' });
  const telemPanel = new TelemetryPanel(telemetry);
  telemPanel.syncSeries();

  // 10 Hz sample rate — high enough for smooth charts, low enough to keep
  // the rolling window small (10 min × 10 Hz × ~13 series ≈ 78 k samples).
  // Telemetry sample rate — 2 Hz keeps charts smooth without burning CPU on
  // a slow-changing physical signal (depth, GF, CNS all change on the order
  // of seconds-to-minutes).
  const TELEM_RECORD_MS = 500;
  let lastTelemRecordMs = 0;

  // Dive computer (Perdix/Teric-style logic; engine = Bühlmann ZH-L16C + GF).
  // Engine's active gas mirrors the rig's active tank — see listener below.
  const diveComp = new DiveComputer({
    initialGases: rig.enabledGases(),
    activeGasId: rig.active.gas.id,
  });
  rig.addListener((e) => {
    if (e.kind === 'activate') {
      diveComp.setActiveGas(e.tank.gas.id);
    } else if (e.kind === 'tankSet') {
      diveComp.setGases(rig.enabledGases());
      diveComp.setActiveGas(rig.active.gas.id);
    }
  });

  const watchPanel = new DiveWatchPanel({ title: 'DIVE COMP · ZHL-16C' });

  // Device-visibility defaults live in divecomp/config/defaults.ts.
  // localStorage wins if the user has explicitly toggled, otherwise the
  // default applies.
  const PERDIX_VIS_KEY = DIVECOMP_DEFAULTS.storage.perdix;
  const PANEL_VIS_KEY = DIVECOMP_DEFAULTS.storage.watchPanel;
  if (!resolveVisibility(PANEL_VIS_KEY, DIVECOMP_DEFAULTS.devices.watchPanel)) {
    watchPanel.hide();
  }

  // Notifications host — used by the realistic gas-switch flow AND by the
  // Perdix menu (so SELECT GAS / END DIVE leaves can give feedback).
  const notifications = new Notifications();

  const perdix = new Perdix2Watch({
    title: 'PERDIX 2 · REC',
    width: 480,
    menuHost: {
      rigTanks: () =>
        rig.tanks.map((t) => ({
          slotId: t.slotId,
          slotLabel: t.slotLabel,
          gasName: t.gas.name,
          isActive: t.slotId === rig.activeSlotId,
        })),
      onSwitchGas: (slotId: string) => {
        const idx = rig.tanks.findIndex((t) => t.slotId === slotId);
        if (idx >= 0) gasSwitchByIndex(idx);
      },
      onEndDive: () => diveComp.endDive(),
      notify: (text: string, kind?: 'info' | 'warn' | 'danger') =>
        notifications.show({ text, kind: kind ?? 'info', durationMs: 2200 }),
    },
  });
  if (!resolveVisibility(PERDIX_VIS_KEY, DIVECOMP_DEFAULTS.devices.perdix)) {
    perdix.hide();
  }

  // Now that the watches are constructed, wire the SetupModal — it needs the
  // device handles for the DEVICES section.
  const setup: SetupModal = new SetupModal(state, {
    rig,
    devices: [
      {
        nameKey: 'gear_dev_perdix',
        isVisible: () => !perdix.isHidden(),
        setVisible: (v) => {
          v ? perdix.show() : perdix.hide();
          localStorage.setItem(PERDIX_VIS_KEY, String(v));
        },
      },
      {
        nameKey: 'gear_dev_generic',
        isVisible: () => !watchPanel.isHidden(),
        setVisible: (v) => {
          v ? watchPanel.show() : watchPanel.hide();
          localStorage.setItem(PANEL_VIS_KEY, String(v));
        },
      },
      {
        nameKey: 'gear_dev_ai',
        specKey: 'gear_dev_na',
        isVisible: () => false,
        setVisible: () => { /* placeholder */ },
        disabled: true,
      },
      {
        nameKey: 'gear_dev_compass',
        specKey: 'gear_dev_na',
        isVisible: () => false,
        setVisible: () => { /* placeholder */ },
        disabled: true,
      },
    ],
    scenes: SCENE_CATALOG.map((s) => ({ id: s.id, label: s.label })),
    selectedSceneId: activeSceneId,
    onSceneChange: (id) => swapScene(id),
  });
  setupRef = setup;

  // Dev hook — inspect rig/diveComp/state/water from the console.
  // `water` is exposed so scripted scenarios can drive setVisibility().
  (window as unknown as { __dc?: object }).__dc = { rig, diveComp, state, water, registry };

  // Gas-switch keybindings — number keys 1..N pick the corresponding tank slot.
  // Realistic gas-switch protocol:
  //   • Tap a tank key while it would be safe at the current depth → instant
  //     switch + a brief "GAS CHANGE → <mix>" info banner.
  //   • Tap a tank key whose MOD is exceeded at the current depth → caution
  //     banner; the switch waits for a confirmation press within 3 s. Second
  //     press inside that window commits anyway (lost-gas / emergency case).
  const SWITCH_CONFIRM_MS = 3000;
  const MOD_PPO2 = 1.4;       // recreational MOD limit (manual §12.1 default)
  const DECO_PPO2 = 1.61;     // OC deco gas window upper bound
  let pendingSwitch: { slotId: string; expiresAt: number } | null = null;

  function gasSwitchByIndex(idx: number): void {
    const target = rig.tanks[idx];
    if (!target) return;
    if (target.slotId === rig.activeSlotId) return;

    const fO2 = target.gas.o2Pct / 100;
    const modBottom = 10 * (MOD_PPO2 / fO2 - 1);
    const modDeco   = 10 * (DECO_PPO2 / fO2 - 1);
    const pAmbBar = 1 + Math.max(0, state.depth) / 10;
    const ppo2 = fO2 * pAmbBar;

    const overModDeco = ppo2 > DECO_PPO2;
    const overModBottom = ppo2 > MOD_PPO2 && !overModDeco;

    if (overModBottom || overModDeco) {
      const ok = pendingSwitch?.slotId === target.slotId && Date.now() < pendingSwitch.expiresAt;
      if (!ok) {
        // First press — require confirmation within 3 s.
        pendingSwitch = { slotId: target.slotId, expiresAt: Date.now() + SWITCH_CONFIRM_MS };
        notifications.show({
          text: `MOD EXCEEDED · ${target.gas.name} max ${modBottom.toFixed(0)} m · PRESS AGAIN`,
          kind: overModDeco ? 'danger' : 'warn',
          icon: '⚠',
          durationMs: SWITCH_CONFIRM_MS,
          key: 'mod-warn',
        });
        return;
      }
      // Confirmation — commit anyway and clear the pending state.
      pendingSwitch = null;
    } else {
      pendingSwitch = null;
    }

    rig.setActive(target.slotId);
    notifications.show({
      text: `GAS CHANGE → ${target.gas.name}`,
      kind: 'info',
      icon: '◆',
      durationMs: 2400,
      key: 'gas-switch',
    });
  }

  window.addEventListener('keydown', (e) => {
    if (state.paused) return;
    if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
    const n = parseInt(e.key, 10);
    if (Number.isFinite(n) && n >= 1 && n <= rig.tanks.length) {
      // Gauge mode and single-gas modes don't allow underwater switching.
      if (!currentMode.allowsGasSwitch) {
        notifications.show({
          text: `MODE ${currentMode.shortTag} — gas switch disabled`,
          kind: 'warn',
          icon: '⚠',
          durationMs: 2000,
          key: 'mode-block',
        });
        return;
      }
      gasSwitchByIndex(n - 1);
    } else if (e.key.toLowerCase() === 'm') {
      // Cycle through dive modes for testing.
      const i = ALL_MODES.findIndex((m) => m.id === currentMode.id);
      currentMode = ALL_MODES[(i + 1) % ALL_MODES.length];
      notifications.show({
        text: `MODE → ${currentMode.name.toUpperCase()}`,
        kind: 'info',
        icon: '◆',
        durationMs: 2000,
        key: 'mode-switch',
      });
    } else if (e.key.toLowerCase() === 'y') {
      // Toggle the telemetry panel.
      telemPanel.toggle();
    }
  });

  // Modal triggers — single "MENU" entry point now; the standalone GEAR
  // button was removed (gear lives under Menu → Gear setup, and the New
  // Dive flow opens gear automatically).
  const settingsBtn = document.getElementById('settingsBtn');
  if (settingsBtn) {
    settingsBtn.addEventListener('click', () => {
      if (!setup.open_) settings.open();
    });
    settingsBtn.setAttribute('title', t('menu_open_title'));
  }
  // Remove the legacy GEAR button from the overlay if it's still in the DOM.
  document.getElementById('gearBtn')?.remove();

  window.addEventListener('keydown', (e) => {
    const k = e.key.toLowerCase();
    // `G` opens gear directly (advanced shortcut; still works).
    if (k === 'g' && !setup.open_ && !settings.open_) setup.open();
    // `O` (and the MENU button) opens the menu.
    if (k === 'o' && !setup.open_ && !settings.open_) settings.open();
    if (e.key === 'Escape') {
      if (settings.open_) settings.close();
      else if (setup.open_) setup.close(false);
    }
  });

  // Ensure the sprite atlas is ready before scenes start drawing — they
  // gracefully fall back to procedural draws, but we'd rather show sprites
  // from frame one when they're going to land in a moment anyway.
  await assetsReady;

  // Welcome screen — gear modal opens only after the player dismisses it.
  new WelcomeScreen(() => setup.open({ initial: true }));

  // Opt-in UI smoke harness (`?uismoke=1`) drives the welcome → menu →
  // new-dive flow and asserts state at each step.
  maybeStartUiSmoke();

  // Lifecycle watcher — flip the scene picker into a "locked" state the
  // moment physics flags the dive as started (depth ≥ 1 m). resetState()
  // nulls diveStartT and the picker becomes interactive again.
  app.ticker.add((ticker) => {
    if (!state.paused) {
      const dtRaw = ticker.deltaMS / 1000;
      const dt = Math.min(0.05, dtRaw);
      const subs = 2;
      let exhale = 0;
      let ventL = 0;
      let consumedSurfL = 0;
      // Terrain limits — computed once per frame at the diver's current worldX.
      // The diver's world x in scene coords ≈ scrollX + viewWidth_m/2 (same
      // mapping the hazard code uses).
      let terrain: { floor_m: number; ceiling_m: number } | undefined;
      if (scenery.getDepthLimitsAt) {
        const wM = app.renderer.width / app.renderer.resolution / curPxPerMeter;
        const diverWorldX = water.sceneScrollX + wM * 0.5;
        terrain = scenery.getDepthLimitsAt(diverWorldX, state.depth);
      }
      for (let i = 0; i < subs; i++) {
        const ev = step(state, input, dt / subs, terrain);
        if (ev.exhale > exhale) exhale = ev.exhale;
        ventL += ev.bcdVent;
        consumedSurfL += ev.gasConsumedSurfL;
      }

      // Mission tick — runners update per-frame, the HUD re-renders.
      const missionLevel = missionRegistry.getLevel();
      if (missionLevel && missionLevel.missions.length > 0) {
        const runtimes = missionRegistry.update(state, dt);
        missionHud.render(missionLevel, runtimes);
      }

      // Drain the rig's active tank by the same volume the physics consumed.
      // The legacy `state.equipment.tankPressureBar` still drains its own AL80
      // for the existing HUD; this keeps the watch's multi-tank view honest
      // while the deeper refactor (HUD → rig) lands later.
      if (consumedSurfL > 0) {
        const active = rig.active;
        const drainBar = consumedSurfL / active.cylinder.capacityL;
        rig.drainActiveBar(drainBar);
      }

      // Drive the dive computer from the same depth the physics produces.
      // In Gauge mode the manual says tissues are cleared and not tracked —
      // we simply skip the engine update, which freezes the tissue state.
      // Off-gassing between dives still works in non-Gauge modes.
      if (currentMode.tracksTissues) {
        diveComp.update(state.depth, dt);
      }

      const h = app.renderer.height / app.renderer.resolution;
      const pxPerMeter = h / 14;
      const camTopDepth = state.depth - (h * 0.6) / pxPerMeter;

      water.update(state, dt);
      scenery.update(state, camTopDepth, water.sceneScrollX, water.attenuation, water.illumination);

      // Silt-stir — getBottomDepthAt returns null for scenes without a flat
      // bottom (cliff). When the diver hovers within 0.6 m of the sand the
      // particles system spawns a brown cloud trailing behind them.
      let stir = 0;
      if (scenery.getBottomDepthAt) {
        const bd = scenery.getBottomDepthAt(water.sceneScrollX);
        if (bd != null) {
          const clearance = bd - state.depth;          // +ve = diver above bottom
          const stirRange = 0.6;
          if (clearance >= 0 && clearance < stirRange) {
            stir = 1 - clearance / stirRange;
          }
        }
      }
      particulates.setStirLevel(stir);
      particulates.setDiverScreen(water.diverScreenX(), water.diverScreenY());
      particulates.update(state, dt, camTopDepth, pxPerMeter);

      // Smooth the silt visibility drop toward `stir`. Rise much faster
      // than recovery — stirring up a cloud is instant, settling takes
      // seconds. Effective visibility is 1 minus the silt drop (capped),
      // so a quiet diver hovering above sand has no hit at all.
      {
        const target = stir;
        const tau = target > siltVisDrop ? SILT_RISE_TAU_S : SILT_FALL_TAU_S;
        siltVisDrop += (target - siltVisDrop) * Math.min(1, dt / tau);
        const effectiveVis = 1 - siltVisDrop * SILT_MAX_DROP;
        water.setVisibility(effectiveVis, SILT_HAZE_COLOR);
      }

      // Hazard touch — poll the scene for any hazards within 0.8 m. First
      // contact (per hazard id) fires a banner and a small physiological
      // bump; re-firing is throttled per id so the diver isn't spammed.
      if (scenery.getHazardContacts) {
        const hazards = scenery.getHazardContacts(water.sceneScrollX, state.depth, 0.8);
        const now = performance.now();
        for (const h of hazards) {
          const last = hazardCooldown.get(h.id) ?? 0;
          if (now - last < HAZARD_COOLDOWN_MS) continue;
          hazardCooldown.set(h.id, now);
          handleHazardContact(h);
        }
      }

      // Zone overlay — current depth band's biota stats.
      const zi = scenery.zoneInfoAt(state.depth);
      zoneOverlay.update({
        scene: scenery.name,
        label: zi.label,
        population: zi.population,
        variety: zi.variety,
        note: zi.note,
      });
      diver.setPosition(water.diverScreenX(), water.diverScreenY());
      diver.update(state, dt);
      const facing = state.lastKickDir !== 0 ? state.lastKickDir : 1;
      bubbles.update(dt, exhale, ventL, water.diverScreenX(), water.diverScreenY(), facing);
    }
    hud.update(state);
    const snap = diveComp.snapshot();
    const rigSnap = {
      tanks: rig.tanks.map((t) => ({
        slotId: t.slotId,
        slotLabel: t.slotLabel,
        gasName: t.gas.name,
        pressureBar: t.pressureBar,
        ratedBar: t.cylinder.ratedBar,
        isActive: t.slotId === rig.activeSlotId,
        enabled: t.enabled,
      })),
    };
    watchPanel.update(snap, rigSnap);

    // GTR (Gas Time Remaining) = (active tank pressure − reserve) / drain rate.
    // Drain rate uses 5-second rolling SAC × current ambient pressure / active
    // cylinder volume. The 5s smoothing matches the Perdix's averaging
    // behaviour and stops the readout jittering with the breath cycle.
    const RESERVE_BAR = 50;
    const active = rig.active;
    const sac_Lpm = sac5sLpm(state);
    const p_amb = 1 + Math.max(0, state.depth) / 10;
    const drainBarPerMin = (sac_Lpm * p_amb) / active.cylinder.capacityL;
    const remainingBar = Math.max(0, active.pressureBar - RESERVE_BAR);
    let gtrMin: number;
    if (active.pressureBar <= RESERVE_BAR) {
      gtrMin = 0;
    } else if (drainBarPerMin < 0.5) {
      gtrMin = Infinity;
    } else {
      gtrMin = remainingBar / drainBarPerMin;
    }

    perdix.update(snap, rigSnap, {
      velocityMps: state.v,
      wallClock: new Date(),
      ambientTempC: 23,
      gtrMin,
      activeTankIndex: rig.tanks.findIndex((t) => t.slotId === rig.activeSlotId),
      mode: currentMode,
    });

    // ---- Telemetry recording (throttled to 10 Hz) ----
    const nowMs = performance.now();
    if (nowMs - lastTelemRecordMs >= TELEM_RECORD_MS) {
      lastTelemRecordMs = nowMs;
      telemetry.record('depth',    state.depth);
      telemetry.record('velocity', -state.v);             // ascent positive
      telemetry.record('lung',     state.lungCur);
      telemetry.record('bcd',      bcdVolumeAtDepthL(state.bcdSurf, state.depth));
      telemetry.record('co2',      state.co2);
      telemetry.record('ndl',      snap.ndlMin);
      telemetry.record('ceiling',  snap.ceiling_m);
      telemetry.record('gf99',     snap.gf99Pct);
      telemetry.record('surfGf',   snap.surfGfPct);
      telemetry.record('cns',      snap.cnsPct);
      telemetry.record('density',  snap.density.gPerL);
      telemetry.record('tankP',    active.pressureBar);
      telemetry.record('sac',      sac_Lpm);
    }
    telemPanel.update();
  });
}

main().catch((err) => {
  console.error(err);
  document.body.innerHTML =
    `<pre style="color:#ff4a4a;padding:20px;font-family:monospace">${String(err)}</pre>`;
});
