/**
 * TankRig — the set of tanks worn by the diver plus a pointer to the one
 * currently feeding the regulator.
 *
 * Real-world correspondence: a diver carries N cylinders (back-mount + stage
 * bottles) but breathes from exactly one second-stage at a time. Switching
 * tanks is a *physical* action separate from telling the dive computer about
 * it; this class models the former and emits an event so the computer can
 * sync.
 *
 * Listeners decouple the rig from the engine/UI — anything interested
 * (DiveComputer, watch UI, sound effects, log recorder) can subscribe.
 */

import type { GasMix } from '../engine';
import type { Tank, SlotId } from './tank';
import { makeTank, type TankInit } from './tank';
import { STOCK_GASES } from '../engine';
import { CYLINDERS } from './cylinders';

export type RigEvent =
  | { kind: 'activate'; tank: Tank; previous: Tank | null }
  | { kind: 'pressure'; tank: Tank; deltaBar: number }
  | { kind: 'tankSet'; tanks: Tank[] }
  | { kind: 'gasChanged'; tank: Tank };

export type RigListener = (e: RigEvent) => void;

export class TankRig {
  private tanksArr: Tank[];
  private activeSlotIdVal: SlotId;
  private listeners: RigListener[] = [];

  constructor(tanks: Tank[], activeSlotId: SlotId) {
    if (tanks.length === 0) throw new Error('TankRig requires ≥ 1 tank');
    if (!tanks.some(t => t.slotId === activeSlotId)) {
      throw new Error(`activeSlotId '${activeSlotId}' not present in tanks`);
    }
    this.tanksArr = tanks;
    this.activeSlotIdVal = activeSlotId;
  }

  // ---- Read API ----

  get tanks(): readonly Tank[] {
    return this.tanksArr;
  }

  get activeSlotId(): SlotId {
    return this.activeSlotIdVal;
  }

  get active(): Tank {
    return this.tanksArr.find(t => t.slotId === this.activeSlotIdVal)!;
  }

  /** All gases the watch should consider for deco — enabled tanks only, deduplicated by id. */
  enabledGases(): GasMix[] {
    const seen = new Set<string>();
    const out: GasMix[] = [];
    for (const t of this.tanksArr) {
      if (!t.enabled) continue;
      if (seen.has(t.gas.id)) continue;
      seen.add(t.gas.id);
      out.push(t.gas);
    }
    return out;
  }

  tankBySlot(slotId: SlotId): Tank | undefined {
    return this.tanksArr.find(t => t.slotId === slotId);
  }

  totalDryMassKg(): number {
    return this.tanksArr.reduce((sum, t) => sum + t.cylinder.dryMassKg, 0);
  }

  // ---- Mutations (each emits an event) ----

  /**
   * Switch the regulator to a different tank. No-op if already active.
   * Caller is expected to enforce any "switch sequence" UX before this fires —
   * here we only update state and notify.
   */
  setActive(slotId: SlotId): void {
    if (slotId === this.activeSlotIdVal) return;
    const next = this.tanksArr.find(t => t.slotId === slotId);
    if (!next) throw new Error(`unknown slotId: ${slotId}`);
    const previous = this.active;
    this.activeSlotIdVal = slotId;
    this.emit({ kind: 'activate', tank: next, previous });
  }

  /** Drain (or refill) the active tank by deltaBar (sign-correct). */
  drainActiveBar(deltaBar: number): void {
    const t = this.active;
    const before = t.pressureBar;
    t.pressureBar = Math.max(0, Math.min(t.cylinder.ratedBar, before - deltaBar));
    const actualDelta = t.pressureBar - before;
    if (actualDelta !== 0) this.emit({ kind: 'pressure', tank: t, deltaBar: -actualDelta });
  }

  /** Replace the tank list wholesale (e.g. user re-configured gear). */
  setTanks(tanks: Tank[], newActiveSlotId?: SlotId): void {
    if (tanks.length === 0) throw new Error('cannot empty the rig');
    const slot = newActiveSlotId ?? this.activeSlotIdVal;
    if (!tanks.some(t => t.slotId === slot)) {
      throw new Error(`activeSlotId '${slot}' missing from new tank list`);
    }
    this.tanksArr = tanks;
    this.activeSlotIdVal = slot;
    this.emit({ kind: 'tankSet', tanks: this.tanksArr });
  }

  /** Toggle a tank's enabled flag (deco-list inclusion). */
  setEnabled(slotId: SlotId, enabled: boolean): void {
    const t = this.tanksArr.find(x => x.slotId === slotId);
    if (!t) return;
    if (t.enabled === enabled) return;
    if (!enabled && slotId === this.activeSlotIdVal) {
      throw new Error('cannot disable the active tank — switch first');
    }
    t.enabled = enabled;
    this.emit({ kind: 'tankSet', tanks: this.tanksArr });
  }

  /** Refill all tanks to rated pressure — used by reset / new-dive plumbing. */
  refillAll(): void {
    for (const t of this.tanksArr) t.pressureBar = t.cylinder.ratedBar;
    this.emit({ kind: 'tankSet', tanks: this.tanksArr });
  }

  /** Swap the cylinder spec on one tank (e.g. user changes AL80 → Steel 12L). */
  setCylinder(slotId: SlotId, spec: import('./cylinders').CylinderSpec): void {
    const t = this.tanksArr.find((x) => x.slotId === slotId);
    if (!t) return;
    t.cylinder = spec;
    // Clamp pressure to the new rated and refill on type change for sanity.
    t.pressureBar = spec.ratedBar;
    this.emit({ kind: 'tankSet', tanks: this.tanksArr });
  }

  /** Bind a different gas mix to one tank. */
  setGas(slotId: SlotId, gas: GasMix): void {
    const t = this.tanksArr.find((x) => x.slotId === slotId);
    if (!t) return;
    t.gas = gas;
    this.emit({ kind: 'gasChanged', tank: t });
  }

  /** Append a new tank slot (auto-generates a unique slot id). */
  addTank(spec: import('./cylinders').CylinderSpec, gas: GasMix): Tank {
    let idx = this.tanksArr.length + 1;
    let slotId = `T${idx}`;
    while (this.tanksArr.some((t) => t.slotId === slotId)) {
      idx += 1;
      slotId = `T${idx}`;
    }
    const t: Tank = {
      slotId,
      slotLabel: slotId,
      cylinder: spec,
      gas,
      pressureBar: spec.ratedBar,
      enabled: true,
    };
    this.tanksArr.push(t);
    this.emit({ kind: 'tankSet', tanks: this.tanksArr });
    return t;
  }

  /** Drop a tank slot. The active slot cannot be removed. */
  removeTank(slotId: SlotId): boolean {
    if (slotId === this.activeSlotIdVal) return false;
    const i = this.tanksArr.findIndex((t) => t.slotId === slotId);
    if (i < 0) return false;
    this.tanksArr.splice(i, 1);
    this.emit({ kind: 'tankSet', tanks: this.tanksArr });
    return true;
  }

  // ---- Events ----

  addListener(l: RigListener): () => void {
    this.listeners.push(l);
    return () => {
      const i = this.listeners.indexOf(l);
      if (i >= 0) this.listeners.splice(i, 1);
    };
  }

  private emit(e: RigEvent): void {
    for (const l of this.listeners) l(e);
  }
}

// ---- Default rigs ----

/**
 * 3-tank tech-light setup: backmount AL80 air + two AL40 stages (EAN50, O₂).
 * Matches a typical "advanced rec / intro tech" weekend diver.
 */
export function defaultRig(): TankRig {
  const tanks: Tank[] = [
    makeTank({
      slotId: 'BACK',
      slotLabel: 'Back',
      cylinder: CYLINDERS.al80,
      gas: STOCK_GASES.air,
    }),
    makeTank({
      slotId: 'L-STAGE',
      slotLabel: 'Stage L',
      cylinder: CYLINDERS.al40,
      gas: STOCK_GASES.ean50,
    }),
    makeTank({
      slotId: 'R-STAGE',
      slotLabel: 'Stage R',
      cylinder: CYLINDERS.al40,
      gas: STOCK_GASES.o2,
    }),
  ];
  return new TankRig(tanks, 'BACK');
}

/** Single-tank recreational setup (AL80 EAN32). */
export function singleTankRig(): TankRig {
  const tanks: Tank[] = [
    makeTank({
      slotId: 'BACK',
      slotLabel: 'Back',
      cylinder: CYLINDERS.al80,
      gas: STOCK_GASES.ean32,
    }),
  ];
  return new TankRig(tanks, 'BACK');
}
