/**
 * ImmersiveToggle — hides all UI chrome so the user can watch the water
 * scene without overlays. Bound to the `I` key + a chip rendered next
 * to the scene picker. The toggle stays visible in both states so the
 * user can always get back.
 *
 * Activation flips `body.is-immersive`, and styles.css uses that class
 * to dim everything except the Pixi canvas. Keeping the toggle in pure
 * DOM (no Pixi container) means it's trivially click-targetable and
 * doesn't fight the canvas event order.
 */

import { onLangChange, t } from '../i18n';

export class ImmersiveToggle {
  readonly el: HTMLButtonElement;
  private active = false;

  constructor(private onChange?: (active: boolean) => void) {
    this.el = document.createElement('button');
    this.el.type = 'button';
    this.el.className = 'immersive-toggle';
    this.applyLabels();
    this.el.addEventListener('click', () => this.toggle());

    // Hot-swap labels when the language flips.
    onLangChange(() => this.applyLabels());

    window.addEventListener('keydown', (e) => {
      // Skip when a text field has focus — `I` is a normal keystroke there.
      const target = e.target as HTMLElement | null;
      if (target && (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable)) return;
      // Skip when a modal is open — `I` is unsafe to consume there.
      if (document.querySelector('.setup-overlay.open, .settings-overlay.open')) return;
      if (e.key.toLowerCase() === 'i' && !e.repeat && !e.metaKey && !e.ctrlKey) {
        this.toggle();
      }
    });
  }

  private applyLabels(): void {
    this.el.title = t('immersive_title');
    this.el.innerHTML = `<span class="ico">◐</span><span class="lbl">${t('immersive_short')}</span>`;
  }

  toggle(): void {
    this.set(!this.active);
  }

  set(on: boolean): void {
    this.active = on;
    document.body.classList.toggle('is-immersive', on);
    this.el.classList.toggle('is-on', on);
    this.onChange?.(on);
  }

  isOn(): boolean {
    return this.active;
  }
}
