import { FRC_L, RV_L, TLC_L } from './config';
import { clamp, type InputState } from './physics';
import { resetState, type SimState } from './state';

/**
 * Wires keyboard / mouse-wheel / middle-button events to state mutation.
 *
 * Wheel: shifts `state.lungBias` (additive offset to FRC). Bias decays
 *        slowly back to zero (auto-breath returns to FRC-centered).
 *        Direction respects `state.settings.wheelInvert`.
 *
 * Middle mouse button (button === 1): hold to freeze breath. On press,
 *        physics snapshots the current gas mass; on release, normal
 *        breathing resumes.
 *
 * Keys: W/S = BCD inflate/deflate, SPACE = fast dump, R = reset, G = open
 *       setup modal (handled in main.ts).
 */
export function setupInput(state: SimState): InputState {
  const input: InputState = {
    bcdInflate: false,
    bcdDeflate: false,
    bcdDump: false,
    breathHold: false,
    kickRequest: 0,
  };

  window.addEventListener('keydown', (e) => {
    if (state.paused) return;
    const k = e.key.toLowerCase();
    if (k === 'w') input.bcdInflate = true;
    // S now triggers the fast dump valve directly (no slow-deflate mode).
    if (k === 's') input.bcdDump = true;
    // A / D fire a single kick impulse — physics gates rapid-fire via refractory.
    // Ignore key auto-repeat so holding the key does NOT continuously kick.
    if (k === 'a' && !e.repeat) input.kickRequest = -1;
    if (k === 'd' && !e.repeat) input.kickRequest = 1;
    if (k === 'r') resetState(state);
  });

  window.addEventListener('keyup', (e) => {
    const k = e.key.toLowerCase();
    if (k === 'w') input.bcdInflate = false;
    if (k === 's') input.bcdDump = false;
  });

  // Wheel — shifts lungBias. Direction toggled by wheelInvert setting.
  // Default (wheelInvert=false): wheel-DOWN (deltaY>0) = INHALE (bias up).
  window.addEventListener(
    'wheel',
    (e) => {
      if (state.paused) return;
      // Bias range corresponds to baseline at [RV, TLC] around FRC.
      const sign = state.settings.wheelInvert ? -1 : 1;
      const delta = e.deltaY * 0.0035 * sign;
      const minBias = RV_L - FRC_L; // -1.3
      const maxBias = TLC_L - FRC_L; // +3.5
      state.lungBias = clamp(state.lungBias + delta, minBias, maxBias);
      e.preventDefault();
    },
    { passive: false }
  );

  // Middle mouse button — breath-hold while held.
  window.addEventListener('mousedown', (e) => {
    if (state.paused) return;
    if (e.button === 1) {
      input.breathHold = true;
      // Prevent autoscroll cursor on Windows.
      e.preventDefault();
    }
  });
  window.addEventListener('mouseup', (e) => {
    if (e.button === 1) {
      input.breathHold = false;
    }
  });
  // Stop autoscroll if user holds-and-moves.
  window.addEventListener('auxclick', (e) => {
    if (e.button === 1) e.preventDefault();
  });

  // Safety: release hold if window loses focus or pointer leaves.
  window.addEventListener('blur', () => {
    input.breathHold = false;
  });
  window.addEventListener('pointerleave', () => {
    input.breathHold = false;
  });

  return input;
}
