/**
 * Menu modal — non-gear preferences and dive-lifecycle controls.
 *
 * Sections:
 *   • LANGUAGE — i18n picker (en / zh).
 *   • BREATHING INPUT — wheel-direction toggle.
 *   • DIVE — gear access + New Dive (restart with confirm).
 *
 * The barotrauma-warning toggle that used to live here was dropped in
 * favour of always-on safety alerts, per UX feedback. Filename remains
 * `settings.ts` for now to keep import paths stable; the class is renamed
 * to MenuModal and exported as both MenuModal and SettingsModal (alias)
 * so legacy imports keep compiling.
 */

import { applyAll, getLang, onLangChange, setLang, t } from './i18n';
import { confirmDialog } from './divecomp/ui/confirmDialog';
import { persistWheelInvert, type SimState } from './state';

const ROOT_ID = 'menu-modal';

export interface MenuModalOptions {
  /** User has confirmed a brand-new dive: reset state + reopen gear. */
  onNewDive: () => void;
  /** True while a dive is underway — drives the New Dive confirm prompt. */
  isDiveActive: () => boolean;
  /**
   * Optional: open the gear editor directly. Surfaced for back-compat only
   * (e.g. the `G` keyboard shortcut). Not rendered in the menu UI anymore.
   */
  onOpenGear?: () => void;
}

export class MenuModal {
  private root!: HTMLElement;
  private state: SimState;
  private opts: MenuModalOptions;
  private isOpen = false;

  constructor(state: SimState, opts: MenuModalOptions) {
    this.state = state;
    this.opts = opts;
    // Force barotrauma warning ON — the user-facing toggle is gone, but
    // legacy code paths still read state.settings.barotraumaWarning, so
    // we just pin it here.
    this.state.settings.barotraumaWarning = true;
    this.build();
    onLangChange(() => {
      const wasOpen = this.isOpen;
      this.build();
      if (wasOpen) {
        this.root.classList.add('open');
        this.refresh();
      }
    });
  }

  get open_(): boolean { return this.isOpen; }

  open() {
    if (this.isOpen) return;
    this.isOpen = true;
    this.state.paused = true;
    this.root.classList.add('open');
    this.refresh();
  }

  close() {
    if (!this.isOpen) return;
    this.isOpen = false;
    this.state.paused = false;
    this.root.classList.remove('open');
  }

  private build() {
    document.getElementById(ROOT_ID)?.remove();

    const root = document.createElement('div');
    root.id = ROOT_ID;
    root.className = 'setup-overlay settings-overlay';
    const lang = getLang();
    root.innerHTML = /*html*/ `
      <div class="setup-card settings-card">
        <div class="setup-head">
          <div>
            <div class="setup-eyebrow">${t('set_eyebrow')}</div>
            <h2 class="setup-title">${t('set_title')}</h2>
          </div>
        </div>

        <div class="settings-grid">

          <section class="setup-section">
            <h3>${t('set_lang_head')}</h3>
            <div class="lang-radio-row">
              <label class="lang-radio">
                <input type="radio" name="lang" value="en" ${lang === 'en' ? 'checked' : ''} />
                <span class="lang-radio-mark"></span>
                <span class="lang-radio-label">${t('set_lang_en')}</span>
              </label>
              <label class="lang-radio">
                <input type="radio" name="lang" value="zh" ${lang === 'zh' ? 'checked' : ''} />
                <span class="lang-radio-mark"></span>
                <span class="lang-radio-label">${t('set_lang_zh')}</span>
              </label>
            </div>
          </section>

          <section class="setup-section">
            <h3>${t('set_breath_head')}</h3>
            <label class="setup-toggle">
              <input type="checkbox" id="wheelInvertToggle" />
              <span class="toggle-mark"></span>
              <span class="toggle-label">
                <b>${t('set_wheel_label')}</b>
                <span class="toggle-spec">${t('set_wheel_spec')}</span>
              </span>
            </label>
          </section>

          <button class="menu-action danger menu-action-solo" id="menuNewDive" type="button">
            <span class="ma-label">${t('menu_new_dive_btn')}</span>
            <span class="ma-spec">${t('menu_new_dive_spec')}</span>
          </button>

        </div>

        <div class="setup-foot">
          <button class="setup-btn primary" id="settingsDone" type="button">${t('set_done')}</button>
        </div>
      </div>
    `;
    document.body.appendChild(root);
    this.root = root;

    const wheelInvertToggle = root.querySelector('#wheelInvertToggle') as HTMLInputElement;
    wheelInvertToggle.checked = this.state.settings.wheelInvert;
    wheelInvertToggle.addEventListener('change', () => {
      this.state.settings.wheelInvert = wheelInvertToggle.checked;
      // Sticky preference — keeps the OS-based default from re-enabling
      // on next reload if the user explicitly turned it off (or vice versa).
      persistWheelInvert(wheelInvertToggle.checked);
    });

    root.querySelectorAll<HTMLInputElement>('input[name="lang"]').forEach((r) => {
      r.addEventListener('change', () => {
        if (r.checked) setLang(r.value as 'en' | 'zh');
      });
    });

    root.querySelector('#menuNewDive')!.addEventListener('click', () => this.handleNewDive());

    root.querySelector('#settingsDone')!.addEventListener('click', () => this.close());
    root.addEventListener('click', (e) => {
      if (e.target === root) this.close();
    });

    applyAll();
  }

  private async handleNewDive(): Promise<void> {
    // If the diver hasn't started yet, no confirmation needed.
    const inDive = this.opts.isDiveActive();
    if (inDive) {
      const ok = await confirmDialog({
        title: t('menu_new_dive_confirm_title'),
        message: t('menu_new_dive_confirm'),
        confirmText: t('menu_new_dive_confirm_ok'),
        cancelText: t('gear_btn_cancel'),
        destructive: true,
      });
      if (!ok) return;
    }
    this.close();
    this.opts.onNewDive();
  }

  private refresh() {
    (this.root.querySelector('#wheelInvertToggle') as HTMLInputElement).checked =
      this.state.settings.wheelInvert;
  }
}

/** Backwards-compatible alias. */
export const SettingsModal = MenuModal;
