/**
 * Gas-density severity classification (Anthony 2017, "Estimating Maximum
 * Operating Depth from Gas Density", Diving & Hyperbaric Medicine).
 *
 *   < 5.7 g/L  safe
 *   5.7-6.2    warning — work-of-breathing climbs, CO₂ retention risk
 *   > 6.2      danger — gas should be helium-bearing at this depth
 *
 * These thresholds drive the watch's "Density" info-screen color coding.
 */

import type { DensityReading, DensitySeverity, GasMix } from './types';
import { density_gPerL_atDepth } from './gasMix';

export const GAS_DENSITY_WARN_GPL = 5.7;
export const GAS_DENSITY_DANGER_GPL = 6.2;

export function severityFor(gPerL: number): DensitySeverity {
  if (gPerL > GAS_DENSITY_DANGER_GPL) return 'danger';
  if (gPerL > GAS_DENSITY_WARN_GPL) return 'warning';
  return 'safe';
}

export function densityReading(
  g: GasMix,
  depth_m: number,
  surfaceMbar = 1013
): DensityReading {
  const gPerL = density_gPerL_atDepth(g, depth_m, surfaceMbar);
  return { gPerL, severity: severityFor(gPerL) };
}
