import {
  BAROTRAUMA_WARN_BAR,
  BAROTRAUMA_DANGER_BAR,
  BCD_DUMP_RATE,
  BCD_INFLATE_RATE,
  CD_A,
  CD_A_HORIZ,
  CO2_APNEA_RATE,
  CO2_EXERTION_SETPOINT_GAIN,
  CO2_PROD_EXERTION_GAIN,
  CO2_REST,
  CO2_TAU_REST_S,
  EXERTION_RISE_TAU_S,
  EXERTION_TAU_S,
  FRC_L,
  G,
  KICK_EXERTION_COST,
  KICK_IMPULSE_MPS,
  KICK_RAPID_BONUS,
  KICK_REFRACTORY_S,
  LUNG_BIAS_DECAY_LPS,
  LUNG_SPEED_MAX,
  MAX_DEPTH,
  MAX_SUSTAINED_SPEED,
  PEAK_BREATH_RATE_BPM,
  PEAK_TIDAL_VOLUME_L,
  REST_BREATH_RATE_BPM,
  REST_TIDAL_VOLUME_L,
  RHO,
  RV_L,
  TARGET_DEPTH,
  TARGET_TOL,
  TLC_L,
  VT1_AROUSAL,
  VT1_BREATH_RATE_BPM,
  VT2_AROUSAL,
  VT2_TIDAL_VOLUME_L,
} from './config';
import {
  cylinderShellBuoyancyKg,
  gasMassKg,
  PRIMARY_LIGHT_KG,
  totalMassKg,
  wetsuitVolumeAtDepthL,
  wingMaxLitersSurface,
  type EquipmentConfig,
} from './equipment';
import type { SimState } from './state';

export interface InputState {
  bcdInflate: boolean;
  bcdDeflate: boolean;
  bcdDump: boolean;
  /** Driven by MMB: true while breath should be held. */
  breathHold: boolean;
  /** One-shot kick request — set by keydown, cleared by physics step. */
  kickRequest: -1 | 0 | 1;
}

export const clamp = (x: number, lo: number, hi: number) =>
  Math.max(lo, Math.min(hi, x));
export const lerp = (a: number, b: number, t: number) => a + (b - a) * t;
export const sign = (x: number): -1 | 0 | 1 => (x > 0 ? 1 : x < 0 ? -1 : 0);

export function ambientPressureAtm(depth_m: number): number {
  return 1 + Math.max(0, depth_m) / 10;
}

export function bcdVolumeAtDepthL(surfL: number, depth_m: number): number {
  return surfL / ambientPressureAtm(depth_m);
}

/**
 * Mechanical (elastic-recoil) transpulmonary pressure based purely on lung
 * volume. Approximately 0 at FRC, ~+30 cmH₂O at TLC, ~-40 cmH₂O at RV.
 * Returns bar.
 */
export function lungMechanicalPressureBar(lungL: number): number {
  const cmH2O =
    lungL >= FRC_L
      ? ((lungL - FRC_L) / (TLC_L - FRC_L)) * 30
      : ((lungL - FRC_L) / (FRC_L - RV_L)) * 40;
  return cmH2O / 1019.7; // cmH₂O → bar
}

/** Legacy alias for HUD displays still expecting cmH₂O. */
export function transpulmonaryCmH2O(lungL: number): number {
  return lungMechanicalPressureBar(lungL) * 1019.7;
}

export function totalDisplacementL(eq: EquipmentConfig, depth: number, lungL: number, bcdSurf: number): number {
  return (
    eq.bodyDisplacementL +
    wetsuitVolumeAtDepthL(eq, depth) +
    bcdVolumeAtDepthL(bcdSurf, depth) +
    lungL
  );
}

export function netForceN(state: SimState, vForDrag = state.v): number {
  const eq = state.equipment;
  const V_m3 = totalDisplacementL(eq, state.depth, state.lungCur, state.bcdSurf) / 1000;
  const Fg = totalMassKg(eq) * G;
  const Fb = RHO * G * V_m3 + cylinderShellBuoyancyKg(eq) * G;
  const Fd = -0.5 * RHO * vForDrag * Math.abs(vForDrag) * CD_A;
  return Fg - Fb + Fd;
}

export function netForceKgf(state: SimState): number {
  const eq = state.equipment;
  const V_m3 = totalDisplacementL(eq, state.depth, state.lungCur, state.bcdSurf) / 1000;
  const liftKg = RHO * V_m3 + cylinderShellBuoyancyKg(eq);
  return totalMassKg(eq) - liftKg;
}

/**
 * Smoothstep — Hermite interpolation between 0 and 1 over [edge0, edge1].
 * Used for the piecewise breathing curves so transitions are continuous.
 */
function smoothstep(edge0: number, edge1: number, x: number): number {
  const t = clamp((x - edge0) / (edge1 - edge0), 0, 1);
  return t * t * (3 - 2 * t);
}

/**
 * Combined arousal — max of CO₂ stress and exercise exertion. Either pathway
 * alone can drive breathing up; in real divers a stressed-but-still diver and
 * a calm-but-working diver both show elevated ventilation.
 */
export function arousal(state: SimState): number {
  return Math.max(state.stress, state.exertion);
}

/**
 * VT1/VT2 ventilatory model.
 *
 *   • Below VT1 (a < 0.40): RR creeps from rest toward VT1 plateau.
 *   • Between VT1 and VT2 : RR climbs steadily; TV is the main driver.
 *   • Above VT2 (a > 0.70): RR spikes non-linearly while TV plateaus / drops
 *                           — classic "rapid shallow" pattern at exhaustion.
 */
export function currentBreathRateBpm(state: SimState): number {
  const a = arousal(state);
  const seg1 = smoothstep(0, VT1_AROUSAL, a) * (VT1_BREATH_RATE_BPM - REST_BREATH_RATE_BPM);
  const seg2 = smoothstep(VT2_AROUSAL, 1.0, a) * (PEAK_BREATH_RATE_BPM - VT1_BREATH_RATE_BPM);
  return REST_BREATH_RATE_BPM + seg1 + seg2;
}

export function currentTidalVolumeL(state: SimState): number {
  const a = arousal(state);
  // TV climbs efficiently up to VT2, then drops slightly as RR takes over.
  const rise = smoothstep(0, VT2_AROUSAL, a) * (VT2_TIDAL_VOLUME_L - REST_TIDAL_VOLUME_L);
  const drop = smoothstep(VT2_AROUSAL, 1.0, a) * (VT2_TIDAL_VOLUME_L - PEAK_TIDAL_VOLUME_L);
  return REST_TIDAL_VOLUME_L + rise - drop;
}

/** Instantaneous lung-volume rate (L/s at ambient). */
export function inhalationRateLps(state: SimState): number {
  return state.ventMetric / 2;
}

/**
 * Instantaneous SAC L/min — the depth-normalised RMV (book Ch. 11.2).
 * Equals lung-volume rate × 60. NOT multiplied by P_amb.
 */
export function sacRateLpm(state: SimState): number {
  return inhalationRateLps(state) * 60;
}

/**
 * Instantaneous tank pressure drop, bar/min.
 *
 *   bar/min = RMV (L/min ambient) × P_amb (ATA) / cylinder capacity (L)
 *
 * which matches the book's worked example (Ch. 11.2): an RMV of 9.4
 * L/min at 4 ATA from an 11 L cylinder drains 9.4 × 4 / 11 = 3.4 bar/min.
 */
export function tankPressureRateBarPerMin(state: SimState): number {
  const eq = state.equipment;
  const P_amb = ambientPressureAtm(state.depth);
  const drawSurfLpm = sacRateLpm(state) * P_amb;
  return drawSurfLpm / eq.cylinder.capacityL;
}

export function gasTimeRemainingMin(state: SimState): number {
  const RESERVE_BAR = 50;
  const eq = state.equipment;
  const remaining = Math.max(0, eq.tankPressureBar - RESERVE_BAR);
  const rate = tankPressureRateBarPerMin(state);
  if (rate < 0.05) return Infinity;
  return remaining / rate;
}

/**
 * SAC L/min over the last 5 seconds — depth-normalised, per the book
 * (NOTES.md Ch. 11.2): the diver's RMV at lung pressure, which is the
 * per-diver constant that gas planning uses. Equivalent to
 * `surface-equiv L/min ÷ P_amb_ATA`, but we accumulate RMV directly
 * in `lRMV` so the value is exact across depth changes inside the
 * window.
 */
export function sac5sLpm(state: SimState): number {
  const log = state.gasLog;
  if (log.length === 0) return 0;
  let sumRMV = 0;
  for (const e of log) sumRMV += e.lRMV;
  const window = Math.max(0.5, Math.min(5, state.t - log[0].t + 0.001));
  return (sumRMV / window) * 60;
}

/** Dive-average SAC L/min — same RMV convention as `sac5sLpm`. */
export function sacDiveAvgLpm(state: SimState): number {
  if (state.diveStartT === null) return 0;
  const elapsed = state.t - state.diveStartT;
  if (elapsed < 1) return 0;
  return (state.gasConsumedRMVL / elapsed) * 60;
}

/** Severity classification for the lung-overpressure banner. */
export type BarotraumaSeverity = 'none' | 'warning' | 'danger';
export function barotraumaSeverity(state: SimState): BarotraumaSeverity {
  const mag = Math.abs(state.transpulmonaryBar);
  if (mag > BAROTRAUMA_DANGER_BAR) return 'danger';
  if (mag > BAROTRAUMA_WARN_BAR) return 'warning';
  return 'none';
}

export interface StepEvents {
  exhale: number;
  /** Surface-eq litres of gas that left the BCD this step (manual + auto-vent). */
  bcdVent: number;
  /** Surface-eq litres of gas the diver inhaled this step (≈ tank consumption). */
  gasConsumedSurfL: number;
  /** True if this step clamped state.depth against floor or ceiling. */
  collided: boolean;
}

/**
 * Optional collision hooks the host can supply each step. Both are pulled
 * from the active scene — physics doesn't know about scenery directly.
 */
export interface TerrainLimits {
  /** Deepest depth the diver may reach (m). +Infinity = open. */
  floor_m: number;
  /** Shallowest depth (m). 0 = surface. */
  ceiling_m: number;
}

export function step(
  state: SimState,
  input: InputState,
  dt: number,
  terrain?: TerrainLimits,
): StepEvents {
  const eq = state.equipment;
  const P_amb = ambientPressureAtm(state.depth);

  // ---- Kick impulse + exertion ----
  // A kick bumps the *target* exertion, not exertion itself; exertion then
  // chases the target with a ~4 s time constant so breathing rises gradually.
  if (input.kickRequest !== 0) {
    const since = state.t - state.lastKickT;
    if (since >= KICK_REFRACTORY_S) {
      const dir = input.kickRequest;
      // Apply impulse, but never let sustained speed exceed cap (drag bleeds it down).
      state.vx = clamp(
        state.vx + dir * KICK_IMPULSE_MPS,
        -MAX_SUSTAINED_SPEED,
        MAX_SUSTAINED_SPEED
      );
      // Rapid-cadence penalty: if user kicks much faster than refractory, target compounds.
      const rapid = since < KICK_REFRACTORY_S * 1.6 ? KICK_RAPID_BONUS : 0;
      state.exertionTarget = clamp(
        state.exertionTarget + KICK_EXERTION_COST + rapid,
        0,
        1
      );
      state.lastKickT = state.t;
      state.lastKickDir = dir;
      state.kickPulse = 1;
    }
    input.kickRequest = 0;
  }

  // Target decays toward 0 (recovery after kicking stops).
  state.exertionTarget = Math.max(
    0,
    state.exertionTarget - (state.exertionTarget / EXERTION_TAU_S) * dt
  );
  // Exertion smoothly follows the target — gradual rise on first kick, gradual
  // fall on recovery. Symmetric time constant.
  const exFollow = Math.min(1, dt / EXERTION_RISE_TAU_S);
  state.exertion = state.exertion + (state.exertionTarget - state.exertion) * exFollow;
  // Kick-pose animation pulse fades over ~0.5 s
  state.kickPulse = Math.max(0, state.kickPulse - dt * 2);

  // ---- Horizontal drag + integration ----
  // F_drag = -0.5 ρ vx|vx| Cd·A ; accel = F / mass
  const dragAx = -(0.5 * RHO * state.vx * Math.abs(state.vx) * CD_A_HORIZ) / eq.bodyMassKg;
  state.vx += dragAx * dt;
  state.x += state.vx * dt;

  // ---- Breath-hold latch ----
  if (input.breathHold && !state.breathHold) {
    // Begin hold: snapshot the gas mass currently in the lungs (surface-eq L).
    state.breathHold = true;
    state.holdGasMassSE = state.lungCur * P_amb;
    state.holdElapsed = 0;
  } else if (!input.breathHold && state.breathHold) {
    state.breathHold = false;
    state.holdElapsed = 0;
  }

  // ---- Stress feedback (extensibility: future systems may overwrite). ----
  // Simple default: stress climbs with CO₂ overshoot above rest.
  const targetStress = clamp((state.co2 - 40) / 40, 0, 1);
  state.stress = lerp(state.stress, targetStress, Math.min(1, dt * 0.5));

  // ---- Lung target dynamics ----
  let lungTarget: number;
  let transpulBar = 0;

  if (state.breathHold) {
    state.holdElapsed += dt;
    // Boyle's Law: held gas mass × P at hold time = current volume × current P.
    const eqVol = state.holdGasMassSE / P_amb;
    if (eqVol > TLC_L) {
      // Lungs cannot expand past TLC — overpressure builds.
      lungTarget = TLC_L;
      const lungGasPressureAtm = state.holdGasMassSE / TLC_L;
      // Overpressure relative to ambient.
      transpulBar = (lungGasPressureAtm - P_amb) * 1.01325;
    } else if (eqVol < RV_L) {
      // Squeeze: lungs at minimum volume, gas pressure below ambient.
      lungTarget = RV_L;
      const lungGasPressureAtm = state.holdGasMassSE / RV_L;
      transpulBar = (lungGasPressureAtm - P_amb) * 1.01325;
    } else {
      lungTarget = eqVol;
      transpulBar = lungMechanicalPressureBar(eqVol);
    }
  } else {
    // Bias decays slowly toward 0 (FRC-centered breathing).
    const decay = LUNG_BIAS_DECAY_LPS * dt;
    if (state.lungBias > 0) {
      state.lungBias = Math.max(0, state.lungBias - decay);
    } else if (state.lungBias < 0) {
      state.lungBias = Math.min(0, state.lungBias + decay);
    }
    const baseline = clamp(FRC_L + state.lungBias, RV_L + 0.2, TLC_L - 0.2);

    const rateBpm = currentBreathRateBpm(state);
    const TV = currentTidalVolumeL(state);
    const omega = (2 * Math.PI * rateBpm) / 60;
    const oscillation = (TV / 2) * Math.sin(omega * state.t);

    lungTarget = clamp(baseline + oscillation, RV_L, TLC_L);
    transpulBar = lungMechanicalPressureBar(state.lungCur);
  }

  state.lungTgt = lungTarget;
  state.transpulmonaryBar = transpulBar;

  // Lung volume tracks target at physiological max flow.
  const dLungReq = state.lungTgt - state.lungCur;
  const dLungThisStep = clamp(dLungReq, -LUNG_SPEED_MAX * dt, LUNG_SPEED_MAX * dt);
  const dVdt = dLungThisStep / dt;
  state.lungCur = clamp(state.lungCur + dLungThisStep, RV_L, TLC_L);

  state.ventMetric = lerp(state.ventMetric, Math.abs(dVdt), Math.min(1, dt * 4));

  // Breath-cycle detection (sign-changes of dV/dt).
  const phase = sign(dVdt);
  if (phase !== 0 && phase !== state.breathPhase) {
    if (state.breathPhase !== 0) {
      state.breathTimes.push(state.t);
      while (state.breathTimes.length && state.t - state.breathTimes[0] > 30) {
        state.breathTimes.shift();
      }
    }
    state.breathPhase = phase;
  }

  // ---- Gas consumption — only while NOT holding ----
  let consumedSurfL = 0;
  if (!state.breathHold && eq.tankPressureBar > 0) {
    const rateBarPerSec = tankPressureRateBarPerMin(state) / 60;
    const barConsumedThisStep = rateBarPerSec * dt;
    consumedSurfL = barConsumedThisStep * eq.cylinder.capacityL;
    eq.tankPressureBar = Math.max(0, eq.tankPressureBar - barConsumedThisStep);

    // Record into rolling 5-s window + dive-total. We log BOTH
    // surface-equiv litres (used to drain the tank) and RMV-equivalent
    // litres (used by SAC readouts). RMV = surface-equiv / P_amb at
    // log time, so depth changes inside the 5 s window stay accurate.
    if (consumedSurfL > 0) {
      const consumedRMV = consumedSurfL / P_amb;
      state.gasLog.push({ t: state.t, lSTP: consumedSurfL, lRMV: consumedRMV });
      while (state.gasLog.length && state.gasLog[0].t < state.t - 5) {
        state.gasLog.shift();
      }
      state.gasConsumedSinceStartL += consumedSurfL;
      state.gasConsumedRMVL += consumedRMV;
    }
  }

  // Dive-start detection: first time depth crosses 1 m, anchor diveStartT.
  if (state.diveStartT === null && state.depth > 1) {
    state.diveStartT = state.t;
    state.gasConsumedSinceStartL = 0;
    state.gasConsumedRMVL = 0;
  }

  // ---- BCD ----
  // The wing has a fixed PHYSICAL volume (wingMax litres). What we track in
  // state.bcdSurf is surface-equivalent gas mass; physical volume at depth =
  // bcdSurf / P_amb. So the inflate cap depends on depth:
  //   bcdSurf <= wingMax · P_amb   ⇔   bcdSurf / P_amb <= wingMax
  //
  // INFLATION + DUMP RATES ARE AT-DEPTH (physical) FLOW RATES. A balanced
  // first-stage regulator delivers gas at ambient pressure, so a button press
  // grows the bladder by a roughly constant physical volume per second
  // regardless of depth — the surface-equivalent contribution per second
  // therefore scales linearly with P_amb. The dump valve is a fixed-aperture
  // orifice and follows the same scaling.
  //
  //   ΔbcdSurf/s = BCD_INFLATE_RATE × P_amb    (when W held)
  //   ΔbcdSurf/s = -BCD_DUMP_RATE × P_amb       (when S held)
  //
  // On ascent, P_amb drops, the cap (wingMax · P_amb) drops with it, and any
  // excess gas auto-vents — that's the rising-bubble-train you see when a
  // diver doesn't dump fast enough.
  const wingMax = wingMaxLitersSurface(eq);
  const maxSurfAtDepth = wingMax * P_amb;
  let ventedSurfL = 0;
  if (input.bcdInflate) state.bcdSurf += BCD_INFLATE_RATE * P_amb * dt;
  if (input.bcdDeflate) {
    const dGas = Math.min(state.bcdSurf, BCD_INFLATE_RATE * P_amb * dt);
    state.bcdSurf -= dGas;
    ventedSurfL += dGas;
  }
  if (input.bcdDump) {
    const dGas = Math.min(state.bcdSurf, BCD_DUMP_RATE * P_amb * dt);
    state.bcdSurf -= dGas;
    ventedSurfL += dGas;
  }
  if (state.bcdSurf > maxSurfAtDepth) {
    ventedSurfL += state.bcdSurf - maxSurfAtDepth;
    state.bcdSurf = maxSurfAtDepth;
  }
  if (state.bcdSurf < 0) state.bcdSurf = 0;

  // ---- Forces ----
  const Fnet = netForceN(state);
  state.a = Fnet / eq.bodyMassKg;
  state.v += state.a * dt;
  state.depth += state.v * dt;

  let collided = false;
  // Effective ceiling / floor — terrain overrides defaults when supplied.
  const minDepth = Math.max(0, terrain?.ceiling_m ?? 0);
  const maxDepth = Math.min(MAX_DEPTH, terrain?.floor_m ?? MAX_DEPTH);
  if (state.depth < minDepth) {
    state.depth = minDepth;
    // Surface bounces lightly; an actual rock ceiling stops you dead.
    if (state.v < 0) state.v = minDepth === 0 ? state.v * -0.15 : 0;
    collided = true;
  }
  if (state.depth > maxDepth) {
    state.depth = maxDepth;
    if (state.v > 0) state.v = 0;
    collided = true;
  }

  // ---- CO₂ — target-seeking model ----
  //
  // While breathing, CO₂ tracks toward a setpoint (40 mmHg at rest, shifted
  // upward by exertion). Ventilation controls how *fast* it tracks, not the
  // direction — so faster breathing during work doesn't paradoxically scrub
  // the diver's CO₂ below baseline (the bug the producer-consumer model had).
  //
  // Breath-hold is the only path that lets CO₂ climb above the setpoint:
  // no ventilation → CO₂ accumulates monotonically at production rate.
  if (state.breathHold) {
    const co2ProdRate = CO2_APNEA_RATE * (1 + state.exertion * CO2_PROD_EXERTION_GAIN);
    state.co2 = clamp(state.co2 + co2ProdRate * dt, 30, 100);
  } else {
    const setpoint = CO2_REST + state.exertion * CO2_EXERTION_SETPOINT_GAIN;
    // ventMetric ≈ 0.5 at rest, ~2.5 at full panic ventilation.
    const ventScale = Math.max(0.5, state.ventMetric / 0.5);
    const tau = CO2_TAU_REST_S / ventScale;
    state.co2 += (setpoint - state.co2) * Math.min(1, dt / tau);
    state.co2 = clamp(state.co2, 30, 100);
  }

  // ---- Scoring ----
  if (Math.abs(state.depth - TARGET_DEPTH) <= TARGET_TOL) {
    state.onTargetTime += dt;
    if (state.onTargetTime > state.bestTime) state.bestTime = state.onTargetTime;
  } else {
    state.onTargetTime = Math.max(0, state.onTargetTime - dt * 2);
  }

  state.t += dt;
  return {
    exhale: dVdt < -0.3 ? -dVdt : 0,
    bcdVent: ventedSurfL,
    gasConsumedSurfL: consumedSurfL,
    collided,
  };
}

export function isBarotraumaRisk(lungL: number): boolean {
  return Math.abs(lungMechanicalPressureBar(lungL)) > 0.07;
}

export { gasMassKg, PRIMARY_LIGHT_KG };
