/**
 * GenScene — a Scene preset that renders any SceneSpec.
 *
 * Lives at the bottom of the dependency stack (no LLM dependency) so the
 * scene works the moment it's loaded, using DEFAULT_GEN_SPEC. Host code
 * (or an LLM provider) calls `applySpec(spec)` to hot-swap to a new
 * dive site without rebuilding the Pixi container hierarchy.
 *
 * Generic creature drawer — eight archetypes (`school`, `fish`, `eel`,
 * `urchin`, `coral`, `anemone`, `jelly`, `ray`) cover most of what
 * casual prompts ask for; richer ones can be added later without
 * breaking the spec format.
 */

import { Container, Graphics } from 'pixi.js';
import type { SimState } from '../state';
import type { HazardContact, Scene, ZoneInfo } from './types';
import {
  DEFAULT_GEN_SPEC,
  type BottomSpec,
  type CreatureSpec,
  type SceneSpec,
  type ZoneSpec,
} from './genScene.types';
import { SpriteBiotaPool } from '../assets';

interface GenCreature {
  archetype: CreatureSpec['archetype'];
  depth: number;
  xAlong: number;
  phase: number;
  litColor: number;
  scale: number;
  benthic: boolean;
  hazard?: HazardContact['kind'];
  hazardLabel?: string;
  /** Stable index for hazard de-dup. */
  index: number;
}

export class GenScene implements Scene {
  readonly id = 'gen';
  readonly name = 'GEN';
  readonly container = new Container();

  private bottomGfx = new Graphics();
  private biotaGfx = new Graphics();
  /**
   * Sprite-backed biota — each frame we try the pool first; archetypes
   * with no registered sprite fall back to the procedural `biotaGfx`
   * draw below. Added to the scene graph AFTER biotaGfx so sprites
   * render on top of any fallback fills for the same depth band.
   */
  private biotaPool = new SpriteBiotaPool();
  private spec: SceneSpec = DEFAULT_GEN_SPEC;
  private bottomProfile: number[] = [];
  private creatures: GenCreature[] = [];

  private w = 0;
  private h = 0;
  private pxPerMeter = 60;

  /** Source-of-truth seed for procedural placement. Re-seeded per applySpec. */
  private seed = 0;

  constructor(initialSpec?: SceneSpec) {
    this.container.addChild(this.bottomGfx, this.biotaGfx, this.biotaPool.container);
    this.applySpec(initialSpec ?? DEFAULT_GEN_SPEC);
  }

  /** Hot-swap the active scene. Existing Pixi containers are reused. */
  applySpec(spec: SceneSpec): void {
    this.spec = spec;
    this.seed = hashStr(spec.id) | 0;
    this.bottomProfile.length = 0;
    this.creatures.length = 0;
    if (spec.bottom) this.buildBottomProfile(spec.bottom);
    this.buildCreatures();
  }

  /** Latest applied spec — for round-tripping back into the prompt UI. */
  getSpec(): SceneSpec {
    return this.spec;
  }

  resize(w: number, h: number, pxPerMeter: number): void {
    this.w = w;
    this.h = h;
    this.pxPerMeter = pxPerMeter;
  }

  update(
    _state: SimState,
    camTopDepth: number,
    scrollX: number,
    _sunLight: number,
    _illumination: number
  ): void {
    if (!this.w || !this.h) return;
    const camBotDepth = camTopDepth + this.h / this.pxPerMeter;
    if (this.spec.bottom) {
      this.drawBottom(this.spec.bottom, camTopDepth, camBotDepth, scrollX);
    } else {
      this.bottomGfx.clear();
    }
    this.drawBiota(camTopDepth, camBotDepth, scrollX);
  }

  // ---------------- Scene API ----------------

  zoneInfoAt(depth: number): ZoneInfo {
    let active: ZoneSpec | undefined;
    for (const z of this.spec.zones) {
      if (depth >= z.startDepth_m && depth < z.endDepth_m) {
        active = z;
        break;
      }
    }
    const label = active?.label ?? 'OPEN WATER';
    const note = active?.note;
    let pop = 0;
    const types = new Set<string>();
    const range = active ? [active.startDepth_m, active.endDepth_m] : [depth - 4, depth + 4];
    for (const c of this.creatures) {
      if (c.depth >= range[0] && c.depth < range[1]) {
        pop += c.archetype === 'school' ? 8 : 1;
        types.add(c.archetype);
      }
    }
    return { label, population: pop, variety: types.size, note };
  }

  getHazardContacts(scrollX_m: number, diverDepth_m: number, range_m: number): HazardContact[] {
    const len = this.spec.bottom?.lengthM ?? 280;
    const diverWorldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    const out: HazardContact[] = [];
    for (const c of this.creatures) {
      if (!c.hazard) continue;
      let dx = c.xAlong - diverWorldX;
      const half = len / 2;
      dx = ((dx + half) % len + len) % len - half;
      const dy = c.depth - diverDepth_m;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist <= range_m) {
        out.push({
          kind: c.hazard,
          label: c.hazardLabel ?? c.archetype.toUpperCase(),
          id: `${c.hazard}:${c.index}`,
          severity: 1 - dist / range_m,
        });
      }
    }
    return out;
  }

  getBottomDepthAt(scrollX_m: number): number | null {
    if (!this.spec.bottom) return null;
    const diverWorldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    return this.bottomDepthAt(diverWorldX);
  }

  /** Bottom-only floor when the spec has a bottom; open water otherwise. */
  getDepthLimitsAt(worldX_m: number, _currentDepth_m: number = 0) {
    if (!this.spec.bottom) return { floor_m: Infinity, ceiling_m: 0 };
    return { floor_m: this.bottomDepthAt(worldX_m) - 0.25, ceiling_m: 0 };
  }

  // ---------------- Bottom geometry ----------------

  private buildBottomProfile(bottom: BottomSpec): void {
    // Sample the periodic profile at 1/m, with octaves for organic variety.
    const total = Math.max(8, Math.floor(bottom.lengthM));
    const k = (2 * Math.PI) / Math.max(1, bottom.period_m);
    const seedF = (this.seed % 1000) * 0.01;
    for (let i = 0; i < total; i++) {
      const u = i;
      const v =
        0.6 * Math.sin(u * k + seedF) +
        0.3 * Math.sin(u * k * 2.3 + seedF * 1.7) +
        0.1 * Math.sin(u * k * 5.7 + seedF * 2.3);
      this.bottomProfile.push(v);
    }
  }

  private bottomDepthAt(worldX_m: number): number {
    const bottom = this.spec.bottom;
    if (!bottom || this.bottomProfile.length === 0) return Infinity;
    const len = bottom.lengthM;
    const u = ((worldX_m % len) + len) % len;
    const idx = Math.floor(u) % this.bottomProfile.length;
    return bottom.baseDepth_m + this.bottomProfile[idx] * bottom.amplitude_m;
  }

  private drawBottom(
    bottom: BottomSpec,
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
  ): void {
    this.bottomGfx.clear();
    const minBottom = bottom.baseDepth_m - bottom.amplitude_m;
    if (camBotDepth < minBottom - 1) return;

    const samples = Math.max(40, Math.ceil(this.w / 12));
    const dx = this.w / samples;
    const pts: number[] = [];
    pts.push(0, this.h + 10);
    for (let i = 0; i <= samples; i++) {
      const px = i * dx;
      const worldX = scrollX + px / this.pxPerMeter;
      const bd = this.bottomDepthAt(worldX);
      pts.push(px, (bd - camTopDepth) * this.pxPerMeter);
    }
    pts.push(this.w, this.h + 10);
    this.bottomGfx.poly(pts).fill({ color: bottom.color, alpha: 0.96 });

    // Accent scatter — keeps the floor from looking flat.
    if (bottom.accentColor != null) {
      const accentRand = mulberry32(this.seed ^ 0x1f1f1f);
      for (let i = 0; i < samples; i += 3) {
        const px = i * dx + accentRand() * dx;
        const worldX = scrollX + px / this.pxPerMeter;
        const bd = this.bottomDepthAt(worldX);
        const py = (bd - camTopDepth) * this.pxPerMeter;
        const r = 0.6 + accentRand() * 1.4;
        this.bottomGfx.circle(px, py + r * 0.5, r)
          .fill({ color: bottom.accentColor, alpha: 0.65 });
      }
    }
  }

  // ---------------- Biota ----------------

  private buildCreatures(): void {
    const rand = mulberry32(this.seed ^ 0x9e3779b1);
    const len = this.spec.bottom?.lengthM ?? 280;
    let index = 0;
    for (const entry of this.spec.creatures) {
      const scaleR = entry.scaleRange ?? [0.8, 1.2];
      const xR = entry.xRange ?? [0, len];
      for (let i = 0; i < entry.count; i++) {
        const benthic = !!entry.benthic;
        const xAlong = xR[0] + rand() * (xR[1] - xR[0]);
        let depth: number;
        if (benthic && this.spec.bottom) {
          depth = this.bottomDepthAt(xAlong) - 0.3;
        } else {
          depth = entry.depthRange[0] + rand() * (entry.depthRange[1] - entry.depthRange[0]);
        }
        const colorPool = entry.colors.length > 0 ? entry.colors : [0xa6d6e8];
        this.creatures.push({
          archetype: entry.archetype,
          depth,
          xAlong,
          phase: rand() * Math.PI * 2,
          litColor: colorPool[Math.floor(rand() * colorPool.length)],
          scale: scaleR[0] + rand() * (scaleR[1] - scaleR[0]),
          benthic,
          hazard: entry.hazard,
          hazardLabel: entry.hazardLabel,
          index: index++,
        });
      }
    }
  }

  private drawBiota(camTopDepth: number, camBotDepth: number, scrollX: number): void {
    const g = this.biotaGfx;
    g.clear();
    this.biotaPool.beginFrame();
    const len = this.spec.bottom?.lengthM ?? 280;
    const t = performance.now() * 0.001;
    for (const c of this.creatures) {
      // Compute screen x, with wrap-aware mapping when there's a bottom strip.
      let screenX: number;
      if (this.spec.bottom) {
        const u = ((c.xAlong - scrollX) % len + len) % len;
        const px = u * this.pxPerMeter;
        // Wrap to viewport so creatures appear from both sides as the diver moves.
        screenX = px - Math.floor(px / Math.max(1, this.w)) * this.w;
      } else {
        // Open water — anchor screenX by xAlong mod viewport width.
        const px = ((c.xAlong - scrollX) % (this.w / this.pxPerMeter * 4));
        screenX = (px * this.pxPerMeter) % Math.max(1, this.w);
        if (screenX < 0) screenX += this.w;
      }
      if (screenX < -60 || screenX > this.w + 60) continue;

      const effDepth = c.benthic ? c.depth : c.depth + Math.sin(t * 0.6 + c.phase) * 0.6;
      if (effDepth < camTopDepth - 1 || effDepth > camBotDepth + 1) continue;
      const y = (effDepth - camTopDepth) * this.pxPerMeter;
      const phase = c.phase + t * (c.benthic ? 0.4 : 1.2);

      // Sprite path — try the pool first. Add a small tilt so pelagic
      // creatures don't read as static cut-outs; benthic stays upright.
      // Scale the sprite by pxPerMeter so creatures feel proportional
      // to the zoom level. `phaseSeed` jitters the animation cycle so
      // fish don't move in lockstep.
      const tilt = c.benthic ? 0 : Math.sin(phase) * 0.06;
      const spriteScale = c.scale * (this.pxPerMeter / 60);
      if (this.biotaPool.draw(
        c.archetype, screenX, y, tilt, spriteScale, c.litColor, 1, c.phase * 0.3,
      )) {
        continue;
      }
      // Procedural fallback (school + any archetype the registry doesn't have).
      drawCreature(g, c.archetype, screenX, y, phase, c.scale, c.litColor);
    }
    this.biotaPool.endFrame();
  }
}

// ---------------- Archetype drawers ----------------

function drawCreature(
  g: Graphics,
  archetype: CreatureSpec['archetype'],
  x: number,
  y: number,
  phase: number,
  scale: number,
  color: number,
): void {
  const alpha = 0.95;
  switch (archetype) {
    case 'school': {
      const n = 9;
      for (let i = 0; i < n; i++) {
        const a = i * 0.7 + phase;
        const fx = x + Math.cos(a) * 16 * scale;
        const fy = y + Math.sin(a * 1.3) * 9 * scale;
        const s = 2.5 * scale;
        g.poly([fx - s, fy, fx + s, fy - s * 0.6, fx + s, fy + s * 0.6])
          .fill({ color, alpha });
      }
      return;
    }
    case 'fish': {
      const w = 18 * scale, h2 = 5 * scale;
      const dir = Math.sin(phase * 0.5) > 0 ? 1 : -1;
      g.poly([
        x - (w * 0.5) * dir, y,
        x,                   y - h2,
        x + (w * 0.5) * dir, y,
        x,                   y + h2,
      ]).fill({ color, alpha });
      g.poly([
        x + (w * 0.5) * dir, y,
        x + (w * 0.5 + h2 * 1.4) * dir, y - h2 * 1.1,
        x + (w * 0.5 + h2 * 1.4) * dir, y + h2 * 1.1,
      ]).fill({ color, alpha: alpha * 0.85 });
      return;
    }
    case 'eel': {
      // Long ribbon body — drawn as a chain of short segments.
      const seg = 6, len = 14 * scale, r = 2.4 * scale;
      const dir = Math.sin(phase * 0.5) > 0 ? 1 : -1;
      for (let i = 0; i < seg; i++) {
        const t = i / (seg - 1);
        const sx = x + (t - 0.5) * len * dir;
        const sy = y + Math.sin(phase + t * 3) * 2.4;
        g.circle(sx, sy, r * (1 - t * 0.4)).fill({ color, alpha });
      }
      return;
    }
    case 'urchin': {
      const r = 4 * scale;
      g.circle(x, y, r).fill({ color, alpha });
      const spines = 10;
      for (let i = 0; i < spines; i++) {
        const a = (i / spines) * Math.PI * 2;
        const sx = x + Math.cos(a) * r * 1.8;
        const sy = y + Math.sin(a) * r * 1.8;
        g.moveTo(x, y).lineTo(sx, sy)
          .stroke({ color, alpha: alpha * 0.85, width: 0.9 });
      }
      return;
    }
    case 'coral': {
      // Branching colony — bunch of vertical spires + a basal lobe.
      const baseR = 8 * scale;
      for (let i = 0; i < 4; i++) {
        const ox = (i - 1.5) * baseR * 0.5;
        const top = y - (8 + i * 2) * scale;
        g.moveTo(x + ox, y).lineTo(x + ox * 0.7, top)
          .stroke({ color, alpha, width: 2.4 });
        g.circle(x + ox * 0.7, top, 2 * scale).fill({ color, alpha });
      }
      g.ellipse(x, y + 1, baseR, 3 * scale).fill({ color, alpha: alpha * 0.85 });
      return;
    }
    case 'anemone': {
      const baseR = 5 * scale;
      g.ellipse(x, y + baseR * 0.4, baseR, baseR * 0.55)
        .fill({ color: 0x6e4040, alpha });
      const arms = 9;
      for (let i = 0; i < arms; i++) {
        const a = -Math.PI + (i / (arms - 1)) * Math.PI + Math.sin(phase + i) * 0.08;
        const ex = x + Math.cos(a) * baseR * 1.6;
        const ey = y + Math.sin(a) * baseR * 1.0;
        g.moveTo(x, y - 1).lineTo(ex, ey).stroke({ color, alpha, width: 1.2 });
      }
      return;
    }
    case 'jelly': {
      // Translucent bell with trailing tentacles.
      const r = 6 * scale;
      g.ellipse(x, y, r, r * 0.7).fill({ color, alpha: 0.55 });
      g.ellipse(x, y, r, r * 0.7).stroke({ color, alpha: 0.9, width: 1 });
      for (let i = -2; i <= 2; i++) {
        const tx = x + i * r * 0.25;
        const tail = y + r * (1.2 + Math.sin(phase + i) * 0.2) * scale;
        g.moveTo(tx, y).lineTo(tx + Math.sin(phase + i) * 1.5, tail)
          .stroke({ color, alpha: 0.6, width: 0.8 });
      }
      return;
    }
    case 'ray': {
      // Wide diamond + tail. Flaps with phase.
      const span = 22 * scale, h2 = 7 * scale;
      const flap = Math.sin(phase) * 2.5;
      g.poly([
        x - span * 0.5, y + flap,
        x,              y - h2,
        x + span * 0.5, y - flap,
        x,              y + h2,
      ]).fill({ color, alpha });
      g.moveTo(x, y).lineTo(x, y + h2 * 2.4)
        .stroke({ color, alpha: alpha * 0.7, width: 1.4 });
      return;
    }
  }
}

// ---------------- helpers ----------------

function mulberry32(seed: number) {
  let s = seed | 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function hashStr(s: string): number {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}
