/**
 * Perdix 2 button operation logic.
 *
 * Per the Recreational-Modes manual (RevC, V91), §2.2:
 *
 *   ┌──────────────────────┬───────────────────────┐
 *   │  MENU (left)         │  SELECT (right)       │
 *   ├──────────────────────┼───────────────────────┤
 *   │ From main screen:    │ From main screen:     │
 *   │   open main menu     │   cycle info screens  │
 *   ├──────────────────────┼───────────────────────┤
 *   │ In a menu:           │ In a menu:            │
 *   │   move down / wrap   │   activate / edit     │
 *   ├──────────────────────┼───────────────────────┤
 *   │ Editing a setting:   │ Editing a setting:    │
 *   │   change the value   │   save the value      │
 *   └──────────────────────┴───────────────────────┘
 *
 * BOTH buttons together: only used to power the watch on. No other operation
 * uses a chord.
 *
 * The watch shows context-appropriate button hints at the bottom of the
 * screen so the user never needs to remember the rules — that's what
 * `ButtonHints` here represents.
 *
 * Default keyboard mapping:
 *
 *   MENU   →  [   (or J / ArrowLeft)
 *   SELECT →  ]   (or K / ArrowRight)
 *   BOTH   →  \   (or Enter)
 *
 * The watch panel intercepts these keys only while it has user focus —
 * clicking the watch face grabs focus; clicking the water view releases it,
 * so number-key gas-switch and game keys don't conflict.
 */

export type Perdix2ButtonId = 'MENU' | 'SELECT' | 'BOTH';

export interface Perdix2Buttons {
  press(id: Perdix2ButtonId): void;
}

/** Default key → button mapping. Replaceable via watch options. */
export const DEFAULT_KEYMAP: Record<string, Perdix2ButtonId> = {
  '[': 'MENU',
  ']': 'SELECT',
  '\\': 'BOTH',
  // Friendly alternates
  'j': 'MENU',
  'k': 'SELECT',
  'Enter': 'BOTH',
  'ArrowLeft': 'MENU',
  'ArrowRight': 'SELECT',
};

/**
 * Map a KeyboardEvent → button id given a keymap. Returns null if the key
 * doesn't bind any button.
 */
export function keyToButton(
  e: KeyboardEvent,
  map: Record<string, Perdix2ButtonId> = DEFAULT_KEYMAP
): Perdix2ButtonId | null {
  return map[e.key] ?? map[e.key.toLowerCase()] ?? null;
}

/**
 * Hint strip shown at the bottom of the screen. Two columns — the label
 * above each physical button shows what that button will do *right now*.
 */
export interface ButtonHints {
  menu: string;     // shown above MENU (left)
  select: string;   // shown above SELECT (right)
}
