/**
 * MissionHud — small floating panel in the bottom-left of the water
 * view that lists the active missions and their progress.
 *
 * The panel is hidden when the active level has no missions, so scenes
 * meant for free exploration (wreck, cave) don't clutter the screen.
 */

import type { LevelSpec, MissionRuntime } from './types';

export class MissionHud {
  readonly el: HTMLElement;
  private $title: HTMLElement;
  private $items: HTMLElement;

  constructor() {
    this.el = document.createElement('div');
    this.el.className = 'mission-hud';
    this.el.hidden = true;
    this.el.innerHTML = `
      <div class="mh-head">
        <span class="mh-title">MISSION</span>
        <span class="mh-level"></span>
      </div>
      <div class="mh-items"></div>
    `;
    this.$title = this.el.querySelector('.mh-level')!;
    this.$items = this.el.querySelector('.mh-items')!;
  }

  /** Re-paint the panel from the active level + the runtime snapshots. */
  render(level: LevelSpec | null, runtimes: MissionRuntime[]): void {
    if (!level || runtimes.length === 0) {
      this.el.hidden = true;
      return;
    }
    this.el.hidden = false;
    this.$title.textContent = level.label;

    // Build rows. One DOM child per mission; we recycle them when count is stable.
    const target = runtimes.length;
    while (this.$items.children.length > target) {
      this.$items.removeChild(this.$items.lastChild!);
    }
    while (this.$items.children.length < target) {
      const row = document.createElement('div');
      row.className = 'mh-row';
      row.innerHTML = `
        <div class="mh-row-head">
          <span class="mh-row-label"></span>
          <span class="mh-row-pct"></span>
        </div>
        <div class="mh-row-line"></div>
        <div class="mh-bar"><div class="mh-bar-fill"></div></div>
        <div class="mh-row-hint"></div>
      `;
      this.$items.appendChild(row);
    }

    for (let i = 0; i < target; i++) {
      const row = this.$items.children[i] as HTMLElement;
      const r = runtimes[i];
      (row.querySelector('.mh-row-label') as HTMLElement).textContent = r.spec.label;
      (row.querySelector('.mh-row-pct') as HTMLElement).textContent =
        `${Math.round(r.progress * 100)}%`;
      (row.querySelector('.mh-row-line') as HTMLElement).textContent =
        r.hudLine ?? '';
      const fill = row.querySelector('.mh-bar-fill') as HTMLElement;
      fill.style.width = `${Math.round(r.progress * 100)}%`;
      const hint = row.querySelector('.mh-row-hint') as HTMLElement;
      hint.textContent = r.hudHint ?? '';
      row.classList.toggle('is-done', r.status === 'complete');
      row.classList.toggle('is-failed', r.status === 'failed');
    }
  }
}
