/**
 * DiveComputer — host-facing facade over the vendored Bühlmann ZH-L16C engine.
 *
 * Responsibilities:
 *   • Owns one BuhlmannModel (= one diver's tissue state).
 *   • Tracks dive-time, max depth, average depth on our side (vendored model
 *     accumulates time across all `record()` calls including surface intervals,
 *     which is not what the watch displays).
 *   • Exposes a per-frame `update(depth_m, dt_s)` and a cheap `snapshot()`.
 *   • Multi-gas planning via `planDeco()` (call sparingly — runs a fork simulation).
 *
 * Not yet owned here: pressure-sensor abstraction, surface-pressure latch,
 * notifications, mode behavior, AI integration. Those layer on top.
 */

import { BuhlmannModel } from './vendored/buhlmannModel';
import { BuhlmannConfig } from './vendored/buhlmannConfig';
import { CeilingType, NDLType } from './vendored/types';
import { Depth } from './vendored/depth';
import { Time } from './vendored/time';

import { VendorGasCache } from './adapter';
import { densityReading } from './gasDensity';
import { DEFAULT_CONSERVATISM, validateConservatism } from './conservatism';
import type {
  Conservatism,
  DecoPlan,
  DecoSnapshot,
  GasMix,
} from './types';

/** Threshold (m) below which dive-time begins counting. Matches Perdix/Teric auto-on. */
const DIVE_START_DEPTH_M = 1.0;

export interface DiveComputerOptions {
  conservatism?: Conservatism;
  surfaceMbar?: number;
  ascentRateMpm?: number;       // default 10 (Perdix/Teric)
  ceilingType?: CeilingType;    // default Adaptive (matches watch TTS semantics)
  ndlType?: NDLType;            // default Actual
  initialGases: GasMix[];       // must contain at least the active gas
  activeGasId: string;
}

export class DiveComputer {
  private model: BuhlmannModel;
  private conservatismVal: Conservatism;
  private surfaceMbarVal: number;
  private ascentRateMpm: number;
  private ceilingTypeVal: CeilingType;
  private ndlTypeVal: NDLType;

  private gases: GasMix[];
  private activeGasIdVal: string;
  private cache = new VendorGasCache();

  // Host-tracked counters (vendored model can't give us these directly)
  private currentDepth_m = 0;
  private maxDepth_mVal = 0;
  private depthIntegral_ms = 0;   // ∑(depth × dt_s) for avg
  private diveTimeSVal = 0;
  private inDiveSegment = false;

  constructor(opts: DiveComputerOptions) {
    this.conservatismVal = opts.conservatism ?? DEFAULT_CONSERVATISM;
    const err = validateConservatism(this.conservatismVal);
    if (err) throw new Error(`bad conservatism: ${err}`);

    this.surfaceMbarVal = opts.surfaceMbar ?? 1013;
    this.ascentRateMpm = opts.ascentRateMpm ?? 10;
    this.ceilingTypeVal = opts.ceilingType ?? CeilingType.Adaptive;
    this.ndlTypeVal = opts.ndlType ?? NDLType.Actual;

    this.gases = [...opts.initialGases];
    if (!this.gases.some(g => g.id === opts.activeGasId)) {
      throw new Error(`activeGasId '${opts.activeGasId}' not in initialGases`);
    }
    this.activeGasIdVal = opts.activeGasId;

    this.model = this.buildModel();
  }

  // ---- Public API ----

  get activeGas(): GasMix {
    return this.gases.find(g => g.id === this.activeGasIdVal)!;
  }

  get conservatism(): Conservatism {
    return this.conservatismVal;
  }

  get surfaceMbar(): number {
    return this.surfaceMbarVal;
  }

  get allGases(): readonly GasMix[] {
    return this.gases;
  }

  get currentDepthM(): number {
    return this.currentDepth_m;
  }

  /**
   * Switch the breathing gas. Triggers an instantaneous gas-switch record so
   * subsequent tissue loading uses the new mix.
   */
  setActiveGas(gasId: string): void {
    if (gasId === this.activeGasIdVal) return;
    if (!this.gases.some(g => g.id === gasId)) {
      throw new Error(`unknown gasId: ${gasId}`);
    }
    this.activeGasIdVal = gasId;
    // Record a zero-duration sample with the new gas so the model's internal
    // active-gas tracking is in sync.
    const vGas = this.cache.get(this.activeGas);
    this.model.record(Depth.fromMeters(this.currentDepth_m), Time.zero(), vGas);
    this.invalidateSnapshotCache();
  }

  private invalidateSnapshotCache(): void {
    this.cachedSnap = null;
    this.snapCacheT = -Infinity;
  }

  /**
   * Replace the available gas list. Used when the player edits the gas table
   * in the gear modal. Active gas id must still resolve.
   */
  setGases(gases: GasMix[]): void {
    if (!gases.some(g => g.id === this.activeGasIdVal)) {
      throw new Error(`activeGasId no longer present in new gas list`);
    }
    this.gases = [...gases];
    this.cache.clear();
  }

  /**
   * Change conservatism. WARNING: changing mid-dive rebuilds the model and
   * loses tissue loading. Callers should only do this at the surface.
   */
  setConservatism(c: Conservatism): void {
    const err = validateConservatism(c);
    if (err) throw new Error(`bad conservatism: ${err}`);
    this.conservatismVal = c;
    this.model = this.buildModel();
  }

  /**
   * Surface pressure can change between dives (different altitude). Should be
   * set before descent and held constant for the duration of a dive.
   */
  setSurfacePressure(mbar: number): void {
    if (mbar < 500 || mbar > 1200) throw new Error(`bad surface mbar: ${mbar}`);
    this.surfaceMbarVal = mbar;
    this.model = this.buildModel();
  }

  /**
   * Drive one simulation step. Always call this — even at the surface — so
   * off-gassing is tracked between dives.
   *
   * Vendor model takes (depth, time, gas) where time is the *segment*
   * duration at that depth. For our 60 Hz host this is ~16 ms per call.
   */
  update(depth_m: number, dt_s: number): void {
    if (dt_s <= 0) return;
    this.currentDepth_m = Math.max(0, depth_m);

    // Dive-time + averages: only accumulate when below the auto-on threshold.
    if (this.currentDepth_m >= DIVE_START_DEPTH_M) {
      this.inDiveSegment = true;
      this.diveTimeSVal += dt_s;
      this.depthIntegral_ms += this.currentDepth_m * dt_s;
      if (this.currentDepth_m > this.maxDepth_mVal) {
        this.maxDepth_mVal = this.currentDepth_m;
      }
    }

    const vDepth = Depth.fromMeters(this.currentDepth_m);
    const vTime = Time.fromSeconds(dt_s);
    const vGas = this.cache.get(this.activeGas);
    this.model.record(vDepth, vTime, vGas);
  }

  /**
   * Cached snapshot — safe to call every frame.
   *
   * The heavy queries (`ndl`, `ceiling` in Adaptive mode) each fork the
   * Bühlmann model and forward-simulate, which can cost 10+ ms per call
   * at deep depths where the diver is rapidly loading tissues. At 60 Hz
   * that's enough to drop frames on slower hardware. Since NDL / ceiling
   * / GF99 / CNS change on minute timescales, we refresh them at ~3 Hz
   * and serve cached values in between. Tissue loading itself still ticks
   * every frame via `update()`.
   */
  snapshot(): DecoSnapshot {
    const now = performance.now();
    if (this.cachedSnap && now - this.snapCacheT < this.SNAP_CACHE_MS) {
      // Refresh the cheap, depth-derived fields every frame so callers
      // that read `depth_m`/`density` see live values; expensive deco
      // fields stay cached.
      return {
        ...this.cachedSnap,
        depth_m: this.currentDepth_m,
        density: densityReading(this.activeGas, this.currentDepth_m, this.surfaceMbarVal),
        diveTimeS: this.diveTimeSVal,
        avgDepth_m: this.diveTimeSVal > 0
          ? this.depthIntegral_ms / this.diveTimeSVal
          : 0,
        maxDepth_m: this.maxDepth_mVal,
      };
    }
    const ss = this.model.supersaturation();
    const ceiling = this.model.ceiling();
    const ndl = this.model.ndl();
    const inDeco = this.model.inDeco();

    const snap: DecoSnapshot = {
      ndlMin: inDeco ? 0 : ndl.asMinutes(),
      ceiling_m: ceiling.asMeters(),
      inDeco,
      gf99Pct: ss.gf99,
      surfGfPct: ss.gfSurf,
      cnsPct: this.model.cns(),
      otu: this.model.otu(),

      activeGas: this.activeGas,
      density: densityReading(this.activeGas, this.currentDepth_m, this.surfaceMbarVal),

      depth_m: this.currentDepth_m,
      maxDepth_m: this.maxDepth_mVal,
      avgDepth_m: this.diveTimeSVal > 0 ? this.depthIntegral_ms / this.diveTimeSVal : 0,
      diveTimeS: this.diveTimeSVal,

      conservatism: this.conservatismVal,
      surfaceMbar: this.surfaceMbarVal,
    };
    this.cachedSnap = snap;
    this.snapCacheT = now;
    return snap;
  }

  // Snapshot cache — see snapshot() above.
  private cachedSnap: DecoSnapshot | null = null;
  private snapCacheT = -Infinity;
  /** ~3 Hz refresh — fast enough for HUD smoothness, ~50× cheaper than 60 Hz. */
  private readonly SNAP_CACHE_MS = 333;

  /**
   * Build the full decompression plan with stops + gas switches. Runs a fork
   * simulation — not cheap. Call at most ~1 Hz, not every frame.
   *
   * Returns null if the gas list is empty or the active gas is missing.
   */
  planDeco(): DecoPlan | null {
    if (this.gases.length === 0) return null;
    const enabledGases = this.cache.getAll(this.gases);
    const activeVendorGas = this.cache.get(this.activeGas);
    if (!enabledGases.some(g => g.equals(activeVendorGas))) return null;

    try {
      const runtime = this.model.deco(enabledGases);
      return { stages: runtime.decoStages, ttsMin: runtime.tts.asMinutes() };
    } catch (e) {
      // Vendor throws on edge cases (no gas list, etc.). Treat as no plan.
      return null;
    }
  }

  /**
   * Reset just the dive-time + max-depth counters. Tissues are preserved —
   * that's what makes repetitive-dive tracking work.
   */
  endDive(): void {
    this.diveTimeSVal = 0;
    this.depthIntegral_ms = 0;
    this.maxDepth_mVal = 0;
    this.inDiveSegment = false;
    this.invalidateSnapshotCache();
  }

  /**
   * Hard reset — tissues, dive time, all counters. Use only when the user
   * explicitly clears state (e.g. "clear tissues" diagnostic, mode switch
   * to/from Gauge).
   */
  hardReset(): void {
    this.diveTimeSVal = 0;
    this.depthIntegral_ms = 0;
    this.maxDepth_mVal = 0;
    this.inDiveSegment = false;
    this.currentDepth_m = 0;
    this.model = this.buildModel();
    this.cache.clear();
    this.invalidateSnapshotCache();
  }

  // ---- Internal ----

  private buildModel(): BuhlmannModel {
    const cfg = new BuhlmannConfig(
      [this.conservatismVal.gfLow, this.conservatismVal.gfHigh],
      this.surfaceMbarVal,
      this.ascentRateMpm,
      this.ceilingTypeVal,
      false,
      this.ndlTypeVal
    );
    return new BuhlmannModel(cfg);
  }
}
