/**
 * Cylinder catalog — physical attributes of common SCUBA cylinders.
 *
 * The numbers here drive both buoyancy (game physics) and gas inventory
 * (dive-computer engine). All values are widely-cited recreational/tech
 * references (Halcyon, Luxfer, Worthington).
 *
 *   capacityL          — internal water volume (L); gas inventory = capacity × pressureBar
 *   ratedBar           — service pressure
 *   emptyBuoyancyKg    — in-water buoyancy when cylinder is empty (positive = floats)
 *   dryMassKg          — physical weight in air, empty (for gear-weight readouts)
 *   regsBuoyancyKg     — extra negative buoyancy from regs/manifold permanently attached
 */

export interface CylinderSpec {
  id: string;
  name: string;
  variant: 'single' | 'twinset' | 'stage';
  capacityL: number;
  ratedBar: number;
  emptyBuoyancyKg: number;
  dryMassKg: number;
  regsBuoyancyKg: number;
}

