/**
 * SpriteBiotaPool — per-scene Sprite pool keyed by archetype.
 *
 * The Pixi `Graphics` API is rebuilt every frame (clear + redraw), but
 * Sprites are persistent display objects. To bridge the two patterns,
 * scenes call:
 *
 *     pool.beginFrame();
 *     for each creature:
 *         if (pool.draw(archetype, ...) === false) fallbackToGraphics();
 *     pool.endFrame();
 *
 * `beginFrame()` marks every pooled sprite as available; `draw()`
 * claims (or grows) a sprite for that archetype; `endFrame()` hides any
 * sprite not claimed this frame so creatures that scrolled offscreen
 * don't ghost.
 *
 * Sprites are added to `container`, which the scene attaches to its
 * own graph above the procedural Graphics layer.
 */

import { Container, Sprite } from 'pixi.js';
import { getAssetRegistry } from './AssetRegistry';

interface PoolItem {
  sprite: Sprite;
  archetype: string;
  inUse: boolean;
  /** Sim time (s) when this pool slot was first activated — drives anim phase. */
  phaseStart: number;
}

const DEFAULT_FRAME_MS = 120;

export class SpriteBiotaPool {
  readonly container = new Container();
  private items: PoolItem[] = [];

  beginFrame(): void {
    for (const it of this.items) it.inUse = false;
  }

  /**
   * Place a sprite for `archetype` at (x, y). Returns true if the
   * registry had a sprite for this archetype; false otherwise (caller
   * should fall back to procedural drawing).
   *
   * For multi-frame sheets, the active frame is computed from elapsed
   * time since the pool slot was first claimed (per-creature phase
   * offset gives the scene a natural "not all fish in lockstep" look
   * when callers pass `phaseSeed`).
   */
  draw(
    archetype: string,
    x: number,
    y: number,
    rotation: number,
    scale: number,
    tint: number,
    alpha: number = 1,
    phaseSeed: number = 0,
  ): boolean {
    const spec = getAssetRegistry().get(archetype);
    if (!spec) return false;

    // Reuse a hidden sprite of the same archetype if one exists.
    let item = this.items.find((p) => !p.inUse && p.archetype === archetype);
    if (!item) {
      const sprite = new Sprite(spec.frames[0]);
      const ax = spec.anchor?.x ?? 0.5;
      const ay = spec.anchor?.y ?? 0.5;
      sprite.anchor.set(ax, ay);
      this.container.addChild(sprite);
      item = {
        sprite,
        archetype,
        inUse: false,
        phaseStart: performance.now() * 0.001,
      };
      this.items.push(item);
    }

    // Pick a frame if the sprite is animated.
    if (spec.frames.length > 1) {
      const frameMs = spec.frameDurationMs ?? DEFAULT_FRAME_MS;
      const t = (performance.now() * 0.001 - item.phaseStart) + phaseSeed;
      const idx = Math.floor((t * 1000) / frameMs) % spec.frames.length;
      item.sprite.texture = spec.frames[idx >= 0 ? idx : (idx + spec.frames.length)];
    }

    const baseScale = spec.baseScale ?? 1;
    item.inUse = true;
    item.sprite.visible = true;
    item.sprite.x = x;
    item.sprite.y = y;
    item.sprite.rotation = rotation;
    item.sprite.scale.set(scale * baseScale);
    item.sprite.tint = tint;
    item.sprite.alpha = alpha;
    return true;
  }

  endFrame(): void {
    for (const it of this.items) if (!it.inUse) it.sprite.visible = false;
  }

  /** Drop every pooled sprite — used when a scene is torn down. */
  destroy(): void {
    for (const it of this.items) it.sprite.destroy();
    this.items.length = 0;
    this.container.removeChildren();
  }
}
