/**
 * Placeholder marine-life atlas — 7 hand-rolled SVG creature sprites.
 *
 * Drawn as grayscale-with-accents (white body, grey fins, black eye)
 * so Pixi's tint can apply each creature's `litColor` and yield a
 * coherent palette across the existing colour pools. After tint:
 *   #fff (body)   → full tint colour
 *   #bbb (belly)  → ~73% tint
 *   #888 (fins)   → ~53% tint
 *   #555 (deep)   → ~33% tint
 *   #000 (eye)    → black
 *
 * `school` is intentionally skipped — its existing procedural
 * implementation has lively per-fish phase oscillation that a static
 * sprite can't match. GenScene falls back to procedural for any
 * archetype the registry doesn't have.
 *
 * Licence: CC0 / public domain. These are original simple shapes
 * drawn by hand for placeholder purposes; replace with a higher-
 * fidelity pack later by registering different sprites under the
 * same archetype keys.
 */

import type { SpriteSource } from './types';

