/**
 * Concrete dive modes — Air / Nitrox / 3GasNx / Gauge.
 *
 * Each mode is a plain object satisfying the `DiveMode` interface; instances
 * are immutable so callers can keep references safely.
 */

import type { GasMix } from '../engine';
import type { DiveMode, DiveModeId } from './types';

const isAir = (g: GasMix): boolean => g.o2Pct === 21 && g.hePct === 0;
const noHelium = (g: GasMix): boolean => g.hePct === 0;

export const airMode: DiveMode = {
  id: 'air',
  name: 'Air',
  shortTag: 'AIR',
  maxGases: 1,
  allowsGasSwitch: false,
  tracksTissues: true,
  maxO2Pct: 21,
  allowsTrimix: false,
  filterGases: (all) => all.filter(isAir).slice(0, 1),
};

export const nitroxMode: DiveMode = {
  id: 'nitrox',
  name: 'Nitrox',
  shortTag: 'NX',
  maxGases: 1,
  allowsGasSwitch: false,
  tracksTissues: true,
  maxO2Pct: 40,
  allowsTrimix: false,
  filterGases: (all) =>
    all.filter((g) => noHelium(g) && g.o2Pct >= 21 && g.o2Pct <= 40).slice(0, 1),
};

export const threeGasMode: DiveMode = {
  id: '3gas-nx',
  name: '3 Gas Nx',
  shortTag: '3NX',
  maxGases: 3,
  allowsGasSwitch: true,
  tracksTissues: true,
  maxO2Pct: 100,
  allowsTrimix: false,
  filterGases: (all) =>
    all.filter((g) => noHelium(g) && g.o2Pct >= 21).slice(0, 3),
};

export const gaugeMode: DiveMode = {
  id: 'gauge',
  name: 'Gauge',
  shortTag: 'GAUGE',
  maxGases: 0,
  allowsGasSwitch: false,
  tracksTissues: false,
  maxO2Pct: 100,
  allowsTrimix: false,
  // Gauge ignores gases entirely — return empty so the deco planner has
  // nothing to chew on and the engine consumer can skip tissue updates.
  filterGases: () => [],
};

export const ALL_MODES: readonly DiveMode[] = [
  airMode,
  nitroxMode,
  threeGasMode,
  gaugeMode,
];

export function getMode(id: DiveModeId): DiveMode {
  switch (id) {
    case 'air':     return airMode;
    case 'nitrox':  return nitroxMode;
    case '3gas-nx': return threeGasMode;
    case 'gauge':   return gaugeMode;
  }
}
