/**
 * ZoneOverlay — small floating chip showing the current zone label plus the
 * creature population + variety reported by the active scene.
 *
 * Lives inside the water view overlay (z-index just above the world but
 * below modals + watch panels).
 */

export interface ZoneOverlayValues {
  scene: string;   // scene display name
  label: string;
  population: number;
  variety: number;
  note?: string;
}

export class ZoneOverlay {
  readonly el: HTMLElement;
  private elScene!: HTMLElement;
  private elZone!: HTMLElement;
  private elPop!: HTMLElement;
  private elVar!: HTMLElement;
  private elNote!: HTMLElement;

  constructor() {
    this.el = document.createElement('div');
    this.el.className = 'zone-overlay';
    this.el.innerHTML = /*html*/ `
      <div class="zh">
        <span class="scene" data-bind="scene">CLIFF WALL</span>
        <span class="sep">·</span>
        <span class="zone" data-bind="zone">SHALLOW REEF</span>
      </div>
      <div class="zb">
        <span class="cell"><span class="lbl">POP</span><b data-bind="pop">0</b></span>
        <span class="cell"><span class="lbl">VAR</span><b data-bind="var">0</b></span>
        <span class="note" data-bind="note"></span>
      </div>
    `;
    this.elScene = this.el.querySelector('[data-bind="scene"]') as HTMLElement;
    this.elZone  = this.el.querySelector('[data-bind="zone"]')  as HTMLElement;
    this.elPop   = this.el.querySelector('[data-bind="pop"]')   as HTMLElement;
    this.elVar   = this.el.querySelector('[data-bind="var"]')   as HTMLElement;
    this.elNote  = this.el.querySelector('[data-bind="note"]')  as HTMLElement;
  }

  update(v: ZoneOverlayValues): void {
    this.elScene.textContent = v.scene;
    this.elZone.textContent  = v.label;
    this.elPop.textContent   = String(v.population);
    this.elVar.textContent   = String(v.variety);
    this.elNote.textContent  = v.note ?? '';
  }
}
