import { Container, Graphics } from 'pixi.js';
import type { SimState } from '../state';
import { clamp } from '../physics';

interface Particle {
  xNorm: number;        // 0..1 across width
  worldY: number;       // world depth m
  size: number;
  drift: number;        // horizontal drift L/s
  brightness: number;
}

/**
 * Drifting particulate matter — depth-anchored in world space so descending
 * the camera shows them rising past the diver. Brightness fades with depth.
 */
/**
 * Drifting particulate matter — depth-anchored in world space so descending
 * the camera shows them rising past the diver. Brightness fades with depth.
 *
 * Silt-stir: when the diver hovers close to a sand/silt bottom, host code
 * calls `setStirLevel()` (0..1) to drive a brown silt cloud that thickens
 * the visible field and trails behind the diver.
 */
export class Particulates {
  container = new Container();
  private gfx = new Graphics();
  private particles: Particle[] = [];
  /** Sandy/silty particles spawned by bottom-proximity. Trail behind the diver. */
  private silt: SiltParticle[] = [];
  private w = 0;
  private h = 0;
  private stirLevel = 0;
  /** Last reported diver screen position — used to anchor the silt cloud. */
  private diverScreenX = 0;
  private diverScreenY = 0;
  private spawnAccum = 0;

  constructor(count = 130) {
    this.container.addChild(this.gfx);
    for (let i = 0; i < count; i++) {
      this.particles.push({
        xNorm: Math.random(),
        worldY: Math.random() * 40 - 5,
        size: 0.6 + Math.random() * 1.8,
        drift: (Math.random() - 0.5) * 0.04,
        brightness: 0.3 + Math.random() * 0.5,
      });
    }
  }

  resize(w: number, h: number) {
    this.w = w;
    this.h = h;
  }

  /** Set the silt-stir intensity (0 = none, 1 = heavy). Capped silently. */
  setStirLevel(level: number): void {
    this.stirLevel = Math.max(0, Math.min(1, level));
  }

  /** Host hook — the diver's current screen position, used as the silt source. */
  setDiverScreen(x: number, y: number): void {
    this.diverScreenX = x;
    this.diverScreenY = y;
  }

  update(state: SimState, dt: number, camTopDepth: number, pxPerMeter: number) {
    this.gfx.clear();
    const depthTint = clamp(1 - (state.depth / 80) * 0.7, 0.15, 1);
    const viewMeters = this.h / pxPerMeter;

    // Base particulates — always drift.
    for (const p of this.particles) {
      while (p.worldY - camTopDepth > viewMeters + 5) p.worldY -= viewMeters * 2;
      while (p.worldY - camTopDepth < -5) p.worldY += viewMeters * 2;
      p.xNorm += p.drift * dt;
      if (p.xNorm < 0) p.xNorm += 1;
      if (p.xNorm > 1) p.xNorm -= 1;
      const x = p.xNorm * this.w;
      const y = (p.worldY - camTopDepth) * pxPerMeter;
      if (y < -8 || y > this.h + 8) continue;
      this.gfx
        .circle(x, y, p.size)
        .fill({ color: 0xdceaf5, alpha: p.brightness * 0.6 * depthTint });
    }

    // Silt cloud — only when stirred. Particles spawn under/around the diver
    // and drift downward + outward, fading over ~3 s. Visibility hit = more
    // particles painted on screen.
    if (this.stirLevel > 0.02) {
      // Target spawn rate ~30 / s at full stir.
      this.spawnAccum += dt * this.stirLevel * 30;
      while (this.spawnAccum >= 1) {
        this.spawnAccum -= 1;
        this.silt.push({
          x: this.diverScreenX + (Math.random() - 0.5) * 60,
          y: this.diverScreenY + 12 + Math.random() * 14,
          vx: (Math.random() - 0.5) * 14,
          vy: -4 - Math.random() * 8,      // slight upward — disturbed silt floats briefly
          r: 1.4 + Math.random() * 2.6,
          life: 1.0,
          tint: 0xb59c6e,
        });
      }
    }
    // Update + draw silt, with silt-particle lifetimes independent of stir.
    for (let i = this.silt.length - 1; i >= 0; i--) {
      const s = this.silt[i];
      s.x += s.vx * dt;
      s.y += s.vy * dt;
      // Soft downward acceleration as the silt resettles.
      s.vy += 12 * dt;
      s.life -= dt * 0.35;
      if (s.life <= 0 || s.y > this.h + 20) {
        this.silt.splice(i, 1);
        continue;
      }
      this.gfx
        .circle(s.x, s.y, s.r)
        .fill({ color: s.tint, alpha: 0.6 * s.life * depthTint });
    }
  }
}

interface SiltParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  r: number;
  life: number;
  tint: number;
}

interface Bubble {
  xNorm: number;
  y: number;
  r: number;
  vy: number;
  vx: number;
  life: number;
}

/**
 * Bubble stream emitted from the regulator when the diver is exhaling.
 * Bubbles rise (decreasing y in screen space), wobble slightly, and fade.
 */
export class Bubbles {
  container = new Container();
  private gfx = new Graphics();
  private bubbles: Bubble[] = [];
  private w = 0;
  private h = 0;

  constructor() {
    this.container.addChild(this.gfx);
  }

  resize(w: number, h: number) {
    this.w = w;
    this.h = h;
  }

  /** Single exhale bubble at the mouth, which flips with the diver's facing. */
  spawnExhale(diverScreenX: number, diverScreenY: number, facing: number) {
    const dir = facing < 0 ? -1 : 1;
    this.bubbles.push({
      xNorm: (diverScreenX + 32 * dir) / Math.max(1, this.w) +
        (Math.random() - 0.5) * 0.01,
      y: diverScreenY + 4,
      r: 1 + Math.random() * 2.5,
      vy: 35 + Math.random() * 30,
      vx: (Math.random() - 0.5) * 8 + dir * 6, // slight forward drift
      life: 1.0,
    });
  }

  /**
   * Burst of vent bubbles from the BCD inflator/dump valve (upper-back of the
   * diver). Larger and faster than exhale bubbles; count scales with the
   * litres vented this step.
   */
  spawnVent(diverScreenX: number, diverScreenY: number, ventL: number) {
    // ~4-12 bubbles per emit, more if a lot of gas vented at once.
    const n = Math.min(12, 2 + Math.floor(ventL * 6));
    for (let i = 0; i < n; i++) {
      this.bubbles.push({
        // BCD wing sits above the diver (-22..-16 px); jitter horizontally a bit.
        xNorm: (diverScreenX + (Math.random() - 0.5) * 14) / Math.max(1, this.w),
        y: diverScreenY - 18 + Math.random() * 6,
        r: 1.6 + Math.random() * 3.2,    // larger than exhale
        vy: 55 + Math.random() * 40,      // rise faster
        vx: (Math.random() - 0.5) * 18,
        life: 1.0,
      });
    }
  }

  update(
    dt: number,
    exhaleRate: number,
    ventL: number,
    diverX: number,
    diverY: number,
    facing: number
  ) {
    if (exhaleRate > 0 && Math.random() < clamp(exhaleRate * 0.9, 0, 0.9)) {
      this.spawnExhale(diverX, diverY, facing);
    }
    if (ventL > 0.02) {
      this.spawnVent(diverX, diverY, ventL);
    }

    this.gfx.clear();
    for (let i = this.bubbles.length - 1; i >= 0; i--) {
      const b = this.bubbles[i];
      b.y -= b.vy * dt;
      b.xNorm += (b.vx * dt) / Math.max(1, this.w);
      b.life -= dt * 0.7;
      if (b.life <= 0 || b.y < -10) {
        this.bubbles.splice(i, 1);
        continue;
      }
      const x = b.xNorm * this.w;
      this.gfx
        .circle(x, b.y, b.r)
        .fill({ color: 0xdcf0fa, alpha: 0.5 * b.life })
        .stroke({ color: 0xffffff, alpha: 0.6 * b.life, width: 0.6 });
    }
  }
}
