import { FRC_L } from './config';
import { defaultEquipment, type EquipmentConfig } from './equipment';
import { detectOS } from './platform';

const WHEEL_INVERT_KEY = 'ppb.wheelInvert';

/**
 * Resolve the wheel-invert default at boot time.
 *
 *   1. If the user has explicitly toggled the setting before, the
 *      localStorage value wins (sticky preference).
 *   2. Otherwise, default to ON for macOS (because Mac's system-level
 *      "natural scroll" already inverts wheel direction — without this
 *      flip, scroll-down would feel like exhale on Mac) and OFF on
 *      Windows / Linux / unknown.
 */
function defaultWheelInvert(): boolean {
  try {
    const stored = localStorage.getItem(WHEEL_INVERT_KEY);
    if (stored === 'true') return true;
    if (stored === 'false') return false;
  } catch { /* private mode / disabled storage — fall through */ }
  return detectOS() === 'mac';
}

/** Persist the user's manual wheel-invert choice so OS-default doesn't fight it next reload. */
export function persistWheelInvert(value: boolean): void {
  try { localStorage.setItem(WHEEL_INVERT_KEY, String(value)); }
  catch { /* quota / disabled storage */ }
}

export interface UserSettings {
  /** When true, wheel-up = inhale (default false: wheel-down = inhale). */
  wheelInvert: boolean;
  /** When true, fire the lung-overpressure banner when transpulmonary > limits. */
  barotraumaWarning: boolean;
}

export interface SimState {
  // Kinematics (vertical)
  depth: number;
  v: number;
  a: number;

  // Kinematics (horizontal — kicking)
  /** Virtual x position in metres (purely for telemetry/scene parallax). */
  x: number;
  /** Horizontal velocity, m/s. */
  vx: number;
  /** Sim time of last kick, for refractory + rapid-kick detection. */
  lastKickT: number;
  /** -1 left, +1 right, 0 none — latest stroke direction. */
  lastKickDir: -1 | 0 | 1;
  /** Animation-only kick pulse (0..1), decays each frame. */
  kickPulse: number;

  // Lung state
  /** Current actual lung volume (L), clamped to [RV, TLC]. */
  lungCur: number;
  /** Computed target volume (auto-breath + bias, or hold-Boyle). */
  lungTgt: number;
  /** Wheel-driven offset added to FRC baseline (L). Decays slowly to 0. */
  lungBias: number;

  // Breath-hold
  /** True while the middle mouse button is held. */
  breathHold: boolean;
  /** Snapshot of gas mass in lungs (in surface-equivalent L = V × P_atm). */
  holdGasMassSE: number;
  /** Elapsed time of current hold (s) — informational. */
  holdElapsed: number;
  /** Current transpulmonary pressure (bar). Signed: + = lungs overpressure. */
  transpulmonaryBar: number;

  // Stress (0..1) — CO₂-driven arousal component.
  stress: number;
  /** Exercise-driven arousal (0..1). Smoothly tracks `exertionTarget` with a
   *  ~4 s time constant — kicks no longer cause an instant jump in breathing. */
  exertion: number;
  /** Setpoint that kicks bump up directly. Exertion lerps toward this each
   *  frame and the target itself decays exponentially. */
  exertionTarget: number;

  // BCD
  bcdSurf: number;

  // CO2 + ventilation
  co2: number;
  ventMetric: number;
  breathPhase: -1 | 0 | 1;
  breathTimes: number[];

  // SAC tracking
  /**
   * Per-step gas consumption in a 5-second rolling window.
   *   • `lSTP` — litres at surface pressure (= the diver's actual tank
   *     drain in surface-equivalent volume; used by tank-pressure math)
   *   • `lRMV` — litres at ambient pressure (= lSTP / P_amb at the
   *     moment of logging; sums to the depth-normalised SAC the book
   *     describes — Ch. 11.2, "SAC L/min = RMV")
   */
  gasLog: { t: number; lSTP: number; lRMV: number }[];
  /** Total gas consumed (L STP) since dive start. */
  gasConsumedSinceStartL: number;
  /** Total RMV-equivalent gas consumed (L at ambient) since dive start. */
  gasConsumedRMVL: number;
  /** Sim time (s) at which depth first crossed ~1 m, or null pre-dive. */
  diveStartT: number | null;

  // Scoring
  onTargetTime: number;
  bestTime: number;

  // Sim clock
  t: number;

  // Config
  equipment: EquipmentConfig;
  settings: UserSettings;

  // Pause flag (modal open)
  paused: boolean;
}

export function defaultSettings(): UserSettings {
  return {
    wheelInvert: defaultWheelInvert(),
    barotraumaWarning: true,
  };
}

export function createState(): SimState {
  return {
    depth: 0,
    v: 0,
    a: 0,
    x: 0,
    vx: 0,
    lastKickT: -10,
    lastKickDir: 0,
    kickPulse: 0,
    lungCur: FRC_L,
    lungTgt: FRC_L,
    lungBias: 0,
    breathHold: false,
    holdGasMassSE: FRC_L,
    holdElapsed: 0,
    transpulmonaryBar: 0,
    stress: 0,
    exertion: 0,
    exertionTarget: 0,
    bcdSurf: 0,
    co2: 40,
    ventMetric: 0.25,
    breathPhase: 0,
    breathTimes: [],
    gasLog: [],
    gasConsumedSinceStartL: 0,
    gasConsumedRMVL: 0,
    diveStartT: null,
    onTargetTime: 0,
    bestTime: 0,
    t: 0,
    equipment: defaultEquipment(),
    settings: defaultSettings(),
    paused: false,
  };
}

export function resetState(s: SimState) {
  s.depth = 0;
  s.v = 0;
  s.a = 0;
  s.x = 0;
  s.vx = 0;
  s.lastKickT = -10;
  s.lastKickDir = 0;
  s.kickPulse = 0;
  s.lungCur = FRC_L;
  s.lungTgt = FRC_L;
  s.lungBias = 0;
  s.breathHold = false;
  s.holdGasMassSE = FRC_L;
  s.holdElapsed = 0;
  s.transpulmonaryBar = 0;
  s.stress = 0;
  s.exertion = 0;
  s.exertionTarget = 0;
  s.bcdSurf = 0;
  s.co2 = 40;
  s.ventMetric = 0.25;
  s.breathPhase = 0;
  s.breathTimes.length = 0;
  s.gasLog.length = 0;
  s.gasConsumedSinceStartL = 0;
  s.gasConsumedRMVL = 0;
  s.diveStartT = null;
  s.onTargetTime = 0;
  s.equipment.tankPressureBar = s.equipment.cylinder.ratedPressureBar;
  // equipment selections, settings, bestTime preserved
}
