/**
 * Rasterise an inline SVG string to a Pixi Texture.
 *
 * Pixi's Assets loader can take an SVG URL directly, but inline data
 * URLs sometimes hit MIME parsing quirks across browsers; doing the
 * Blob → Image → Canvas → Texture trip ourselves is more predictable
 * and gives us full control over the rasterisation resolution.
 *
 * Drawn at 2× the logical size for crisp display on high-DPI screens.
 */

import { Texture } from 'pixi.js';

export async function svgToTexture(
  svg: string,
  width: number,
  height: number,
): Promise<Texture> {
  const blob = new Blob([svg], { type: 'image/svg+xml' });
  const url = URL.createObjectURL(blob);
  try {
    const img = new Image();
    await new Promise<void>((resolve, reject) => {
      img.onload = () => resolve();
      img.onerror = (e) => reject(new Error(`SVG decode failed: ${String(e)}`));
      img.src = url;
    });
    const dpr = Math.min(2, window.devicePixelRatio || 1);
    const canvas = document.createElement('canvas');
    canvas.width = Math.max(1, Math.round(width * dpr * 2));
    canvas.height = Math.max(1, Math.round(height * dpr * 2));
    const ctx = canvas.getContext('2d');
    if (!ctx) throw new Error('2D context unavailable');
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    return Texture.from(canvas);
  } finally {
    URL.revokeObjectURL(url);
  }
}
