/**
 * CaveScene — overhead environment with rock ceiling, sand floor, and a
 * single open shaft to the surface near the entry. Exercises ceiling
 * collision: diver can't ascend through rock except at the shaft.
 *
 * Geometry (world-x in metres):
 *   0–6      open entry shaft (rock floor at ~22 m, no ceiling)
 *   6–34     cave proper — ceiling at ~12 m (jagged), floor at ~22 m
 *   34+      back wall (vertical pillar both above and below)
 *
 * The ceiling and floor are sampled at 1 m resolution. Physics uses
 * getDepthLimitsAt(worldX) which returns the appropriate [ceiling, floor]
 * for that x. Colliders for the back wall are returned via getColliders().
 */

import { Container, Graphics } from 'pixi.js';
import type { SimState } from '../state';
import { resolveDepthLimits } from './collision';
import type {
  CollisionRect,
  DepthLimits,
  HazardContact,
  Scene,
  ZoneInfo,
} from './types';

const STRIP_LENGTH_M = 60;
const SAMPLES_PER_M = 1;
const SHAFT_END_M = 6;
const BACK_WALL_M = 34;
const CEIL_BASE_M = 12;
const CEIL_AMP_M = 1.6;
const FLOOR_BASE_M = 22;
const FLOOR_AMP_M = 0.8;

interface CaveCreature {
  archetype: 'shrimp' | 'urchin' | 'school';
  worldX: number;
  depth: number;
  phase: number;
  scale: number;
  color: number;
  index: number;
  hazard?: HazardContact['kind'];
  hazardLabel?: string;
}

export class CaveScene implements Scene {
  readonly id = 'cave';
  readonly name = 'CAVE';
  readonly container = new Container();

  private rockGfx = new Graphics();
  private floorGfx = new Graphics();
  private biotaGfx = new Graphics();
  private ceilProfile: number[] = [];
  private floorProfile: number[] = [];
  private creatures: CaveCreature[] = [];

  private w = 0;
  private h = 0;
  private pxPerMeter = 60;

  constructor() {
    this.container.addChild(this.rockGfx, this.floorGfx, this.biotaGfx);
    this.buildProfiles();
    this.buildCreatures();
  }

  resize(w: number, h: number, pxPerMeter: number): void {
    this.w = w;
    this.h = h;
    this.pxPerMeter = pxPerMeter;
  }

  update(
    _state: SimState,
    camTopDepth: number,
    scrollX: number,
    _sun: number,
    _ill: number
  ): void {
    if (!this.w || !this.h) return;
    const camBotDepth = camTopDepth + this.h / this.pxPerMeter;
    this.drawRock(camTopDepth, camBotDepth, scrollX);
    this.drawFloor(camTopDepth, camBotDepth, scrollX);
    this.drawBiota(camTopDepth, camBotDepth, scrollX);
  }

  // ---------------- Scene API ----------------

  zoneInfoAt(depth: number): ZoneInfo {
    if (depth < 4) return { label: 'OPEN SHAFT', population: 0, variety: 0, note: 'route to surface' };
    if (depth < CEIL_BASE_M)
      return { label: 'SHAFT', population: this.creatures.filter(c => c.depth < CEIL_BASE_M).length,
        variety: 2, note: 'rock ceiling above 12 m' };
    if (depth < FLOOR_BASE_M - 1)
      return { label: 'CAVE INTERIOR', population: this.creatures.length, variety: 3,
        note: 'overhead environment — no direct ascent' };
    return { label: 'CAVE FLOOR', population: 8, variety: 2, note: 'silt + shrimp' };
  }

  /** Cave colliders: a thick back-wall pillar that fully blocks past BACK_WALL_M. */
  getColliders(): CollisionRect[] {
    return [
      {
        centreX_m: BACK_WALL_M + 6,
        centreDepth_m: 12,
        halfW_m: 7,
        halfH_m: 50,        // tall enough to block at any depth
        rotation: 0,
      },
    ];
  }

  /**
   * Depth window the diver may occupy:
   *   inside the cave (SHAFT_END_M..BACK_WALL_M):
   *     ceiling = ceilAt(worldX), floor = floorAt(worldX)
   *   in the shaft (0..SHAFT_END_M):
   *     ceiling = 0, floor = floorAt(worldX) — surface is reachable here
   *   past the back wall: only matters via getColliders()
   */
  getDepthLimitsAt(worldX_m: number, currentDepth_m: number = 0): DepthLimits {
    let ceiling = 0;
    let floor = this.floorAt(worldX_m) - 0.25;
    if (worldX_m > SHAFT_END_M) {
      ceiling = this.ceilAt(worldX_m) + 0.25;
    } else {
      // In the shaft, soft ramp the ceiling so the diver doesn't snap when
      // crossing the lip — interpolate from 0 to ceilAt() over the last 1 m.
      const t = Math.max(0, Math.min(1, (worldX_m - (SHAFT_END_M - 1)) / 1));
      ceiling = t * (this.ceilAt(worldX_m) + 0.25);
    }
    return resolveDepthLimits(worldX_m, currentDepth_m, floor, ceiling, this.getColliders());
  }

  getBottomDepthAt(scrollX_m: number): number | null {
    const worldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    return this.floorAt(worldX);
  }

  getHazardContacts(scrollX_m: number, diverDepth_m: number, range_m: number): HazardContact[] {
    const worldX = scrollX_m + (this.w / Math.max(1, this.pxPerMeter)) * 0.5;
    const out: HazardContact[] = [];
    for (const c of this.creatures) {
      if (!c.hazard) continue;
      const dx = c.worldX - worldX;
      const dy = c.depth - diverDepth_m;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist <= range_m) {
        out.push({
          kind: c.hazard,
          label: c.hazardLabel ?? c.archetype.toUpperCase(),
          id: `${c.hazard}:${c.index}`,
          severity: 1 - dist / range_m,
        });
      }
    }
    return out;
  }

  // ---------------- Geometry ----------------

  private buildProfiles(): void {
    const total = STRIP_LENGTH_M * SAMPLES_PER_M;
    for (let i = 0; i < total; i++) {
      const u = i / SAMPLES_PER_M;
      // Ceiling: jagged, sharper variation.
      const c = 0.5 * Math.sin(u * 0.33 + 1.7) + 0.4 * Math.sin(u * 0.91 + 2.9)
              + 0.2 * Math.sin(u * 2.1 + 1.1);
      this.ceilProfile.push(c);
      // Floor: gentler.
      const f = 0.55 * Math.sin(u * 0.21 + 0.7) + 0.3 * Math.sin(u * 0.47 + 2.1);
      this.floorProfile.push(f);
    }
  }

  private ceilAt(worldX: number): number {
    if (worldX <= SHAFT_END_M) return -10;   // open shaft — ceiling far overhead.
    const u = Math.max(0, Math.min(STRIP_LENGTH_M - 1, worldX));
    const idx = Math.floor(u * SAMPLES_PER_M) % this.ceilProfile.length;
    return CEIL_BASE_M + this.ceilProfile[idx] * CEIL_AMP_M;
  }

  private floorAt(worldX: number): number {
    const u = Math.max(0, Math.min(STRIP_LENGTH_M - 1, worldX));
    const idx = Math.floor(u * SAMPLES_PER_M) % this.floorProfile.length;
    return FLOOR_BASE_M + this.floorProfile[idx] * FLOOR_AMP_M;
  }

  // ---------------- Drawing ----------------

  private drawRock(camTopDepth: number, camBotDepth: number, scrollX: number): void {
    const g = this.rockGfx;
    g.clear();
    if (camBotDepth < 0) return;
    const samples = Math.max(60, Math.ceil(this.w / 8));
    const dx = this.w / samples;

    // Build a polygon from the screen top down to the ceiling curve.
    const pts: number[] = [];
    pts.push(0, -10);
    for (let i = 0; i <= samples; i++) {
      const px = i * dx;
      const worldX = scrollX + px / this.pxPerMeter;
      const cd = this.ceilAt(worldX);
      const y = cd > 0 ? (cd - camTopDepth) * this.pxPerMeter : -20;
      pts.push(px, y);
    }
    pts.push(this.w, -10);
    g.poly(pts).fill({ color: 0x2a221e, alpha: 0.98 });

    // Scatter darker speckles for texture along the ceiling.
    for (let i = 0; i < samples; i += 2) {
      const px = i * dx;
      const worldX = scrollX + px / this.pxPerMeter;
      const cd = this.ceilAt(worldX);
      if (cd <= 0) continue;
      const y = (cd - camTopDepth) * this.pxPerMeter;
      g.circle(px + (i % 3) * 2, y + 2, 1.2).fill({ color: 0x1a1310, alpha: 0.7 });
    }

    // Back wall — a vertical mass past BACK_WALL_M.
    const wallScreenX = (BACK_WALL_M - scrollX) * this.pxPerMeter;
    if (wallScreenX < this.w + 60) {
      const left = Math.max(0, wallScreenX);
      g.rect(left, -10, this.w - left + 60, this.h + 20)
        .fill({ color: 0x2a221e, alpha: 0.98 });
    }
  }

  private drawFloor(camTopDepth: number, camBotDepth: number, scrollX: number): void {
    const g = this.floorGfx;
    g.clear();
    if (camBotDepth < FLOOR_BASE_M - FLOOR_AMP_M - 1) return;
    const samples = Math.max(40, Math.ceil(this.w / 10));
    const dx = this.w / samples;
    const pts: number[] = [];
    pts.push(0, this.h + 10);
    for (let i = 0; i <= samples; i++) {
      const px = i * dx;
      const worldX = scrollX + px / this.pxPerMeter;
      const fd = this.floorAt(worldX);
      pts.push(px, (fd - camTopDepth) * this.pxPerMeter);
    }
    pts.push(this.w, this.h + 10);
    g.poly(pts).fill({ color: 0x4a3d2a, alpha: 0.96 });
  }

  // ---------------- Biota ----------------

  private buildCreatures(): void {
    const rand = mulberry32(0xcaffe1);
    const push = (
      archetype: CaveCreature['archetype'],
      count: number,
      xRange: [number, number],
      depthBand: 'ceiling' | 'floor' | [number, number],
      hazard?: HazardContact['kind'],
      hazardLabel?: string,
    ) => {
      for (let i = 0; i < count; i++) {
        const worldX = xRange[0] + rand() * (xRange[1] - xRange[0]);
        let depth: number;
        if (depthBand === 'ceiling') {
          depth = this.ceilAt(worldX) + 0.4;
        } else if (depthBand === 'floor') {
          depth = this.floorAt(worldX) - 0.3;
        } else {
          depth = depthBand[0] + rand() * (depthBand[1] - depthBand[0]);
        }
        this.creatures.push({
          archetype,
          worldX,
          depth,
          phase: rand() * Math.PI * 2,
          scale: 0.7 + rand() * 0.6,
          color: archetype === 'shrimp' ? 0xc69772 :
                 archetype === 'urchin' ? 0x2a1822 :
                 0xb6cfd6,
          index: this.creatures.length,
          hazard,
          hazardLabel,
        });
      }
    };
    push('shrimp', 14, [8, BACK_WALL_M - 2], 'floor');
    push('urchin',  6, [10, BACK_WALL_M - 2], 'ceiling', 'stinging', 'URCHIN');
    push('school',  4, [9, BACK_WALL_M - 4], [14, 18]);
  }

  private drawBiota(camTopDepth: number, camBotDepth: number, scrollX: number): void {
    const g = this.biotaGfx;
    g.clear();
    const t = performance.now() * 0.001;
    for (const c of this.creatures) {
      const sx = (c.worldX - scrollX) * this.pxPerMeter;
      if (sx < -40 || sx > this.w + 40) continue;
      const eff = c.depth + (c.archetype === 'school' ? Math.sin(t * 0.5 + c.phase) * 0.4 : 0);
      if (eff < camTopDepth - 1 || eff > camBotDepth + 1) continue;
      const sy = (eff - camTopDepth) * this.pxPerMeter;
      const phase = c.phase + t * 0.6;
      switch (c.archetype) {
        case 'shrimp': {
          const r = 1.6 * c.scale;
          g.ellipse(sx, sy, r * 1.6, r * 0.7).fill({ color: c.color, alpha: 0.95 });
          g.moveTo(sx, sy).lineTo(sx + r * 1.4, sy + r * 1.2)
            .stroke({ color: c.color, alpha: 0.7, width: 0.6 });
          break;
        }
        case 'urchin': {
          const r = 3.2 * c.scale;
          g.circle(sx, sy, r).fill({ color: c.color, alpha: 0.95 });
          for (let i = 0; i < 8; i++) {
            const a = (i / 8) * Math.PI * 2;
            g.moveTo(sx, sy).lineTo(sx + Math.cos(a) * r * 1.8, sy + Math.sin(a) * r * 1.8)
              .stroke({ color: c.color, alpha: 0.8, width: 0.8 });
          }
          break;
        }
        case 'school': {
          const n = 7;
          for (let i = 0; i < n; i++) {
            const a = i * 0.7 + phase;
            const fx = sx + Math.cos(a) * 14 * c.scale;
            const fy = sy + Math.sin(a * 1.3) * 8 * c.scale;
            const s = 2.2 * c.scale;
            g.poly([fx - s, fy, fx + s, fy - s * 0.5, fx + s, fy + s * 0.5])
              .fill({ color: c.color, alpha: 0.9 });
          }
          break;
        }
      }
    }
  }
}

// ---- helpers ----
function mulberry32(seed: number) {
  let s = seed | 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
