import { Container, Graphics, Text } from 'pixi.js';
import {
  APHOTIC_DEPTH,
  K_LIGHT,
  MAX_DEPTH,
  PRIMARY_LIGHT_RANGE_M,
} from '../config';
import { clamp } from '../physics';
import type { SimState } from '../state';

/**
 * Training-range overlay descriptor. `null` clears the overlay.
 */
export interface TrainingRangeOverlay {
  targetDepth_m: number;
  tolerance_m: number;
  /** 0xRRGGBB tint. Defaults to cyan. */
  color?: number;
}

/** Surface-relative light remaining at depth z (Beer-Lambert). */
export function surfaceLightAt(depth_m: number): number {
  return Math.exp(-K_LIGHT * Math.max(0, depth_m));
}

const METERS_VISIBLE = 14; // vertical world meters that fit the canvas height
/**
 * How far the diver slides horizontally on screen before the camera starts
 * panning. Inside this band, kicks move the diver visibly across the canvas;
 * beyond it the diver pegs at the edge and the scenery scrolls instead.
 */
const DIVER_SLIDE_RANGE_M = 5;

interface DepthLabel {
  meter: number;
  gfx: Graphics;
  txt: Text;
}

export class WaterScene {
  /** Base layer — water gradient, caustics, depth grid (rendered first). */
  container = new Container();
  /** Overlay layer — darkness, light cone, target band (rendered between
   *  scenery and the diver). */
  overlay = new Container();
  /**
   * Foreground layer — sits ON TOP of the diver/particles/bubbles so the
   * visibility tint actually dims the diver too (not just the scenery).
   * Drawn last in main.ts world container.
   */
  foreground = new Container();
  private bg = new Graphics();
  private darkness = new Graphics();
  /**
   * Mid-layer haze (between scenery and diver). Subtle. Most of the tint
   * lives in `hazeFg` so the diver visibly dims when visibility drops.
   */
  private haze = new Graphics();
  /** Foreground haze rectangle — painted on the foreground layer. */
  private hazeFg = new Graphics();
  private lightCone = new Graphics();
  private gridLayer = new Container();
  private surfaceLayer = new Container();
  private causticsLayer = new Container();
  private targetLayer = new Graphics();
  private surfaceLine = new Graphics();
  private causticShafts: Graphics[] = [];
  /** Visibility 0..1 (1 = clear, 0 = full blackout). */
  private visibilityLevel = 1;
  /** Tint applied at low visibility. Default deep silt-brown. */
  private hazeColor = 0x2a2018;
  /** Training-range overlay (training-mission-driven). `null` = hidden. */
  private trainingRange: TrainingRangeOverlay | null = null;
  /** Fine dive limit (m). `null` = no warning line. */
  private fineDiveLimit_m: number | null = null;

  private depthLabels: DepthLabel[] = [];
  private w = 0;
  private h = 0;
  private host: HTMLElement;
  private camTopDepth = 0;
  private pxPerMeter = 60;
  /** Light remaining at diver depth (0..1). Exposed for scenery modules. */
  attenuation = 1;
  /** Composite illumination at the diver (max of sun + primary light). */
  illumination = 1;
  /** Horizontal camera offset in metres (>0 = camera has panned right). */
  sceneScrollX = 0;
  /** Pixels the diver is offset from screen centre (within the slide band). */
  private diverScreenOffsetPx = 0;

  constructor(host: HTMLElement) {
    this.host = host;
    this.container.addChild(
      this.bg,
      this.surfaceLayer,
      this.causticsLayer
    );
    // Overlay (rendered after scenery so darkness/light cone dim biota).
    // Depth grid sits ABOVE darkness so the ruler is always readable.
    // Haze rides on top of darkness so it can paint with its own colour.
    this.overlay.addChild(this.darkness, this.haze, this.lightCone, this.gridLayer, this.targetLayer);
    this.foreground.addChild(this.hazeFg);
    // Light cone uses ADD blend so it brightens through the darkness layer.
    this.lightCone.blendMode = 'add';

    // Pool of caustic shaft graphics.
    for (let i = 0; i < 6; i++) {
      const g = new Graphics();
      this.causticShafts.push(g);
      this.causticsLayer.addChild(g);
    }
    this.surfaceLayer.addChild(this.surfaceLine);
  }

  /**
   * Resize the canvas. `pxPerMeter` is supplied externally so the host
   * can decide whether to keep the per-meter density fixed (immersive
   * mode "reveals" more meters) or scale it to the new height (legacy
   * "always 14 m vertical" behaviour). Pass `null` to fall back to the
   * old auto-scale rule.
   */
  resize(width: number, height: number, pxPerMeter?: number | null) {
    this.w = width;
    this.h = height;
    this.pxPerMeter = pxPerMeter ?? height / METERS_VISIBLE;
    this.rebuildDepthGrid();
  }

  /** Project a world depth (m) to screen Y px. */
  worldToScreen(depthM: number): number {
    return (depthM - this.camTopDepth) * this.pxPerMeter;
  }

  /**
   * Set ambient visibility (0..1). 1 = clear, 0 = full blackout.
   * `tintColor` is the colour painted at low visibility — default deep
   * silt-brown; switching to 0x000000 gives a night-dive look, 0xc8b18a
   * a chalky plankton-bloom look. Tint and level can be driven
   * independently from sun illumination.
   */
  setVisibility(level: number, tintColor?: number): void {
    this.visibilityLevel = clamp(level, 0, 1);
    if (tintColor != null) this.hazeColor = tintColor;
  }

  getVisibility(): number { return this.visibilityLevel; }
  getHazeColor(): number { return this.hazeColor; }

  /**
   * Configure the training-range band. Pass `null` to clear the overlay.
   * Drawn by the existing targetLayer each frame.
   */
  setTrainingRange(range: TrainingRangeOverlay | null): void {
    this.trainingRange = range;
  }

  /** Configure the fine-dive-limit warning line (m). `null` clears. */
  setFineDiveLimit(depth_m: number | null): void {
    this.fineDiveLimit_m = depth_m;
  }

  /** Screen Y at which the diver lives. */
  diverScreenY(): number {
    return this.h * 0.6;
  }

  diverScreenX(): number {
    return this.w * 0.5 + this.diverScreenOffsetPx;
  }

  update(state: SimState, dt: number) {
    if (!this.w || !this.h) return;

    // Camera follows diver; diver at 60% from top.
    this.camTopDepth = state.depth - (this.h * 0.6) / this.pxPerMeter;
    const camBotDepth = state.depth + (this.h * 0.4) / this.pxPerMeter;

    // Horizontal: diver slides on screen up to ±DIVER_SLIDE_RANGE_M, beyond
    // that the camera pans and the diver pegs at the edge.
    const localM = clamp(state.x, -DIVER_SLIDE_RANGE_M, DIVER_SLIDE_RANGE_M);
    this.diverScreenOffsetPx = localM * this.pxPerMeter;
    this.sceneScrollX = state.x - localM;

    // --- Water gradient (drawn via CSS on host for crisp anti-aliasing) ---
    // Beer-Lambert: water RGB tends toward deep-navy / black as light drops.
    const c1 = depthColor(Math.max(0, this.camTopDepth));
    const c2 = depthColor(Math.max(0, camBotDepth));
    this.host.style.background = `linear-gradient(180deg, rgb(${c1.join(',')}), rgb(${c2.join(',')}))`;

    // --- Darkness overlay (Beer-Lambert attenuation of natural light) ---
    // No surface light below APHOTIC_DEPTH; in between, exp falloff.
    const sunAt = surfaceLightAt(state.depth);
    const sunFloor = state.depth >= APHOTIC_DEPTH ? 0 : sunAt;
    // Cap darkness so deep water remains navy-blue (matches real ocean photos
    // — at 100 m you still see colour, just dim and blue).
    const darkAlpha = clamp((1 - sunFloor) * 0.62, 0, 0.62);
    this.bg.clear();
    this.darkness.clear();
    // Tint the overlay toward deep navy rather than pure black so the scene
    // doesn't crush to flat darkness — closer to true Beer-Lambert behaviour
    // where the blue channel survives longest.
    this.darkness.rect(0, 0, this.w, this.h).fill({ color: 0x061122, alpha: darkAlpha });

    // Visibility haze — painted across TWO layers so the diver dims with
    // the rest of the scene. The mid-layer copy lives between scenery and
    // diver (in `overlay`); the foreground copy sits ABOVE bubbles (in
    // `foreground`). We split the total alpha ~55/45 so silt looks foggy
    // without completely flat-shading the diver until visibility is near
    // zero.
    this.haze.clear();
    this.hazeFg.clear();
    const v = clamp(this.visibilityLevel, 0, 1);
    if (v < 0.999) {
      const totalAlpha = clamp((1 - v) * (0.4 + (1 - v) * 0.55), 0, 0.95);
      const midAlpha = totalAlpha * 0.55;
      const fgAlpha = totalAlpha * 0.45;
      this.haze.rect(0, 0, this.w, this.h).fill({ color: this.hazeColor, alpha: midAlpha });
      this.hazeFg.rect(0, 0, this.w, this.h).fill({ color: this.hazeColor, alpha: fgAlpha });
    }

    // --- Primary light cone (forward-pointing, ADD-blended) ---
    this.lightCone.clear();
    let primaryAt = 0;
    if (state.equipment.primaryLight) {
      this.drawLightCone(state);
      primaryAt = 1;
    }
    this.attenuation = sunFloor;
    this.illumination = Math.max(sunFloor, primaryAt * 0.95);

    // --- Surface + caustics, only when shallow enough to see them ---
    this.surfaceLayer.visible = this.camTopDepth < 0;
    this.causticsLayer.visible = this.camTopDepth < 1;

    if (this.surfaceLayer.visible) {
      const surfY = -this.camTopDepth * this.pxPerMeter;
      // Wavy surface line
      this.surfaceLine.clear();
      this.surfaceLine.moveTo(0, surfY);
      for (let x = 0; x <= this.w; x += 4) {
        const y =
          surfY +
          Math.sin(x / 40 + state.t * 1.6) * 1.8 +
          Math.sin(x / 13 - state.t * 2.3) * 0.7;
        this.surfaceLine.lineTo(x, y);
      }
      this.surfaceLine.stroke({ color: 0xffffff, alpha: 0.45, width: 1.2 });

      // Sky above surface
      this.surfaceLine
        .rect(0, 0, this.w, Math.max(0, surfY))
        .fill({ color: 0x6ea7c4, alpha: 0.65 });
    }

    if (this.causticsLayer.visible) {
      const surfY = Math.max(-200, -this.camTopDepth * this.pxPerMeter);
      const surfaceVisibility = clamp(1 - state.depth / 8, 0, 1);
      for (let i = 0; i < this.causticShafts.length; i++) {
        const g = this.causticShafts[i];
        g.clear();
        const cx =
          (i * this.w) / this.causticShafts.length +
          ((state.t * 8 + i * 30) % (this.w / this.causticShafts.length));
        g.poly([
          cx - 30, surfY,
          cx + 30, surfY,
          cx + 100, surfY + 260,
          cx - 100, surfY + 260,
        ]).fill({ color: 0xb6e3ef, alpha: 0.16 * surfaceVisibility });
      }
    }

    // --- Depth grid ---
    this.updateDepthGrid(this.camTopDepth, camBotDepth);

    // --- Training-range band + fine-dive-limit line ---
    // Both are level-driven; nothing draws when the level didn't configure them.
    this.targetLayer.clear();
    if (this.trainingRange) {
      const tr = this.trainingRange;
      const ty = this.worldToScreen(tr.targetDepth_m);
      if (ty > -20 && ty < this.h + 20) {
        const tolPx = tr.tolerance_m * this.pxPerMeter;
        const color = tr.color ?? 0x38d6e6;
        this.targetLayer
          .rect(0, ty - tolPx, this.w, tolPx * 2)
          .fill({ color, alpha: 0.05 });
        this.drawDashed(this.targetLayer, 0, ty, this.w, ty, 6, 6);
        this.targetLayer.stroke({ color, alpha: 0.55, width: 1.2 });
        this.drawDashed(this.targetLayer, 0, ty - tolPx, this.w, ty - tolPx, 2, 4);
        this.targetLayer.stroke({ color, alpha: 0.2, width: 1 });
        this.drawDashed(this.targetLayer, 0, ty + tolPx, this.w, ty + tolPx, 2, 4);
        this.targetLayer.stroke({ color, alpha: 0.2, width: 1 });
      }
    }
    if (this.fineDiveLimit_m != null) {
      const ly = this.worldToScreen(this.fineDiveLimit_m);
      if (ly > -20 && ly < this.h + 20) {
        this.drawDashed(this.targetLayer, 0, ly, this.w, ly, 10, 8);
        this.targetLayer.stroke({ color: 0xff4a4a, alpha: 0.7, width: 1.4 });
      }
    }
  }

  /**
   * Forward-pointing light cone — stacked triangles from narrow/bright at the
   * lamp to wide/dim at the tip. Uses ADD blend (set in constructor) so the
   * cone brightens whatever lies beneath the darkness overlay.
   */
  private drawLightCone(state: SimState) {
    const cx = this.diverScreenX();
    const cy = this.diverScreenY();
    // Aim: facing direction from latest kick; default to right.
    const aimX = state.lastKickDir !== 0 ? state.lastKickDir : 1;
    const aimY = 0.18; // tiny downward bias — lamp is mounted high on hip
    const norm = Math.hypot(aimX, aimY);
    const ux = aimX / norm;
    const uy = aimY / norm;
    // Perpendicular for cone spread.
    const px = -uy;
    const py = ux;

    // Lamp origin: just forward of the diver body.
    const lx = cx + ux * 12;
    const ly = cy + uy * 12;

    const rangePx = PRIMARY_LIGHT_RANGE_M * this.pxPerMeter * 0.85;
    const halfAngleMax = 0.32; // ~18° at the outer edge — narrower beam

    const layers = 6;
    for (let i = 0; i < layers; i++) {
      const f = i / (layers - 1); // 0 outer-dim → 1 inner-bright
      const length = rangePx * (1 - 0.5 * f);
      const half = halfAngleMax * (1 - 0.6 * f);
      const halfW = Math.tan(half) * length;
      const tipX = lx + ux * length;
      const tipY = ly + uy * length;
      const leftX = tipX + px * halfW;
      const leftY = tipY + py * halfW;
      const rightX = tipX - px * halfW;
      const rightY = tipY - py * halfW;
      // Keep the cone soft — no single layer should saturate the scene.
      const alpha = 0.05 + (f ** 1.5) * 0.22;
      this.lightCone
        .poly([lx, ly, leftX, leftY, rightX, rightY])
        .fill({ color: 0xffe8b0, alpha });
    }
    // Tiny hot spot at the lamp — subtle, doesn't blow out the diver sprite.
    this.lightCone.circle(lx, ly, 3).fill({ color: 0xfff2c8, alpha: 0.55 });
  }

  private drawDashed(
    g: Graphics,
    x1: number, y1: number,
    x2: number, y2: number,
    dash: number, gap: number
  ) {
    const dx = x2 - x1;
    const dy = y2 - y1;
    const len = Math.hypot(dx, dy);
    const nx = dx / len;
    const ny = dy / len;
    let pos = 0;
    while (pos < len) {
      const a = pos;
      const b = Math.min(pos + dash, len);
      g.moveTo(x1 + nx * a, y1 + ny * a);
      g.lineTo(x1 + nx * b, y1 + ny * b);
      pos = b + gap;
    }
  }

  private rebuildDepthGrid() {
    this.gridLayer.removeChildren();
    this.depthLabels = [];
    // Build a label per integer meter across the full envelope. Only the
    // few near the camera are drawn each frame (cheap visibility cull).
    for (let m = 0; m <= MAX_DEPTH; m++) {
      const gfx = new Graphics();
      const txt = new Text({
        text: `${m} m`,
        style: {
          fontFamily: 'JetBrains Mono, monospace',
          fontSize: 10,
          fill: 0xffffff,
        },
      });
      txt.alpha = 0.2;
      this.gridLayer.addChild(gfx, txt);
      this.depthLabels.push({ meter: m, gfx, txt });
    }
  }

  private updateDepthGrid(top: number, bot: number) {
    for (const d of this.depthLabels) {
      const visible = d.meter >= Math.floor(top) - 1 && d.meter <= bot + 1;
      d.gfx.visible = visible;
      d.txt.visible = visible;
      if (!visible) continue;
      const y = (d.meter - top) * this.pxPerMeter;
      d.gfx.clear();
      this.drawDashed(d.gfx, 20, y, this.w - 20, y, 3, 6);
      d.gfx.stroke({ color: 0xffffff, alpha: 0.07, width: 1 });
      d.txt.x = 8;
      d.txt.y = y - 12;
    }
  }
}

/**
 * Returns an RGB triplet representing seawater color at a given depth (m)
 * by mixing the surface tropical blue toward deep navy using the Beer-Lambert
 * fraction. Red dies fastest, then green, then blue — we approximate that with
 * per-channel coefficients (k_r >> k_g > k_b) so colour shifts blue with depth.
 */
function depthColor(depth_m: number): [number, number, number] {
  const z = Math.max(0, depth_m);
  // Per-channel attenuation (broad approximation of ocean water optics).
  const fr = Math.exp(-0.40 * z);  // red drops fastest
  const fg = Math.exp(-0.12 * z);
  const fb = Math.exp(-0.05 * z);  // blue penetrates deepest
  const r = Math.round(45 * fr + 2 * (1 - fr));
  const g = Math.round(106 * fg + 12 * (1 - fg));
  const b = Math.round(138 * fb + 22 * (1 - fb));
  return [clampInt(r), clampInt(g), clampInt(b)];
}

function clampInt(x: number): number {
  return Math.max(0, Math.min(255, Math.round(x)));
}
