import { Container, Graphics } from 'pixi.js';
import { bcdVolumeAtDepthL, clamp } from '../physics';
import { RV_L, TLC_L } from '../config';
import type { SimState } from '../state';

/**
 * Side-view diver silhouette in DIR-style horizontal trim:
 *   - body axis horizontal, head facing right
 *   - back-mounted wing + tank ride above the spine
 *   - knees gently bent so fins ride feet-up (Jablonski Ch. 12.15)
 *
 * Pitch responds to vertical velocity: nose-up when rising, nose-down when
 * descending. Chest "thickness" scales with lung volume; BCD wings inflate
 * with at-depth gas volume; fins flutter for a slow-hover idle.
 */
export class DiverSprite {
  container = new Container();
  private root = new Container();

  private bcdWings = new Graphics();
  private tank = new Graphics();
  private torso = new Graphics();
  private arms = new Graphics();
  private legsBack = new Graphics();
  private finL = new Graphics();
  private finR = new Graphics();
  private head = new Graphics();
  private regHose = new Graphics();

  constructor() {
    this.container.addChild(this.root);
    // Z order: BCD/tank on back (drawn first so torso overlaps them in front);
    // legs/fins behind torso; head and regulator on top.
    this.root.addChild(
      this.bcdWings,
      this.tank,
      this.legsBack,
      this.finL,
      this.finR,
      this.torso,
      this.arms,
      this.head,
      this.regHose
    );

    this.drawStatic();
  }

  setPosition(x: number, y: number) {
    this.root.x = x;
    this.root.y = y;
  }

  update(state: SimState, _dt: number) {
    // Pitch: clockwise rotation = nose-down in canvas space (y grows down).
    // Sinking (v > 0) → nose-down → +rotation. Rising → nose-up → -rotation.
    this.root.rotation = clamp(state.v * 0.18, -0.6, 0.6);

    // Face the direction of the last kick. Defaults to right (+1) at boot.
    const facing = state.lastKickDir !== 0 ? state.lastKickDir : 1;
    this.root.scale.x = facing;
    // Keep Y-scale (chest thickness) positive regardless.
    this.torso.scale.x = 1;

    // Chest thickness scales with lung volume (Y, not X — horizontal pose).
    const lungT = (state.lungCur - RV_L) / (TLC_L - RV_L);
    const chestThickness = 0.88 + lungT * 0.28; // 0.88 .. 1.16
    this.torso.scale.set(1, chestThickness);

    // Dorsal BCD wing inflates with at-depth gas volume.
    const bcdAtDepth = bcdVolumeAtDepthL(state.bcdSurf, state.depth);
    this.redrawBcd(bcdAtDepth);

    // Slow flutter idle on the fins, amplified during a kick pulse.
    this.redrawFins(state.t, state.kickPulse);
  }

  private drawStatic() {
    // ---- TANK (cylinder on the diver's back, runs along the spine) ----
    this.tank.clear();
    // Tank body: horizontal cylinder above the torso.
    this.tank
      .roundRect(-22, -24, 38, 10, 4)
      .fill(0x2a2f36)
      .stroke({ color: 0x0c1014, width: 1 });
    // Valve / first stage at the head end.
    this.tank.rect(14, -22, 6, 6).fill(0xaab4be);
    this.tank.rect(18, -25, 3, 5).fill(0x5b6770);

    // ---- TORSO (horizontal, body axis = X) ----
    this.torso.clear();
    // Stylized side-view body: shoulders right, hips left.
    this.torso
      .moveTo(-26, 4)
      .quadraticCurveTo(-26, -8, -16, -9)
      .lineTo(12, -10)
      .quadraticCurveTo(20, -10, 22, -3)
      .quadraticCurveTo(22, 6, 14, 8)
      .lineTo(-14, 10)
      .quadraticCurveTo(-26, 10, -26, 4)
      .closePath()
      .fill(0x131c23)
      .stroke({ color: 0x000000, width: 1 });

    // Wetsuit seam / harness shoulder strap suggestion.
    this.torso
      .moveTo(-10, -10)
      .lineTo(-10, 9)
      .stroke({ color: 0x38d6e6, alpha: 0.18, width: 1 });

    // Weight pocket (small dark patch on belly side).
    this.torso.roundRect(-16, 4, 12, 5, 1).fill(0x080b0e);

    // ---- ARMS (extended forward in DIR resting position) ----
    this.arms.clear();
    // Upper arm from shoulder forward
    this.arms
      .moveTo(14, -4)
      .lineTo(30, -2)
      .stroke({ color: 0x141a20, width: 5, cap: 'round' });
    // Lower arm tilted slightly upward
    this.arms
      .moveTo(30, -2)
      .lineTo(42, -6)
      .stroke({ color: 0x141a20, width: 5, cap: 'round' });
    // Hand
    this.arms.circle(43, -7, 2.6).fill(0xcaa078);
    // Second arm hint (the far one) — lighter, lower
    this.arms
      .moveTo(13, 1)
      .lineTo(28, 4)
      .stroke({ color: 0x0e1418, alpha: 0.6, width: 4, cap: 'round' });

    // ---- HEAD + MASK at the right end ----
    this.head.x = 28;
    this.head.y = -1;
    this.head.clear();
    // Hood
    this.head.circle(0, 0, 9).fill(0x0d1318);
    // Mask (forward-facing rectangle)
    this.head
      .roundRect(2, -4, 10, 8, 2)
      .fill(0x0a0e12)
      .stroke({ color: 0x38d6e6, width: 1 });
    // Lens reflection
    this.head.rect(4, -3, 3, 2.5).fill({ color: 0x78c8dc, alpha: 0.55 });
    this.head.rect(8, -3, 3, 2.5).fill({ color: 0x78c8dc, alpha: 0.55 });
    // Mouthpiece (regulator second stage)
    this.head.rect(2, 4, 8, 4).fill(0x1a2026);

    // ---- REGULATOR HOSE: from mouthpiece curving back to valve ----
    this.regHose.clear();
    this.regHose
      .moveTo(30, 5)             // at mouth
      .quadraticCurveTo(28, -10, 18, -19)  // curve up and back to valve
      .stroke({ color: 0x1a2026, width: 2.8, cap: 'round' });
  }

  private redrawBcd(volumeL: number) {
    // Wing volume drives both width (along spine) and dorsal puff (upward).
    const t = clamp(volumeL / 10, 0, 1.4);
    const len = 42 + t * 18;
    const puff = 6 + t * 10;
    this.bcdWings.clear();
    // Single wing shape running along the spine, bulging upward.
    this.bcdWings
      .moveTo(-len / 2 - 6, -16)
      .quadraticCurveTo(-len / 2 - 4, -16 - puff, -len / 2 + 8, -16 - puff)
      .lineTo(len / 2 - 8, -16 - puff)
      .quadraticCurveTo(len / 2 + 4, -16 - puff, len / 2 + 6, -16)
      .lineTo(-len / 2 - 6, -16)
      .closePath()
      .fill({ color: 0x3c8ca0, alpha: 0.85 })
      .stroke({ color: 0xb4e1eb, alpha: 0.5, width: 1.2 });
    // Highlight
    this.bcdWings
      .moveTo(-len / 2 + 2, -16 - puff + 2)
      .lineTo(len / 2 - 4, -16 - puff + 2)
      .stroke({ color: 0xffffff, alpha: 0.18, width: 1 });
  }

  private redrawFins(t: number, kickPulse = 0) {
    // Frog-kick idle: knees stay bent, lower legs sweep gently.
    // Two legs, opposite phase, small amplitude — amplified during a kick.
    const amp = 0.18 + kickPulse * 0.55;
    const sweep = Math.sin(t * 2.5) * amp;

    // Hip → knee (thigh): back and slightly up.
    // Knee → ankle (calf): further back, more up (knees bent feet-up).
    const hipY = 0;
    const hipX = -26;

    // Kick pulse pushes the legs back harder on the power-stroke (extra reach).
    const kickReach = kickPulse * 8;

    // Leg 1 (near side, dorsal)
    const kneeX1 = hipX - 16 - kickReach * 0.4;
    const kneeY1 = hipY - 4;
    const ankleX1 = kneeX1 - 12 - kickReach;
    const ankleY1 = kneeY1 - 12 + Math.sin(t * 2.5) * (3 + kickPulse * 4);

    // Leg 2 (far side, slightly offset)
    const kneeX2 = hipX - 18 - kickReach * 0.4;
    const kneeY2 = hipY + 2;
    const ankleX2 = kneeX2 - 12 - kickReach;
    const ankleY2 = kneeY2 - 10 + Math.sin(t * 2.5 + 0.6) * (3 + kickPulse * 4);

    this.legsBack.clear();
    // Far leg first (lower z)
    this.legsBack
      .moveTo(hipX, hipY + 4).lineTo(kneeX2, kneeY2)
      .stroke({ color: 0x0c1216, width: 6, cap: 'round' });
    this.legsBack
      .moveTo(kneeX2, kneeY2).lineTo(ankleX2, ankleY2)
      .stroke({ color: 0x0c1216, width: 6, cap: 'round' });
    // Near leg on top
    this.legsBack
      .moveTo(hipX, hipY - 2).lineTo(kneeX1, kneeY1)
      .stroke({ color: 0x0e1418, width: 6, cap: 'round' });
    this.legsBack
      .moveTo(kneeX1, kneeY1).lineTo(ankleX1, ankleY1)
      .stroke({ color: 0x0e1418, width: 6, cap: 'round' });

    // Fins trailing left (-x direction), trim-style (long blade)
    drawTrimFin(this.finL, ankleX1, ankleY1, sweep);
    drawTrimFin(this.finR, ankleX2, ankleY2, -sweep * 0.8);
  }
}

/**
 * Long trim-style fin trailing backward (toward -x). Phase rotates the blade
 * slightly to suggest the flutter cycle.
 */
function drawTrimFin(g: Graphics, ax: number, ay: number, phase: number) {
  g.clear();
  const cos = Math.cos(phase);
  const sin = Math.sin(phase);
  const tx = (px: number, py: number): [number, number] => [
    ax + px * cos - py * sin,
    ay + px * sin + py * cos,
  ];
  // Long oval blade extending in -x direction from ankle.
  const p0 = tx(0, -3);
  const p1 = tx(-22, -6);
  const p2 = tx(-26, 0);
  const p3 = tx(-22, 6);
  const p4 = tx(0, 3);
  g.poly([p0[0], p0[1], p1[0], p1[1], p2[0], p2[1], p3[0], p3[1], p4[0], p4[1]])
    .fill(0x0a0d10)
    .stroke({ color: 0x1f2a35, width: 1 });
  // Foot pocket
  const pf = tx(-3, 0);
  g.circle(pf[0], pf[1], 3).fill(0x1a2026);
}
