/**
 * Scene factory — single point that maps a scene id to a fresh instance.
 *
 * Used by both the initial-load path (URL param) and the in-page selector
 * to spin up a Scene without main.ts having to know which class to call.
 */

import { CaveScene } from './cave';
import { CoralReefScene } from './coralReef';
import { GenScene } from './genScene';
import { Scenery } from './scenery';
import { ShipwreckScene } from './shipwreck';
import type { Scene } from './types';

export interface SceneCatalogEntry {
  id: string;
  label: string;
  build: () => Scene;
}

export const SCENE_CATALOG: SceneCatalogEntry[] = [
  { id: 'cliff', label: 'CLIFF',  build: () => new Scenery() },
  { id: 'coral', label: 'CORAL',  build: () => new CoralReefScene() },
  { id: 'wreck', label: 'WRECK',  build: () => new ShipwreckScene() },
  { id: 'cave',  label: 'CAVE',   build: () => new CaveScene() },
  { id: 'gen',   label: 'GEN',    build: () => new GenScene() },
];

export function createScene(id: string): Scene {
  const entry = SCENE_CATALOG.find((e) => e.id === id) ?? SCENE_CATALOG[0];
  return entry.build();
}
