/**
 * confirmDialog — promise-based in-page confirm dialog.
 *
 * Replaces `window.confirm()` with a styled overlay that matches the rest of
 * the UI. Resolves to true (confirm) or false (cancel / backdrop click / Esc).
 *
 * Usage:
 *   const ok = await confirmDialog({
 *     title: 'Reset?',
 *     message: 'This wipes the current dive.',
 *     confirmText: 'RESET',
 *     destructive: true,
 *   });
 */

import './confirmDialog.css';

export interface ConfirmDialogOptions {
  title?: string;
  message: string;
  confirmText?: string;
  cancelText?: string;
  /** When true, the confirm button + chrome accent uses the danger (red) palette. */
  destructive?: boolean;
}

export function confirmDialog(opts: ConfirmDialogOptions): Promise<boolean> {
  return new Promise<boolean>((resolve) => {
    const overlay = document.createElement('div');
    overlay.className = 'dc-confirm-overlay';
    overlay.tabIndex = -1;

    const danger = !!opts.destructive;
    overlay.innerHTML = /*html*/ `
      <div class="dc-confirm-card${danger ? ' danger' : ''}" role="alertdialog" aria-modal="true">
        ${opts.title ? `<h3 class="dc-confirm-title">${escape(opts.title)}</h3>` : ''}
        <p class="dc-confirm-body">${escape(opts.message)}</p>
        <div class="dc-confirm-foot">
          <button type="button" class="dc-confirm-btn" data-act="cancel">${escape(opts.cancelText ?? 'CANCEL')}</button>
          <button type="button" class="dc-confirm-btn primary${danger ? ' danger' : ''}" data-act="ok">${escape(opts.confirmText ?? 'OK')}</button>
        </div>
      </div>
    `;
    document.body.appendChild(overlay);

    const cleanup = (result: boolean): void => {
      overlay.removeEventListener('keydown', onKey);
      overlay.remove();
      resolve(result);
    };
    const onKey = (e: KeyboardEvent): void => {
      if (e.key === 'Escape') { e.preventDefault(); cleanup(false); }
      else if (e.key === 'Enter') { e.preventDefault(); cleanup(true); }
    };
    overlay.addEventListener('keydown', onKey);

    overlay.querySelector('[data-act="ok"]')!
      .addEventListener('click', () => cleanup(true));
    overlay.querySelector('[data-act="cancel"]')!
      .addEventListener('click', () => cleanup(false));
    // Backdrop click = cancel
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) cleanup(false);
    });

    // Focus the primary action so Enter/Esc work without extra clicks.
    requestAnimationFrame(() => {
      (overlay.querySelector('[data-act="ok"]') as HTMLElement | null)?.focus();
    });
  });
}

function escape(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}
