import {
  BAROTRAUMA_DANGER_BAR,
  BAROTRAUMA_WARN_BAR,
  CO2_BREAKPOINT,
  CO2_DANGER,
  CO2_DISCOMFORT,
  FRC_L,
  G,
  MAX_ASCENT_RATE_MPS,
  MAX_DEPTH,
  RV_L,
  TLC_L,
} from './config';
import {
  ambientPressureAtm,
  barotraumaSeverity,
  bcdVolumeAtDepthL,
  clamp,
  currentBreathRateBpm,
  currentTidalVolumeL,
  netForceKgf,
  sac5sLpm,
  sacDiveAvgLpm,
} from './physics';
import { t } from './i18n';
import type { SimState } from './state';
import type { TankRig } from './divecomp/equipment';

/** Callback fired when the user clicks a tank chip — routes to gas-switch logic in main.ts. */
export type TankSwitchHandler = (index: number) => void;

export class HUD {
  private rig: TankRig;
  private onTankSwitch: TankSwitchHandler;
  /** Signature of the current rig topology — used to detect when chips need rebuild. */
  private chipsSig = '';

  private el = (id: string): HTMLElement => {
    const e = document.getElementById(id);
    if (!e) throw new Error(`HUD missing #${id}`);
    return e;
  };

  constructor(rig: TankRig, onTankSwitch: TankSwitchHandler) {
    this.rig = rig;
    this.onTankSwitch = onTankSwitch;
    this.buildDepthScale();
    this.buildLungMarks();
    this.rebuildTankChips();
    // Rebuild chips when the rig's shape changes (tank added/removed, gas swapped).
    this.rig.addListener((ev) => {
      if (ev.kind === 'tankSet' || ev.kind === 'gasChanged') this.rebuildTankChips();
    });
  }

  /** Rebuild the chip DOM. Called on init + whenever the rig topology changes. */
  private rebuildTankChips(): void {
    const host = document.getElementById('tankChips');
    if (!host) return;
    host.innerHTML = '';
    this.rig.tanks.forEach((_, idx) => {
      const chip = document.createElement('button');
      chip.type = 'button';
      chip.className = 'tank-chip';
      chip.setAttribute('data-idx', String(idx));
      chip.innerHTML = `
        <span class="dot"></span>
        <span class="lbl"></span>
        <span class="gas"></span>
        <span class="bar"><span class="fill"></span></span>
        <span class="p"></span>
      `;
      chip.addEventListener('click', () => this.onTankSwitch(idx));
      host.appendChild(chip);
    });
    this.chipsSig = this.rig.tanks.map((t) => t.slotId).join('|');
  }

  /** Refresh chip values (selected state, pressure, fill). Called every frame from update(). */
  private updateTankChips(): void {
    // If the rig topology changed without firing the event (e.g. HMR), rebuild defensively.
    const sig = this.rig.tanks.map((t) => t.slotId).join('|');
    if (sig !== this.chipsSig) this.rebuildTankChips();

    const host = document.getElementById('tankChips');
    if (!host) return;
    const chips = host.querySelectorAll<HTMLElement>('.tank-chip');
    this.rig.tanks.forEach((tank, idx) => {
      const chip = chips[idx];
      if (!chip) return;
      const isActive = tank.slotId === this.rig.activeSlotId;
      chip.classList.toggle('is-active', isActive);
      chip.classList.toggle('is-off', !tank.enabled);
      (chip.querySelector('.lbl') as HTMLElement).textContent = `T${idx + 1}`;
      (chip.querySelector('.gas') as HTMLElement).textContent = tank.gas.name;
      (chip.querySelector('.p') as HTMLElement).textContent = Math.round(tank.pressureBar).toString();
      const pct = tank.cylinder.ratedBar > 0
        ? Math.max(0, Math.min(100, (tank.pressureBar / tank.cylinder.ratedBar) * 100))
        : 0;
      const fill = chip.querySelector('.fill') as HTMLElement;
      fill.style.width = `${pct}%`;
      fill.classList.toggle('low',  tank.pressureBar < 50 && tank.pressureBar >= 21);
      fill.classList.toggle('crit', tank.pressureBar < 21);
    });
  }

  private buildDepthScale() {
    const host = this.el('depthScale');
    // Major ticks every 20 m across the full 0..MAX_DEPTH envelope.
    const STEP = 20;
    for (let m = 0; m <= MAX_DEPTH; m += STEP) {
      const div = document.createElement('div');
      div.className = 'tick';
      div.style.top = `${(m / MAX_DEPTH) * 100}%`;
      div.textContent = `${m}`;
      host.appendChild(div);
    }
    // Recreational MOD line at 40 m for orientation.
    const recLine = document.createElement('div');
    recLine.className = 'tick rec-line';
    recLine.style.top = `${(40 / MAX_DEPTH) * 100}%`;
    recLine.textContent = '40·rec';
    host.appendChild(recLine);
    // Target line removed — training-range overlay on the water canvas
    // is now the primary visual cue, and it's level-driven (not always-on).
  }

  private buildLungMarks() {
    const host = this.el('lungBar');
    const range = TLC_L - RV_L;
    const marks = [
      { v: RV_L, l: 'RV 1.2' },
      { v: FRC_L, l: 'FRC 2.5' },
      { v: TLC_L, l: 'TLC 6.0' },
    ];
    for (const m of marks) {
      const d = document.createElement('div');
      d.className = 'lung-mark';
      d.style.top = `${(1 - (m.v - RV_L) / range) * 100}%`;
      d.textContent = m.l;
      host.appendChild(d);
    }
  }

  update(s: SimState) {
    const pAtm = ambientPressureAtm(s.depth);

    this.el('depthVal').textContent = s.depth.toFixed(2);
    this.el('ovDepth').textContent = s.depth.toFixed(2);
    this.el('pAtm').textContent = pAtm.toFixed(2);
    (this.el('depthPos') as HTMLElement).style.top =
      `${clamp(s.depth / MAX_DEPTH, 0, 1) * 100}%`;

    // Velocity + ascent-rate warning (Jablonski: max 10 m/min ascent).
    this.el('velVal').textContent = s.v.toFixed(2);
    this.el('accVal').textContent = s.a.toFixed(2);
    const va = this.el('velArrow');
    const tooFast = -s.v > MAX_ASCENT_RATE_MPS;
    if (Math.abs(s.v) < 0.05) {
      va.textContent = '◇';
      va.className = 'vel-arrow';
    } else if (s.v < 0) {
      va.textContent = tooFast ? '▲▲' : '▲';
      va.className = tooFast ? 'vel-arrow danger' : 'vel-arrow up';
    } else {
      va.textContent = '▼';
      va.className = 'vel-arrow down';
    }

    // Lung
    this.el('lungVal').textContent = s.lungCur.toFixed(2);
    const baselineL = FRC_L + s.lungBias;
    this.el('lungBase').textContent = baselineL.toFixed(2);
    const lungT = (s.lungCur - RV_L) / (TLC_L - RV_L);
    const lungTgtT = (s.lungTgt - RV_L) / (TLC_L - RV_L);
    (this.el('lungFill') as HTMLElement).style.top = `${(1 - lungT) * 100}%`;
    (this.el('lungFill') as HTMLElement).style.height = `${lungT * 100}%`;
    (this.el('lungTargetLine') as HTMLElement).style.top =
      `${(1 - lungTgtT) * 100}%`;
    // Transpulmonary in bar (signed: + = lung overpressure).
    const ptpBar = s.transpulmonaryBar;
    this.el('lungP').textContent = `${ptpBar >= 0 ? '+' : ''}${ptpBar.toFixed(3)}`;
    const lungWarn = this.el('lungWarn') as HTMLElement;
    if (Math.abs(ptpBar) > BAROTRAUMA_WARN_BAR) {
      lungWarn.style.display = 'inline';
      lungWarn.style.color = Math.abs(ptpBar) > BAROTRAUMA_DANGER_BAR ? 'var(--rd)' : 'var(--am)';
      lungWarn.textContent = Math.abs(ptpBar) > BAROTRAUMA_DANGER_BAR
        ? t('baro_rupture')
        : t('baro_warning');
    } else {
      lungWarn.style.display = 'none';
    }
    // Auto-breath telemetry
    this.el('lungRate').textContent = currentBreathRateBpm(s).toFixed(0);
    this.el('lungTV').textContent = currentTidalVolumeL(s).toFixed(2);

    // BCD — show physical at-depth volume only (surface-eq is a confusing
    // bookkeeping value now that depth-aware capping works).
    const wingMax = s.equipment.wing.maxLitersSurface;
    const vBcd = bcdVolumeAtDepthL(s.bcdSurf, s.depth);
    this.el('bcdVal').textContent = vBcd.toFixed(2);
    (this.el('bcdFill') as HTMLElement).style.width =
      `${clamp((vBcd / wingMax) * 100, 0, 100)}%`;
    const bcdTag = this.el('bcdTag');
    if (bcdTag) bcdTag.textContent = `${s.equipment.wing.liftKg.toFixed(0)} ${t('hud_bcd_lift')}`;

    // Net force (kg-equivalent for diver readability).
    const FnetKgf = netForceKgf(s);
    const FnetN = FnetKgf * G;
    this.el('netF').textContent = `${FnetN >= 0 ? '+' : ''}${FnetN.toFixed(1)}`;
    const nfl = this.el('netFLabel');
    if (Math.abs(FnetKgf) < 0.3) {
      nfl.textContent = t('state_neutral');
      nfl.style.color = 'var(--gn)';
    } else if (FnetKgf > 0) {
      nfl.textContent = `${FnetKgf.toFixed(1)} kg ↓`;
      nfl.style.color = 'var(--am)';
    } else {
      nfl.textContent = `${(-FnetKgf).toFixed(1)} kg ↑`;
      nfl.style.color = 'var(--cy)';
    }

    // CO2
    this.el('co2Val').textContent = s.co2.toFixed(0);
    const co2Pct = clamp((s.co2 - 30) / (90 - 30), 0, 1) * 100;
    (this.el('co2Needle') as HTMLElement).style.left = `${co2Pct}%`;

    // Breath rate
    const recent = s.breathTimes.filter((t) => s.t - t < 20);
    const bpm = ((recent.length / 2) * 60) / 20;
    this.el('brRate').textContent = bpm.toFixed(0);

    // Exertion + horizontal velocity (kicks).
    this.el('exertVal').textContent = (s.exertion * 100).toFixed(0);
    this.el('vxVal').textContent = s.vx.toFixed(2);

    const dot = this.el('breathDot');
    const bs = this.el('brState');
    if (s.co2 >= CO2_DANGER) {
      dot.className = 'breath-dot crit';
      bs.textContent = t('state_danger');
      bs.style.color = 'var(--rd)';
    } else if (s.co2 >= CO2_BREAKPOINT) {
      dot.className = 'breath-dot crit';
      bs.textContent = t('state_breakpt');
      bs.style.color = 'var(--rd)';
    } else if (s.co2 >= CO2_DISCOMFORT) {
      dot.className = 'breath-dot warn';
      bs.textContent = t('state_urge');
      bs.style.color = 'var(--am)';
    } else {
      dot.className = 'breath-dot';
      bs.textContent = t('state_rest');
      bs.style.color = 'var(--ink)';
    }

    // Hold scoring HUD removed — the mission HUD (src/missions/MissionHud.ts)
    // owns this surface now and only renders when a depth-hold mission is
    // active. `state.onTargetTime` is still computed by physics in case
    // future missions want to read it directly.

    // Tank / SAC panel — driven by the multi-tank rig (active tank's data).
    const active = this.rig.active;
    const ratedBar = active.cylinder.ratedBar;
    this.el('tankPVal').textContent = Math.round(active.pressureBar).toString();
    const gasMassActive =
      (active.cylinder.capacityL * active.pressureBar * gasSurfDen(active.gas)) / 1000;
    this.el('gasMass').textContent = gasMassActive.toFixed(2);
    const tankFrac = clamp(active.pressureBar / ratedBar, 0, 1);
    (this.el('tankFill') as HTMLElement).style.width = `${tankFrac * 100}%`;
    const tankTag = this.el('tankTag');
    const activeIdx = this.rig.tanks.findIndex((t) => t.slotId === this.rig.activeSlotId);
    if (tankTag) tankTag.textContent = `T${activeIdx + 1} · ${active.gas.name}`;

    // SAC: rolling 5-second window + dive average (both are diver-level, not tank-level).
    const fiveS = sac5sLpm(s);
    const avg = sacDiveAvgLpm(s);
    this.el('sac5s').textContent = fiveS < 0.5 ? '—' : fiveS.toFixed(1);
    this.el('sacAvg').textContent = s.diveStartT === null || avg < 0.5 ? '—' : avg.toFixed(1);

    // GTR for the active tank (matches manual §10.7 + Perdix display).
    const RESERVE_BAR = 50;
    const sac_Lpm = fiveS;
    const p_amb = ambientPressureAtm(s.depth);
    const drainBarPerMin = (sac_Lpm * p_amb) / active.cylinder.capacityL;
    const remainingBar = Math.max(0, active.pressureBar - RESERVE_BAR);
    let tMin: number;
    if (active.pressureBar <= RESERVE_BAR) tMin = 0;
    else if (drainBarPerMin < 0.5) tMin = Infinity;
    else tMin = remainingBar / drainBarPerMin;
    this.el('gasTime').textContent = !isFinite(tMin) ? '∞' : tMin < 999 ? tMin.toFixed(0) : '999+';

    // Refresh the chip strip below.
    this.updateTankChips();

    // Gear summary line (panel 7) — describes the static gear plus active tank.
    const gear = this.el('gearSummary');
    if (gear) {
      const eq = s.equipment;
      const light = eq.primaryLight ? ' · LIGHT' : '';
      const tankBit = `${active.cylinder.name.split(' ')[0]} ${active.gas.name}`;
      gear.textContent = `${tankBit} · ${eq.wing.liftKg.toFixed(0)}kg wing · ${eq.wetsuit.name.split(' ')[0]} · ${eq.leadKg.toFixed(1)}kg Pb${light}`;
    }

    // Breath-hold indicator
    const bh = this.el('breathHoldInd');
    bh.classList.toggle('on', s.breathHold);
    if (s.breathHold) {
      const span = bh.querySelector('span');
      if (span) span.textContent = `${s.holdElapsed.toFixed(1)}s · TPP ${s.transpulmonaryBar >= 0 ? '+' : ''}${s.transpulmonaryBar.toFixed(3)} bar`;
    }

    // Lung-overpressure banner (only if warning enabled in settings)
    const banner = this.el('baroBanner');
    const sev = barotraumaSeverity(s);
    if (s.settings.barotraumaWarning && sev !== 'none') {
      banner.classList.add('on');
      banner.classList.toggle('danger', sev === 'danger');
      (this.el('baroTitle') as HTMLElement).textContent =
        sev === 'danger' ? t('baro_title_danger') : t('baro_title_warn');
      (this.el('baroVal') as HTMLElement).textContent =
        `${s.transpulmonaryBar >= 0 ? '+' : ''}${s.transpulmonaryBar.toFixed(3)}`;
    } else {
      banner.classList.remove('on', 'danger');
    }
  }
}

/** Surface gas density (g/L) — matches divecomp/engine/gasMix's helper, duplicated here to avoid the dep. */
function gasSurfDen(g: { o2Pct: number; hePct: number }): number {
  const fO2 = g.o2Pct / 100;
  const fHe = g.hePct / 100;
  const fN2 = 1 - fO2 - fHe;
  return (fO2 * 32 + fHe * 4 + fN2 * 28) / 24.04;
}
