/**
 * Conservatism presets — Shearwater Perdix 2 / Teric defaults.
 * See Perdix 2 manual §12.2 (Deco Setup) and Teric manual §11.2.
 *
 *   Low    45 / 95  — least conservative
 *   Med    40 / 85  — factory default in both watches
 *   High   35 / 75  — more conservative
 *   Custom user-defined GF pair (still validated to 1..100, low ≤ high)
 */

import type { Conservatism, ConservatismName } from './types';

export const CONSERVATISM_PRESETS: Record<Exclude<ConservatismName, 'custom'>, Conservatism> = {
  low:  { name: 'low',  gfLow: 45, gfHigh: 95 },
  med:  { name: 'med',  gfLow: 40, gfHigh: 85 },
  high: { name: 'high', gfLow: 35, gfHigh: 75 },
};

export const DEFAULT_CONSERVATISM: Conservatism = CONSERVATISM_PRESETS.med;

export function customGf(gfLow: number, gfHigh: number): Conservatism {
  return { name: 'custom', gfLow, gfHigh };
}

export function validateConservatism(c: Conservatism): string | null {
  if (c.gfLow < 1 || c.gfLow > 100) return 'GF Low out of range (1..100)';
  if (c.gfHigh < 1 || c.gfHigh > 100) return 'GF High out of range (1..100)';
  if (c.gfLow > c.gfHigh) return 'GF Low must be ≤ GF High';
  return null;
}
