/**
 * UI smoke harness — runs a scripted sequence of UI interactions and
 * asserts the world is in the expected state at each step. Opt-in via the
 * `?uismoke=1` URL parameter so it never fires in normal play.
 *
 * Steps it covers:
 *   1. Dismiss the welcome screen.
 *   2. Toggle immersive on/off via the `I` key + click.
 *   3. Open MENU, switch language to zh and back, close.
 *   4. Open MENU → New Dive — gear modal opens with the SCENE section.
 *   5. Pick CORAL in the SetupModal scene chips.
 *   6. Cancel setup → no scene picker exists on the runtime overlay.
 *   7. New-Dive again, pick GEN → after close GEN panel is attached.
 *
 * Failures print red diagnostics in the console but never throw — the
 * harness keeps going so we can see every issue in one run.
 */

interface CheckResult { ok: boolean; msg: string }

const log = {
  step(n: number, t: string) { console.log(`%c[smoke ${n}] ${t}`, 'color:#7ad7ff'); },
  pass(t: string) { console.log(`%c  ✓ ${t}`, 'color:#6ee29a'); },
  fail(t: string) { console.log(`%c  ✗ ${t}`, 'color:#ff7070;font-weight:bold'); },
  info(t: string) { console.log(`%c  · ${t}`, 'color:#a0acb8'); },
};

const wait = (ms: number) => new Promise<void>(r => setTimeout(r, ms));

function check(label: string, ok: boolean): CheckResult {
  if (ok) log.pass(label);
  else log.fail(label);
  return { ok, msg: label };
}

function $(sel: string): HTMLElement | null {
  return document.querySelector<HTMLElement>(sel);
}
function $all(sel: string): HTMLElement[] {
  return [...document.querySelectorAll<HTMLElement>(sel)];
}

async function dismissWelcome(): Promise<void> {
  const start = $('#welcomeStart');
  if (start) {
    start.click();
    // .welcome-screen has a 450 ms CSS transition; only after transitionend
    // fires does welcome's onDismiss → setup.open(initial:true) run. Wait
    // long enough for that to complete, then ESC to close setup so the
    // test starts from a clean unpaused-no-modal state.
    await wait(700);
  }
}

async function closeAnyModal(): Promise<void> {
  // Close gear / menu via Escape.
  document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape', bubbles: true }));
  await wait(200);
}

/**
 * Force the sim into a deterministic state for the duration of the test:
 * cleared depth, no dive started, and (after the welcome screen) we set
 * state.paused = true between every step the test isn't actively pausing
 * with a modal. The harness has to fight slightly against the real
 * physics that keeps advancing — without this, the diver can descend
 * past 1 m within ~1 s of unpaused play, locking the scene picker.
 */
function pinSimToSurface(): void {
  const dc = (window as unknown as { __dc?: { state: { depth: number; v: number; bcdSurf: number; diveStartT: number | null; paused: boolean } } }).__dc;
  if (!dc) return;
  dc.state.depth = 0;
  dc.state.v = 0;
  dc.state.bcdSurf = 0;
  dc.state.diveStartT = null;
  dc.state.paused = true;
}

export async function runUiSmoke(): Promise<void> {
  console.group('%c=== UI SMOKE ===', 'color:#7ad7ff;font-weight:bold');
  await wait(400);

  log.step(1, 'Dismiss welcome');
  await dismissWelcome();
  await closeAnyModal();
  // Strip any persisted scene preference so the test starts deterministically.
  localStorage.removeItem('ppb_scene');
  pinSimToSurface();
  check('canvas is mounted', !!$('canvas'));

  log.step(2, 'Toggle immersive twice');
  pinSimToSurface();
  const immBtn = $('.immersive-toggle');
  check('immersive toggle present', !!immBtn);
  immBtn?.click();
  await wait(150);
  check('immersive ON', document.body.classList.contains('is-immersive'));
  immBtn?.click();
  await wait(150);
  check('immersive OFF', !document.body.classList.contains('is-immersive'));

  log.step(3, 'Runtime layout: no scene picker on the water overlay');
  check('no runtime scene picker', !$('.scene-cluster'));
  check('no runtime scenario panel', !$('.scenario-panel'));

  log.step(4, 'Open MENU, flip language to zh and back');
  pinSimToSurface();
  $('#settingsBtn')?.click();
  for (let i = 0; i < 8; i++) {
    if ($('#menu-modal.open')) break;
    await wait(50);
  }
  check('menu opened', !!$('#menu-modal.open'));
  // Menu only shows New Dive — Gear · Setup was removed.
  check('menu shows New Dive', !!$('#menuNewDive'));
  check('menu hides Gear · Setup', !$('#menuOpenGear'));
  const zh = $('input[name="lang"][value="zh"]') as HTMLInputElement | null;
  zh?.click();
  await wait(150);
  check('zh radio checked', !!zh?.checked);
  const en = $('input[name="lang"][value="en"]') as HTMLInputElement | null;
  en?.click();
  await wait(150);
  check('en radio checked', !!en?.checked);
  $('#settingsDone')?.click();
  await wait(250);
  check('menu closed', !$('#menu-modal.open'));

  log.step(5, 'New Dive opens gear modal with SCENE chips inside');
  pinSimToSurface();
  $('#settingsBtn')?.click();
  await wait(300);
  $('#menuNewDive')?.click();
  await wait(500);
  check('setup modal opened after New Dive', !!$('#setup-modal.open'));
  const setupSceneChips = $all('.setup-scene-chip');
  check('SCENE chips rendered inside gear modal', setupSceneChips.length >= 4);
  const coralChip = setupSceneChips.find(b => b.textContent?.trim() === 'CORAL');
  coralChip?.click();
  await wait(150);
  check('CORAL chip is selected', !!coralChip?.classList.contains('is-on'));

  log.step(6, 'Cancel setup — modal closes and no runtime picker exists');
  $('#setupCancel')?.click();
  await wait(300);
  pinSimToSurface();
  check('setup modal closed', !$('#setup-modal.open'));
  check('still no runtime scene picker', !$('.scene-cluster'));

  log.step(7, 'New Dive again → pick GEN → close → GEN panel attached');
  pinSimToSurface();
  $('#settingsBtn')?.click();
  await wait(250);
  $('#menuNewDive')?.click();
  await wait(450);
  const genChip = $all('.setup-scene-chip').find(b => b.textContent?.trim() === 'GEN');
  if (genChip) {
    genChip.click();
    await wait(200);
    check('GEN chip selected', !!genChip.classList.contains('is-on'));
    $('#setupDive')?.click();
    await wait(400);
    check('setup closed after DIVE', !$('#setup-modal.open'));
    check('GEN panel attached on water overlay', !!$('.gen-panel'));
  } else {
    log.info('GEN chip missing — skipping');
  }

  console.groupEnd();
  console.log('%c=== END UI SMOKE ===', 'color:#7ad7ff;font-weight:bold');
}

/** Auto-fire when the page is opened with `?uismoke=1`. */
export function maybeStartUiSmoke(): void {
  if (!new URLSearchParams(location.search).has('uismoke')) return;
  // HMR can re-execute this module multiple times; gate with a window flag
  // so the harness only fires once per page load.
  const w = window as unknown as { __uismokeFired?: boolean };
  if (w.__uismokeFired) return;
  w.__uismokeFired = true;
  // Defer until the welcome screen and canvases are mounted.
  setTimeout(() => { void runUiSmoke(); }, 1200);
}
