/**
 * Notification host — transient banners for dive-computer events.
 *
 * Mirrors the Perdix manual §4.8 notification semantics:
 *   info   — neutral chrome (cyan)
 *   warn   — caution (amber)
 *   danger — pulsing red, requires acknowledgement
 *
 * A single host renders a stack; new notifications push onto the top.
 * Auto-dismiss after `durationMs` unless `persistent` is set.
 */

import './notifications.css';

export type NotifKind = 'info' | 'warn' | 'danger';

export interface NotifOptions {
  text: string;
  kind?: NotifKind;
  icon?: string;
  durationMs?: number;
  /** When set, replace any active notification with the same key. */
  key?: string;
}

interface ActiveNotif {
  el: HTMLElement;
  timer: number | null;
  key?: string;
}

export class Notifications {
  private host: HTMLElement;
  private items: ActiveNotif[] = [];

  constructor() {
    this.host = document.createElement('div');
    this.host.className = 'dc-notifications';
    document.body.appendChild(this.host);
  }

  show(opts: NotifOptions): () => void {
    const { text, kind = 'info', icon, durationMs = 3000, key } = opts;

    // De-dupe by key — replace any existing item with the same key.
    if (key) {
      const existing = this.items.find(i => i.key === key);
      if (existing) this.dismiss(existing);
    }

    const el = document.createElement('div');
    el.className = `dc-notif ${kind}`;
    el.innerHTML = `${icon ? `<span class="ico">${icon}</span>` : ''}<span>${escapeHtml(text)}</span>`;
    this.host.prepend(el);
    // Trigger CSS transition on next frame.
    requestAnimationFrame(() => el.classList.add('is-on'));

    const item: ActiveNotif = { el, timer: null, key };
    this.items.push(item);

    if (durationMs > 0) {
      item.timer = window.setTimeout(() => this.dismiss(item), durationMs);
    }

    return () => this.dismiss(item);
  }

  private dismiss(item: ActiveNotif): void {
    const i = this.items.indexOf(item);
    if (i < 0) return;
    this.items.splice(i, 1);
    if (item.timer !== null) clearTimeout(item.timer);
    item.el.classList.remove('is-on');
    setTimeout(() => item.el.remove(), 200);
  }

  clear(): void {
    for (const item of [...this.items]) this.dismiss(item);
  }
}

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}
