/**
 * Perdix 2 page renderers — pure functions over the engine snapshot.
 *
 * Layout decisions follow §4.3-§4.7 of the manual and a recreational-mode
 * reference image:
 *
 *   Row 1: depth (left)             | SAFETY STOP / DECO STOP / — (right)
 *   Row 2: TIME (dive time + batt)  | NDL / DECO (right, large)
 *   Row 3: ACTIVE GAS | T1 PRESSURE + bar | GTR T1
 *
 * Colors:
 *   • Labels (TIME / NDL / T1 / BAR / GTR) — magenta
 *   • Values (numbers) — white
 *   • Active-state labels (SAFETY STOP) — cyan
 *   • Warning state — amber; danger — red (flashing)
 */

import type { DecoSnapshot } from '../../engine';
import type { PanelRigSnapshot } from '../../panel/DiveWatchPanel';
import type { MenuController } from './menu';
import type { DiveMode } from '../../modes';

export interface PageHost {
  root: HTMLElement;
  update(s: DecoSnapshot, rig?: PanelRigSnapshot, extra?: PageExtras): void;
}

export interface PageExtras {
  velocityMps: number;
  wallClock: Date;
  ambientTempC: number;
  /** Battery 0..1; if undefined the icon shows full. */
  battery?: number;
  /** Minutes of breathing gas remaining at current depth + SAC. Infinity when not consuming. */
  gtrMin?: number;
  /** Index of active tank in the rig (0-based). Used to render T1/T2/T3. */
  activeTankIndex?: number;
  /** Active dive mode — drives the mode tag and gauge-mode behaviour. */
  mode?: DiveMode;
}

// ---------------------------------------------------------------- helpers

function el(tag: string, cls?: string, html?: string): HTMLElement {
  const e = document.createElement(tag);
  if (cls) e.className = cls;
  if (html != null) e.innerHTML = html;
  return e;
}

function fmtDiveTime(s: number): string {
  const total = Math.max(0, Math.floor(s));
  return `${Math.floor(total / 60)}:${(total % 60).toString().padStart(2, '0')}`;
}

function fmtClock(d: Date): string {
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false });
}

function ascentArrows(vMps: number): { text: string; level: 0 | 1 | 2 } {
  // Manual §4.4: 1 arrow per 3 mpm. White ≤ 9 mpm, yellow ≤ 18, red > 18.
  const mpm = -vMps * 60;
  if (mpm <= 0) return { text: '', level: 0 };
  const arrows = Math.min(6, Math.max(1, Math.floor(mpm / 3)));
  return { text: '▲'.repeat(arrows), level: mpm >= 18 ? 2 : mpm >= 9 ? 1 : 0 };
}

/** Convert deco state + depth to the safety-stop block content. */
function stopBlock(s: DecoSnapshot): {
  label: string;
  labelClass: string;
  value: string;
  valueClass: string;
} {
  if (s.inDeco) {
    const stopD = Math.max(3, Math.ceil(s.ceiling_m / 3) * 3);
    return { label: 'DECO STOP', labelClass: 'rd', value: `${stopD} m`, valueClass: 'crit' };
  }
  // Recreational safety-stop window: 2.4–8.3 m after a dive >11 m
  if (s.maxDepth_m > 11 && s.depth_m >= 2.4 && s.depth_m <= 8.3) {
    return { label: 'SAFETY STOP', labelClass: 'cy', value: '3:00', valueClass: '' };
  }
  // Otherwise show nothing in the upper-right; NDL block below will show.
  return { label: '', labelClass: '', value: '', valueClass: '' };
}

// ---------------------------------------------------------------- DIVE MAIN

export function buildMainPage(): PageHost {
  const root = el('div', 'p2-page p2-main');

  // Row 1 left — depth + ascent arrows + mode tag below depth
  const depth = el('div', 'p2-cell p2-depth');
  const depthRow = el('span', 'depth-row');
  const depthV = el('span', 'v', '0.0');
  const depthU = el('span', 'u', 'm');
  const arrows = el('span', 'arrows');
  depthRow.append(depthV, depthU, arrows);
  const modeTag = el('span', 'p2-mode-tag', '3NX');
  depth.append(depthRow, modeTag);

  // Row 1 right — safety/deco stop block
  const stop = el('div', 'p2-cell p2-stop right');
  const stopLbl = el('span', 'lbl');
  const stopVal = el('span', 'v');
  stop.append(stopLbl, stopVal);

  // Row 2 left — TIME + battery
  const time = el('div', 'p2-cell p2-time');
  const timeLbl = el('span', 'lbl', 'TIME');
  const timeRow = el('div', 'row');
  const timeV = el('span', 'v', '0:00');
  const batt = el('span', 'p2-batt');
  const battFill = el('span', 'fill');
  batt.appendChild(battFill);
  timeRow.append(timeV, batt);
  time.append(timeLbl, timeRow);

  // Row 2 right — NDL
  const ndl = el('div', 'p2-cell p2-ndl right');
  const ndlLbl = el('span', 'lbl', 'NDL');
  const ndlV = el('span', 'v', '99');
  ndl.append(ndlLbl, ndlV);

  // Row 3 — gas | tank | GTR (sub-grid)
  const row3 = el('div', 'p2-row3');
  const gas = el('div', 'p2-cell p2-gas');
  const gasV = el('span', 'v', 'Air');
  gas.appendChild(gasV);

  const tank = el('div', 'p2-cell p2-tank');
  tank.innerHTML = /*html*/ `
    <div class="tank-head">
      <span class="lbl" data-bind="tankLbl">T1</span>
      <span class="bar"><span class="fill"></span></span>
    </div>
    <div class="tank-val">
      <span class="v" data-bind="tankP">207</span>
      <span class="u">BAR</span>
    </div>
  `;

  const gtr = el('div', 'p2-cell p2-gtr right');
  const gtrLbl = el('span', 'lbl', 'GTR T1');
  const gtrV = el('span', 'v', '—');
  gtr.append(gtrLbl, gtrV);
  // remember refs for update
  (gtr as any)._lbl = gtrLbl;
  (gtr as any)._v = gtrV;

  row3.append(gas, tank, gtr);

  root.append(depth, stop, time, ndl, row3);

  // Button-hint strip
  const hints = el('div', 'p2-hints');
  hints.innerHTML = `<span class="menu-hint">MENU</span><span class="select-hint">INFO</span>`;
  root.append(hints);

  return {
    root,
    update(s, rig, extra) {
      // Depth + ascent
      depthV.textContent = s.depth_m.toFixed(1);
      const v = extra?.velocityMps ?? 0;
      const ar = ascentArrows(v);
      arrows.textContent = ar.text;
      arrows.classList.toggle('warn', ar.level === 1);
      arrows.classList.toggle('crit', ar.level === 2);

      // Mode tag
      if (extra?.mode) modeTag.textContent = extra.mode.shortTag;

      // Stop block
      const sb = stopBlock(s);
      stopLbl.textContent = sb.label;
      stopLbl.className = `lbl ${sb.labelClass}`;
      stopVal.textContent = sb.value;
      stopVal.className = `v ${sb.valueClass}`;

      // Dive time
      timeV.textContent = fmtDiveTime(s.diveTimeS);

      // Battery
      const b = extra?.battery ?? 1.0;
      battFill.style.height = `${Math.max(8, Math.min(100, b * 100))}%`;
      batt.classList.toggle('warn', b < 0.4 && b >= 0.15);
      batt.classList.toggle('crit', b < 0.15);

      // NDL / DECO
      if (s.inDeco) {
        ndlLbl.textContent = 'DECO';
        ndlV.textContent = '0';
        ndlV.className = 'v deco';
      } else {
        ndlLbl.textContent = 'NDL';
        const m = Math.max(0, Math.min(99, Math.floor(s.ndlMin)));
        ndlV.textContent = String(m);
        ndlV.className = 'v' + (m < 5 ? ' warn' : '');
      }

      // Active gas
      gasV.textContent = s.activeGas.name;
      const mod14 = Math.max(0, 10 * (1.4 / (s.activeGas.o2Pct / 100) - 1));
      gasV.classList.toggle('crit', s.depth_m > mod14);

      // Active tank — find in rig, fall back to '—'
      const active = rig?.tanks.find(t => t.isActive);
      const tankLblEl = tank.querySelector('[data-bind="tankLbl"]') as HTMLElement;
      const tankPEl = tank.querySelector('[data-bind="tankP"]') as HTMLElement;
      const tankFill = tank.querySelector('.bar .fill') as HTMLElement;
      // Perdix-style transmitter labels: T1, T2, T3, T4 by index.
      const tIdx = (extra?.activeTankIndex ?? 0) + 1;
      const tName = `T${tIdx}`;
      if (active) {
        tankLblEl.textContent = tName;
        tankPEl.textContent = Math.round(active.pressureBar).toString();
        const pct = active.ratedBar > 0 ? (active.pressureBar / active.ratedBar) * 100 : 0;
        tankFill.style.width = `${Math.max(0, Math.min(100, pct))}%`;
        tankFill.classList.toggle('low', active.pressureBar < 50);
        tankFill.classList.toggle('crit', active.pressureBar < 21);
      } else {
        tankLblEl.textContent = '—';
        tankPEl.textContent = '—';
        tankFill.style.width = '0%';
      }

      // GTR — minutes of gas left at current SAC + depth.
      gtrLbl.textContent = `GTR ${tName}`;
      const g = extra?.gtrMin;
      if (g === undefined || g === null) {
        gtrV.textContent = '—';
        gtrV.classList.remove('warn', 'crit');
      } else if (!isFinite(g)) {
        gtrV.textContent = '∞';
        gtrV.classList.remove('warn', 'crit');
      } else if (g <= 0) {
        gtrV.textContent = '0';
        gtrV.classList.remove('warn');
        gtrV.classList.add('crit');
      } else {
        gtrV.textContent = g < 100 ? Math.round(g).toString() : '99';
        gtrV.classList.toggle('crit', g < 2);
        gtrV.classList.toggle('warn', g >= 2 && g < 5);
      }
    },
  };
}

// ---------------------------------------------------------------- INFO SCREENS

export function buildInfoCnsPage(): PageHost {
  const root = el('div', 'p2-page p2-info-screen');
  root.innerHTML = /*html*/ `
    <div class="title">CNS · MOD · TEMP</div>
    <div class="grid">
      <div class="cell"><span class="lbl">CNS</span>           <span class="v" data-bind="cns">0</span><span class="u">%</span></div>
      <div class="cell"><span class="lbl">OTU</span>           <span class="v" data-bind="otu">0</span><span class="u">UNITS</span></div>
      <div class="cell"><span class="lbl">MOD PO₂ 1.4</span>   <span class="v" data-bind="mod">0</span><span class="u">M</span></div>
      <div class="cell"><span class="lbl">TEMP</span>          <span class="v" data-bind="temp">—</span><span class="u">°C</span></div>
    </div>
    <div class="p2-hints"><span class="menu-hint">EXIT</span><span class="select-hint">NEXT</span></div>
  `;
  return {
    root,
    update(s, _rig, extra) {
      const cnsEl = root.querySelector('[data-bind="cns"]') as HTMLElement;
      cnsEl.textContent = s.cnsPct.toFixed(0);
      cnsEl.classList.toggle('warn', s.cnsPct >= 80 && s.cnsPct < 100);
      cnsEl.classList.toggle('crit', s.cnsPct >= 100);
      (root.querySelector('[data-bind="otu"]') as HTMLElement).textContent = s.otu.toFixed(0);
      const mod = Math.max(0, 10 * (1.4 / (s.activeGas.o2Pct / 100) - 1));
      (root.querySelector('[data-bind="mod"]') as HTMLElement).textContent = mod.toFixed(0);
      (root.querySelector('[data-bind="temp"]') as HTMLElement).textContent =
        extra ? extra.ambientTempC.toFixed(0) : '—';
    },
  };
}

export function buildInfoGfPage(): PageHost {
  const root = el('div', 'p2-page p2-info-screen');
  root.innerHTML = /*html*/ `
    <div class="title">GRADIENT FACTORS</div>
    <div class="grid">
      <div class="cell"><span class="lbl">GF99</span>    <span class="v" data-bind="gf99">0</span><span class="u">%</span></div>
      <div class="cell"><span class="lbl">SurGF</span>   <span class="v" data-bind="surf">0</span><span class="u">%</span></div>
      <div class="cell"><span class="lbl">CEILING</span> <span class="v" data-bind="ceil">0</span><span class="u">M</span></div>
      <div class="cell"><span class="lbl">CONSERV</span> <span class="v" data-bind="gf">40/85</span><span class="u">GF LO/HI</span></div>
    </div>
    <div class="p2-hints"><span class="menu-hint">EXIT</span><span class="select-hint">NEXT</span></div>
  `;
  return {
    root,
    update(s) {
      const gf99 = root.querySelector('[data-bind="gf99"]') as HTMLElement;
      gf99.textContent = Math.max(0, s.gf99Pct).toFixed(0);
      gf99.classList.toggle('warn', s.gf99Pct > 85 && s.gf99Pct <= 100);
      gf99.classList.toggle('crit', s.gf99Pct > 100);
      const surf = root.querySelector('[data-bind="surf"]') as HTMLElement;
      surf.textContent = Math.max(0, s.surfGfPct).toFixed(0);
      surf.classList.toggle('warn', s.surfGfPct > s.conservatism.gfHigh);
      (root.querySelector('[data-bind="ceil"]') as HTMLElement).textContent = s.ceiling_m.toFixed(0);
      (root.querySelector('[data-bind="gf"]') as HTMLElement).textContent =
        `${s.conservatism.gfLow}/${s.conservatism.gfHigh}`;
    },
  };
}

export function buildInfoDensityPage(): PageHost {
  const root = el('div', 'p2-page p2-info-screen');
  root.innerHTML = /*html*/ `
    <div class="title">GAS DENSITY · BREATH</div>
    <div class="grid">
      <div class="cell"><span class="lbl">DENSITY</span>     <span class="v" data-bind="den">0.00</span><span class="u">G/L</span></div>
      <div class="cell"><span class="lbl">PO₂</span>         <span class="v" data-bind="po2">0.00</span><span class="u">ATA</span></div>
      <div class="cell"><span class="lbl">END (TRIMIX)</span><span class="v" data-bind="end">0</span><span class="u">M</span></div>
      <div class="cell"><span class="lbl">SURF GAS</span>    <span class="v" data-bind="surf">0.00</span><span class="u">G/L · 1 ATM</span></div>
    </div>
    <div class="p2-hints"><span class="menu-hint">EXIT</span><span class="select-hint">BACK</span></div>
  `;
  return {
    root,
    update(s) {
      const den = root.querySelector('[data-bind="den"]') as HTMLElement;
      den.textContent = s.density.gPerL.toFixed(2);
      den.classList.toggle('warn', s.density.severity === 'warning');
      den.classList.toggle('crit', s.density.severity === 'danger');
      const pAmb_bar = s.surfaceMbar / 1000 + s.depth_m / 10;
      const po2 = (s.activeGas.o2Pct / 100) * pAmb_bar;
      const po2El = root.querySelector('[data-bind="po2"]') as HTMLElement;
      po2El.textContent = po2.toFixed(2);
      po2El.classList.toggle('warn', po2 > 1.4 && po2 <= 1.6);
      po2El.classList.toggle('crit', po2 > 1.6);
      const end = Math.max(0, (s.depth_m + 10) * (1 - s.activeGas.hePct / 100) - 10);
      (root.querySelector('[data-bind="end"]') as HTMLElement).textContent = end.toFixed(0);
      const fO2 = s.activeGas.o2Pct / 100;
      const fHe = s.activeGas.hePct / 100;
      const fN2 = 1 - fO2 - fHe;
      const surfDen = (fO2 * 32 + fHe * 4 + fN2 * 28) / 24.04;
      (root.querySelector('[data-bind="surf"]') as HTMLElement).textContent = surfDen.toFixed(2);
    },
  };
}

// ---------------------------------------------------------------- MENU

export interface MenuPageHandle extends PageHost {
  /** Rebuild the menu DOM from the controller's current node + selection. */
  refresh(): void;
}

/**
 * Renders the menu controlled by `MenuController`. The watch calls `refresh()`
 * after each button press (the controller is the source of truth for state).
 *
 * Top of the menu shows the current branch label; a breadcrumb crumb appears
 * below it when the user has descended ≥ 1 level.
 */
export function buildMenuPage(controller: MenuController): MenuPageHandle {
  const root = el('div', 'p2-page p2-menu');
  root.innerHTML = /*html*/ `
    <div class="head">
      <span class="title" data-bind="title">MAIN MENU</span>
      <span class="crumb" data-bind="crumb"></span>
    </div>
    <div class="items" data-bind="items"></div>
    <div class="p2-hints"><span class="menu-hint">NEXT</span><span class="select-hint">SELECT</span></div>
  `;
  const titleEl = root.querySelector('[data-bind="title"]') as HTMLElement;
  const crumbEl = root.querySelector('[data-bind="crumb"]') as HTMLElement;
  const itemsEl = root.querySelector('[data-bind="items"]') as HTMLElement;

  function refresh(): void {
    titleEl.textContent = controller.title;
    crumbEl.textContent = controller.depth > 1 ? `· depth ${controller.depth}` : '';
    const items = controller.items;
    const selIdx = controller.currentIndex;
    itemsEl.innerHTML = items
      .map((it, i) => {
        const cls = `item${i === selIdx ? ' sel' : ''}${it.kind === 'branch' ? ' branch' : ''}`;
        const chev = it.kind === 'branch' && it.id !== 'back' ? '<span class="chev">›</span>' : '';
        return `<div class="${cls}">${escapeHtmlSafe(it.label)}${chev}</div>`;
      })
      .join('');
    // Auto-scroll selected into view (for long menus)
    const sel = itemsEl.querySelector('.item.sel');
    sel?.scrollIntoView({ block: 'nearest' });
  }

  refresh();
  return {
    root,
    update() { /* menu doesn't react to snapshot data — refresh is button-driven */ },
    refresh,
  };
}

function escapeHtmlSafe(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}
