import { Container, Graphics } from 'pixi.js';
import {
  APHOTIC_DEPTH,
  MAX_DEPTH,
  ZONE_LOWER_MESO_MAX,
  ZONE_SHALLOW_MAX,
  ZONE_UPPER_MESO_MAX,
} from '../config';
import { clamp } from '../physics';
import type { SimState } from '../state';
import { SpriteBiotaPool } from '../assets';

/**
 * Underwater scenery — cliff wall + depth-zoned biota.
 *
 * The cliff is a procedural jagged polygon anchored to the right side of the
 * screen, extending from CLIFF_TOP_M down to MAX_DEPTH. Biota (fish schools,
 * gorgonians, sponges, deep silhouettes) are pre-distributed across depth
 * zones and rendered with attenuation- and light-modulated colour.
 *
 *   illumination = 0  -> pure silhouette (deep blue / near-black)
 *   illumination = 1  -> full natural colour (only happens with sun OR light)
 */

const CLIFF_TOP_M = 6;
/** World length of cliff strip (m). We wrap with modulo so swimming forever works. */
const CLIFF_LENGTH_M = 240;
/** Cliff cross-section samples (every metre vertically). */
const SAMPLES_PER_M = 2;

type Zone = 'shallow' | 'upper_meso' | 'lower_meso' | 'aphotic';

function zoneAt(depth: number): Zone {
  if (depth < ZONE_SHALLOW_MAX) return 'shallow';
  if (depth < ZONE_UPPER_MESO_MAX) return 'upper_meso';
  if (depth < ZONE_LOWER_MESO_MAX) return 'lower_meso';
  return 'aphotic';
}

interface Creature {
  /** World depth anchor (m). */
  depth: number;
  /** World x along cliff strip (m, mod CLIFF_LENGTH_M). */
  xAlong: number;
  /** Drives oscillation / drift phase. */
  phase: number;
  type: 'school' | 'gorgonian' | 'sponge' | 'pelagic' | 'deep';
  /** Lit colour (when illumination ≈ 1). */
  litColor: number;
  /** Per-creature scale factor. */
  scale: number;
}

export class Scenery {
  container = new Container();
  private cliffGfx = new Graphics();
  private biotaGfx = new Graphics();
  /**
   * Sprite-backed biota for the archetypes we have textures for —
   * `school` and `pelagic` map onto Ansimuz `fish-dart` and `fish-big`.
   * `gorgonian` / `sponge` / `deep` have no registry sprite and stay
   * procedural via `biotaGfx`.
   */
  private biotaPool = new SpriteBiotaPool();
  private cliffProfile: number[] = []; // for each x sample: cliff "inset" px factor
  private creatures: Creature[] = [];

  private w = 0;
  private h = 0;
  private pxPerMeter = 60;

  constructor() {
    this.container.addChild(this.cliffGfx, this.biotaGfx, this.biotaPool.container);
    this.buildCliffProfile();
    this.buildCreatures();
  }

  resize(w: number, h: number, pxPerMeter: number) {
    this.w = w;
    this.h = h;
    this.pxPerMeter = pxPerMeter;
  }

  /**
   * @param camTopDepth   - world depth at screen top
   * @param scrollX       - horizontal camera offset in metres
   * @param sunLight      - 0..1 surface light remaining at diver depth
   * @param illumination  - max(sunLight, primary cone) — colour driver
   */
  update(
    _state: SimState,
    camTopDepth: number,
    scrollX: number,
    sunLight: number,
    illumination: number
  ) {
    if (!this.w || !this.h) return;

    const camBotDepth = camTopDepth + this.h / this.pxPerMeter;
    this.drawCliff(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
    this.drawBiota(camTopDepth, camBotDepth, scrollX, sunLight, illumination);
  }

  // ---------------- Cliff geometry ----------------

  private buildCliffProfile() {
    // Stable jaggedness — sums of sinusoids at varying frequencies.
    const total = CLIFF_LENGTH_M * SAMPLES_PER_M;
    const seed = 7.31;
    for (let i = 0; i < total; i++) {
      const u = i / SAMPLES_PER_M; // metres
      const v =
        0.45 * Math.sin(u * 0.21 + seed) +
        0.30 * Math.sin(u * 0.07 + seed * 2.1) +
        0.18 * Math.sin(u * 0.51 + seed * 0.9) +
        0.07 * Math.sin(u * 1.34 + seed * 3.7);
      // Normalize to 0..1 (cliff inset depth)
      this.cliffProfile.push(0.5 + 0.5 * v);
    }
  }

  private drawCliff(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sunLight: number,
    _illumination: number
  ) {
    this.cliffGfx.clear();
    if (camBotDepth < CLIFF_TOP_M) return; // cliff not yet visible

    // Cliff is on the right edge — silhouette polygon.
    const maxInset = this.w * 0.42;
    const xEdge = this.w;
    const startDepth = Math.max(CLIFF_TOP_M, camTopDepth - 2);
    const endDepth = Math.min(MAX_DEPTH, camBotDepth + 2);

    const pts: number[] = [];
    pts.push(xEdge, (startDepth - camTopDepth) * this.pxPerMeter);

    for (let d = startDepth; d <= endDepth; d += 0.5) {
      const u = (scrollX + d * 0.7) % CLIFF_LENGTH_M;
      const idx = Math.floor(((u + CLIFF_LENGTH_M) % CLIFF_LENGTH_M) * SAMPLES_PER_M);
      const t = this.cliffProfile[idx % this.cliffProfile.length];
      const depthFactor = clamp((d - CLIFF_TOP_M) / 20, 0.15, 1);
      const inset = maxInset * (0.35 + 0.55 * t) * depthFactor;
      pts.push(xEdge - inset, (d - camTopDepth) * this.pxPerMeter);
    }
    pts.push(xEdge, (endDepth - camTopDepth) * this.pxPerMeter);

    // Cliff base — warm stone. The darkness overlay applied by WaterScene
    // dims this naturally as depth increases; light cone reveals it again.
    this.cliffGfx.poly(pts).fill({ color: 0x3d3026, alpha: 0.96 });

    // Subtle highlight streaks on the cliff face (algae, mineral lines).
    for (let i = 1; i < pts.length / 2 - 1; i += 4) {
      const x = pts[i * 2];
      const y = pts[i * 2 + 1];
      this.cliffGfx
        .moveTo(x + 4, y)
        .lineTo(x + 12, y + 14)
        .stroke({ color: 0x6b5a3e, alpha: 0.35, width: 1 });
    }
  }

  // ---------------- Biota ----------------

  private buildCreatures() {
    const rand = mulberry32(0xc0ffee);
    const push = (
      depthRange: [number, number],
      count: number,
      type: Creature['type'],
      colorPool: number[],
      scaleRange: [number, number]
    ) => {
      for (let i = 0; i < count; i++) {
        this.creatures.push({
          depth: depthRange[0] + rand() * (depthRange[1] - depthRange[0]),
          xAlong: rand() * CLIFF_LENGTH_M,
          phase: rand() * Math.PI * 2,
          type,
          litColor: colorPool[Math.floor(rand() * colorPool.length)],
          scale: scaleRange[0] + rand() * (scaleRange[1] - scaleRange[0]),
        });
      }
    };

    // Shallow reef (0-30 m) — vivid anthias schools, hard corals, parrotfish.
    push([CLIFF_TOP_M, ZONE_SHALLOW_MAX], 14, 'school',
      [0xff9b3d, 0xffcc66, 0xffbf80], [0.8, 1.4]);
    push([8, ZONE_SHALLOW_MAX], 9, 'gorgonian',
      [0xe06b3a, 0xffaa55, 0xc7702b], [0.9, 1.5]);
    push([10, ZONE_SHALLOW_MAX], 7, 'sponge',
      [0xc04a55, 0xf08a3d, 0xd9b04a], [0.6, 1.1]);

    // Upper mesophotic (30-60 m) — gorgonians, sponges, larger pelagics.
    push([ZONE_SHALLOW_MAX, ZONE_UPPER_MESO_MAX], 11, 'gorgonian',
      [0xb83a4e, 0x8e5cc3, 0x7d3a85], [1.0, 1.7]);
    push([ZONE_SHALLOW_MAX + 5, ZONE_UPPER_MESO_MAX], 5, 'school',
      [0x6090b0, 0x7aa5c0], [0.6, 1.0]);
    push([ZONE_SHALLOW_MAX + 8, ZONE_UPPER_MESO_MAX], 4, 'pelagic',
      [0x3a4855, 0x2e3a45], [1.4, 2.2]);

    // Lower mesophotic (60-150 m) — black coral, distinct fauna, sparse.
    push([ZONE_UPPER_MESO_MAX, ZONE_LOWER_MESO_MAX], 10, 'gorgonian',
      [0x4a2e62, 0x2e1d3a, 0x553e72], [1.2, 2.0]);
    push([ZONE_UPPER_MESO_MAX + 10, ZONE_LOWER_MESO_MAX], 5, 'sponge',
      [0x5d3a55, 0x3a2e44], [0.9, 1.4]);
    push([ZONE_UPPER_MESO_MAX, ZONE_LOWER_MESO_MAX], 3, 'pelagic',
      [0x202830, 0x161c22], [1.6, 2.6]);

    // Aphotic (>150 m) — ghost shapes, only visible with light.
    push([ZONE_LOWER_MESO_MAX, MAX_DEPTH - 5], 6, 'deep',
      [0x9aa6b3, 0x6e7a86], [1.2, 2.4]);
    push([ZONE_LOWER_MESO_MAX + 10, MAX_DEPTH - 5], 4, 'gorgonian',
      [0x586470, 0x424d58], [1.4, 2.4]);
  }

  private drawBiota(
    camTopDepth: number,
    camBotDepth: number,
    scrollX: number,
    _sunLight: number,
    _illumination: number
  ) {
    const g = this.biotaGfx;
    g.clear();
    this.biotaPool.beginFrame();

    const maxInset = this.w * 0.42;
    const xEdge = this.w;
    const spriteScale = this.pxPerMeter / 60;

    for (const c of this.creatures) {
      if (c.depth < camTopDepth - 1 || c.depth > camBotDepth + 1) continue;

      const u = (c.xAlong - scrollX) % CLIFF_LENGTH_M;
      const uMod = ((u % CLIFF_LENGTH_M) + CLIFF_LENGTH_M) % CLIFF_LENGTH_M;
      const along = uMod / CLIFF_LENGTH_M;
      const cliffInset = 0.35 + 0.55 * (0.5 + 0.5 * Math.sin(along * Math.PI * 6));
      const offsetOut = Math.sin(c.phase + scrollX * 0.01) * 24;
      const x = xEdge - maxInset * cliffInset - offsetOut - 14;
      if (x < -50 || x > this.w + 50) continue;

      const y = (c.depth - camTopDepth) * this.pxPerMeter;

      // Draw at lit colour — darkness overlay dims naturally with depth, and
      // the ADD-blended primary light cone re-brightens whatever it covers.
      const color = c.litColor;
      const alpha = c.type === 'deep' ? 0.70 : 0.92;
      const t = (scrollX * 0.02 + c.phase) % (Math.PI * 2);

      switch (c.type) {
        case 'school': {
          // Cluster of small darting fish — 7 sprite instances if the
          // `fish-dart` sprite is loaded, otherwise triangle fallback.
          const n = 7;
          for (let i = 0; i < n; i++) {
            const ang = i * 0.9 + t;
            const fx = x + Math.cos(ang) * 14 * c.scale;
            const fy = y + Math.sin(ang * 1.3) * 9 * c.scale;
            const phaseSeed = i * 0.13 + c.phase;
            if (this.biotaPool.draw(
              'fish-dart', fx, fy, 0,
              c.scale * spriteScale * 0.55, color, alpha, phaseSeed,
            )) {
              continue;
            }
            const s = 3 * c.scale;
            g.poly([fx - s, fy, fx + s, fy - s * 0.6, fx + s, fy + s * 0.6])
              .fill({ color, alpha });
          }
          break;
        }
        case 'gorgonian': {
          // Branching fan — drawn as L-system-style outward fronds.
          const baseX = x;
          const baseY = y;
          const branches = 5;
          const len = 18 * c.scale;
          // trunk
          g.moveTo(baseX + 4, baseY + 6)
            .lineTo(baseX, baseY - 4)
            .stroke({ color, alpha, width: 1.4 });
          for (let i = 0; i < branches; i++) {
            const a = -Math.PI / 2 + (i - branches / 2) * 0.35 + Math.sin(t + i) * 0.08;
            const ex = baseX + Math.cos(a) * len;
            const ey = baseY + Math.sin(a) * len;
            g.moveTo(baseX, baseY)
              .lineTo(ex, ey)
              .stroke({ color, alpha, width: 1.1 });
            // sub-branches
            for (let j = 1; j <= 2; j++) {
              const sx = baseX + Math.cos(a) * len * (j / 3);
              const sy = baseY + Math.sin(a) * len * (j / 3);
              const sub = a + 0.5;
              g.moveTo(sx, sy)
                .lineTo(sx + Math.cos(sub) * 5 * c.scale, sy + Math.sin(sub) * 5 * c.scale)
                .stroke({ color, alpha: alpha * 0.85, width: 0.9 });
              const sub2 = a - 0.5;
              g.moveTo(sx, sy)
                .lineTo(sx + Math.cos(sub2) * 5 * c.scale, sy + Math.sin(sub2) * 5 * c.scale)
                .stroke({ color, alpha: alpha * 0.85, width: 0.9 });
            }
          }
          break;
        }
        case 'sponge': {
          // Round-ish blobs stacked.
          const r = 6 * c.scale;
          g.circle(x, y, r).fill({ color, alpha });
          g.circle(x + r * 0.6, y - r * 0.5, r * 0.7).fill({ color, alpha });
          g.circle(x - r * 0.5, y - r * 0.3, r * 0.6).fill({ color, alpha });
          break;
        }
        case 'pelagic': {
          // Lone large fish — sprite when available, lens-shape fallback.
          if (this.biotaPool.draw(
            'fish-big', x, y, Math.sin(c.phase) * 0.05,
            c.scale * spriteScale * 0.85, color, alpha, c.phase * 0.3,
          )) break;
          const w = 22 * c.scale;
          const h = 6 * c.scale;
          const dir = Math.sin(t) > 0 ? 1 : -1;
          g.poly([
            x - w / 2 * dir, y,
            x, y - h / 2,
            x + w / 2 * dir, y,
            x, y + h / 2,
          ]).fill({ color, alpha });
          // Tail
          g.poly([
            x + w / 2 * dir, y,
            x + (w / 2 + h) * dir, y - h * 0.8,
            x + (w / 2 + h) * dir, y + h * 0.8,
          ]).fill({ color, alpha: alpha * 0.9 });
          break;
        }
        case 'deep': {
          // Ghostly elongated form — only really seen with light.
          const w = 18 * c.scale;
          const h = 4 * c.scale;
          g.poly([
            x - w / 2, y,
            x, y - h,
            x + w / 2, y,
            x, y + h,
          ]).fill({ color, alpha });
          // Faint tendrils
          g.moveTo(x, y + h)
            .lineTo(x - 4, y + h + 8 * c.scale)
            .stroke({ color, alpha: alpha * 0.5, width: 0.8 });
          g.moveTo(x, y + h)
            .lineTo(x + 4, y + h + 10 * c.scale)
            .stroke({ color, alpha: alpha * 0.5, width: 0.8 });
          break;
        }
      }
    }
    this.biotaPool.endFrame();
  }

  /** Zone label for HUD/debug use. */
  zoneLabel(depth: number): string {
    switch (zoneAt(depth)) {
      case 'shallow':    return 'SHALLOW REEF';
      case 'upper_meso': return 'UPPER MESOPHOTIC';
      case 'lower_meso': return 'LOWER MESOPHOTIC';
      case 'aphotic':    return 'APHOTIC';
    }
  }

  // ---- Scene-interface conformance ----
  readonly id = 'cliff';
  readonly name = 'CLIFF WALL';

  zoneInfoAt(depth: number): import('./types').ZoneInfo {
    const zone = zoneAt(depth);
    // Population = creatures whose depth falls inside ± 8 m of the current depth
    // band (matches the visible-range heuristic).
    let pop = 0;
    const types = new Set<string>();
    const zoneStart = zone === 'shallow' ? 0
      : zone === 'upper_meso' ? ZONE_SHALLOW_MAX
      : zone === 'lower_meso' ? ZONE_UPPER_MESO_MAX
      : ZONE_LOWER_MESO_MAX;
    const zoneEnd = zone === 'shallow' ? ZONE_SHALLOW_MAX
      : zone === 'upper_meso' ? ZONE_UPPER_MESO_MAX
      : zone === 'lower_meso' ? ZONE_LOWER_MESO_MAX
      : MAX_DEPTH;
    for (const c of this.creatures) {
      if (c.depth >= zoneStart && c.depth < zoneEnd) {
        // Schools count as a small school of ~7 fish (see drawBiota).
        pop += c.type === 'school' ? 7 : 1;
        types.add(c.type);
      }
    }
    const note =
      zone === 'shallow'    ? 'reef · abundant'    :
      zone === 'upper_meso' ? 'mesophotic · sparse' :
      zone === 'lower_meso' ? 'black coral · cold' :
                              'aphotic · silhouettes only';
    return { label: this.zoneLabel(depth), population: pop, variety: types.size, note };
  }
}

// Small deterministic RNG — keeps creature placement stable across resizes.
function mulberry32(seed: number) {
  let s = seed | 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

