/**
 * DiveWatchPanel — draggable floating overlay that hosts a watch skin.
 *
 * This file owns: drag, persisted geometry, minimize/close affordances, and
 * the generic "default skin" (depth + NDL + GF + density + gas + dive time).
 *
 * Future Perdix-2 / Teric skins will replace the body content with their own
 * widgets while reusing this shell.
 */

import './panel.css';
import type { DecoSnapshot } from '../engine';

/**
 * Minimal rig snapshot for the panel — no direct dependency on the rig module
 * so this skin can also be driven from synthetic data (tests, replay).
 */
export interface PanelRigTank {
  slotId: string;
  slotLabel: string;
  gasName: string;
  pressureBar: number;
  ratedBar: number;
  isActive: boolean;
  enabled: boolean;
}
export interface PanelRigSnapshot {
  tanks: PanelRigTank[];
}

const STORAGE_KEY = 'ppb_divewatch_geo';
const Z_INDEX_BASE = 90;

interface Geometry {
  left: number;
  top: number;
}

export interface DiveWatchPanelOptions {
  title?: string;
  initialGeometry?: Geometry;
  /** Used for the localStorage key — allows multiple coexisting panels. */
  instanceId?: string;
}

export class DiveWatchPanel {
  readonly root: HTMLElement;
  private body!: HTMLElement;
  private storageKey: string;
  private geometry: Geometry;
  private hidden = false;
  private minimised = false;

  // Cached element refs for fast per-frame updates
  private elDepth!: HTMLElement;
  private elMax!: HTMLElement;
  private elNdlLabel!: HTMLElement;
  private elNdlVal!: HTMLElement;
  private elNdlUnit!: HTMLElement;
  private elGf99!: HTMLElement;
  private elSurfGf!: HTMLElement;
  private elCns!: HTMLElement;
  private elDens!: HTMLElement;
  private elGas!: HTMLElement;
  private elDiveTime!: HTMLElement;
  private elTanks!: HTMLElement;
  private tankRowsByPressure: WeakMap<HTMLElement, HTMLElement> = new WeakMap();
  private renderedRigSig = '';

  constructor(opts: DiveWatchPanelOptions = {}) {
    const title = opts.title ?? 'DIVE COMPUTER';
    this.storageKey = STORAGE_KEY + (opts.instanceId ? `:${opts.instanceId}` : '');
    this.geometry = opts.initialGeometry ?? this.loadGeometry() ?? this.defaultGeometry();

    this.root = document.createElement('div');
    this.root.className = 'dwp';
    this.root.style.zIndex = String(Z_INDEX_BASE);
    this.root.innerHTML = /*html*/ `
      <div class="dwp-head">
        <span class="dwp-title">${escapeHtml(title)}</span>
        <div class="dwp-actions">
          <button class="dwp-btn dwp-min" type="button" title="minimize">_</button>
          <button class="dwp-btn dwp-close" type="button" title="hide">✕</button>
        </div>
      </div>
      <div class="dwp-body">
        <div class="dwp-depth">
          <span class="v" data-bind="depth">0.0</span>
          <span class="u">m</span>
          <span class="max">MAX <b data-bind="max">0.0</b> m</span>
        </div>
        <div class="dwp-ndl">
          <span class="lbl" data-bind="ndlLabel">NDL</span>
          <span><span class="v ok" data-bind="ndlVal">—</span><span class="u" data-bind="ndlUnit">min</span></span>
        </div>
        <div class="dwp-mini">
          <div class="cell"><span class="lbl">GF99</span><b data-bind="gf99">0</b></div>
          <div class="cell"><span class="lbl">SurGF</span><b data-bind="surfGf">0</b></div>
          <div class="cell"><span class="lbl">CNS</span><b data-bind="cns">0%</b></div>
          <div class="cell"><span class="lbl">DENS</span><b data-bind="dens">0.0</b></div>
        </div>
        <div class="dwp-tanks" data-bind="tanks"></div>
        <div class="dwp-foot">
          <span class="gas" data-bind="gas">Air</span>
          <span class="time" data-bind="diveTime">0:00</span>
        </div>
      </div>
    `;
    document.body.appendChild(this.root);

    this.body = this.root.querySelector('.dwp-body') as HTMLElement;
    this.cacheBindings();
    this.applyGeometry();
    this.bindDrag();
    this.bindControls();
  }

  // ---- Public API ----

  update(s: DecoSnapshot, rig?: PanelRigSnapshot): void {
    if (this.hidden) return;
    if (rig) this.updateTanks(rig);

    this.elDepth.textContent = s.depth_m.toFixed(1);
    this.elMax.textContent = s.maxDepth_m.toFixed(1);

    if (s.inDeco) {
      this.elNdlLabel.textContent = 'DECO';
      this.elNdlVal.textContent = s.ceiling_m.toFixed(0);
      this.elNdlUnit.textContent = 'm ceil';
      setSeverity(this.elNdlVal, 'crit');
    } else {
      this.elNdlLabel.textContent = 'NDL';
      const ndl = Math.max(0, Math.min(99, Math.floor(s.ndlMin)));
      this.elNdlVal.textContent = String(ndl);
      this.elNdlUnit.textContent = 'min';
      setSeverity(this.elNdlVal, ndl < 5 ? 'warn' : 'ok');
    }

    this.elGf99.textContent = `${Math.max(0, s.gf99Pct).toFixed(0)}%`;
    setSeverity(this.elGf99, s.gf99Pct > 100 ? 'crit' : s.gf99Pct > 85 ? 'warn' : '');

    this.elSurfGf.textContent = `${Math.max(0, s.surfGfPct).toFixed(0)}%`;
    setSeverity(this.elSurfGf, s.surfGfPct > s.conservatism.gfHigh ? 'warn' : '');

    this.elCns.textContent = `${s.cnsPct.toFixed(0)}%`;
    setSeverity(this.elCns, s.cnsPct > 100 ? 'crit' : s.cnsPct > 80 ? 'warn' : '');

    this.elDens.textContent = `${s.density.gPerL.toFixed(2)} g/L`;
    setSeverity(this.elDens,
      s.density.severity === 'danger' ? 'crit' :
      s.density.severity === 'warning' ? 'warn' : '');

    this.elGas.textContent = s.activeGas.name;
    this.elGas.classList.toggle('warn', s.density.severity === 'danger');

    this.elDiveTime.textContent = formatDiveTime(s.diveTimeS);
  }

  show(): void {
    this.hidden = false;
    this.root.classList.remove('is-hidden');
  }
  hide(): void {
    this.hidden = true;
    this.root.classList.add('is-hidden');
  }
  isHidden(): boolean {
    return this.hidden;
  }

  setTitle(title: string): void {
    const el = this.root.querySelector('.dwp-title') as HTMLElement | null;
    if (el) el.textContent = title;
  }

  destroy(): void {
    this.root.remove();
  }

  // ---- Internals ----

  private cacheBindings(): void {
    const q = (name: string): HTMLElement =>
      this.root.querySelector(`[data-bind="${name}"]`) as HTMLElement;
    this.elDepth = q('depth');
    this.elMax = q('max');
    this.elNdlLabel = q('ndlLabel');
    this.elNdlVal = q('ndlVal');
    this.elNdlUnit = q('ndlUnit');
    this.elGf99 = q('gf99');
    this.elSurfGf = q('surfGf');
    this.elCns = q('cns');
    this.elDens = q('dens');
    this.elGas = q('gas');
    this.elDiveTime = q('diveTime');
    this.elTanks = q('tanks');
  }

  /** Rebuild tank rows only when the rig shape changes; update bars + labels otherwise. */
  private updateTanks(rig: PanelRigSnapshot): void {
    const sig = rig.tanks.map(t => `${t.slotId}/${t.gasName}/${t.enabled}`).join('|');
    if (sig !== this.renderedRigSig) {
      this.renderedRigSig = sig;
      this.elTanks.innerHTML = rig.tanks.map((_, i) => /*html*/ `
        <div class="dwp-tank" data-tank-idx="${i}">
          <span class="dwp-tank-slot"></span>
          <span class="dwp-tank-gas"></span>
          <span class="dwp-tank-bar"><span class="fill"></span></span>
          <span class="dwp-tank-p"></span>
        </div>
      `).join('');
    }
    const rows = this.elTanks.querySelectorAll<HTMLElement>('.dwp-tank');
    rig.tanks.forEach((t, i) => {
      const row = rows[i];
      if (!row) return;
      row.classList.toggle('is-active', t.isActive);
      row.classList.toggle('is-off', !t.enabled);
      (row.querySelector('.dwp-tank-slot') as HTMLElement).textContent = t.slotLabel;
      (row.querySelector('.dwp-tank-gas') as HTMLElement).textContent = t.gasName;
      (row.querySelector('.dwp-tank-p') as HTMLElement).textContent = `${Math.round(t.pressureBar)}`;
      const fill = row.querySelector('.fill') as HTMLElement;
      const pct = t.ratedBar > 0 ? Math.max(0, Math.min(100, (t.pressureBar / t.ratedBar) * 100)) : 0;
      fill.style.width = `${pct}%`;
      fill.classList.toggle('low', t.pressureBar < 50);
      fill.classList.toggle('crit', t.pressureBar < 21);
    });
  }

  private defaultGeometry(): Geometry {
    return { left: window.innerWidth - 340, top: 70 };
  }

  private applyGeometry(): void {
    const { left, top } = this.clamped(this.geometry);
    this.root.style.left = `${left}px`;
    this.root.style.top = `${top}px`;
  }

  private clamped(g: Geometry): Geometry {
    const rect = this.root.getBoundingClientRect();
    const w = rect.width || 300;
    const h = rect.height || 200;
    return {
      left: Math.max(8, Math.min(window.innerWidth - w - 8, g.left)),
      top: Math.max(8, Math.min(window.innerHeight - 32, g.top)),
    };
  }

  private bindDrag(): void {
    const head = this.root.querySelector('.dwp-head') as HTMLElement;
    let drag: { mx: number; my: number; left: number; top: number; ptr: number } | null = null;

    head.addEventListener('pointerdown', (e) => {
      // Don't start drag from action-button clicks.
      if ((e.target as HTMLElement).closest('.dwp-actions')) return;
      head.setPointerCapture(e.pointerId);
      const rect = this.root.getBoundingClientRect();
      drag = { mx: e.clientX, my: e.clientY, left: rect.left, top: rect.top, ptr: e.pointerId };
      this.root.style.zIndex = String(Z_INDEX_BASE + 5);
      e.preventDefault();
    });

    head.addEventListener('pointermove', (e) => {
      if (!drag || e.pointerId !== drag.ptr) return;
      this.geometry.left = drag.left + (e.clientX - drag.mx);
      this.geometry.top = drag.top + (e.clientY - drag.my);
      this.applyGeometry();
    });

    const end = (e: PointerEvent): void => {
      if (!drag || e.pointerId !== drag.ptr) return;
      try { head.releasePointerCapture(e.pointerId); } catch { /* already released */ }
      this.saveGeometry();
      this.root.style.zIndex = String(Z_INDEX_BASE);
      drag = null;
    };
    head.addEventListener('pointerup', end);
    head.addEventListener('pointercancel', end);
  }

  private bindControls(): void {
    const minBtn = this.root.querySelector('.dwp-min') as HTMLButtonElement;
    const closeBtn = this.root.querySelector('.dwp-close') as HTMLButtonElement;
    minBtn.addEventListener('click', () => {
      this.minimised = !this.minimised;
      this.root.classList.toggle('is-min', this.minimised);
    });
    closeBtn.addEventListener('click', () => this.hide());
  }

  private loadGeometry(): Geometry | null {
    try {
      const raw = localStorage.getItem(this.storageKey);
      if (!raw) return null;
      const g = JSON.parse(raw);
      if (typeof g?.left !== 'number' || typeof g?.top !== 'number') return null;
      return { left: g.left, top: g.top };
    } catch {
      return null;
    }
  }

  private saveGeometry(): void {
    try {
      localStorage.setItem(this.storageKey, JSON.stringify(this.geometry));
    } catch {
      /* quota / private mode — non-fatal */
    }
  }
}

// ---- helpers ----

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&' ? '&amp;' :
    c === '<' ? '&lt;'  :
    c === '>' ? '&gt;'  :
    c === '"' ? '&quot;' : '&#39;'
  );
}

function setSeverity(el: HTMLElement, sev: '' | 'ok' | 'warn' | 'crit'): void {
  el.classList.remove('ok', 'warn', 'crit');
  if (sev) el.classList.add(sev);
}

function formatDiveTime(s: number): string {
  const total = Math.max(0, Math.floor(s));
  const mm = Math.floor(total / 60);
  const ss = total % 60;
  return `${mm}:${ss.toString().padStart(2, '0')}`;
}
