/**
 * Centralised defaults for the dive-computer module.
 *
 * Edit these values to change the out-of-the-box behaviour for new players
 * (or any player who hasn't touched the corresponding setting yet).
 * Anything the user has explicitly toggled is persisted to localStorage and
 * takes precedence over the defaults below — see how `main.ts` resolves
 * device visibility for the read pattern.
 */

export const DIVECOMP_DEFAULTS = {
  /** Per-device visibility on a fresh session. */
  devices: {
    /** Perdix-style watch face. Off by default — opt in via the gear modal. */
    perdix: false,
    /** Compact generic panel (depth/NDL/density/gas/etc.). On by default. */
    watchPanel: true,
    /** Wireless air-integration transmitter. Not yet implemented. */
    aiTransmitter: false,
    /** Compass module. Not yet implemented. */
    compass: false,
  },

  /** Localstorage keys that mirror the toggles in `devices`. */
  storage: {
    perdix:     'ppb_perdix_visible',
    watchPanel: 'ppb_watchpanel_visible',
  },
} as const;

/**
 * Resolve a boolean visibility flag: localStorage wins if the user has
 * touched it before, otherwise fall back to the default in DIVECOMP_DEFAULTS.
 */
export function resolveVisibility(
  storageKey: string,
  fallback: boolean
): boolean {
  try {
    const raw = localStorage.getItem(storageKey);
    if (raw === null) return fallback;
    return raw === 'true';
  } catch {
    return fallback;
  }
}
